  var colLib2 = -1, rEnc = -1, rDec = -1;
  for (var r = 0; r < aoa.length; r++) {
    var row = aoa[r] || [];
    for (var c3 = 0; c3 < Math.min(row.length, 4); c3++) {
      var t = String(row[c3] == null ? '' : row[c3]).trim();
      if (t === 'Encaissements' && rEnc < 0) { colLib2 = c3; rEnc = r; }
      if (rEnc >= 0 && c3 === colLib2 && t === 'D\u00e9caissements' && r > rEnc && rDec < 0) rDec = r;
    }
  }
  if (colLib2 < 0) return { erreur: 'Section \u00ab Encaissements \u00bb introuvable.' };
  if (rDec < 0) rDec = aoa.length;
  var indent = function(s) { var mI = String(s).match(/^ */); return mI ? mI[0].length : 0; };
  for (var r2 = rEnc; r2 < rDec; r2++) {
    var labR = String((aoa[r2] || [])[colLib2] == null ? '' : aoa[r2][colLib2]);
    if (labR.trim().toUpperCase() === 'TEVA') { rTeva = r2; break; }
  }
  if (rTeva < 0) return { erreur: 'Rubrique TEVA introuvable dans Encaissements > Remises LABOS.' };
  var indT = indent(aoa[rTeva][colLib2]);
