function egRemiseGlobaleHTML(cfg, labo, rapp) {
  if (!achatsBase || !okimiaBase) return '';
  var cible = (typeof labo.remiseGlobaleCible === 'number') ? labo.remiseGlobaleCible : 51;
  var matchL = function(k) { return cfg.tokens.some(function(tk) { return String(k).toUpperCase().indexOf(tk) >= 0; }); };
  var annees = {};
  Object.keys(achatsBase.mois).forEach(function(mk) {
    var o = achatsBase.mois[mk];
    if (Object.keys(o.cerpRT || {}).some(matchL)) annees[mk.slice(0, 4)] = 1;
    Object.keys(o.dirFact || {}).forEach(function(nf) { if (matchL(o.dirFact[nf].f || '')) annees[mk.slice(0, 4)] = 1; });
  });
  var tdB = 'padding:3px 6px;border-bottom:1px solid var(--border);text-align:right;font-family:monospace;font-size:11px';
  var corps = '', notes = [];
  Object.keys(annees).sort().reverse().forEach(function(an) {
    var dernier = null;
    Object.keys(achatsBase.mois).sort().forEach(function(mk) {
      if (mk.slice(0, 4) === an && Object.keys(achatsBase.mois[mk].cerpRT || {}).some(matchL)) dernier = mk;
    });
    var brutInd = 0, remInd = 0;
    if (dernier) {
      var oT = achatsBase.mois[dernier].cerpRT;
      Object.keys(oT).forEach(function(k) {
        if (!matchL(k)) return;
        Object.keys(oT[k]).forEach(function(tx) { var v = oT[k][tx]; brutInd += v[3] || 0; remInd += v[4] || 0; });
      });
    }
    var brutDir = 0, remDir = 0, dirSrc = 'factures PDF', moisDir = {};
    Object.keys(achatsBase.mois).forEach(function(mk) {
      if (mk.slice(0, 4) !== an) return;
      var dF = achatsBase.mois[mk].dirFact || {};
      Object.keys(dF).forEach(function(nf) {
        var F = dF[nf];
        if (!matchL(F.f || '')) return;
        moisDir[mk] = 1;
        Object.keys(F.taux || {}).forEach(function(tx) { brutDir += F.taux[tx][0] || 0; remDir += (F.taux[tx][0] || 0) - (F.taux[tx][1] || 0); });
      });
    });
    if (brutDir < 0.01) {
      dirSrc = 'assiette des avoirs';
      Object.keys(labo.avoirsTrim || {}).forEach(function(tr) {
        if (tr.slice(0, 4) !== an) return;
        (labo.avoirsTrim[tr].lignes || []).forEach(function(l) { if (l.canal === 'Direct') { brutDir += l.ca; remDir += l.ca * l.taux / 100; } });
      });
    }
    var avoirs = 0, nbAv = 0;
    Object.keys(labo.avoirsTrim || {}).forEach(function(tr) {
      if (tr.slice(0, 4) !== an) return;
      nbAv++;
      (labo.avoirsTrim[tr].lignes || []).forEach(function(l) { avoirs += l.rist; });
    });
    var mens = (rapp && rapp.mensAn && rapp.mensAn[an]) || 0;
    var brut = brutInd + brutDir;
    if (brut < 0.01) return;
    var remFact = remInd + remDir;
    var numT = remFact + avoirs + mens;
    var taux = 100 * numT / brut;
    var ecart = numT - cible / 100 * brut;
    if (nbAv < 4) notes.push(an + ' : ' + nbAv + '/4 avoir(s) import\u00e9(s) \u2014 les manquants restent compt\u00e9s en mensualit\u00e9s (et peuvent glisser d\u2019ann\u00e9e) : importez-les pour un verdict d\u00e9finitif');
    if (dirSrc !== 'factures PDF') notes.push(an + ' : Direct estim\u00e9 par l\u2019assiette des avoirs (' + nbAv + ' trimestre(s)) \u2014 importez le ZIP des factures directes de l\u2019ann\u00e9e pour l\u2019exact');
    else {
      var attMois = dernier ? (dernier.slice(5) === '12' ? 12 : parseInt(dernier.slice(5), 10)) : 12;
      var nbMD = Object.keys(moisDir).length;
      if (nbMD < attMois) notes.push(an + ' : Direct incomplet (' + nbMD + '/' + attMois + ' mois de factures en base) \u2014 importez le ZIP des factures directes manquantes');
    }
    if (dernier && dernier.slice(5) !== '12') notes.push(an + ' : ann\u00e9e en cours \u2014 Indirect cumul\u00e9 \u00e0 fin ' + dernier);
    corps += '<tr><td style="padding:3px 6px;border-bottom:1px solid var(--border);font-weight:700">' + an + (dernier && dernier.slice(5) !== '12' ? ' <span style="font-weight:400;color:var(--text-ter)">(en cours)</span>' : '') + '</td>' +
      '<td style="' + tdB + '">' + brut.toFixed(2) + '</td>' +
      '<td style="' + tdB + '">' + remFact.toFixed(2) + '</td>' +
      '<td style="' + tdB + '">' + avoirs.toFixed(2) + ' <span style="color:var(--text-ter)">(' + nbAv + '/4)</span></td>' +
      '<td style="' + tdB + '">' + mens.toFixed(2) + '</td>' +
      '<td style="' + tdB + ';font-weight:700">' + numT.toFixed(2) + '</td>' +
      '<td style="' + tdB + ';font-weight:700;color:' + (taux >= cible ? 'var(--accent-text)' : 'var(--danger)') + '">' + taux.toFixed(2) + ' %</td>' +
      '<td style="' + tdB + ';color:' + (ecart >= 0 ? 'var(--accent-text)' : 'var(--danger)') + '">' + (ecart >= 0 ? '+' : '') + ecart.toFixed(2) + '</td></tr>';
  });
  if (!corps) return '';
  var html = '<details open style="margin:12px 0;border:1px solid var(--border);border-radius:var(--radius-sm);padding:2px 10px 8px 10px;background:var(--surface)">' +
    '<summary style="cursor:pointer;font-size:12.5px;font-weight:700;padding:6px 0;user-select:none">\ud83d\udcaf Remise globale constat\u00e9e par ann\u00e9e d\u2019achats \u2014 objectif ' +
    '<input type="text" value="' + cible + '" onchange="egRemiseCibleMaj(this)" onclick="event.preventDefault()" style="width:44px;font-size:11.5px;padding:2px 4px;border:1px solid var(--border);border-radius:var(--radius-sm);text-align:right" title="Taux global contractuel (%) \u2014 sauvegard\u00e9 sur la fiche labo"> %</summary>' +
    '<table style="width:100%;border-collapse:collapse;font-size:11px"><thead><tr>' +
    '<th style="text-align:left;padding:3px 6px;border-bottom:1px solid var(--border)">Ann\u00e9e</th>' +
    '<th style="' + tdB + '">Brut remis\u00e9</th><th style="' + tdB + '">Remises facture</th><th style="' + tdB + '">Avoirs</th>' +
    '<th style="' + tdB + '">Mensualit\u00e9s</th><th style="' + tdB + '">Total avantages</th><th style="' + tdB + '">Taux</th><th style="' + tdB + '">\u00c9cart \u20ac</th>' +
    '</tr></thead><tbody>' + corps + '</tbody></table>' +
    (notes.length ? '<p style="font-size:10.5px;color:#b45309;margin:4px 0 0 0">\u26a0 ' + notes.join('<br>\u26a0 ') + '</p>' : '') +
    '<p style="font-size:10.5px;color:var(--text-ter);margin:4px 0 0 0">Brut = Indirect CERP (cumul annuel par taux) + Direct \u00b7 Mensualit\u00e9s = cr\u00e9dits bancaires Okimia de l\u2019ann\u00e9e, nets des avoirs rapproch\u00e9s \u00b7 Avoirs rattach\u00e9s \u00e0 leur trimestre d\u2019ACHATS, quel que soit le mois de versement.</p></details>';
  return html;
}

// v8.57 \u2014 PARSEUR D'AVOIR ROBUSTE. Sur les avoirs 2024/2025, le montant de
// chaque ligne flotte verticalement : tant\u00f4t fusionn\u00e9 en fin de PREMI\u00c8RE ligne du
// bloc, tant\u00f4t sur la ligne autonome juste AVANT le bloc \u2014 l'ancien \u00ab premier
// n\u00e9gatif du bloc \u00bb perdait des lignes ET d\u00e9calait des montants d'un taux \u00e0
// l'autre. Attribution positionnelle stricte + contr\u00f4le \u03a3 lignes vs total du PDF :
// un avoir incoh\u00e9rent est REJET\u00c9, jamais devin\u00e9 (m\u00eame philosophie que les factures).
function egAvoirTrimParse(lignes) {
  var num = function(v) { return Math.abs(parseFloat(String(v).replace(/[\s\.]/g, '').replace(',', '.')) || 0); };
  var reMtAut = /^-\s?[\d\s\.]*\d,\d{1,2}$/;    // ligne = UN montant autonome
  var reMtFin = /-\s?[\d\s\.]*\d,\d{1,2}\s*$/;  // montant en FIN de ligne
  var rePied = /Ristournes conformes|Montant \(net de taxe\)|Net \u00e0 payer|Vos Coordonn/;
  var debuts = [];
  for (var i = 0; i < lignes.length; i++) if (lignes[i].indexOf('Ristourne additionnelle') === 0) debuts.push(i);
  if (!debuts.length) return { erreur: 'Aucun bloc \u00ab Ristourne additionnelle \u00bb lisible \u2014 est-ce bien un avoir trimestriel TEVA ?' };
  var parTrim = {}, nb = 0, tot = 0, illisibles = [];
  for (var k = 0; k < debuts.length; k++) {
    var s = debuts[k];
    var e = (k + 1 < debuts.length) ? debuts[k + 1] : lignes.length;
    if (k + 1 >= debuts.length) { // dernier bloc : s'arr\u00eater au pied de page
      for (var j = s + 1; j < lignes.length; j++) if (rePied.test(lignes[j])) { e = j; break; }
    }
    var b = lignes.slice(s, e).join('\n');
    var tx = b.match(/fix\u00e9 \u00e0 ([\d,\.]+)\s?%/);
    var ca = b.match(/r\u00e9f\u00e9rence de ([\d\s\.]+,\d{1,2}) euros/);
    var canal = b.match(/via le (Direct|Indirect)/);
    var per = b.match(/(\d{2})\/(\d{2})\/(\d{4}) au (\d{2})\/(\d{2})\/(\d{4})/);
    // Montant : 1) fusionn\u00e9 en fin de la PREMI\u00c8RE ligne du bloc \u00b7 2) ligne autonome
    // juste AVANT le bloc \u00b7 3) \u00e0 l'int\u00e9rieur du bloc, SAUF la derni\u00e8re ligne si
    // elle est un montant autonome coll\u00e9 au bloc suivant (il lui appartient).
    var mt = lignes[s].match(reMtFin);
    if (!mt && s > 0 && reMtAut.test(lignes[s - 1])) mt = [lignes[s - 1]];
    if (!mt) {
      for (var m2 = s + 1; m2 < e; m2++) {
        if (m2 === e - 1 && k + 1 < debuts.length && reMtAut.test(lignes[m2])) break; // au bloc suivant
        var c2 = lignes[m2].match(reMtFin);
        if (c2) { mt = c2; break; }
      }
    }
    if (!(tx && ca && canal && per && mt)) { illisibles.push('bloc ' + (k + 1)); continue; }
    var trim = per[6] + '-T' + Math.ceil(parseInt(per[5], 10) / 3);
    if (!parTrim[trim]) parTrim[trim] = [];
    var l = { canal: canal[1], taux: parseFloat(tx[1].replace(',', '.')), ca: num(ca[1]), rist: num(mt[0]) };
    parTrim[trim].push(l);
    nb++; tot = Math.round((tot + l.rist) * 100) / 100;
  }
  // Contr\u00f4le : \u03a3 lignes vs \u00ab Montant (net de taxe) -X EUR \u00bb du PDF
  var totPdf = null;
  var mTot = lignes.join('\n').match(/-\s?([\d\s\.]*\d,\d{1,2})\s*EUR/);
  if (mTot) totPdf = num(mTot[1]);
  var ok = (totPdf === null) ? 'sans-total' : (Math.abs(tot - totPdf) <= 0.02);
  return { parTrim: parTrim, nb: nb, tot: tot, totPdf: totPdf, ok: ok, illisibles: illisibles };
}

function egSuiviAvoirTrimImport(input) {
  var file = input.files && input.files[0];
  if (!file) return;
  var labo = condLabos[condLaboActif];
  if (!labo) { input.value = ''; return; }
  var reader = new FileReader();
  reader.onload = function(e) {
    pdfjsLib.getDocument({ data: new Uint8Array(e.target.result) }).promise.then(async function(doc) {
      var pages = await achatsPdfLignes(doc);
      var r = egAvoirTrimParse([].concat.apply([], pages));
      if (r.erreur) { alert(r.erreur); input.value = ''; return; }
      if (r.illisibles.length) { alert('\u26a0 Avoir NON import\u00e9 : ' + r.illisibles.length + ' bloc(s) illisible(s) (' + r.illisibles.join(', ') + ') \u2014 rien n\u2019est devin\u00e9. Envoyez le PDF \u00e0 Claude pour analyse.'); input.value = ''; return; }
      if (r.ok === false) { alert('\u26a0 Avoir NON import\u00e9 : \u03a3 lignes ' + r.tot.toFixed(2) + ' \u20ac \u2260 total du PDF ' + r.totPdf.toFixed(2) + ' \u20ac \u2014 attribution des montants incertaine, rien n\u2019est devin\u00e9.'); input.value = ''; return; }
      if (!labo.avoirsTrim) labo.avoirsTrim = {};
      Object.keys(r.parTrim).forEach(function(t) {
        labo.avoirsTrim[t] = { lignes: r.parTrim[t], fichier: file.name, importeLe: new Date().toISOString().slice(0, 10) };
      });
      condSauvegarder();
      egRemonteeRender();
      alert('\u2713 Avoir trimestriel import\u00e9 : ' + r.nb + ' ligne(s) \u00b7 ' + Object.keys(r.parTrim).join(', ') + '\n\u03a3 ristournes : ' + r.tot.toFixed(2) + ' \u20ac' + (r.ok === 'sans-total' ? '\n\u26a0 total de contr\u00f4le introuvable dans le PDF (import\u00e9 quand m\u00eame)' : ' \u2014 \u2713 \u00e9gal au total du PDF'));
      input.value = '';
    }).catch(function(err) { alert('PDF illisible : ' + err.message); input.value = ''; });
  };
  reader.readAsArrayBuffer(file);
}

function egSuiviAvoirSuppr(trim) {
  var labo = condLabos[condLaboActif];
  if (!labo || !labo.avoirsTrim || !labo.avoirsTrim[trim]) return;
  if (!confirm('Supprimer d\u00e9finitivement l\u2019avoir ' + trim + ' et son contr\u00f4le m\u00e9moris\u00e9 de la fiche ' + (labo.nom || '') + ' ?\n(Seul moyen de les retirer \u2014 rien ne s\u2019efface jamais automatiquement.)')) return;
  delete labo.avoirsTrim[trim];
  condSauvegarder();
  egRemonteeRender();
}

// v8.50 \u2014 FACTURES DIRECTES TEVA : ventilation par taux de remise CGV.
// v8.54 \u2014 ASSIETTE = REMBOURSABLES UNIQUEMENT : TVA par ligne + libell\u00e9 captur\u00e9s
// (calibr\u00e9 sur les 4 factures de janvier 9204179460/9204184261/62/63) ; hors
// assiette trac\u00e9 par motif : reprise 0 % \u00b7 TVA \u2260 2,1 % \u00b7 liste \ud83d\udeab (fiche labo).
// Parseur calibr\u00e9 sur 3 factures r\u00e9elles (9204904333, 9204857630, 9204850942 \u2014
// 5 lignes, taux 2,5/30/80 %, totaux valid\u00e9s au centime). brut = qt\u00e9 \u00d7 PU brut,
// net = Montant HT factur\u00e9. Rang\u00e9 au mois de la DATE de facture (pas de d\u00e9calage
// M-1 ici : l'avoir trimestriel r\u00e9f\u00e9rence les achats du trimestre civil).
// ── Parseur facture directe TEVA — fonction destinée à l'app (ES5, PDF.js lignes) ──
// Entrée : tableau de lignes (sortie achatsPdfLignes aplatie). Sortie : objet facture.
function egFactureDirParse(lignes, nomFichier, listeExcl) {
  var texte = lignes.join('\n');
  listeExcl = listeExcl || []; // v8.54 : termes (MAJUSCULES) des list\u00e9s non rembours\u00e9s \u00e0 TVA 2,1 %
  if (!/Teva Sant\u00e9/i.test(texte)) return { erreur: 'Pas une facture Teva Sant\u00e9' };
  var num = function(v) { return parseFloat(String(v).replace(/[\s.]/g, '').replace(',', '.')) || 0; };
  var mNum = texte.match(/Facture\s*:\s*(\d{6,})/);
  var mDate = texte.match(/Date Document\s*:\s*(\d{2})\.(\d{2})\.(\d{4})/);
  // v8.51 : un avoir (reprise p\u00e9rim\u00e9s, retour\u2026) n'est PAS un achat \u2014 \u00e9cart\u00e9 proprement
  if (!mNum && /Avoir/i.test(texte)) return { erreur: 'Avoir (reprise/retour) \u2014 pas une facture d\u2019achat, exclu du contr\u00f4le' };
  if (!mNum || !mDate) return { erreur: 'Num\u00e9ro ou date de facture introuvable (' + (nomFichier || '') + ')' };
  var out = { numero: mNum[1], date: mDate[3] + '-' + mDate[2] + '-' + mDate[1], mois: mDate[3] + '-' + mDate[2], lignes: [], taux: {}, horsAnalyse: [0, 0],
    // v8.54 : hors assiette ventil\u00e9 par motif \u2014 [brut, net, nb lignes]
    hors: { reprise: [0, 0, 0], tva: [0, 0, 0], liste: [0, 0, 0] } };
  var eanCourant = '', libCourant = '';
  // v8.54 : la TVA de la ligne (2e %) est captur\u00e9e \u2014 groupes : qt\u00e9, PU brut, remise %, PU net, TVA %, montant HT
  var reLigne = /^(\d+)\s+(\d[\d\s]*,\d{2})\s+([\d,.]+)\s*%\s+(\d[\d\s]*,\d{2})\s+([\d.,]+)\s*%\s+(\d[\d\s]*,\d{2})$/;
  // Totaux de pied : candidats « qté brut net tva ttc » validés par net+tva≈ttc
  var reTotal = /(?:^|\s)(\d+)\s+(\d[\d\s]*,\d{2})\s+(\d[\d\s]*,\d{2})\s+(\d[\d\s]*,\d{2})\s+(\d[\d\s]*,\d{2})(?:$|\s)/;
  var totBrut = null, totNet = null;
  for (var i = 0; i < lignes.length; i++) {
    var L = lignes[i];
    var mE = L.match(/^(\d{13})$/);
    if (mE) { eanCourant = mE[1]; libCourant = (i > 0 ? String(lignes[i - 1]) : '').trim(); continue; } // v8.54 : libell\u00e9 = ligne pr\u00e9c\u00e9dant l'EAN
    var m = L.match(reLigne);
    if (m) {
      var qte = parseInt(m[1], 10), puB = num(m[2]), tx = parseFloat(m[3].replace(',', '.')), puN = num(m[4]), ht = num(m[6]);
      // v8.54 : TVA de la ligne \u2014 parseFloat direct (\u00ab 2.10 % \u00bb avec un POINT :
      // jamais num(), qui traiterait le point comme s\u00e9parateur de milliers \u2192 210).
      var tvaL = parseFloat(String(m[5]).replace(',', '.'));
      var brut = Math.round(qte * puB * 100) / 100;
      var libU = libCourant.toUpperCase();
      // v8.54 : motif hors assiette \u2014 reprise 0 % (v8.51) > TVA \u2260 2,1 % > liste \ud83d\udeab.
      // Une TVA illisible (NaN) sort aussi par le motif \u00ab tva \u00bb : rien n'entre en assiette sans TVA 2,1 % v\u00e9rifi\u00e9e.
      var motif = null;
      if (tx === 0) motif = 'reprise';
      else if (!(Math.abs(tvaL - 2.1) < 0.005)) motif = 'tva';
      else if (listeExcl.some(function(t) { return t && libU.indexOf(t) >= 0; })) motif = 'liste';
      out.lignes.push({ ean: eanCourant, lib: libCourant, qte: qte, puBrut: puB, taux: tx, puNet: puN, tva: tvaL, htNet: ht, htBrut: brut, motif: motif });
      if (motif) {
        // Compt\u00e9e dans le contr\u00f4le interne au centime (la ligne est sur la facture),
        // mais EXCLUE de l'assiette par taux \u2014 trac\u00e9e par motif, rien en silence.
        out.hors[motif][0] = Math.round((out.hors[motif][0] + brut) * 100) / 100;
        out.hors[motif][1] = Math.round((out.hors[motif][1] + ht) * 100) / 100;
        out.hors[motif][2]++;
        out.horsAnalyse[0] = Math.round((out.horsAnalyse[0] + brut) * 100) / 100;
        out.horsAnalyse[1] = Math.round((out.horsAnalyse[1] + ht) * 100) / 100;
      } else {
        var k = String(tx);
        if (!out.taux[k]) out.taux[k] = [0, 0]; // [brut, net]
        out.taux[k][0] = Math.round((out.taux[k][0] + brut) * 100) / 100;
        out.taux[k][1] = Math.round((out.taux[k][1] + ht) * 100) / 100;
      }
      eanCourant = ''; libCourant = '';
      continue;
    }
    var mT = L.match(reTotal);
    if (mT) {
      var cN = num(mT[3]), cT = num(mT[4]), cTTC = num(mT[5]);
      if (Math.abs(cN + cT - cTTC) <= 0.05) { totBrut = num(mT[2]); totNet = cN; } // le dernier candidat sain = Total
    }
  }
  if (!out.lignes.length) return { erreur: 'Aucune ligne produit reconnue (' + (nomFichier || '') + ')' };
  // Contrôle interne : Σ lignes vs totaux de pied de facture (tolérance 0,02 €/ligne)
  var sB = 0, sN = 0;
  out.lignes.forEach(function(l) { sB += l.htBrut; sN += l.htNet; });
  sB = Math.round(sB * 100) / 100; sN = Math.round(sN * 100) / 100;
  out.totBrut = totBrut; out.totNet = totNet;
  var tol = Math.max(0.02, out.lignes.length * 0.02);
  out.ok = (totBrut === null) ? 'sans-total' : (Math.abs(sB - totBrut) <= tol && Math.abs(sN - totNet) <= tol);
  out.sommeBrut = sB; out.sommeNet = sN;
  return out;
}

// v8.54 \u2014 Liste \ud83d\udeab Hors assiette : list\u00e9s NON REMBOURS\u00c9S factur\u00e9s \u00e0 TVA 2,1 %
// (ex. Tadalafil, Sildenafil). Liste COMPL\u00c8TE (pas additive), stock\u00e9e sur la fiche
// labo, appliqu\u00e9e \u00e0 l'IMPORT uniquement \u2014 modification \u21d2 r\u00e9importer le ZIP (idempotent).
var EG_HORS_ASSIETTE_DEFAUT = 'TADALAFIL, SILDENAFIL';
function egHorsAssietteListe(labo) {
  var s = (labo && typeof labo.horsAssiette === 'string') ? labo.horsAssiette : EG_HORS_ASSIETTE_DEFAUT;
  return s.split(',').map(function(t) { return t.trim().toUpperCase(); }).filter(function(t) { return t.length > 0; });
}
function egSuiviHorsAssietteMaj(input) {
  var labo = condLabos[condLaboActif];
  if (!labo) return;
  labo.horsAssiette = input.value;
  try { condSauvegarder(); } catch (e) {}
  var st = document.getElementById('eg-hors-assiette-note');
  if (st) { st.textContent = '\u2713 sauvegard\u00e9 \u2014 r\u00e9importez le ZIP des factures (la liste ne s\u2019applique qu\u2019\u00e0 l\u2019import)'; st.style.color = '#b45309'; }
}

function egSuiviFacturesDirImport(input) {
  var files = Array.from(input.files || []);
  if (!files.length) return;
  var finir = function() { input.value = ''; };
  var pdfs = []; // { nom, buf }
  var collecte = files.map(function(f) {
    return new Promise(function(res) {
      var r = new FileReader();
      r.onload = function(e) {
        if (/\.zip$/i.test(f.name)) {
          var suite = function() {
            JSZip.loadAsync(e.target.result).then(function(zip) {
              var proms = [];
              zip.forEach(function(chemin, entry) {
                if (!entry.dir && /\.pdf$/i.test(chemin)) proms.push(entry.async('arraybuffer').then(function(b) { pdfs.push({ nom: chemin.split('/').pop(), buf: b }); }));
              });
              Promise.all(proms).then(res);
            }).catch(function(err) { alert('ZIP illisible : ' + err.message); res(); });
          };
          if (typeof JSZip === 'undefined') {
            var s = document.createElement('script');
            s.src = 'https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js';
            s.onload = suite;
            s.onerror = function() { alert('Module ZIP indisponible \u2014 d\u00e9posez directement les PDF.'); res(); };
            document.head.appendChild(s);
          } else suite();
        } else { pdfs.push({ nom: f.name, buf: e.target.result }); res(); }
      };
      r.readAsArrayBuffer(f);
    });
  });
  Promise.all(collecte).then(async function() {
    if (!pdfs.length) { alert('Aucun PDF trouv\u00e9.'); finir(); return; }
    if (!achatsBase) await achatsChargerBase();
    // v8.54 : liste \ud83d\udeab de la fiche labo, appliqu\u00e9e \u00e0 CET import (r\u00e9import = remplacement idempotent)
    var laboFiche = condLabos[condLaboActif] || {};
    var listeExcl = egHorsAssietteListe(laboFiche);
    var okN = 0, totNet = 0, cumulTaux = {}, moisVus = {}, rejets = [], sansTotal = [], entHors = [],
        cumHors = { reprise: [0, 0, 0], tva: [0, 0, 0], liste: [0, 0, 0] };
    for (var i = 0; i < pdfs.length; i++) {
      var p = pdfs[i];
      try {
        var doc = await pdfjsLib.getDocument({ data: new Uint8Array(p.buf) }).promise;
        var pages = await achatsPdfLignes(doc);
        var r2 = egFactureDirParse([].concat.apply([], pages), p.nom, listeExcl);
        if (r2.erreur) { rejets.push(p.nom + ' : ' + r2.erreur); continue; }
        if (r2.ok === false) { rejets.push(p.nom + ' : \u03a3 lignes ' + r2.sommeNet.toFixed(2) + ' \u2260 total facture ' + (r2.totNet === null ? '?' : r2.totNet.toFixed(2)) + ' \u20ac \u2014 NON import\u00e9e (\u00e0 v\u00e9rifier)'); continue; }
        if (r2.ok === 'sans-total') sansTotal.push(r2.numero);
        // v8.54 : cumul des exclusions VENTIL\u00c9 par motif \u2014 rien d'\u00e9cart\u00e9 en silence
        ['reprise', 'tva', 'liste'].forEach(function(mh) {
          if (r2.hors[mh][2]) {
            cumHors[mh][0] = Math.round((cumHors[mh][0] + r2.hors[mh][0]) * 100) / 100;
            cumHors[mh][1] = Math.round((cumHors[mh][1] + r2.hors[mh][1]) * 100) / 100;
            cumHors[mh][2] += r2.hors[mh][2];
          }
        });
        if (!Object.keys(r2.taux).length) {
          // v8.52 : purger une \u00e9ventuelle entr\u00e9e v8.50 de cette facture (r\u00e9import nettoyant)
          var oV = achatsBase.mois[r2.mois];
          if (oV && oV.dirFact && oV.dirFact[r2.numero]) { delete oV.dirFact[r2.numero]; okN++; moisVus[r2.mois] = 1; }
          entHors.push(r2.numero + ' (' + r2.lignes.length + ' ligne(s), ' + r2.sommeNet.toFixed(2) + ' \u20ac net)');
          continue;
        }
        var mo = r2.mois;
        if (!achatsBase.mois[mo]) achatsBase.mois[mo] = {};
        var o = achatsBase.mois[mo];
        if (!o.dirFact) o.dirFact = {};
        o.dirFact[r2.numero] = { f: 'TEVA', d: r2.date, n: r2.lignes.length, taux: r2.taux }; // r\u00e9import du m\u00eame n\u00b0 = remplacement (idempotent)
        moisVus[mo] = 1; okN++;
        Object.keys(r2.taux).forEach(function(tx) {
          if (!cumulTaux[tx]) cumulTaux[tx] = [0, 0];
          cumulTaux[tx][0] = Math.round((cumulTaux[tx][0] + r2.taux[tx][0]) * 100) / 100;
          cumulTaux[tx][1] = Math.round((cumulTaux[tx][1] + r2.taux[tx][1]) * 100) / 100;
          totNet += r2.taux[tx][1];
        });
      } catch (err) { rejets.push(p.nom + ' : ' + err.message); }
    }
    if (okN) { try { achatsSauverGitHub(); } catch (eS) {} }
    egRemonteeRender();
    var lignesTx = Object.keys(cumulTaux).sort(function(a, b) { return parseFloat(a) - parseFloat(b); })
      .map(function(tx) { return '  \u2022 ' + tx + ' % : ' + cumulTaux[tx][0].toFixed(2) + ' \u20ac brut / ' + cumulTaux[tx][1].toFixed(2) + ' \u20ac net'; });
    var nbHors = cumHors.reprise[2] + cumHors.tva[2] + cumHors.liste[2];
    alert('\u2713 ' + okN + ' facture(s) directe(s) TEVA import\u00e9e(s) (' + Object.keys(moisVus).sort().join(', ') + ') \u2014 assiette ' + totNet.toFixed(2) + ' \u20ac net HT\n' +
      (lignesTx.length ? 'Ventilation par taux (assiette remboursable) :\n' + lignesTx.join('\n') + '\n' : '') +
      (nbHors ? '\u24d8 ' + nbHors + ' ligne(s) \u00e9cart\u00e9e(s) de l\u2019assiette :\n' +
        (cumHors.reprise[2] ? '  \u2022 reprise 0 % (p\u00e9rim\u00e9s / hors remise) : ' + cumHors.reprise[2] + ' ligne(s) \u2014 ' + cumHors.reprise[0].toFixed(2) + ' \u20ac brut / ' + cumHors.reprise[1].toFixed(2) + ' \u20ac net\n' : '') +
        (cumHors.tva[2] ? '  \u2022 TVA \u2260 2,1 % (OTC / para / non rembours\u00e9s) : ' + cumHors.tva[2] + ' ligne(s) \u2014 ' + cumHors.tva[0].toFixed(2) + ' \u20ac brut / ' + cumHors.tva[1].toFixed(2) + ' \u20ac net\n' : '') +
        (cumHors.liste[2] ? '  \u2022 liste \ud83d\udeab (' + ((typeof laboFiche.horsAssiette === 'string') ? laboFiche.horsAssiette : EG_HORS_ASSIETTE_DEFAUT) + ') : ' + cumHors.liste[2] + ' ligne(s) \u2014 ' + cumHors.liste[0].toFixed(2) + ' \u20ac brut / ' + cumHors.liste[1].toFixed(2) + ' \u20ac net\n' : '') : '') +
      (entHors.length ? '\u24d8 Facture(s) enti\u00e8rement hors assiette (contr\u00f4l\u00e9e(s) au centime, rien \u00e0 compter) : ' + entHors.join(' \u00b7 ') + '\n' : '') +
      (sansTotal.length ? '\u26a0 Sans total de contr\u00f4le (import\u00e9es quand m\u00eame) : ' + sansTotal.join(', ') + '\n' : '') +
      (rejets.length ? '\u26a0 Rejet\u00e9es :\n' + rejets.join('\n') : ''));
    finir();
  });
}

function egSuiviTrimAide() {
  var old = document.getElementById('eg-trim-aide');
  if (old) { old.remove(); return; }
  var m = document.createElement('div');
  m.id = 'eg-trim-aide';
  m.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.5);z-index:9994;display:flex;align-items:center;justify-content:center;padding:20px;box-sizing:border-box';
  m.innerHTML = '<div style="background:var(--surface,#fff);border-radius:8px;max-width:620px;width:100%;max-height:82vh;overflow:auto;padding:18px 20px;font-size:13px;line-height:1.55;color:var(--text,#222)">'
    + '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px"><strong>\u2753 Contr\u00f4le trimestriel \u2014 le workflow</strong>'
    + '<button type="button" onclick="document.getElementById(\'eg-trim-aide\').remove()" style="background:none;border:none;cursor:pointer;font-size:14px;color:var(--text-ter,#888)">\u2715</button></div>'
    + '<p style="margin:6px 0"><strong>1. \ud83d\udcc4 Avoir trimestriel (PDF)</strong> : d\u00e9posez le PDF \u00ab Ristourne additionnelle \u00bb \u2014 une ligne par taux \u00d7 canal (Direct/Indirect), avec CA de r\u00e9f\u00e9rence et ristourne. Le \u00ab Total constat\u00e9 \u00bb doit remonter \u00e0 39 % (23,5 % sur le palier 2,5 %). Chaque import est contr\u00f4l\u00e9 : \u03a3 des lignes = total du PDF, sinon l\u2019avoir est rejet\u00e9, jamais devin\u00e9 (v8.57). Les avoirs des ann\u00e9es pr\u00e9c\u00e9dentes s\u2019importent \u00e0 l\u2019identique \u2014 le trimestre est lu dans le PDF.</p>'
    + '<p style="margin:6px 0"><strong>2. Assiette Indirect</strong> : aliment\u00e9e par les r\u00e9caps CERP par taux (v8.39+) et le Suivi Alliance, import\u00e9s dans l\u2019onglet \ud83d\udce5 Achats & Imports.</p>'
    + '<p style="margin:6px 0"><strong>3. \ud83e\uddfe Factures directes (PDF/ZIP)</strong> : d\u00e9posez les PDF de factures TEVA (s\u00e9lection multiple) ou le ZIP Digipharmacie qui les contient. Chaque facture est ventil\u00e9e ligne \u00e0 ligne par taux de remise (brut = qt\u00e9 \u00d7 PU brut) et contr\u00f4l\u00e9e au centime contre son pied de facture \u2014 une facture incoh\u00e9rente est rejet\u00e9e, jamais devin\u00e9e. R\u00e9importer une facture d\u00e9j\u00e0 connue la remplace (pas de double comptage). La base est sauvegard\u00e9e sur GitHub automatiquement.</p>'
    + '<p style="margin:6px 0"><strong>\ud83c\udfe6 Rapprochement bancaire</strong> : d\u00e9posez \u00e0 chaque fois l\u2019export GLOBAL Okimia (synth\u00e8se XLSX) \u2014 il remplace int\u00e9gralement le pr\u00e9c\u00e9dent. Chaque avoir import\u00e9 est recherch\u00e9 au centime dans les cr\u00e9dits TEVA des 4 mois suivant son trimestre (seul ou fondu avec une mensualit\u00e9 identifi\u00e9e). \u26a0 rouge = avoir d\u00e9clar\u00e9 jamais vers\u00e9, \u00e0 r\u00e9clamer.</p>'
    + '<p style="margin:6px 0"><strong>\ud83d\udcaf Remise globale</strong> : par ann\u00e9e d\u2019achats, (remises facture + avoirs + mensualit\u00e9s) / brut remis\u00e9, compar\u00e9 \u00e0 l\u2019objectif contractuel (\u00e9ditable, d\u00e9faut 51 %). Les avoirs non import\u00e9s restent compt\u00e9s en mensualit\u00e9s \u2014 le verdict s\u2019affine tout seul \u00e0 chaque import.</p>'
    + '<p style="margin:6px 0"><strong>\ud83d\udcc5 Par ann\u00e9e</strong> : contr\u00f4les et pr\u00e9visionnels sont regroup\u00e9s par ann\u00e9e en menus d\u00e9pliants \u2014 l\u2019ann\u00e9e la plus r\u00e9cente est ouverte, cliquez un bandeau d\u2019ann\u00e9e pour le d\u00e9plier ou le replier. Le bandeau r\u00e9sume chaque trimestre : \u2713 avoir contr\u00f4l\u00e9 (\u03a3 ristournes) ou \ud83d\udcd0 pr\u00e9visionnel (attendu).</p>'
    + '<p style="margin:6px 0"><strong>\ud83d\udcd0 Pr\u00e9visionnel</strong> : les trimestres qui ont des achats en base mais pas encore d\u2019avoir affichent l\u2019assiette par taux et la ristourne attendue, calcul\u00e9e avec les taux totaux r\u00e9ellement constat\u00e9s sur vos derniers avoirs \u2014 le chiffre \u00e0 comparer \u00e0 l\u2019avoir d\u00e8s r\u00e9ception, et votre attendu de tr\u00e9sorerie.</p>'
    + '<p style="margin:6px 0"><strong>Lecture du tableau</strong> : \u00ab Achats base \u00bb en face de chaque ligne de l\u2019avoir = votre assiette (CA brut) pour ce taux et ce canal ; un \u00e9cart rouge (au-del\u00e0 de 2 %) signale une assiette incompl\u00e8te c\u00f4t\u00e9 laboratoire \u2014 pr\u00e9sentez les montants totaux, jamais la m\u00e9thode.</p>'
    + '<p style="margin:6px 0;color:var(--text-sec,#555)">Notes : les factures sont rang\u00e9es au mois de leur date (l\u2019avoir r\u00e9f\u00e9rence le trimestre civil des achats). L\u2019assiette Direct = <strong>rembours\u00e9s uniquement</strong> (v8.54). Sortent automatiquement, avec motif d\u00e9taill\u00e9 au r\u00e9capitulatif d\u2019import \u2014 rien n\u2019est \u00e9cart\u00e9 en silence : les lignes \u00e0 <strong>0 %</strong> (reprises de p\u00e9rim\u00e9s, hors remise), les lignes \u00e0 <strong>TVA \u2260 2,1 %</strong> (non rembours\u00e9s \u00e0 10 %, OTC/para \u00e0 20 % ou 5,5 %) et les libell\u00e9s de la liste <strong>\ud83d\udeab Hors assiette</strong> (list\u00e9s non rembours\u00e9s factur\u00e9s \u00e0 2,1 %, ex. Tadalafil \u2014 liste compl\u00e8te \u00e9ditable dans le bandeau, appliqu\u00e9e \u00e0 l\u2019import : toute modification \u21d2 r\u00e9importer le ZIP, idempotent). Les documents <strong>Avoir</strong> sont \u00e9cart\u00e9s. Le contr\u00f4le interne au centime de chaque facture porte, lui, sur TOUTES les lignes. Les contr\u00f4les m\u00e9moris\u00e9s (v8.41) restent fig\u00e9s, jamais recalcul\u00e9s r\u00e9troactivement.</p>'
    + '</div>';
  m.addEventListener('click', function(e){ if (e.target === m) m.remove(); });
  document.body.appendChild(m);
}

// Achats de la base par taux pour un trimestre (indirect = CERP r\u00e9cap + Alliance)
function egSuiviAchatsTauxTrim(trimKey, cfg) {
  var out = { taux: {}, direct: 0, indTotal: 0, moisSansDetail: [], mois: [], tauxDir: {}, directF: 0 };
  if (!achatsBase) return out;
  var an = parseInt(trimKey.slice(0, 4), 10), T = parseInt(trimKey.slice(6), 10);
  var moisT = [1, 2, 3].map(function(i) { return an + '-' + ('0' + ((T - 1) * 3 + i)).slice(-2); });
  out.mois = moisT;
  var matchL = function(k) { return cfg.tokens.some(function(tk) { return String(k).toUpperCase().indexOf(tk) >= 0; }); };
  moisT.forEach(function(m) {
    var o = achatsBase.mois[m] || {};
    var vuDetail = false;
    Object.keys(o.cerpRT || {}).forEach(function(k) {
      if (!matchL(k)) return;
      vuDetail = true;
      Object.keys(o.cerpRT[k]).forEach(function(tx) {
        var v = o.cerpRT[k][tx];
        if (!out.taux[tx]) out.taux[tx] = { ind: 0, rem: 0 };
        out.taux[tx].ind += v[0] || 0;
        out.taux[tx].rem += v[1] || 0;
      });
    });
    Object.keys(o.allianceT || {}).forEach(function(k) {
      if (!matchL(k)) return;
      Object.keys(o.allianceT[k]).forEach(function(tx) {
        var v = o.allianceT[k][tx];
        if (!(v.bm > 0)) return;
        if (!out.taux[tx]) out.taux[tx] = { ind: 0, rem: 0 };
        out.taux[tx].ind += v.bm;
        out.taux[tx].rem += v.rm;
      });
    });
    if ((o.cerpR && Object.keys(o.cerpR).some(matchL)) && !vuDetail) out.moisSansDetail.push(m);
    // v8.40 : total indirect PAR LABO (toujours disponible, m\u00eame sans d\u00e9tail par taux)
    Object.keys(o.cerpR || {}).forEach(function(k) { if (matchL(k)) out.indTotal += (o.cerpR[k][0] || 0); });
    Object.keys(o.alliance || {}).forEach(function(k) { if (matchL(k)) out.indTotal += (o.alliance[k].bm || 0); });
    // v8.50 : factures directes PDF \u2192 assiette Direct par taux (brut/net)
    Object.keys(o.dirFact || {}).forEach(function(nf) {
      var F = o.dirFact[nf];
      if (!matchL(F.f || '')) return;
      Object.keys(F.taux || {}).forEach(function(tx) {
        if (parseFloat(tx) === 0) return; // v8.52 : lignes 0 % stock\u00e9es par la v8.50 \u2014 hors assiette
        if (!out.tauxDir[tx]) out.tauxDir[tx] = { brut: 0, net: 0 };
        out.tauxDir[tx].brut += F.taux[tx][0] || 0;
        out.tauxDir[tx].net += F.taux[tx][1] || 0;
        out.directF += F.taux[tx][1] || 0;
      });
    });
    (o.digi || []).forEach(function(d) {
      if (d.t !== 'F' || (d.ht || 0) < 0) return;
      if (!matchL(d.f) && !matchL(d.fi)) return;
      out.direct += (d.b21 || d.ht || 0);
    });
  });
  return out;
}

// Tableau de contr\u00f4le trimestriel (rendu sous le tableau mensuel des labos non-EG)
function egSuiviTrimHTML(cfg) {
  var labo = condLabos[condLaboActif] || {};
  var trims = Object.keys(labo.avoirsTrim || {}).sort().reverse();
  // v8.54 : liste \ud83d\udeab affich\u00e9e/\u00e9ditable \u2014 \u00e9chapp\u00e9e pour l'attribut value
  var horsAss = (typeof labo.horsAssiette === 'string') ? labo.horsAssiette : EG_HORS_ASSIETTE_DEFAUT;
  var horsAssEsc = String(horsAss).replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/</g, '&lt;');
  var html = '<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin:16px 0 6px 0">' +
    '<span style="font-size:12px;font-weight:700">\ud83e\uddfe Contr\u00f4le trimestriel (avoirs ' + (labo.nom || '') + ')</span>' +
    '<label style="font-size:11px;padding:4px 10px;background:#0f6e56;color:#fff;border-radius:var(--radius-sm);cursor:pointer;font-weight:600">\ud83d\udcc4 Avoir trimestriel (PDF)<input type="file" accept=".pdf" style="display:none" onchange="egSuiviAvoirTrimImport(this)"></label>' +
    '<label style="font-size:11px;padding:4px 10px;background:#7c2d92;color:#fff;border-radius:var(--radius-sm);cursor:pointer;font-weight:600" title="Factures directes TEVA : PDF (s\u00e9lection multiple) ou ZIP Digipharmacie \u2192 ventilation par taux de remise, contr\u00f4l\u00e9e au centime">\ud83e\uddfe Factures directes (PDF/ZIP)<input type="file" accept=".pdf,.zip" multiple style="display:none" onchange="egSuiviFacturesDirImport(this)"></label>' +
    '<button type="button" onclick="egSuiviTrimAide()" style="font-size:11px;padding:4px 8px;background:#fff;border:1px solid var(--border);border-radius:var(--radius-sm);cursor:pointer;font-weight:600">\u2753 Workflow</button>' +
    '<label style="font-size:11px;display:inline-flex;align-items:center;gap:4px;font-weight:600" title="List\u00e9s NON REMBOURS\u00c9S factur\u00e9s \u00e0 TVA 2,1 % (ex. Tadalafil) : leurs lignes sortent de l\u2019assiette de ristourne (motif \u00ab liste \u00bb). Liste COMPL\u00c8TE, s\u00e9par\u00e9e par des virgules \u2014 PAS additive. Appliqu\u00e9e \u00e0 l\u2019IMPORT uniquement : toute modification \u21d2 r\u00e9importer le ZIP des factures (idempotent).">\ud83d\udeab Hors assiette' +
    '<input type="text" value="' + horsAssEsc + '" onchange="egSuiviHorsAssietteMaj(this)" style="font-size:11px;padding:3px 6px;border:1px solid var(--border);border-radius:var(--radius-sm);width:190px"></label>' +
    '<span id="eg-hors-assiette-note" style="font-size:10px"></span>' +
    '<label style="font-size:11px;padding:4px 10px;background:#1d4ed8;color:#fff;border-radius:var(--radius-sm);cursor:pointer;font-weight:600" title="Export GLOBAL Okimia (synth\u00e8se XLSX) \u2014 chaque d\u00e9p\u00f4t REMPLACE int\u00e9gralement les donn\u00e9es bancaires pr\u00e9c\u00e9dentes, puis sauvegarde sur GitHub.">\ud83c\udfe6 Export Okimia (XLSX)<input type="file" accept=".xlsx" style="display:none" onchange="egOkimiaImport(this)"></label>' +
    '<span style="font-size:10.5px;color:var(--text-ter)">Assiette contr\u00f4l\u00e9e contre la base \ud83d\udce5 \u2014 Indirect : r\u00e9caps CERP + Alliance par taux \u00b7 Direct : factures directes PDF, rembours\u00e9s TVA 2,1 % uniquement (v8.54)</span>' +
    '</div>';
  if (!trims.length) html += '<p style="font-size:11.5px;color:var(--text-ter)">Aucun avoir import\u00e9 \u2014 d\u00e9posez le PDF \u00ab Ristourne additionnelle \u00bb du trimestre.</p>';
  var td = 'padding:3px 6px;border-bottom:1px solid var(--border);text-align:right;font-family:monospace;font-size:11px';
  // v8.58 : chaque section (contr\u00f4le ou pr\u00e9visionnel) est rang\u00e9e dans son ANN\u00c9E,
  // rendue en menu d\u00e9pliant <details> \u2014 l'ann\u00e9e la plus r\u00e9cente est ouverte.
  var secAnnees = {};
  var trimAjSec = function(an, lib, frag) {
    if (!secAnnees[an]) secAnnees[an] = { html: '', libs: [] };
    secAnnees[an].libs.push(lib);
    secAnnees[an].html += frag;
  };
  trims.forEach(function(trim) {
    var sec = '';
    var av = labo.avoirsTrim[trim];
    var base = egSuiviAchatsTauxTrim(trim, cfg);
    var caD = 0, caI = 0, rist = 0;
    av.lignes.forEach(function(l) { rist += l.rist; if (l.canal === 'Direct') caD += l.ca; else caI += l.ca; });
    var baseInd = 0;
    Object.keys(base.taux).forEach(function(tx) { baseInd += base.taux[tx].ind; });
    var MOIS_N = ['', 'janvier', 'f\u00e9vrier', 'mars', 'avril', 'mai', 'juin', 'juillet', 'ao\u00fbt', 'septembre', 'octobre', 'novembre', 'd\u00e9cembre'];
    var T2 = parseInt(trim.slice(6), 10);
    var libMois = MOIS_N[(T2 - 1) * 3 + 1] + ' \u2192 ' + MOIS_N[(T2 - 1) * 3 + 3] + ' ' + trim.slice(0, 4);
    sec += '<p style="font-size:11.5px;font-weight:700;margin:8px 0 4px 0">' + trim + ' <span style="font-weight:600;color:var(--text-sec)">(achats de ' + libMois + ')</span> \u2014 ristournes ' + rist.toFixed(2) + ' \u20ac <span style="font-weight:400;color:var(--text-ter)">(' + (av.fichier || '') + (av.importeLe ? ', import\u00e9 le ' + av.importeLe : '') + (av.ctrl && av.ctrl.maj ? ', contr\u00f4le m\u00e9moris\u00e9 le ' + av.ctrl.maj : '') + ')</span> ' +
      '<button type="button" onclick="egSuiviAvoirSuppr(\'' + trim + '\')" style="font-size:10px;background:none;border:none;color:var(--danger);cursor:pointer" title="Supprimer cet avoir de la fiche (action volontaire, avec confirmation)">\ud83d\uddd1</button></p>' +
      '<table style="width:100%;border-collapse:collapse;font-size:11px"><thead><tr>' +
      '<th style="text-align:left;padding:3px 6px;border-bottom:1px solid var(--border)">Canal / taux facture</th>' +
      '<th style="' + td + '">CA r\u00e9f. avoir</th>' +
      '<th style="' + td + '">Achats base</th>' +
      '<th style="' + td + '">\u00c9cart assiette</th>' +
      '<th style="' + td + '">Ristourne</th>' +
      '<th style="' + td + '">Total constat\u00e9</th>' +
      '</tr></thead><tbody>';
    av.lignes.forEach(function(l) {
      var totPct = l.taux + (l.ca > 0 ? 100 * l.rist / l.ca : 0);
      var b = (l.canal === 'Indirect') ? (base.taux[String(l.taux)] ? base.taux[String(l.taux)].ind : null)
                                         : (base.tauxDir[String(l.taux)] ? base.tauxDir[String(l.taux)].brut : null); // v8.50 : brut = CA de r\u00e9f\u00e9rence TEVA
      var ecart = (b !== null) ? b - l.ca : null;
      sec += '<tr><td style="padding:3px 6px;border-bottom:1px solid var(--border)">' + l.canal + ' ' + l.taux + ' %</td>' +
        '<td style="' + td + '">' + l.ca.toFixed(2) + '</td>' +
        '<td style="' + td + '">' + (b !== null ? b.toFixed(2) : '\u2014') + '</td>' +
        '<td style="' + td + ';color:' + (ecart !== null && Math.abs(ecart) > Math.max(10, l.ca * 0.02) ? 'var(--danger)' : 'var(--text-sec)') + '">' + (ecart !== null ? (ecart >= 0 ? '+' : '') + ecart.toFixed(2) : '\u2014') + '</td>' +
        '<td style="' + td + '">' + l.rist.toFixed(2) + '</td>' +
        '<td style="' + td + ';font-weight:700">' + totPct.toFixed(2) + ' %</td></tr>';
    });
    // v8.40 : la comparaison globale utilise les totaux par labo (toujours en base),
    // m\u00eame quand le d\u00e9tail par taux n'est pas encore r\u00e9import\u00e9.
    var indBase = base.indTotal || baseInd;
    // v8.41 \u2014 CONTR\u00d4LE M\u00c9MORIS\u00c9 avec l'avoir : d\u00e8s que la base fournit des chiffres,
    // ils sont FIG\u00c9S sur la fiche labo (av.ctrl) \u2192 GitHub. Si la base est vide ou
    // purg\u00e9e plus tard, le contr\u00f4le historique reste affich\u00e9 tel qu'il a \u00e9t\u00e9 constat\u00e9.
    if (indBase || base.direct) {
      var nouveauCtrl = { ind: Math.round((indBase || 0) * 100) / 100, dir: Math.round((base.direct || 0) * 100) / 100, maj: new Date().toISOString().slice(0, 10) };
      if (!av.ctrl || av.ctrl.ind !== nouveauCtrl.ind || av.ctrl.dir !== nouveauCtrl.dir) {
        av.ctrl = nouveauCtrl;
        try { condSauvegarder(); } catch(eC) {}
      }
    } else if (av.ctrl) {
      // base indisponible \u2192 r\u00e9afficher le contr\u00f4le m\u00e9moris\u00e9
      indBase = av.ctrl.ind || 0;
      base.direct = av.ctrl.dir || 0;
    }
    var ecI = indBase ? indBase - caI : null;
    var ecD = base.direct ? base.direct - caD : null;
    sec += '<tr style="font-weight:700;background:var(--surface2)">' +
      '<td style="padding:4px 6px">TOTAL \u2014 Direct ' + caD.toFixed(2) + ' \u00b7 Indirect ' + caI.toFixed(2) + '</td>' +
      '<td style="' + td + '">' + (caD + caI).toFixed(2) + '</td>' +
      '<td style="' + td + '">' + (indBase ? indBase.toFixed(2) + ' ind.' : '\u2014') + (base.direct ? ' \u00b7 ' + base.direct.toFixed(2) + ' dir.' : '') + '</td>' +
      '<td style="' + td + ';color:' + (((ecI !== null && Math.abs(ecI) > 50) || (ecD !== null && Math.abs(ecD) > 50)) ? 'var(--danger)' : 'var(--text-sec)') + '">' +
        (ecI !== null ? (ecI >= 0 ? '+' : '') + ecI.toFixed(2) + ' ind.' : '\u2014') +
        (ecD !== null ? ' \u00b7 ' + (ecD >= 0 ? '+' : '') + ecD.toFixed(2) + ' dir.' : '') + '</td>' +
      '<td style="' + td + '">' + rist.toFixed(2) + '</td>' +
      '<td style="' + td + '">' + ((caD + caI) > 0 ? (100 * rist / (caD + caI)).toFixed(2) + ' % moy.' : '\u2014') + '</td></tr></tbody></table>';
    if (ecI !== null && ecI > 50) {
      sec += '<p style="font-size:11px;color:var(--danger);font-weight:600;margin:3px 0 0 0">\u26a0 ' + ecI.toFixed(2) + ' \u20ac d\u2019achats INDIRECTS de votre base hors assiette TEVA' + (ecD !== null && ecD > 50 ? ' (+' + ecD.toFixed(2) + ' \u20ac en direct)' : '') + ' \u2014 \u00e0 la ristourne moyenne, \u2248 ' + (((caD + caI) > 0 ? rist / (caD + caI) : 0.19) * (ecI + Math.max(0, ecD || 0))).toFixed(0) + ' \u20ac de ristourne en jeu ce trimestre. Le d\u00e9tail par taux dira o\u00f9 (produits hors r\u00e9pertoire ? assiette incompl\u00e8te ?).</p>';
    }
    if (base.moisSansDetail.length) {
      sec += '<p style="font-size:10.5px;color:#b45309;margin:3px 0 0 0">\u26a0 D\u00e9tail par taux absent pour ' + base.moisSansDetail.join(', ') + ' \u2014 r\u00e9importez les r\u00e9caps CERP de ces mois (v8.39+) pour un contr\u00f4le d\u2019assiette complet.</p>';
    }
    trimAjSec(trim.slice(0, 4), 'T' + trim.slice(6) + ' \u2713 ' + Math.round(rist) + ' \u20ac', sec);
  });

  // v8.53 \u2014 PR\u00c9VISIONNEL : trimestres avec des achats en base mais pas (encore)
  // d'avoir. Assiette par canal \u00d7 taux depuis la base ; ristourne attendue au
  // taux total R\u00c9ELLEMENT constat\u00e9 sur les derniers avoirs (repli 23,5/39 % \u00e9toil\u00e9 *).
  if (achatsBase) {
    var refs = {};
    Object.keys(labo.avoirsTrim || {}).sort().forEach(function(trR) {
      ((labo.avoirsTrim[trR] || {}).lignes || []).forEach(function(lr) {
        if (lr.ca > 0) refs[lr.canal + '|' + lr.taux] = Math.round((lr.taux + 100 * lr.rist / lr.ca) * 100) / 100;
      });
    });
    var trimsPrev = {};
    Object.keys(achatsBase.mois || {}).forEach(function(moP) {
      var tkP = moP.slice(0, 4) + '-T' + Math.ceil(parseInt(moP.slice(5), 10) / 3);
      if (!(labo.avoirsTrim || {})[tkP]) trimsPrev[tkP] = 1;
    });
    var tdP = 'padding:3px 6px;border-bottom:1px solid var(--border);text-align:right;font-family:monospace;font-size:11px';
    Object.keys(trimsPrev).sort().forEach(function(tk) {
      var sec = '';
      var bP = egSuiviAchatsTauxTrim(tk, cfg);
      var lignesP = [];
      Object.keys(bP.tauxDir).forEach(function(tx) { if (bP.tauxDir[tx].brut > 0) lignesP.push({ canal: 'Direct', taux: parseFloat(tx), ass: Math.round(bP.tauxDir[tx].brut * 100) / 100 }); });
      Object.keys(bP.taux).forEach(function(tx) { if (bP.taux[tx].ind > 0) lignesP.push({ canal: 'Indirect', taux: parseFloat(tx), ass: Math.round(bP.taux[tx].ind * 100) / 100 }); });
      if (!lignesP.length) return;
      lignesP.sort(function(a, b) { return a.canal === b.canal ? a.taux - b.taux : (a.canal === 'Direct' ? -1 : 1); });
      var corps = '', totAss = 0, totRist = 0, refsManq = false;
      lignesP.forEach(function(l) {
        var ref = refs[l.canal + '|' + l.taux], deft = false;
        if (ref === undefined) { deft = true; ref = (l.taux <= 2.5) ? 23.5 : 39; refsManq = refsManq || (l.taux < 39); }
        var rist = l.ass * Math.max(0, ref - l.taux) / 100;
        totAss += l.ass; totRist += rist;
        corps += '<tr><td style="padding:3px 6px;border-bottom:1px solid var(--border)">' + l.canal + ' ' + l.taux + ' %</td>' +
          '<td style="' + tdP + '">' + l.ass.toFixed(2) + '</td>' +
          '<td style="' + tdP + '">' + ref.toFixed(2) + ' %' + (deft ? ' *' : '') + '</td>' +
          '<td style="' + tdP + ';font-weight:600">' + rist.toFixed(2) + '</td></tr>';
      });
      var T3n = parseInt(tk.slice(6), 10);
      var MOIS_P = ['', 'janvier', 'f\u00e9vrier', 'mars', 'avril', 'mai', 'juin', 'juillet', 'ao\u00fbt', 'septembre', 'octobre', 'novembre', 'd\u00e9cembre'];
      sec += '<p style="font-size:11.5px;font-weight:700;margin:12px 0 4px 0">\ud83d\udcd0 Pr\u00e9visionnel ' + tk + ' <span style="font-weight:600;color:var(--text-sec)">(achats de ' + MOIS_P[(T3n - 1) * 3 + 1] + ' \u2192 ' + MOIS_P[(T3n - 1) * 3 + 3] + ' ' + tk.slice(0, 4) + ' \u2014 avoir non re\u00e7u)</span> \u2014 ristourne attendue \u2248 <span style="color:var(--accent-text)">' + totRist.toFixed(2) + ' \u20ac</span></p>' +
        '<table style="width:100%;border-collapse:collapse;font-size:11px"><thead><tr>' +
        '<th style="text-align:left;padding:3px 6px;border-bottom:1px solid var(--border)">Canal / taux facture</th>' +
        '<th style="' + tdP + '">Assiette base</th>' +
        '<th style="' + tdP + '" title="Taux total constat\u00e9 sur vos derniers avoirs pour ce canal et ce taux ; * = valeur par d\u00e9faut (aucun avoir de r\u00e9f\u00e9rence)">Taux total attendu</th>' +
        '<th style="' + tdP + '">Ristourne attendue</th>' +
        '</tr></thead><tbody>' + corps +
        '<tr style="font-weight:700;background:var(--surface2)"><td style="padding:4px 6px">TOTAL</td>' +
        '<td style="' + tdP + '">' + totAss.toFixed(2) + '</td><td style="' + tdP + '"></td>' +
        '<td style="' + tdP + '">' + totRist.toFixed(2) + '</td></tr></tbody></table>' +
        '<p style="font-size:10.5px;color:var(--text-ter);margin:3px 0 0 0">Taux de r\u00e9f\u00e9rence = derniers avoirs import\u00e9s' + (refsManq ? ' \u00b7 * repli 23,5 / 39 % faute d\u2019avoir de r\u00e9f\u00e9rence' : '') + ' \u00b7 \u00e0 comparer \u00e0 l\u2019avoir r\u00e9el d\u00e8s r\u00e9ception. Un taux facture \u2265 au taux cible attend 0 \u20ac de ristourne.</p>';
      if (bP.moisSansDetail.length) {
        sec += '<p style="font-size:10.5px;color:#b45309;margin:3px 0 0 0">\u26a0 Assiette Indirect incompl\u00e8te : d\u00e9tail par taux absent pour ' + bP.moisSansDetail.join(', ') + ' (r\u00e9caps CERP v8.39+).</p>';
      }
      trimAjSec(tk.slice(0, 4), 'T' + tk.slice(6) + ' \ud83d\udcd0 \u2248 ' + Math.round(totRist) + ' \u20ac', sec);
    });
  }
  // v8.58 : assemblage \u2014 un <details> par ann\u00e9e, la plus r\u00e9cente ouverte
  Object.keys(secAnnees).sort().reverse().forEach(function(an, ix) {
    var g = secAnnees[an];
    html += '<details' + (ix === 0 ? ' open' : '') + ' style="margin:10px 0;border:1px solid var(--border);border-radius:var(--radius-sm);padding:2px 10px 8px 10px;background:var(--surface)">' +
      '<summary style="cursor:pointer;font-size:12.5px;font-weight:700;padding:6px 0;user-select:none">\ud83d\udcc5 ' + an + ' <span style="font-weight:600;color:var(--text-sec);font-size:11.5px">\u2014 ' + g.libs.join(' \u00b7 ') + '</span></summary>' +
      g.html + '</details>';
  });
  // v8.59 : rapprochement bancaire + remise globale (donn\u00e9es Okimia)
  if (okimiaBase === null && !_okimiaChargement) {
    try { okimiaChargerBase().then(function() { try { egRemonteeRender(); } catch (eR2) {} }); } catch (eK) {}
  }
  var rapp = (okimiaBase && Object.keys(okimiaBase.mois || {}).length) ? egOkimiaRapproche(labo) : null;
  html += egOkimiaRapprocheHTML(rapp);
  try { html += egRemiseGlobaleHTML(cfg, labo, rapp); } catch (eG) {}
  return html;
}

function egRemonteeMoisData() {
  var labo = condLabos[condLaboActif];
  if (!labo) return null;
  if (!labo.suiviRemonteeMois) labo.suiviRemonteeMois = {};
  return labo.suiviRemonteeMois;
}

function egRemonteeMoisHTML() {
  var data = egRemonteeMoisData();
  if (data === null) return '';
  var inS = 'font-size:12px;padding:4px 8px;border:1px solid var(--border);border-radius:var(--radius-sm);background:var(--surface2);';
  var MOIS = ['Janvier','F\u00e9vrier','Mars','Avril','Mai','Juin','Juillet','Ao\u00fbt','Septembre','Octobre','Novembre','D\u00e9cembre'];
  var an = _egRemAnnee;
  var totT = 0, totD = 0, totADir = 0, totAGross = 0, totACerp = 0, totAAlliance = 0;
  var html =
    '<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin:14px 0 6px 0">' +
    '<span style="font-size:12px;font-weight:700">\ud83d\udcc5 Suivi mensuel (achats)</span>' +
    '<button type="button" onclick="_egRemAnnee--;egRemonteeRender()" style="font-size:11px;padding:3px 9px;background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);cursor:pointer">\u2039</button>' +
    '<span style="font-size:12px;font-weight:600">' + an + '</span>' +
    '<button type="button" onclick="_egRemAnnee++;egRemonteeRender()" style="font-size:11px;padding:3px 9px;background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);cursor:pointer">\u203a</button>' +
    '<label style="font-size:11px;padding:4px 10px;background:#7c3aed;color:#fff;border-radius:var(--radius-sm);cursor:pointer;font-weight:600" title="Achats DIRECTS + avoirs EG (index Digipharmacie)">\ud83d\udce6 Digipharmacie<input type="file" accept=".zip,.csv,.xlsx" style="display:none" onchange="egRemonteeDigiImport(this)"></label>' +
    '<label style="font-size:11px;padding:4px 10px;background:#0369a1;color:#fff;border-radius:var(--radius-sm);cursor:pointer;font-weight:600" title="Factures grossiste CERP (PDF multi-factures) : remont\u00e9e = 25% du brut \u2212 remise CERP, ligne \u00e0 ligne">\ud83e\uddfe Factures CERP<input type="file" accept=".pdf" style="display:none" onchange="egRemonteeCerpImport(this)"></label>' +
    '<label style="font-size:11px;padding:4px 10px;background:#b45309;color:#fff;border-radius:var(--radius-sm);cursor:pointer;font-weight:600" title="Suivi Achats G\u00e9n\u00e9riques Alliance (PDF mensuel) : ligne EG LABO - Total">\ud83d\ude9a Suivi Alliance<input type="file" accept=".pdf" style="display:none" onchange="egRemonteeAllianceImport(this)"></label>' +
    '<span style="font-size:10.5px;color:var(--text-ter)">Avoirs CSP/EG \u2192 Remise d\u00e9clar\u00e9e \u00b7 Factures CSP/EG \u2192 achats \u2192 th\u00e9orique \u2248 (ratio mix ventes)</span>' +
    '</div>' +
    '<table style="width:100%;border-collapse:collapse;font-size:12px"><thead><tr>' +
    '<th style="text-align:left;padding:4px 6px;border-bottom:1px solid var(--border);font-size:11px;color:var(--text-sec)">Mois</th>' +
    '<th style="text-align:right;padding:4px 6px;border-bottom:1px solid var(--border);font-size:11px;color:var(--text-sec)" title="Achats DIRECTS EG du mois (factures CSP/EG, base HT 2,1 % \u2014 import Digipharmacie)">Achats directs</th>' +
    '<th style="text-align:right;padding:4px 6px;border-bottom:1px solid var(--border);font-size:11px;color:var(--text-sec)" title="CA brut EG chez CERP (r\u00e9cap sous contrats prioritaire ; contr\u00f4l\u00e9 contre les factures d\u00e9taill\u00e9es quand les deux sont en base \u2014 \u26a0 si \u00e9cart > 1 \u20ac)">Achats CERP</th>' +
    '<th style="text-align:right;padding:4px 6px;border-bottom:1px solid var(--border);font-size:11px;color:var(--text-sec)" title="CA brut EG chez Alliance (Suivi Achats G\u00e9n\u00e9riques)">Achats Alliance</th>' +
    '<th style="text-align:right;padding:4px 6px;border-bottom:1px solid var(--border);font-size:11px;color:var(--text-sec)" title="CERP + Alliance">Total grossiste</th>' +
    '<th style="text-align:right;padding:4px 6px;border-bottom:1px solid var(--border);font-size:11px;color:var(--text-sec)" title="Avoir re\u00e7u le mois SUIVANT (d\u00e9calage de paiement M+1) \u2014 rang\u00e9 ici dans le mois d\u2019achats qu\u2019il r\u00e9mun\u00e8re">Remise d\u00e9clar\u00e9e labo <span style="font-weight:400">(re\u00e7ue M+1)</span></th>' +
    '<th style="text-align:right;padding:4px 6px;border-bottom:1px solid var(--border);font-size:11px;color:var(--text-sec)" title="Somme des composantes : direct \u2248 + CERP + Alliance (saisie manuelle prioritaire)">Remise th\u00e9orique <span style="font-weight:400">(direct + grossiste)</span></th>' +
    '<th style="text-align:right;padding:4px 6px;border-bottom:1px solid var(--border);font-size:11px;color:var(--text-sec)">\u00c9cart</th>' +
    '</tr></thead><tbody>';
  for (var m = 1; m <= 12; m++) {
    var cle = an + '-' + ('0' + m).slice(-2);
    var r = data[cle] || {};
    // v8.21 : th\u00e9orique = somme des composantes (direct \u2248 + CERP + Alliance),
    // sauf saisie manuelle (t_manuel prioritaire). Migration douce du champ v8.20.
    if (typeof r.theorique === 'number' && r.t_direct === undefined && r.t_cerp === undefined && r.t_alliance === undefined && r.t_manuel === undefined) {
      if (r.source === 'digi\u2248') r.t_direct = r.theorique; else r.t_manuel = r.theorique;
    }
    // v8.28 \u2014 ordre de calcul r\u00e9tabli (r\u00e9gression v8.26/27 : t et comps utilis\u00e9s avant d\u00e9finition)
    // 1. valeur d\u00e9clar\u00e9e stock\u00e9e
    var dv = (typeof r.declare === 'number') ? r.declare : null;
    // 2. base Achats & Imports : compl\u00e8te tout ce que les imports EG n'ont pas fourni
    var auto = egRemonteeAutoDepuisBase(cle);
    if (typeof r.t_direct !== 'number' && auto.tDirect !== null) { r = Object.assign({}, r); r.t_direct = auto.tDirect; }
    if (typeof r.t_cerp !== 'number' && auto.tCerp !== null) { r = Object.assign({}, r); r.t_cerp = auto.tCerp; }
    if (typeof r.t_alliance !== 'number' && auto.tAlliance !== null) { r = Object.assign({}, r); r.t_alliance = auto.tAlliance; }
    var aDir = (typeof r.achats === 'number') ? r.achats : auto.aDir;
    var aCerp = (typeof r.a_cerp === 'number') ? r.a_cerp : auto.aCerp;
    var aAlliance = (typeof r.a_alliance === 'number') ? r.a_alliance : auto.aAlliance;
    var aGross = (aCerp !== null || aAlliance !== null) ? Math.round(((aCerp || 0) + (aAlliance || 0)) * 100) / 100 : null;
    var cerpTt = 'CA brut EG chez CERP';
    var cerpWarn = '';
    if (auto.verif) {
      var dV = Math.abs(auto.verif.recap - auto.verif.lignes);
      if (dV > 1) { cerpWarn = ' \u26a0'; cerpTt = '\u26a0 INCOH\u00c9RENCE : r\u00e9cap ' + auto.verif.recap.toFixed(2) + ' \u20ac vs factures ' + auto.verif.lignes.toFixed(2) + ' \u20ac (\u00e9cart ' + dV.toFixed(2) + ' \u20ac) \u2014 factures incompl\u00e8tes en base ?'; }
      else cerpTt = '\u2713 r\u00e9cap et factures d\u00e9taill\u00e9es concordent (' + auto.verif.recap.toFixed(2) + ' \u20ac)';
    }
    if (dv === null && auto.declare !== null) dv = auto.declare;
    var avoirsInfo = (auto.avoirsInfo !== undefined && auto.avoirsInfo !== null) ? auto.avoirsInfo : null;
    // 3. composantes \u2192 th\u00e9orique (saisie manuelle prioritaire)
    var comps = [];
    if (typeof r.t_direct === 'number') comps.push('direct \u2248 ' + r.t_direct.toFixed(2));
    if (typeof r.t_cerp === 'number') comps.push('CERP ' + r.t_cerp.toFixed(2));
    if (typeof r.t_alliance === 'number') comps.push('Alliance ' + r.t_alliance.toFixed(2));
    var tCalc = comps.length ? ((r.t_direct || 0) + (r.t_cerp || 0) + (r.t_alliance || 0)) : null;
    var t = (typeof r.t_manuel === 'number') ? r.t_manuel : (tCalc !== null ? Math.round(tCalc * 100) / 100 : null);
    // 4. totaux, \u00e9cart, marqueur
    if (t !== null) totT += t;
    if (dv !== null) totD += dv;
    totADir += (aDir || 0); totAGross += (aGross || 0); totACerp += (aCerp || 0); totAAlliance += (aAlliance || 0);
    var ec = (t !== null && dv !== null) ? (dv - t) : null;
    var src2 = '';
    if (comps.length || r.sourceD || avoirsInfo !== null) {
      var tt = comps.length ? ('Composantes : ' + comps.join(' + ') + ' \u20ac') : '';
      if (r.sourceD) tt += (tt ? ' \u2014 ' : '') + 'D\u00e9clar\u00e9 : ' + r.sourceD;
      if (avoirsInfo !== null) tt += (tt ? ' \u2014 ' : '') + 'Avoirs fournisseur re\u00e7us M+1 : ' + avoirsInfo.toFixed(2) + ' \u20ac (retours/litiges/RFA/remises confondus \u2014 \u00e0 ventiler \u00e0 la main dans Remise d\u00e9clar\u00e9e)';
      if (typeof r.t_manuel === 'number' && comps.length) tt += ' \u2014 REMPLAC\u00c9 par saisie manuelle';
      src2 = ' <span style="font-size:9px;color:var(--text-ter)" title="' + tt + '">\ud83d\udcc4' + (typeof r.t_direct === 'number' ? '\u2248' : '') + '</span>';
    }
    html += '<tr>' +
      '<td style="padding:3px 6px;border-bottom:1px solid var(--border)">' + MOIS[m-1] + ' ' + an + src2 + '</td>' +
      '<td style="padding:3px 6px;border-bottom:1px solid var(--border);text-align:right;font-family:monospace;font-size:11px;color:var(--text-sec)">' + (aDir !== null ? aDir.toFixed(2) + ' \u20ac' : '\u2014') + '</td>' +
      '<td style="padding:3px 6px;border-bottom:1px solid var(--border);text-align:right;font-family:monospace;font-size:11px;color:var(--text-sec)" title="' + cerpTt + '">' + (aCerp !== null ? aCerp.toFixed(2) + ' \u20ac' + cerpWarn : '\u2014') + '</td>' +
      '<td style="padding:3px 6px;border-bottom:1px solid var(--border);text-align:right;font-family:monospace;font-size:11px;color:var(--text-sec)">' + (aAlliance !== null ? aAlliance.toFixed(2) + ' \u20ac' : '\u2014') + '</td>' +
      '<td style="padding:3px 6px;border-bottom:1px solid var(--border);text-align:right;font-family:monospace;font-size:11px;font-weight:600">' + (aGross !== null ? aGross.toFixed(2) + ' \u20ac' : '\u2014') + '</td>' +
      '<td style="padding:3px 6px;border-bottom:1px solid var(--border);text-align:right"><input type="number" step="0.01" value="' + (dv !== null ? dv : '') + '" style="' + inS + 'width:92px;text-align:right" onchange="egRemonteeMoisMaj(\'' + cle + '\',\'declare\',this.value)"> \u20ac</td>' +
      '<td style="padding:3px 6px;border-bottom:1px solid var(--border);text-align:right"><input type="number" step="0.01" value="' + (t !== null ? t : '') + '" style="' + inS + 'width:92px;text-align:right" onchange="egRemonteeMoisMaj(\'' + cle + '\',\'theorique\',this.value)"> \u20ac</td>' +
      '<td style="padding:3px 6px;border-bottom:1px solid var(--border);text-align:right;font-weight:600;color:' + (ec === null ? 'var(--text-ter)' : (ec < -0.01 ? 'var(--danger)' : 'var(--accent-text)')) + '">' + (ec === null ? '\u2014' : (ec >= 0 ? '+' : '') + ec.toFixed(2) + ' \u20ac') + '</td>' +
      '</tr>';
  }
  var ecT = totD - totT;
  html += '<tr style="font-weight:700;background:var(--surface2)">' +
    '<td style="padding:5px 6px">TOTAL ' + an + '</td>' +
    '<td style="padding:5px 6px;text-align:right;font-family:monospace;font-size:11px">' + totADir.toFixed(2) + ' \u20ac</td>' +
    '<td style="padding:5px 6px;text-align:right;font-family:monospace;font-size:11px">' + totACerp.toFixed(2) + ' \u20ac</td>' +
    '<td style="padding:5px 6px;text-align:right;font-family:monospace;font-size:11px">' + totAAlliance.toFixed(2) + ' \u20ac</td>' +
    '<td style="padding:5px 6px;text-align:right;font-family:monospace;font-size:11px">' + totAGross.toFixed(2) + ' \u20ac</td>' +
    '<td style="padding:5px 6px;text-align:right">' + totD.toFixed(2) + ' \u20ac</td>' +
    '<td style="padding:5px 6px;text-align:right">' + totT.toFixed(2) + ' \u20ac</td>' +
    '<td style="padding:5px 6px;text-align:right;color:' + (ecT < -0.01 ? 'var(--danger)' : 'var(--accent-text)') + '">' + (ecT >= 0 ? '+' : '') + ecT.toFixed(2) + ' \u20ac</td>' +
    '</tr></tbody></table>';
  return html;
}

// v8.20 — ratio du mix : suppl\u00e9ment th\u00e9orique / montant net factur\u00e9, calcul\u00e9 sur
// le mix r\u00e9el (ventes Ospharm EG pond\u00e9r\u00e9es par PFHT et CGV du catalogue).
// Sert \u00e0 estimer la th\u00e9orique depuis les totaux de factures (l'index Digipharmacie
// ne donne pas le d\u00e9tail produit). D\u00e9faut 0.1031 si mix indisponible.
function egRemonteeRatioMix() {
  try {
    var labo = condLabos[condLaboActif];
    var map = {};
    (labo.produits || []).forEach(function(p) { if (p.marche === 'GENERIQUE REMBOURSE') map[String(p.ean)] = p; });
    var nomU = String(labo.nom || '').toUpperCase().trim();
    var cle = null;
    Object.keys(decOspharmProds || {}).some(function(k) { if (k.toUpperCase().trim() === nomU) { cle = k; return true; } return false; });
    if (!cle) return 0.1031;
    var num = 0, den = 0;
    (decOspharmProds[cle] || []).forEach(function(r) {
      var p2 = map[String(r.ean)];
      if (!p2 || !(r.qte > 0)) return;
      var cgv = (p2.rem_cat || 0) / 100;
      num += r.qte * (p2.pu_catalogue || 0) * Math.max(0, 0.25 - cgv);
      den += r.qte * (p2.pu_catalogue || 0) * (1 - cgv);
    });
    return den > 0 ? (num / den) : 0.1031;
  } catch(e) { return 0.1031; }
}

// v8.20 — import de l'export Digipharmacie (index des factures) : ZIP contenant
// le CSV/XLSX, ou le CSV/XLSX directement. Identification EG : nom de fichier
// de la facture contenant EG_LABO / EG LABO (mandant CSP), ou fournisseur EG LABO.
function egRemonteeDigiImport(input) {
  var file = input.files && input.files[0];
  if (!file) return;
  var nomF = file.name.toLowerCase();
  var finir = function() { input.value = ''; };
  var traiterLignes = function(lignes) {
    // lignes = tableaux de cellules ; localiser l'en-t\u00eate
    var hi = -1, col = {};
    for (var i = 0; i < Math.min(lignes.length, 10) && hi < 0; i++) {
      var l = lignes[i].map(function(c){ return String(c || '').toLowerCase(); });
      var iF = l.findIndex(function(c){ return c.indexOf('nom du fichier') >= 0; });
      if (iF >= 0) {
        hi = i;
        col.fichier = iF;
        col.type = l.findIndex(function(c){ return c === 'type'; });
        col.fourn = l.findIndex(function(c){ return c.indexOf('fournisseur') >= 0; });
        col.date = l.findIndex(function(c){ return c === 'date'; });
        col.b21 = l.findIndex(function(c){ return c.indexOf('2.10') >= 0 || c.indexOf('2,10') >= 0; });
        col.ht = l.findIndex(function(c){ return c.indexOf('montant ht') >= 0; });
      }
    }
    if (hi < 0 || col.date < 0 || col.ht < 0) { alert('Format non reconnu \u2014 attendu : export Digipharmacie (colonnes Nom du fichier, Type, Date, Base HT 2.10%, Montant HT).'); finir(); return; }
    var num = function(v) { v = String(v == null ? '' : v).replace(/\s/g, '').replace(',', '.'); var n = parseFloat(v); return isNaN(n) ? 0 : n; };
    var estEG = function(l2) {
      var f = String(l2[col.fichier] || '').toUpperCase().replace(/[ _-]+/g, '_');
      var fo = String(col.fourn >= 0 ? l2[col.fourn] : '').toUpperCase();
      return f.indexOf('EG_LABO') >= 0 || fo.indexOf('EG LABO') >= 0 || fo === 'EG';
    };
    var avoirs = {}, achats = {}, nbA = 0, nbF = 0, totA = 0, totF = 0;
    for (var r = hi + 1; r < lignes.length; r++) {
      var l2 = lignes[r];
      if (!l2 || !estEG(l2)) continue;
      var dstr = String(l2[col.date] || '');
      var md = dstr.match(/(\d{4})-(\d{2})/);
      if (!md) continue;
      var mois = md[1] + '-' + md[2];
      var type = String(col.type >= 0 ? l2[col.type] : '').toLowerCase();
      var ht = num(l2[col.ht]);
      if (type.indexOf('avoir') >= 0 || ht < 0) {
        avoirs[mois] = (avoirs[mois] || 0) + Math.abs(ht); nbA++; totA += Math.abs(ht);
      } else {
        var b21 = col.b21 >= 0 ? num(l2[col.b21]) : 0;
        var base = b21 || ht; // g\u00e9n\u00e9riques = TVA 2,1 % ; repli sur le HT total
        achats[mois] = (achats[mois] || 0) + base; nbF++; totF += base;
      }
    }
    if (!nbA && !nbF) { alert('Aucune ligne EG LABO (facture ou avoir) dans cet export.'); finir(); return; }
    var ratio = egRemonteeRatioMix();
    var data = egRemonteeMoisData();
    var moisRemplis = [];
    // v8.23 \u2014 D\u00c9CALAGE DE PAIEMENT : l'avoir re\u00e7u au mois M r\u00e9mun\u00e8re les achats
    // du mois M\u22121. Tout le tableau est sur l'axe MOIS D'ACHATS : l'avoir est donc
    // rang\u00e9 dans le mois pr\u00e9c\u00e9dent sa date (avoir juin \u2192 case de mai).
    var moisPrec = function(m) {
      var a = parseInt(m.slice(0, 4), 10), mo = parseInt(m.slice(5, 7), 10) - 1;
      if (mo === 0) { a--; mo = 12; }
      return a + '-' + ('0' + mo).slice(-2);
    };
    Object.keys(avoirs).forEach(function(mAvoir) {
      var m = moisPrec(mAvoir); // mois d'achats r\u00e9mun\u00e9r\u00e9
      if (!data[m]) data[m] = { declare: null };
      data[m].declare = Math.round(avoirs[mAvoir] * 100) / 100;
      data[m].sourceD = 'digi (avoir ' + mAvoir + ')';
      if (moisRemplis.indexOf(m) < 0) moisRemplis.push(m);
    });
    Object.keys(achats).forEach(function(m) {
      if (!data[m]) data[m] = { theorique: null, declare: null };
      data[m].achats = Math.round(achats[m] * 100) / 100;
      data[m].t_direct = Math.round(achats[m] * ratio * 100) / 100; // v8.21 : composante achats directs
      delete data[m].theorique; delete data[m].source;
      if (moisRemplis.indexOf(m) < 0) moisRemplis.push(m);
    });
    condSauvegarder();
    if (moisRemplis.length) { try { _egRemAnnee = parseInt(moisRemplis.sort()[0].slice(0, 4), 10); } catch(e) {} }
    egRemonteeRender();
    alert('\u2713 Export Digipharmacie trait\u00e9\n' + nbA + ' avoir(s) EG \u2192 Remise d\u00e9clar\u00e9e : ' + totA.toFixed(2) + ' \u20ac\n' + nbF + ' facture(s) EG \u2192 achats HT 2,1 % : ' + totF.toFixed(2) + ' \u20ac \u2192 th\u00e9orique \u2248 ' + (totF * ratio).toFixed(2) + ' \u20ac (ratio mix ' + (ratio * 100).toFixed(1) + ' %)\nMois remplis : ' + (moisRemplis.sort().join(', ') || '\u2014'));
    finir();
  };
  var lireTableur = function(buf, nomInterne) {
    if (/\.csv$/i.test(nomInterne)) {
      var txt = new TextDecoder('utf-8').decode(buf).replace(/^\ufeff/, '');
      traiterLignes(txt.split(/\r?\n/).map(function(l) { return l.split(';'); }));
    } else {
      var wbk = XLSX.read(new Uint8Array(buf), { type: 'array' });
      traiterLignes(XLSX.utils.sheet_to_json(wbk.Sheets[wbk.SheetNames[0]], { header: 1, raw: false, defval: '' }));
    }
  };
  var reader = new FileReader();
  reader.onload = function(e) {
    var buf = e.target.result;
    try {
      if (/\.zip$/i.test(nomF)) {
        var suite = function() {
          JSZip.loadAsync(buf).then(function(zip) {
            var cible = null;
            zip.forEach(function(chemin, entry) {
              if (!cible && !entry.dir && /\.(csv|xlsx)$/i.test(chemin)) cible = entry;
            });
            if (!cible) { alert('Aucun CSV/XLSX dans ce ZIP.'); finir(); return; }
            cible.async('arraybuffer').then(function(b2) { lireTableur(b2, cible.name); });
          }).catch(function(err) { alert('ZIP illisible : ' + err.message); finir(); });
        };
        if (typeof JSZip === 'undefined') {
          var s = document.createElement('script');
          s.src = 'https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js';
          s.onload = suite;
          s.onerror = function() { alert('Impossible de charger le module ZIP \u2014 d\u00e9posez directement le CSV ou le XLSX de l\u2019export.'); finir(); };
          document.head.appendChild(s);
        } else suite();
      } else {
        lireTableur(buf, nomF);
      }
    } catch (err) { alert('Erreur : ' + err.message); finir(); }
  };
  reader.readAsArrayBuffer(file);
}

function egRemonteeMoisMaj(cle, champ, val) {
  var data = egRemonteeMoisData();
  if (!data) return;
  if (!data[cle]) data[cle] = { declare: null };
  var v = (val === '' || val === null) ? null : parseFloat(val);
  if (champ === 'theorique') {
    // v8.21 : saisie manuelle prioritaire ; effacer la case rend la main aux composantes
    data[cle].t_manuel = v;
    if (v === null) delete data[cle].t_manuel;
    delete data[cle].theorique; delete data[cle].source; // champs h\u00e9rit\u00e9s v8.20
  } else {
    data[cle][champ] = v;
    if (champ === 'declare') delete data[cle].sourceD;
  }
  condSauvegarder();
  egRemonteeRender();
}

// v8.21 \u2014 utilitaires communs des imports grossistes
function egRemonteeSetComp(mois, champ, valeur) {
  var data = egRemonteeMoisData();
  if (!data) return;
  if (!data[mois]) data[mois] = { declare: null };
  data[mois][champ] = Math.round(valeur * 100) / 100;
  delete data[mois].theorique; delete data[mois].source;
}
var EG_EXCLUS_TOKENS = ['BORAX', 'CHOLECALCI', 'FUSIDIQUE', 'BACLOFENE', 'BACLOF\u00c8NE', 'BROMAZEPAM', 'BROMAZ\u00c9PAM', 'MACROGOL'];

// v8.21 \u2014 \ud83e\uddfe Factures CERP (PDF, multi-factures) : extraction des lignes EG
// (EAN au catalogue OU d\u00e9signation contenant le mot EG \u00e0 TVA 2,1) ;
// remont\u00e9e ligne = max(0, 25% \u00d7 brut \u2212 remise CERP d\u00e9j\u00e0 accord\u00e9e). Exclusions ignor\u00e9es.
function egRemonteeCerpImport(input) {
  var file = input.files && input.files[0];
  if (!file) return;
  var labo = condLabos[condLaboActif];
  var mapCat = {};
  ((labo && labo.produits) || []).forEach(function(p) {
    if (p.marche === 'GENERIQUE REMBOURSE' || p.marche === 'GENERIQUE HORS REMISE') mapCat[String(p.ean)] = p;
  });
  var reader = new FileReader();
  reader.onload = function(e) {
    pdfjsLib.getDocument({ data: new Uint8Array(e.target.result) }).promise.then(async function(doc) {
      var num = function(v) { return parseFloat(String(v).replace(/\s/g, '').replace(',', '.')) || 0; };
      // v8.21 : analyse droite-\u00e0-gauche (fiable m\u00eame si la d\u00e9signation finit par un nombre)
      // colonnes CERP : EAN | D\u00e9signation | Qt\u00e9 | PU HT | [Remise %] | PU Net | Montant HT | code TVA | [drapeaux]
      var estPrix = function(t) { return /^\d{1,3},\d\d$/.test(t) || /^\d{1,6},\d\d$/.test(t); };
      var lireLigne = function(ln) {
        var toks = ln.split(' ').filter(function(t) { return t !== ''; });
        if (!toks.length || !/^\d{13}$/.test(toks[0])) return null;
        while (toks.length && /^[A-Z]{1,2}$/.test(toks[toks.length - 1])) toks.pop(); // drapeaux C/T/MV
        if (!toks.length || !/^\d$/.test(toks[toks.length - 1])) return null;        // code TVA
        var tvaCode = toks.pop();
        if (toks.length < 4 || !estPrix(toks[toks.length - 1])) return null;
        var mht = num(toks.pop());
        if (!estPrix(toks[toks.length - 1])) return null;
        var punet = num(toks.pop());
        var remPct = null, puht;
        if (toks.length >= 2 && estPrix(toks[toks.length - 1]) && estPrix(toks[toks.length - 2])) {
          remPct = num(toks.pop());
          puht = num(toks.pop());
        } else if (estPrix(toks[toks.length - 1])) {
          puht = num(toks.pop());
        } else return null;
        if (!toks.length || !/^\d{1,4}$/.test(toks[toks.length - 1])) return null;    // quantit\u00e9
        var qte = parseInt(toks.pop(), 10);
        if (!qte || toks.length < 2) return null;
        // contr\u00f4le de coh\u00e9rence : qt\u00e9 \u00d7 PU net \u2248 montant HT (tol\u00e9rance 5 c)
        // tol\u00e9rance : PU net AFFICH\u00c9 arrondi au centime \u2192 \u00bd centime d'\u00e9cart possible par unit\u00e9
        if (Math.abs(qte * punet - mht) > Math.max(0.05, qte * 0.006)) return null;
        return { ean: toks[0], des: toks.slice(1).join(' '), qte: qte, puht: puht, mht: mht, tvaCode: tvaCode };
      };
      // v8.22 \u2014 reconstruire d'abord toutes les pages en lignes de texte
      var pagesLignes = [];
      for (var pn0 = 1; pn0 <= doc.numPages; pn0++) {
        var page0 = await doc.getPage(pn0);
        var tc0 = await page0.getTextContent();
        var parY0 = {};
        tc0.items.forEach(function(it) {
          var y = Math.round(it.transform[5]);
          (parY0[y] = parY0[y] || []).push({ x: it.transform[4], s: it.str });
        });
        pagesLignes.push(Object.keys(parY0).map(Number).sort(function(a, b) { return b - a; }).map(function(y) {
          return parY0[y].sort(function(a, b) { return a.x - b.x; }).map(function(o) { return o.s; }).join(' ').replace(/\s+/g, ' ').trim();
        }));
      }
      var touteslignes = [].concat.apply([], pagesLignes);
      var texteTout = touteslignes.join('\n');

      // ═══ FORMAT 1 : \u00ab R\u00e9capitulatif de vos achats sous contrats \u00bb (mensuel agr\u00e9g\u00e9) ═══
      if (/achats sous contrats/i.test(texteTout)) {
        var MOIS_FR2 = { janvier: '01', 'f\u00e9vrier': '02', fevrier: '02', mars: '03', avril: '04', mai: '05', juin: '06', juillet: '07', 'ao\u00fbt': '08', aout: '08', septembre: '09', octobre: '10', novembre: '11', 'd\u00e9cembre': '12', decembre: '12' };
        var mp = texteTout.match(/P\u00e9riode\s*:\s*([A-Za-z\u00e0-\u00fc\u00c0-\u00dc]+)\s+(\d{4})/);
        if (!mp) { alert('P\u00e9riode introuvable dans le r\u00e9capitulatif CERP.'); input.value = ''; return; }
        var moisR = mp[2] + '-' + (MOIS_FR2[mp[1].toLowerCase()] || '');
        if (moisR.slice(-1) === '-') { alert('Mois \u00ab ' + mp[1] + ' \u00bb non reconnu.'); input.value = ''; return; }
        var lnEG = null;
        touteslignes.forEach(function(ln) {
          if (!lnEG && /EG LABO/.test(ln) && /Total Laboratoire/i.test(ln)) lnEG = ln;
        });
        if (!lnEG) { alert('Ligne \u00ab EG LABO \u2026 Total Laboratoire \u00bb introuvable dans ce r\u00e9capitulatif.'); input.value = ''; return; }
        var numsR = (lnEG.match(/\d[\d\s]*[.,]\d\d/g) || []).map(function(x) { return parseFloat(x.replace(/\s/g, '').replace(',', '.')); });
        if (numsR.length < 2) { alert('Montants illisibles sur la ligne EG LABO du r\u00e9capitulatif.'); input.value = ''; return; }
        var brutR = numsR[0], remR = numsR[1]; // CA Mois, Remise Mois (puis Net Mois, CA Ann\u00e9e, ...)
        var topupR = Math.max(0, 0.25 * brutR - remR);
        egRemonteeSetComp(moisR, 't_cerp', topupR);
        egRemonteeSetComp(moisR, 'a_cerp', brutR); // v8.24 : CA brut grossiste CERP
        condSauvegarder();
        try { _egRemAnnee = parseInt(moisR.slice(0, 4), 10); } catch(e3) {}
        egRemonteeRender();
        alert('\u2713 R\u00e9capitulatif CERP ' + moisR + '\nEG LABO : CA mois ' + brutR.toFixed(2) + ' \u20ac \u2212 remises ' + remR.toFixed(2) + ' \u20ac \u2192 remont\u00e9e \u2248 ' + topupR.toFixed(2) + ' \u20ac\n(agr\u00e9g\u00e9 : exclusions Borax etc. non isolables \u2014 le d\u00e9tail facture reste possible en important les factures PDF)');
        input.value = '';
        return;
      }

      // ═══ FORMAT 2 : factures d\u00e9taill\u00e9es (ligne \u00e0 ligne) ═══
      var parMois = {}, nbL = 0, nbEx = 0, nbHorsTarif = 0, totBrut = 0, totTopup = 0, nbRejet = 0;
      for (var pn = 1; pn <= doc.numPages; pn++) {
        var lignes = pagesLignes[pn - 1];
        var texte = lignes.join('\n');
        var dm = texte.match(/(\d{2})\/(\d{2})\/(\d{4})/);
        var mois = dm ? (dm[3] + '-' + dm[2]) : null;
        if (!mois) continue;
        lignes.forEach(function(ln) {
          if (!/^\d{13}\s/.test(ln)) return;
          var l = lireLigne(ln);
          if (!l) { nbRejet++; return; }
          var ean = l.ean, des = l.des, qte = l.qte, puht = l.puht, mht = l.mht, tvaCode = l.tvaCode;
          var pCat = mapCat[ean];
          var estEg = !!pCat;
          if (!estEg && /\bEG\b/.test(des) && tvaCode === '4') { estEg = true; nbHorsTarif++; }
          if (!estEg) return;
          var desU = des.toUpperCase();
          var exclu = (pCat && pCat.marche === 'GENERIQUE HORS REMISE') ||
                      EG_EXCLUS_TOKENS.some(function(tk) { return desU.indexOf(tk) >= 0; });
          nbL++;
          if (exclu) { nbEx++; return; }
          var brut = qte * puht;
          var remise = Math.max(0, brut - mht);
          var topup = Math.max(0, 0.25 * brut - remise);
          totBrut += brut; totTopup += topup;
          if (!parMois[mois]) parMois[mois] = { t: 0, b: 0 };
          parMois[mois].t += topup; parMois[mois].b += brut;
        });
      }
      if (!nbL) { alert('Aucune ligne EG LABO trouv\u00e9e dans ce PDF CERP.'); input.value = ''; return; }
      Object.keys(parMois).forEach(function(m2) { egRemonteeSetComp(m2, 't_cerp', parMois[m2].t); egRemonteeSetComp(m2, 'a_cerp', parMois[m2].b); });
      condSauvegarder();
      var moisTries = Object.keys(parMois).sort();
      if (moisTries.length) { try { _egRemAnnee = parseInt(moisTries[0].slice(0, 4), 10); } catch(e2) {} }
      egRemonteeRender();
      alert('\u2713 Factures CERP trait\u00e9es (' + doc.numPages + ' pages' + (nbRejet ? ', ' + nbRejet + ' ligne(s) produit illisibles ignor\u00e9es' : '') + ')\n' + nbL + ' ligne(s) EG dont ' + nbEx + ' exclusion(s)' + (nbHorsTarif ? ' \u00b7 ' + nbHorsTarif + ' hors tarif EG (d\u00e9tect\u00e9es au nom)' : '') + '\nBrut EG : ' + totBrut.toFixed(2) + ' \u20ac \u2192 remont\u00e9e CERP : ' + totTopup.toFixed(2) + ' \u20ac\nMois : ' + moisTries.map(function(m3) { return m3 + ' (' + parMois[m3].t.toFixed(2) + ' \u20ac)'; }).join(', '));
      input.value = '';
    }).catch(function(err) { alert('PDF illisible : ' + err.message); input.value = ''; });
  };
  reader.readAsArrayBuffer(file);
}

// v8.21 \u2014 \ud83d\ude9a Suivi Achats G\u00e9n\u00e9riques Alliance (PDF mensuel) :
// ligne \u00ab EG LABO - Total \u00bb, colonnes Mois \u2192 remont\u00e9e = 25% \u00d7 brut \u2212 remise.
// Approximation assum\u00e9e : les exclusions ne sont pas identifiables dans un cumul.
function egRemonteeAllianceImport(input) {
  var file = input.files && input.files[0];
  if (!file) return;
  var reader = new FileReader();
  reader.onload = function(e) {
    pdfjsLib.getDocument({ data: new Uint8Array(e.target.result) }).promise.then(async function(doc) {
      var texte = '';
      for (var pn = 1; pn <= doc.numPages; pn++) {
        var page = await doc.getPage(pn);
        var tc = await page.getTextContent();
        var parY = {};
        tc.items.forEach(function(it) {
          var y = Math.round(it.transform[5]);
          (parY[y] = parY[y] || []).push({ x: it.transform[4], s: it.str });
        });
        texte += Object.keys(parY).map(Number).sort(function(a, b) { return b - a; }).map(function(y) {
          return parY[y].sort(function(a, b) { return a.x - b.x; }).map(function(o) { return o.s; }).join(' ');
        }).join('\n') + '\n';
      }
      // Mois du tableau : ignorer la ligne « Date d'\u00e9dition »
      var MOIS_FR = { janvier: '01', fevrier: '02', 'f\u00e9vrier': '02', mars: '03', avril: '04', mai: '05', juin: '06', juillet: '07', aout: '08', 'ao\u00fbt': '08', septembre: '09', octobre: '10', novembre: '11', 'd\u00e9cembre': '12', decembre: '12' };
      var mois = null;
      texte.split('\n').forEach(function(ln) {
        if (mois || /\u00e9dition|edition/i.test(ln)) return;
        var mm = ln.match(/\b(janvier|f\u00e9vrier|fevrier|mars|avril|mai|juin|juillet|ao\u00fbt|aout|septembre|octobre|novembre|d\u00e9cembre|decembre)\s+(\d{4})\b/i);
        if (mm) mois = mm[2] + '-' + MOIS_FR[mm[1].toLowerCase()];
      });
      if (!mois) { alert('Mois du suivi introuvable dans ce PDF Alliance.'); input.value = ''; return; }
      var num = function(v) { return parseFloat(String(v).replace(/\s/g, '').replace(',', '.')) || 0; };
      var lnTot = null;
      texte.split('\n').forEach(function(ln) { if (!lnTot && ln.indexOf('EG LABO - Total') >= 0) lnTot = ln; });
      if (!lnTot) { alert('Ligne \u00ab EG LABO - Total \u00bb introuvable \u2014 est-ce bien le Suivi Achats G\u00e9n\u00e9riques ?'); input.value = ''; return; }
      var vals8 = achatsParseTotaux(lnTot.split(/Total/i)[1] || '');
      // 8 valeurs = Mois(4) + Cumul(4) ; 4 valeurs = Cumul seul (pas d'achat ce mois)
      var brut = 0, remise = 0;
      if (vals8 && vals8.length === 8) { brut = vals8[0]; remise = Math.abs(vals8[1]); }
      var topup = Math.max(0, 0.25 * brut - remise);
      egRemonteeSetComp(mois, 't_alliance', topup);
      egRemonteeSetComp(mois, 'a_alliance', brut); // v8.24 : CA brut grossiste Alliance
      condSauvegarder();
      try { _egRemAnnee = parseInt(mois.slice(0, 4), 10); } catch(e2) {}
      egRemonteeRender();
      alert('\u2713 Suivi Alliance ' + mois + '\nEG LABO mois : brut ' + brut.toFixed(2) + ' \u20ac \u2212 remise ' + remise.toFixed(2) + ' \u20ac \u2192 remont\u00e9e \u2248 ' + topup.toFixed(2) + ' \u20ac' + (brut === 0 ? ' (aucun achat EG ce mois)' : ''));
      input.value = '';
    }).catch(function(err) { alert('PDF illisible : ' + err.message); input.value = ''; });
  };
  reader.readAsArrayBuffer(file);
}

// v8.16 — calcul direct depuis les ventes Ospharm d\u00e9j\u00e0 charg\u00e9es au d\u00e9marrage (GitHub).
// Par d\u00e9faut on utilise CE cache (12 mois glissants) ; le fichier ne sert que pour une autre p\u00e9riode.
// v8.18 — c\u0153ur du calcul : rend {per, theorique, nb, qtot} ou une cha\u00eene d'erreur
function egRemonteeCalculCache() {
  var labo = condLabos[condLaboActif];
  if (!labo) return 'Labo inactif';
  if (typeof decOspharmProds === 'undefined' || !decOspharmProds || !Object.keys(decOspharmProds).length) return 'OSPH_ABSENT';
  var nomU = String(labo.nom || '').toUpperCase().trim();
  var cle = null;
  if (decOspharmProds[labo.nom]) cle = labo.nom;
  else Object.keys(decOspharmProds).some(function(k) { if (k.toUpperCase().trim() === nomU) { cle = k; return true; } return false; });
  if (!cle) return 'Aucune ligne \u00ab ' + labo.nom + ' \u00bb dans le cache Ospharm.';
  var prods = labo.produits || [];
  if (!prods.length) return 'CATALOGUE_ABSENT';
  var map = {};
  prods.forEach(function(p) { if (p.marche === 'GENERIQUE REMBOURSE') map[String(p.ean)] = p; });
  var tot = 0, nb = 0, qtot = 0;
  (decOspharmProds[cle] || []).forEach(function(r) {
    var p2 = map[String(r.ean)];
    if (!p2) return;
    var q = r.qte || 0;
    if (q <= 0) return;
    tot += q * (p2.pu_catalogue || 0) * Math.max(0, 0.25 - (p2.rem_cat || 0) / 100);
    nb++; qtot += q;
  });
  if (!nb) return 'Aucun g\u00e9n\u00e9rique rembours\u00e9 EG dans les ventes Ospharm.';
  var per = 'Ospharm 12 mois glissants';
  try {
    var meta = JSON.parse(localStorage.getItem('_osph_meta') || '{}');
    if (meta.fichier) {
      var md = String(meta.fichier).match(/(\d{4}-\d{2}-\d{2})\s+(\d{4}-\d{2}-\d{2})/);
      per = md ? ('Ospharm ' + md[1] + ' \u2192 ' + md[2]) : ('Ospharm \u2014 ' + meta.fichier.replace(/\.[^.]+$/, ''));
    }
  } catch(e) {}
  return { per: per, theorique: Math.round(tot * 100) / 100, nb: nb, qtot: qtot };
}

// v8.18 — auto-remplissage silencieux au rendu du bloc : la th\u00e9orique se met
// \u00e0 jour toute seule d\u00e8s que les ventes Ospharm (GitHub) sont en m\u00e9moire.
function egRemonteeAutoMaj(tentative) {
  var el = document.getElementById('eg-remontee-bloc');
  if (!el) return;
  var res = egRemonteeCalculCache();
  if (res === 'OSPH_ABSENT' || res === 'CATALOGUE_ABSENT') {
    // donn\u00e9es pas encore charg\u00e9es (auto-load ~2,5-3 s) \u2192 r\u00e9essayer, 10 fois max
    if ((tentative || 0) < 10) setTimeout(function(){ egRemonteeAutoMaj((tentative || 0) + 1); }, 1500);
    return;
  }
  if (typeof res === 'string') return; // erreur d\u00e9finitive : le bouton \u26a1 la montrera
  var rows = egRemonteeData();
  if (!rows) return;
  var idx = -1;
  rows.forEach(function(r, i) { if (String(r.periode || '').indexOf('Ospharm') === 0) idx = i; });
  var inchange = idx >= 0 && rows[idx].periode === res.per && rows[idx].theorique === res.theorique && rows[idx].nb === res.nb;
  if (inchange) return; // point fixe : rien \u00e0 faire, pas de re-rendu
  var ligne = { periode: res.per, theorique: res.theorique, vire: (idx >= 0 ? rows[idx].vire : null), nb: res.nb };
  if (idx >= 0) rows[idx] = ligne; else rows.push(ligne);
  condSauvegarder();
  egRemonteeRender();
}

function egRemonteeDepuisCache() {
  var res = egRemonteeCalculCache();
  if (res === 'OSPH_ABSENT') { alert('Ventes Ospharm pas encore charg\u00e9es \u2014 attendez ~3 s apr\u00e8s l\u2019ouverture puis r\u00e9essayez.'); return; }
  if (res === 'CATALOGUE_ABSENT') { alert('Catalogue EG LABO non charg\u00e9 \u2014 \u2191 Charger depuis GitHub d\u2019abord.'); return; }
  if (typeof res === 'string') { alert(res); return; }
  var rows = egRemonteeData();
  var idx = -1;
  rows.forEach(function(r2, i2) { if (String(r2.periode || '').indexOf('Ospharm') === 0) idx = i2; });
  var ligne = { periode: res.per, theorique: res.theorique, vire: (idx >= 0 ? rows[idx].vire : null), nb: res.nb };
  if (idx >= 0) rows[idx] = ligne; else rows.push(ligne);
  condSauvegarder();
  egRemonteeRender();
  alert('\u2713 ' + res.per + '\n' + res.nb + ' r\u00e9f\u00e9rences g\u00e9n\u00e9riques \u00b7 ' + res.qtot + ' unit\u00e9s\nRemise th\u00e9orique : ' + res.theorique.toFixed(2) + ' \u20ac');
  return;
}

function egRemonteeAide() {
  var a = document.getElementById('eg-remontee-aide');
  if (a) a.style.display = (a.style.display === 'none') ? 'block' : 'none';
}

function egRemonteeMaj(i, champ, val) {
  var rows = egRemonteeData();
  if (!rows || !rows[i]) return;
  if (champ === 'periode') rows[i].periode = val;
  else rows[i][champ] = (val === '' || val === null) ? null : parseFloat(val);
  condSauvegarder();
  egRemonteeRender();
}

function egRemonteeSuppr(i) {
  var rows = egRemonteeData();
  if (!rows || !rows[i]) return;
  if (!confirm('Supprimer la ligne \u00ab ' + (rows[i].periode || '') + ' \u00bb ?')) return;
  rows.splice(i, 1);
  condSauvegarder();
  egRemonteeRender();
}

function egRemonteeLigneManuelle() {
  var rows = egRemonteeData();
  if (!rows) return;
  var per = prompt('Libell\u00e9 de la p\u00e9riode (ex. \u00ab Virement janvier 2026 \u00bb) :');
  if (!per) return;
  rows.push({ periode: per.trim(), theorique: null, vire: null, nb: 0 });
  condSauvegarder();
  egRemonteeRender();
}

function egRemonteeImport(input) {
  var file = input.files && input.files[0];
  if (!file) return;
  var reader = new FileReader();
  reader.onload = function(e) {
    try {
      var wbk = XLSX.read(new Uint8Array(e.target.result), { type: 'array' });
      var ws = wbk.Sheets[wbk.SheetNames[0]];
      var grid = XLSX.utils.sheet_to_json(ws, { header: 1, raw: true, defval: '' });
      // D\u00e9tection tol\u00e9rante : colonne EAN par le contenu (13 chiffres),
      // colonne quantit\u00e9 par l'en-t\u00eate (quantit\u00e9/qt\u00e9, premi\u00e8re occurrence = ann\u00e9e N).
      var headIdx = -1, colQte = -1, colEan = -1;
      for (var i = 0; i < Math.min(grid.length, 15) && headIdx < 0; i++) {
        for (var j = 0; j < grid[i].length; j++) {
          var h = String(grid[i][j]).toLowerCase();
          if (/quantit|qt\u00e9|\bqte\b/.test(h)) { headIdx = i; colQte = j; break; }
        }
      }
      if (headIdx < 0) { alert('Colonne Quantit\u00e9 introuvable \u2014 utilisez l\u2019export Ospharm \u00ab Toutes les ventes \u00bb.'); input.value = ''; return; }
      // Colonne EAN : premi\u00e8re colonne dont les donn\u00e9es sont des codes \u00e0 13 chiffres
      for (var j2 = 0; j2 < (grid[headIdx].length || 20) && colEan < 0; j2++) {
        var hits = 0, seen = 0;
        for (var i2 = headIdx + 1; i2 < Math.min(grid.length, headIdx + 40); i2++) {
          var cv = String((grid[i2] || [])[j2] || '').replace(/\s/g, '');
          if (!cv) continue;
          seen++;
          if (/^\d{13}$/.test(cv)) hits++;
        }
        if (seen >= 3 && hits / seen > 0.7) colEan = j2;
      }
      if (colEan < 0) { alert('Colonne EAN/Code 13 introuvable dans ce fichier.'); input.value = ''; return; }
      // Catalogue EG : g\u00e9n\u00e9riques rembours\u00e9s uniquement (rem_cat = remise facture CGV)
      var labo = condLabos[condLaboActif];
      var prods = (labo && labo.produits) || [];
      if (!prods.length) { alert('Catalogue EG LABO non charg\u00e9 \u2014 \u2191 Charger depuis GitHub d\u2019abord.'); input.value = ''; return; }
      var map = {};
      prods.forEach(function(p) {
        if (p.marche === 'GENERIQUE REMBOURSE') map[String(p.ean)] = p;
      });
      var tot = 0, nb = 0, qtot = 0;
      for (var r = headIdx + 1; r < grid.length; r++) {
        var ean = String((grid[r] || [])[colEan] || '').replace(/\s/g, '');
        if (!/^\d{13}$/.test(ean)) continue;
        var p2 = map[ean];
        if (!p2) continue;
        var q = parseFloat(String((grid[r] || [])[colQte] || '').replace(',', '.')) || 0;
        if (q <= 0) continue;
        var remFact = (p2.rem_cat || 0) / 100;
        var supp = q * (p2.pu_catalogue || 0) * Math.max(0, 0.25 - remFact);
        tot += supp; nb++; qtot += q;
      }
      if (!nb) { alert('Aucun g\u00e9n\u00e9rique rembours\u00e9 EG trouv\u00e9 dans ce fichier.'); input.value = ''; return; }
      var per = prompt('Libell\u00e9 de la p\u00e9riode pour cet import :', file.name.replace(/\.[^.]+$/, ''));
      if (per === null) { input.value = ''; return; }
      var rows = egRemonteeData();
      rows.push({ periode: (per || file.name).trim(), theorique: Math.round(tot * 100) / 100, vire: null, nb: nb });
      condSauvegarder();
      egRemonteeRender();
      alert('\u2713 ' + nb + ' r\u00e9f\u00e9rences g\u00e9n\u00e9riques \u00b7 ' + qtot + ' unit\u00e9s \u2192 remont\u00e9e th\u00e9orique ' + (Math.round(tot * 100) / 100).toFixed(2) + ' \u20ac\n(Saisissez le virement r\u00e9el EG dans la colonne d\u00e9di\u00e9e.)');
    } catch (err) {
      alert('Erreur de lecture : ' + err.message);
    }
    input.value = '';
  };
  reader.readAsArrayBuffer(file);
}

