// ===== AUTO-CLASSEMENT THUASNE COMPRESSION =====
// Affecte automatiquement chaque produit du domaine "Compression" du catalogue Thuasne à l'une des
// 2 gammes DIRECT (seules gammes ayant une affectation par produit possible — FDL/Direct est un
// choix de canal de commande, pas un attribut produit, donc pas géré par cette répartition) :
//   - "Venoflex" + ("Original" ou "Clinic") dans le nom -> Thuasne Compression Direct - LPP Venoflex Original & Clinic
//   - tout le reste du domaine Compression -> Thuasne Compression Direct - Premium
// Détection du domaine Compression : categorie contenant "compression" (insensible à la casse),
// avec repli sur le nom du produit s'il contient "venoflex"/"biflex"/"compression" (au cas où la
// categorie n'a pas été importée pour ce produit).
function condAutoClasserThuasneCompression() {
  if (!condLaboActif || !condLabos[condLaboActif]) return;
  var labo = condLabos[condLaboActif];
  var mPremium = (labo.marches_negocies || []).find(function(m){ return m.marche_id === 'thuasne_compr_direct_premium'; });
  var mLpp = (labo.marches_negocies || []).find(function(m){ return m.marche_id === 'thuasne_compr_direct_lpp'; });
  if (!mPremium || !mLpp) { alert('Applique d\'abord la configuration THUASNE Compression (bouton ci-dessus) avant de classer les produits.'); return; }

  var nbPremium = 0, nbLpp = 0, nbIgnores = 0;
  (labo.produits || []).forEach(function(p) {
    var cat = (p.categorie || '').toLowerCase();
    var nom = (p.nom || '').toLowerCase();
    var estCompression = cat.indexOf('compression') >= 0 || nom.indexOf('venoflex') >= 0 || nom.indexOf('biflex') >= 0 || nom.indexOf('compression') >= 0 || nom.indexOf('clinic') >= 0;
    if (!estCompression) { nbIgnores++; return; }
    // Sur ce catalogue, la ligne "Clinic" n'a pas "Venoflex" dans son nom (ex: "CLINIC 2 CHAU. T1L"),
    // et aucune référence Venoflex ne porte le mot "Original" (c'est la ligne de base, sans suffixe) —
    // donc on classe en LPP dès que "venoflex" OU "clinic" apparaît, sans exiger "original".
    var estVenoflexOC = nom.indexOf('venoflex') >= 0 || nom.indexOf('clinic') >= 0;
    if (!labo.catalogue) labo.catalogue = {};
    var keyCat = p.ean || p.nom;
    if (!labo.catalogue[keyCat]) labo.catalogue[keyCat] = {};
    if (estVenoflexOC) {
      p.marche = mLpp.label; p.marche_id = mLpp.marche_id; nbLpp++;
    } else {
      p.marche = mPremium.label; p.marche_id = mPremium.marche_id; nbPremium++;
    }
    // BUGFIX (v4.94) : meme souci de priorite que pour la Gamme labo - "saved.marche_id" passe
    // avant p.marche_id a l'affichage, donc il faut aussi ecrire dans labo.catalogue.
    labo.catalogue[keyCat].marche = p.marche;
    labo.catalogue[keyCat].marche_id = p.marche_id;
  });

  condRenderMarches();
  condSauvegarder();
  // Synchroniser immédiatement le tableau Catalogue (catProduits est une copie indépendante).
  if (typeof catProduits !== 'undefined' && catProduits.length > 0 && catLaboActif === condLaboActif) {
    var parMarche = {};
    (labo.produits || []).forEach(function(p) { parMarche[p.ean || p.nom] = { marche: p.marche, marche_id: p.marche_id }; });
    catProduits.forEach(function(cp) {
      var key = cp.ean || cp.nom;
      if (parMarche.hasOwnProperty(key)) { cp.marche = parMarche[key].marche; cp.marche_id = parMarche[key].marche_id; }
    });
    if (typeof catRenderTable === 'function') catRenderTable();
  }
  alert('Classement automatique terminé : ' + nbPremium + ' produit(s) → Direct Premium, ' + nbLpp + ' produit(s) → Direct LPP Venoflex Original & Clinic. ' + nbIgnores + ' produit(s) hors compression non touché(s).\n\nVérifie le résultat dans Catalogue (colonne Marché) et corrige à la main les éventuels cas limites (gammes Venoflex sans "Original"/"Clinic" dans le nom, ou produits Compression mal classés).');
}

// ===== CLASSEMENT GAMME LABO PAR ZONE ANATOMIQUE — générique (Thuasne, Marque Verte, Enovis, Gibaud, Podowell) =====
// Renseigne la colonne "Gamme labo" (p.famille) pour le catalogue du labo actif, par mot-clé dans le
// nom du produit (ex: CHEV./MALLEO -> Cheville/Pied), avec repli sur la Famille fournisseur (sous_cat),
// puis sur la Marque/catégorie fournisseur (categorie — utile pour les catalogues organisés par marque
// plutôt que par zone du corps, ex: DONJOY/VEINAX chez Enovis), pour ne jamais laisser un produit sans
// classification. Calibré et vérifié sur le vrai catalogue Thuasne (~95% de couverture) — pour les
// autres labos, la précision dépend de leur nomenclature interne, à vérifier après le premier passage.
function condSauvegarderReglesPerso(texte) {
  if (!condLaboActif || !condLabos[condLaboActif]) return;
  condLabos[condLaboActif].reglesClassification = texte || '';
  condSauvegarder();
}

function condClasserThuasneGammesAnatomiques() {
  if (!condLaboActif || !condLabos[condLaboActif]) return;
  var labo = condLabos[condLaboActif];
  // Règles personnalisées saisies par l'utilisateur (textarea "MOTCLE => Gamme", une par ligne) —
  // appliquées EN PRIORITÉ avant les règles automatiques génériques ci-dessous.
  var reglesPerso = [];
  (labo.reglesClassification || '').split('\n').forEach(function(ligne) {
    var m = ligne.split('=>');
    if (m.length === 2 && m[0].trim() && m[1].trim()) {
      reglesPerso.push({ motCle: m[0].trim().toUpperCase(), gamme: m[1].trim() });
    }
  });
  var compteur = {};
  (labo.produits || []).forEach(function(p) {
    var n = (p.nom || '').toUpperCase();
    var fam = p.sous_cat || '';
    var marque = p.categorie || '';
    var gamme;
    for (var ri = 0; ri < reglesPerso.length; ri++) {
      if (n.indexOf(reglesPerso[ri].motCle) >= 0) { gamme = reglesPerso[ri].gamme; break; }
    }
    if (gamme) {
      // règle perso trouvée, on saute la chaîne automatique
    } else if (n.indexOf('CHUT') >= 0) gamme = 'CHUT'; // Podowell : chaussures CHUT
    else if (n.indexOf('CHUP') >= 0) gamme = 'CHUP'; // Podowell : chaussures CHUP
    else if (n.indexOf('COMPRESSE') >= 0) gamme = 'Compresses'; // Marque Verte (gamme blanche)
    else if (n.indexOf('PANSEMENT') >= 0) gamme = 'Pansements'; // Marque Verte (gamme blanche)
    else if (n.indexOf('BANDE') >= 0) gamme = 'Bandes'; // Marque Verte (gamme blanche)
    else if (n.indexOf('COLLIER') >= 0 || n.indexOf('CERVICAL') >= 0) gamme = 'Cervical (colliers)';
    else if (n.indexOf('LOMB') >= 0 || n.indexOf('CEINTURE') >= 0) gamme = 'Dos / Lombaire (ceintures)';
    else if (n.indexOf('GENOU') >= 0 || n.indexOf('GENU') >= 0) gamme = 'Genou (genouillères)';
    else if (n.indexOf('CHEV') >= 0 || n.indexOf('MALLEO') >= 0 || n.indexOf('LIGACAST') >= 0 || n.indexOf('LIGASTEP') >= 0 || n.indexOf('WALKER') >= 0 || n.indexOf('SPRYSTEP') >= 0) gamme = 'Cheville / Pied';
    else if (n.indexOf('CUISSARD') >= 0) gamme = 'Cuisse';
    else if (n.indexOf('POIGNET') >= 0 || n.indexOf('POIGN') >= 0 || n.indexOf('MAIN') >= 0 || n.indexOf('RHIZO') >= 0 || n.indexOf('POUCE') >= 0) gamme = 'Poignet / Main';
    else if (n.indexOf('EPAUL') >= 0 || n.indexOf('COUDE') >= 0 || n.indexOf('COUDIERE') >= 0 || n.indexOf('EPI') >= 0) gamme = 'Épaule / Coude';
    // BUGFIX (v4.94→v5.04) : la sous-categorie fournisseur "Bas" a ete corrompue en "Autre" sur une
    // partie du catalogue (l'auto-classificateur generique de l'app ecrit "Autre"/"Non classe" par
    // defaut, et catSauvegarder() l'a re-ecrit en dur par-dessus la vraie donnee fournisseur a un
    // moment donne). On detecte donc directement chaussettes/bas/collants/bas-cuisse par leur nom,
    // independamment de la sous-categorie, pour ne plus dependre de cette donnee corrompue.
    // (v5.05) Compression decoupee en sous-classes par type de produit.
    else if (n.indexOf('CHAU.') >= 0) gamme = 'Compression - Chaussettes ' + ((n.indexOf('VENOFLEX')>=0||n.indexOf('CLINIC')>=0) ? 'Original/Clinic' : 'Premium');
    else if (n.indexOf('COLLANT') >= 0) gamme = 'Compression - Collants ' + ((n.indexOf('VENOFLEX')>=0||n.indexOf('CLINIC')>=0) ? 'Original/Clinic' : 'Premium');
    else if (n.indexOf('B.CUISSE') >= 0 || n.indexOf('MI-BAS') >= 0) gamme = 'Compression - Bas ' + ((n.indexOf('VENOFLEX')>=0||n.indexOf('CLINIC')>=0) ? 'Original/Clinic' : 'Premium');
    else if (n.indexOf('VENOFLEX') >= 0 || n.indexOf('CLINIC') >= 0 || n.indexOf('BIFLEX') >= 0) gamme = 'Compression - Autre Original/Clinic';
    else if (/\bCL[123]\b/.test(n)) gamme = 'Compression - Autre Premium'; // classe de compression mentionnee mais type (chaussette/collant/bas) indetermine par le nom, et ni Venoflex ni Clinic -> Premium
    else if (fam === 'Bas') gamme = 'Compression - Bas Premium';
    else if (fam && fam !== 'Autre' && fam !== 'Non classe' && fam !== 'Non classé') gamme = fam; // repli 1 : Famille fournisseur (Lingerie/Maillots, Prothèses mamaires, Lymphologie, Vêtements de compression, Bandes, HomeCare Light, Home Care...) — sentinelles d'auto-classif exclues
    else if (marque && marque !== 'Autre' && marque !== 'Non classe' && marque !== 'Non classé') gamme = marque; // repli 2 : Marque/catégorie fournisseur (ex: DONJOY, VEINAX chez Enovis) — sentinelles d'auto-classif exclues
    else gamme = 'Non classé';
    p.famille = gamme;
    // BUGFIX (v4.94) : l'affichage du Catalogue fusionne via "saved.famille || p.famille" (le
    // catalogue sauvegardé prioritaire sur le produit lui-même) — sans mettre aussi à jour cette
    // copie, l'ancienne valeur ("THUASNE" générique de l'import) continuait à s'afficher malgré la
    // mise à jour de p.famille. On synchronise donc aussi labo.catalogue[clé].
    if (!labo.catalogue) labo.catalogue = {};
    var keyCat = p.ean || p.nom;
    if (!labo.catalogue[keyCat]) labo.catalogue[keyCat] = {};
    labo.catalogue[keyCat].famille = gamme;
    compteur[gamme] = (compteur[gamme] || 0) + 1;
  });
  condSauvegarder();
  // Synchroniser immédiatement le tableau Catalogue (catProduits est une copie indépendante
  // construite au chargement du labo — sans ce bloc, la colonne Gamme labo y restait affichée à
  // l'ancienne valeur tant que l'onglet Catalogue n'était pas rechargé manuellement).
  if (typeof catProduits !== 'undefined' && catProduits.length > 0 && catLaboActif === condLaboActif) {
    var parFamille = {};
    (labo.produits || []).forEach(function(p) { parFamille[p.ean || p.nom] = p.famille; });
    catProduits.forEach(function(cp) {
      var key = cp.ean || cp.nom;
      if (parFamille.hasOwnProperty(key)) cp.famille = parFamille[key];
    });
    if (typeof catRenderTable === 'function') catRenderTable();
  }
  var detail = Object.keys(compteur).sort(function(a,b){ return compteur[b]-compteur[a]; })
    .map(function(k){ return '- ' + k + ' : ' + compteur[k]; }).join('\n');
  alert('Classement par zone anatomique appliqué sur ' + (labo.produits||[]).length + ' produits (colonne Gamme labo).\n\n' + detail + '\n\nVa dans Catalogue pour vérifier et corriger les cas limites à la main si besoin.');
}

function condUpdateMarche(i, key, val) {
  if (!condLaboActif || !condLabos[condLaboActif]) return;
  var m = (condLabos[condLaboActif].marches_negocies || [])[i];
  if (!m) return;
  m[key] = key === 'rem' ? parseFloat(val)||0 : val.trim();
  condSauvegarder();
}

function condSupprimerMarche(i) {
  if (!condLaboActif || !condLabos[condLaboActif]) return;
  condLabos[condLaboActif].marches_negocies.splice(i, 1);
  condRenderMarches();
  condSauvegarder();
}

// ===== PALIERS PAR NOMBRE DE REFERENCES =====
function condRenderPaliers() {
  var container = document.getElementById('cond-paliers-list');
  if (!container) return;
  var labo = condLabos[condLaboActif];
  if (!labo) return;
  var paliers = labo.paliers_references || [];
  var inS = 'font-size:12px;padding:4px 8px;border:1px solid var(--border);border-radius:var(--radius-sm);background:var(--surface2);';
  if (paliers.length === 0) {
    container.innerHTML = '<p style="font-size:12px;color:var(--text-ter);padding:8px 0">Aucun palier defini. Cliquez sur + Palier.</p>';
    return;
  }
  var sorted = paliers.slice().sort(function(a,b){ return (a.nb_refs||0) - (b.nb_refs||0); });
  container.innerHTML = sorted.map(function(p) {
    var i = paliers.indexOf(p);
    return '<div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;background:var(--surface2);padding:8px 10px;border-radius:var(--radius-sm);border-left:3px solid var(--accent)">' +
      '<span style="font-size:11px;color:var(--text-sec);white-space:nowrap">A partir de</span>' +
      '<input type="number" value="' + (p.nb_refs||0) + '" min="0" step="1" style="' + inS + 'width:70px;font-weight:600" oninput="condUpdatePalier(' + i + ',\'nb_refs\',this.value)">' +
      '<span style="font-size:11px;color:var(--text-sec);white-space:nowrap">references → remise</span>' +
      '<input type="number" value="' + (p.remise||0) + '" min="0" max="60" step="0.5" style="' + inS + 'width:60px;font-weight:600;color:var(--accent-text)" oninput="condUpdatePalier(' + i + ',\'remise\',this.value)"> %' +
      '<button type="button" onclick="condSupprimerPalier(' + i + ')" style="font-size:13px;color:var(--danger);background:none;border:none;cursor:pointer">×</button>' +
      '</div>';
  }).join('');
}

function condAjouterPalier() {
  if (!condLaboActif || !condLabos[condLaboActif]) return;
  if (!condLabos[condLaboActif].paliers_references) condLabos[condLaboActif].paliers_references = [];
  condLabos[condLaboActif].paliers_references.push({ nb_refs:0, remise:0 });
  condRenderPaliers();
  condSauvegarder();
}

function condUpdatePalier(i, key, val) {
  if (!condLaboActif || !condLabos[condLaboActif]) return;
  var p = (condLabos[condLaboActif].paliers_references || [])[i];
  if (!p) return;
  p[key] = parseFloat(val) || 0;
  condSauvegarder();
}

function condSupprimerPalier(i) {
  if (!condLaboActif || !condLabos[condLaboActif]) return;
  condLabos[condLaboActif].paliers_references.splice(i, 1);
  condRenderPaliers();
  condSauvegarder();
}

function condSauvegarderType(v) {
  if (!condLaboActif || !condLabos[condLaboActif]) return;
  condLabos[condLaboActif].type = v;
  condSauvegarder();
  try { dashboardRender(); } catch(e) {}
}

function condAutoSave() {
  if (!condLaboActif || !condLabos[condLaboActif]) return;
  condLabos[condLaboActif].nom = document.getElementById('cond-labo-nom').value || '';
  condLabos[condLaboActif].dateEval = document.getElementById('cond-date-eval').value || '';
  condLabos[condLaboActif].mbActuel = parseFloat(document.getElementById('cond-mb-actuel').value) || 0;
  condLabos[condLaboActif].margeActuelle = parseFloat(document.getElementById('cond-marge-actuelle').value) || 0;
  condLabos[condLaboActif].tva = parseFloat(document.getElementById('cond-tva').value) || 5.5;
  var ve = document.getElementById('cond-tarif-validite');
  if (ve) condLabos[condLaboActif].tarifValidite = ve.value || '';
  condUpdateDiag();
  condRenderTabs();
  condCalc();
}

// v7.16 : persistance LÉGÈRE unique de condLabos en localStorage.
// Le condLabos complet (tous produits chargés) pèse ~18 Mo en localStorage (quota ~5 Mo) :
// les écritures directes JSON.stringify(condLabos) échouaient systématiquement ou
// saturaient le quota pour toutes les autres clés (_osph_*, _last_gh_load...).
// Ce helper exclut labo.produits et ne garde que produits_calc (données calculées par EAN).
function condPersistLight() {
  try {
    var condLabosLight = {};
    Object.keys(condLabos).forEach(function(id) {
      var labo = condLabos[id];
      var laboLight = {};
      Object.keys(labo).forEach(function(k) {
        if (k === 'produits' || k === 'produits_calc') return;
        laboLight[k] = labo[k];
      });
      if (labo.produits && labo.produits.length > 0) {
        laboLight.produits_calc = labo.produits
          .filter(function(p) { return p.pv_ttc || p.pa_net || p.marche_id; })
          .map(function(p) {
            return { ean: String(Math.round(Number(p.ean))), pv_ttc: p.pv_ttc||0, pv_ht: p.pv_ht||0, mbu: p.mbu||0, mb_pct: p.mb_pct||0, pa_net: p.pa_net||0, marche_id: p.marche_id||null };
          });
      }
      condLabosLight[id] = laboLight;
    });
    localStorage.setItem('cond_labos', JSON.stringify(condLabosLight));
  } catch(e) {
    // Pas d'alert() bloquant — le localStorage n'est qu'un cache de session,
    // la vraie sauvegarde passe par GitHub (condSyncGitHubAuto).
    console.warn('[Calculateur] cond_labos non persisté en localStorage (' + e.message + ') — sauvegarde GitHub inchangée.');
  }
}

function condSauvegarder() {
  condAutoSave();
  condPersistLight();
  var btn = document.querySelector('[onclick="condSauvegarder()"]');
  if (btn) { btn.textContent = 'Sauvegarde !'; setTimeout(function(){ btn.textContent = 'Sauvegarder'; }, 1500); }
  condSyncGitHubAuto();
}

