// v7.78 : seuil de marge paramétrable (couleur verte/rouge des tableaux
// Décision RDV). localStorage par poste, défaut 28 %.
var decSeuilMargeVal = null;
function decSeuilMarge() {
  if (decSeuilMargeVal !== null) return decSeuilMargeVal;
  var v = parseFloat(localStorage.getItem('dec_seuil_marge'));
  decSeuilMargeVal = (!isNaN(v) && v > 0 && v < 100) ? v : 28;
  return decSeuilMargeVal;
}
function decSeuilMargeChanger(v) {
  v = parseFloat(String(v).replace(',', '.'));
  if (isNaN(v) || v <= 0 || v >= 100) return;
  decSeuilMargeVal = v;
  try { localStorage.setItem('dec_seuil_marge', String(v)); } catch (e) {}
  if (decCurrentStats && decCurrentStats.labo) decAfficherResume(decCurrentStats.labo);
}

function decToggleFiltreCatalogue(checked) {
  decFiltreCatalogue = !!checked;
  if (decCurrentStats && decCurrentStats.labo) decAfficherResume(decCurrentStats.labo);
}

function decAfficherResume(labo) {
  var el = document.getElementById('dec-resume');
  if (!el || !decOspharmProds || !decOspharmProds[labo]) return;
  var selP = document.getElementById('dec-periode');
  if (selP) selP.value = decGetPeriode();
  var prodsBruts = decOspharmProds[labo];
  // Filtre "catalogue" : ne garder que les produits Ospharm dont l'EAN existe dans le catalogue du
  // labo correspondant dans le Calculateur (condLabos[x].produits) — evite d'afficher des refs
  // remontees par Ospharm sous le meme nom de labo mais jamais importees/suivies ici (ex: gammes
  // non distribuees par la pharmacie, doublons de nom de laboratoire chez Ospharm, etc.).
  var laboObj = decTrouverLaboObj(labo);
  var catalogueEans = null;
  if (laboObj && laboObj.produits && laboObj.produits.length > 0) {
    catalogueEans = {};
    laboObj.produits.forEach(function(p){ if (p.ean) catalogueEans[String(p.ean).replace(/\D/g,'')] = true; });
  }
  var filtreActif = decFiltreCatalogue && catalogueEans;
  var prods = filtreActif ? prodsBruts.filter(function(p){ return p.ean && catalogueEans[String(p.ean).replace(/\D/g,'')]; }) : prodsBruts;
  var nbExclus = prodsBruts.length - prods.length;
  var sorted = prods.slice().sort(function(a,b){ return b.caht - a.caht; });
  var totCaht = 0, totMarge = 0, totStock = 0, totQte = 0;
  for (var i = 0; i < prods.length; i++) {
    totCaht    += prods[i].caht;
    totMarge   += prods[i].marge;
    totStock   += prods[i].stock;
    totQte     += prods[i].qte;
  }
  var tauxMarge = totCaht > 0 ? (totMarge / totCaht) * 100 : 0;
  var nbRefs = prods.filter(function(p){ return p.caht > 0; }).length;
  var periode = decGetPeriode();
  var mois = periode === 'encours' ? decMoisEchus() : 12;
  var caAnnu = mois > 0 ? totCaht * 12 / mois : totCaht;
  var margeAnnu = mois > 0 ? totMarge * 12 / mois : totMarge;
  var html = '<strong style="font-size:13px">' + labo + '</strong>';
  html += '<span style="font-size:10px;color:var(--text-ter);margin-left:8px">' + (periode === 'encours' ? 'ann\u00e9e en cours \u00b7 ' + mois + ' mois \u00e9chus' : 'ann\u00e9e liss\u00e9e \u00b7 12 mois') + '</span>';
  if (catalogueEans) {
    html += '<label style="display:inline-flex;align-items:center;gap:5px;margin-left:14px;font-size:11px;color:var(--text-sec);cursor:pointer">' +
      '<input type="checkbox" ' + (decFiltreCatalogue ? 'checked' : '') + ' onchange="decToggleFiltreCatalogue(this.checked)"> ' +
      'Catalogue uniquement' + (nbExclus > 0 ? ' <span style="color:var(--text-ter)">(' + nbExclus + ' ref. Ospharm hors catalogue masqu\u00e9' + (nbExclus>1?'es':'e') + ')</span>' : '') +
      '</label>';
  }
  html += '<label style="display:inline-flex;align-items:center;gap:5px;margin-left:14px;font-size:11px;color:var(--text-sec)" title="Seuil du taux de marge : vert au-dessus, rouge en dessous — mémorisé sur ce poste">Seuil marge <input type="number" value="' + decSeuilMarge() + '" min="1" max="99" step="0.5" style="width:56px;font-size:11px;padding:3px 6px;border:1px solid var(--border);border-radius:var(--radius-sm);text-align:center" onchange="decSeuilMargeChanger(this.value)"> %</label>';
  html += '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(120px,1fr));gap:8px;margin:8px 0 12px">';
  html += '<div><span style="font-size:10px;color:var(--text-ter)">CA p\u00e9riode HT</span><br><strong>' + Math.round(totCaht).toLocaleString('fr') + ' \u20ac</strong></div>';
  if (periode === 'encours') html += '<div><span style="font-size:10px;color:var(--text-ter)">CA annualis\u00e9</span><br><strong>' + Math.round(caAnnu).toLocaleString('fr') + ' \u20ac</strong></div>';
  html += '<div><span style="font-size:10px;color:var(--text-ter)">Marge totale</span><br><strong>' + Math.round(totMarge).toLocaleString('fr') + ' \u20ac</strong></div>';
  html += '<div><span style="font-size:10px;color:var(--text-ter)">Taux de marge</span><br><strong>' + tauxMarge.toFixed(1) + '%</strong></div>';
  html += '<div><span style="font-size:10px;color:var(--text-ter)">Références</span><br><strong>' + nbRefs + '</strong></div>';
  html += '<div><span style="font-size:10px;color:var(--text-ter)">Stock (unités)</span><br><strong>' + Math.round(totStock).toLocaleString('fr') + '</strong></div>';
  html += '</div>';
  var th = 'padding:6px 8px;font-size:10px;font-weight:600;text-transform:uppercase;background:#e8f5f0;text-align:right;border-bottom:1px solid var(--border)';
  var prodsN1 = (decOspharmProdsN1 && decOspharmProdsN1[labo]) ? decOspharmProdsN1[labo] : null;
  var hasN1 = !!prodsN1;
  // v7.46 : période de référence Ospharm visible au niveau des champs
  // v7.47 : + référence du stock (LGPI daté ou Ospharm)
  html += decOsphPeriodeLigne(hasN1, labo);
  html += '<div style="overflow-x:auto"><table style="width:auto;border-collapse:collapse;font-size:11px;table-layout:auto">';
  html += '<thead><tr>';
  html += '<th style="' + th + ';text-align:left">EAN</th>';
  html += '<th style="' + th + ';text-align:left">Produit</th>';
  if (!hasN1) html += '<th style="' + th + '" title="' + decOsphPeriodeTitle('N') + '">Qté</th>';
  if (hasN1) {
    html += '<th style="' + th + '" title="' + decOsphPeriodeTitle('N1') + '">Qté N-1</th>';
    html += '<th style="' + th + '" title="' + decOsphPeriodeTitle('N') + '">Qté N</th>';
    html += '<th style="' + th + '">Évol %</th>';
  }
  html += '<th style="' + th + '">CA HT</th>';
  html += '<th style="' + th + '">Marge</th>';
  html += '<th style="' + th + '">Taux</th>';
  html += '<th style="' + th + '" title="' + decStockRefTitle(labo) + '">Stock</th>';
  html += '</tr></thead><tbody>';
  var totQteN1 = 0, totQteN1Found = false;
  for (var i = 0; i < sorted.length; i++) {
    var p = sorted[i];
    var tm = p.caht > 0 ? (p.marge / p.caht * 100) : 0;
    var bg = i % 2 === 0 ? '#fff' : 'var(--surface2)';
    var td = 'padding:5px 8px;border-bottom:0.5px solid var(--border);text-align:right;background:' + bg;
    html += '<tr>';
    html += '<td style="' + td + ';text-align:left;white-space:nowrap;font-family:monospace;font-size:10px;color:var(--text-ter)">' + (p.ean || '') + '</td>';
    html += '<td style="' + td + ';text-align:left;white-space:nowrap">' + p.lib + '</td>';
    if (!hasN1) html += '<td style="' + td + '">' + Math.round(p.qte).toLocaleString('fr') + '</td>';
    if (hasN1) {
      var qN1 = decTrouverQteN1(p, prodsN1);
      if (qN1 !== null) { totQteN1 += qN1; totQteN1Found = true; }
      var evol = (qN1 !== null && qN1 > 0) ? ((p.qte - qN1) / qN1 * 100) : null;
      html += '<td style="' + td + (qN1 === null ? ';color:var(--text-ter)' : '') + '">' + (qN1 === null ? '—' : Math.round(qN1).toLocaleString('fr')) + '</td>';
      html += '<td style="' + td + '">' + Math.round(p.qte).toLocaleString('fr') + '</td>';
      if (evol === null) {
        html += '<td style="' + td + ';color:var(--text-ter)">—</td>';
      } else {
        var evolColor = evol >= 0 ? 'var(--accent-text)' : '#c01c28';
        html += '<td style="' + td + ';color:' + evolColor + ';font-weight:600">' + (evol >= 0 ? '+' : '') + evol.toFixed(1) + '%</td>';
      }
    }
    html += '<td style="' + td + '">' + Math.round(p.caht).toLocaleString('fr') + ' €</td>';
    html += '<td style="' + td + '">' + Math.round(p.marge).toLocaleString('fr') + ' €</td>';
    html += '<td style="' + td + ';color:' + (tm >= decSeuilMarge() ? 'var(--accent-text)' : '#c01c28') + ';font-weight:600">' + tm.toFixed(1) + '%</td>';
    html += '<td style="' + td + '">' + Math.round(p.stock).toLocaleString('fr') + '</td>';
    html += '</tr>';
  }
  var tdT = 'padding:6px 8px;text-align:right;font-weight:700;border-top:2px solid var(--border);background:var(--surface2)';
  html += '<tr>';
  html += '<td style="' + tdT + '"></td>';
  html += '<td style="' + tdT + ';text-align:left">TOTAL (' + nbRefs + ' réf.)</td>';
  if (!hasN1) html += '<td style="' + tdT + '">' + Math.round(totQte).toLocaleString('fr') + '</td>';
  if (hasN1) {
    var evolTot = (totQteN1Found && totQteN1 > 0) ? ((totQte - totQteN1) / totQteN1 * 100) : null;
    html += '<td style="' + tdT + '">' + (totQteN1Found ? Math.round(totQteN1).toLocaleString('fr') : '—') + '</td>';
    html += '<td style="' + tdT + '">' + Math.round(totQte).toLocaleString('fr') + '</td>';
    html += '<td style="' + tdT + (evolTot === null ? '' : (';color:' + (evolTot >= 0 ? 'var(--accent-text)' : '#c01c28'))) + '">' + (evolTot === null ? '—' : (evolTot >= 0 ? '+' : '') + evolTot.toFixed(1) + '%') + '</td>';
  }
  html += '<td style="' + tdT + '">' + Math.round(totCaht).toLocaleString('fr') + ' €</td>';
  html += '<td style="' + tdT + '">' + Math.round(totMarge).toLocaleString('fr') + ' €</td>';
  html += '<td style="' + tdT + ';color:' + (tauxMarge >= decSeuilMarge() ? 'var(--accent-text)' : '#c01c28') + '">' + tauxMarge.toFixed(1) + '%</td>';
  html += '<td style="' + tdT + '">' + Math.round(totStock).toLocaleString('fr') + '</td>';
  html += '</tr></tbody></table></div>';
  el.innerHTML = html;
  el.style.display = 'block';
  decCurrentStats = { labo: labo, caht: caAnnu, caPeriode: totCaht, margeEur: margeAnnu, taux: tauxMarge, mois: mois, periode: periode, nbRefs: nbRefs };
  decAfficherConditions(labo);
  decAfficherCarte(labo);
  decAfficherOffresSpec(labo);
  decAfficherTheaAnalyse(labo);
  decRenderStockTarget();
}

// Repere visuel + garde-fou : montre clairement a quel labo le prochain import "Stock reel LGPI"
// va s'appliquer (celui actuellement affiche), et desactive le champ tant qu'aucun labo n'est affiche
// pour eviter d'appliquer un stock au mauvais labo sans s'en rendre compte.
function decRenderStockTarget() {
  var el = document.getElementById('dec-stock-target');
  var fileInput = document.getElementById('dec-file-stock');
  var labo = decCurrentStats ? decCurrentStats.labo : null;
  var pret = labo && decOspharmProds && decOspharmProds[labo];
  if (el) {
    el.innerHTML = pret
      ? 'Stock LGPI pour : <strong style="color:var(--accent-text)">' + labo + '</strong>'
      : '<span style="color:var(--warn)">⚠ Affiche d\'abord un labo (recherche ci-dessus ou Vue COALIA) avant d\'importer le stock.</span>';
  }
  if (fileInput) fileInput.disabled = !pret;
}


// ===== DECISION RDV : CONDITIONS LABO + VERDICT =====
var decCurrentStats = null;
var decCondCurrent = null;

function decGetPeriode() {
  try { var p = localStorage.getItem('decPeriode'); return p === 'encours' ? 'encours' : 'lissee'; } catch(e) { return 'lissee'; }
}
function decMoisEchus(d) {
  // Mois échus depuis le 1er janvier (en juin -> 5 : janv a mai). En janvier, repli sur 12.
  d = d || new Date();
  var m = d.getMonth();
  return m === 0 ? 12 : m;
}
function decChangerPeriode() {
  var sel = document.getElementById('dec-periode');
  if (sel) { try { localStorage.setItem('decPeriode', sel.value); } catch(e) {} }
  if (decCurrentStats) decAfficherResume(decCurrentStats.labo);
}

function decGetCondData() {
  try { return JSON.parse(localStorage.getItem('decCondLabos') || '{}'); } catch(e) { return {}; }
}
function decSaveCondData(d) {
  try { localStorage.setItem('decCondLabos', JSON.stringify(d)); } catch(e) {}
}
function decGetSeuils() {
  var s = { caOui: 5000, remOui: 35 };
  try {
    var saved = JSON.parse(localStorage.getItem('decSeuils') || '{}');
    if (saved.caOui > 0) s.caOui = saved.caOui;
    if (saved.remOui > 0) s.remOui = saved.remOui;
  } catch(e) {}
  return s;
}
function decParseUG(str) {
  // "12+2" -> 2/(12+2) = 14.3% ; "10" -> 10%
  if (!str) return 0;
  str = String(str).trim();
  var m = str.match(/^(\d+)\s*\+\s*(\d+)$/);
  if (m) {
    var a = parseFloat(m[1]), o = parseFloat(m[2]);
    return (a + o) > 0 ? (o / (a + o)) * 100 : 0;
  }
  var n = parseFloat(str.replace(',', '.'));
  return isNaN(n) ? 0 : n;
}
function decNormaliserCond(c) {
  // Migration ancien format { remise:'30' } -> marches[]
  c = c || {};
  if (!c.marches || !c.marches.length) {
    var rem = parseFloat(c.remise);
    c.marches = [{ nom: 'G\u00e9n\u00e9ral', mots: '', remise: isNaN(rem) ? '' : rem }];
  }
  if (c.ug === undefined) c.ug = '';
  if (c.rfa === undefined) c.rfa = '';
  if (c.franco === undefined) c.franco = '';
  if (c.seuilCA === undefined || c.seuilRem === undefined) {
    var defS = decGetSeuils();
    if (c.seuilCA === undefined) c.seuilCA = defS.caOui;
    if (c.seuilRem === undefined) c.seuilRem = defS.remOui;
  }
  if (!c.marchesRetenus) c.marchesRetenus = [];
  if (c.dateDebutEngagement === undefined) c.dateDebutEngagement = '';
  if (c.dateFinEngagement === undefined) c.dateFinEngagement = '';
  if (!c.offresSpec) c.offresSpec = [];
  c.offresSpec.forEach(function(o) {
    if ((o.seuils === undefined || o.remises === undefined) && o.paliers) {
      var p = decParsePaliers(o.paliers);
      o.seuils = p.map(function(x){ return x.seuil; }).join(', ');
      o.remises = p.map(function(x){ return x.remise; }).join(', ');
    }
    if (o.seuils === undefined) o.seuils = '';
    if (o.remises === undefined) o.remises = '';
    delete o.paliers;
  });
  delete c.remise;
  return c;
}
// Match un mot-cle en tant que MOT ENTIER (limite de mot), pas une simple sous-chaine -
// sinon le mot-cle "BIAFINE" matche aussi "CICABIAFINE" (sous-chaine presente), ce qui est faux.
function motCleMatch(lib, motCle) {
  if (!motCle) return false;
  var echappe = motCle.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  try { return new RegExp('\\b' + echappe + '\\b').test(lib); } catch(e) { return lib.indexOf(motCle) !== -1; }
}
function decAffecterMarches(labo, marches, prodsOverride, eanToMarche) {
  // Affecte chaque produit Ospharm a son marche :
  // 1) PRIORITE : marche officiel saisi dans le Catalogue (eanToMarche, par EAN), si le produit y est connu.
  //    - marche renseigne et correspondant a un marche negocie -> ce marche
  //    - marche vide ou "Non classe" (declasse volontairement) -> HORS MARCHE (exclu des stats, pas de fallback mots-cles)
  // 2) Produit absent du catalogue (EAN inconnu) -> 1er marche dont un mot-cle matche le libelle,
  //    sinon 1er marche sans mots-cles (fourre-tout).
  var prods = prodsOverride || ((typeof decOspharmProds !== 'undefined' && decOspharmProds && decOspharmProds[labo]) ? decOspharmProds[labo] : []);
  var stats = [], motsM = [];
  var idxDef = -1; // -1 = aucun marche "fourre-tout" designe (mots-cles vides sur aucun marche) -> hors marche par defaut
  var labelToIdx = {};
  for (var j = 0; j < marches.length; j++) {
    stats.push({ ca: 0, nb: 0 });
    motsM.push(String(marches[j].mots || '').split(',').map(function(m){ return m.trim().toUpperCase(); }).filter(function(m){ return m.length > 0; }));
    labelToIdx[String(marches[j].nom || '').toUpperCase()] = j;
  }
  for (var j = 0; j < marches.length; j++) { if (motsM[j].length === 0) { idxDef = j; break; } }
  var caTot = 0, caPond = 0;
  for (var i = 0; i < prods.length; i++) {
    var lib = String(prods[i].lib || '').toUpperCase();
    var idx = -1; // -1 = pas encore tranche (EAN inconnu du catalogue) ; -2 = hors marche explicite (catalogue)
    var cleanEan = prods[i].ean ? String(prods[i].ean).replace(/\D/g, '') : '';
    if (eanToMarche && cleanEan && eanToMarche.hasOwnProperty(cleanEan)) {
      var mCat = String(eanToMarche[cleanEan] || '').toUpperCase();
      idx = labelToIdx.hasOwnProperty(mCat) ? labelToIdx[mCat] : -2;
    }
    if (idx === -1) {
      for (var j = 0; j < marches.length; j++) {
        var hit = false;
        for (var k = 0; k < motsM[j].length; k++) { if (motCleMatch(lib, motsM[j][k])) { hit = true; break; } }
        if (hit) { idx = j; break; }
      }
    }
    if (idx < 0) continue; // -1 = EAN inconnu sans mot-cle correspondant -> hors marche ; -2 = declasse au catalogue
    stats[idx].ca += prods[i].caht;
    stats[idx].nb++;
    caTot += prods[i].caht;
    caPond += prods[i].caht * (parseFloat(marches[idx].remise) || 0);
  }
  return { stats: stats, caTot: caTot, remisePonderee: caTot > 0 ? caPond / caTot : (idxDef >= 0 ? (parseFloat(marches[idxDef].remise) || 0) : 0) };
}
function decPersist() {
  if (!decCurrentStats || !decCondCurrent) return;
  var all = decGetCondData();
  all[decCurrentStats.labo] = decCondCurrent;
  decSaveCondData(all);
}
function decUpdMarche(i, key, val) {
  if (!decCondCurrent || !decCondCurrent.marches[i]) return;
  decCondCurrent.marches[i][key] = val;
  decPersist();
  decRefreshAffectation();
}
function decUpdCond(key, val) {
  if (!decCondCurrent) return;
  decCondCurrent[key] = val;
  decPersist();
  decCalculerVerdict();
}
function decAddMarche() {
  if (!decCondCurrent || !decCurrentStats) return;
  decCondCurrent.marches.push({ nom: 'March\u00e9 ' + (decCondCurrent.marches.length + 1), mots: '', remise: '' });
  decPersist();
  decRenderConditions(decCurrentStats.labo);
}
function decDelMarche(i) {
  if (!decCondCurrent || !decCurrentStats) return;
  decCondCurrent.marches.splice(i, 1);
  if (decCondCurrent.marches.length === 0) decCondCurrent.marches.push({ nom: 'G\u00e9n\u00e9ral', mots: '', remise: '' });
  decPersist();
  decRenderConditions(decCurrentStats.labo);
}
function decAddOffreSpec() {
  if (!decCondCurrent || !decCurrentStats) return;
  decCondCurrent.offresSpec.push({ titre: 'Offre volumes', mots: '', seuils: '84, 156', remises: '50, 55' });
  decPersist();
  decRenderConditions(decCurrentStats.labo);
}
function decUpdOffreSpec(i, key, val) {
  if (!decCondCurrent || !decCondCurrent.offresSpec[i]) return;
  decCondCurrent.offresSpec[i][key] = val;
  decPersist();
  if (decCurrentStats) decAfficherOffresSpec(decCurrentStats.labo);
}
function decDelOffreSpec(i) {
  if (!decCondCurrent || !decCurrentStats) return;
  decCondCurrent.offresSpec.splice(i, 1);
  decPersist();
  decRenderConditions(decCurrentStats.labo);
}
function decParseListe(str) {
  return (str || '').split(',').map(function(s){ return parseFloat(s.replace(',', '.').trim()); }).filter(function(n){ return !isNaN(n); });
}
function decParsePaliersSR(seuils, remises) {
  var s = decParseListe(seuils), r = decParseListe(remises), out = [];
  for (var i = 0; i < Math.min(s.length, r.length); i++) out.push({ seuil: s[i], remise: r[i] });
  return out;
}
// Compat ascendante (ancien format "seuil:remise, ...")
function decAddMarcheRetenu() {
  if (!decCondCurrent || !decCurrentStats) return;
  var today = new Date().toISOString().slice(0,10);
  decCondCurrent.marchesRetenus.push({ nom: '', dateDebut: today, dateFin: '', notes: '' });
  decPersist();
  decRenderConditions(decCurrentStats.labo);
}
function decUpdMarcheRetenu(i, key, val) {
  if (!decCondCurrent || !decCondCurrent.marchesRetenus[i]) return;
  decCondCurrent.marchesRetenus[i][key] = val;
  decPersist();
}
function decDelMarcheRetenu(i) {
  if (!decCondCurrent || !decCurrentStats) return;
  decCondCurrent.marchesRetenus.splice(i, 1);
  decPersist();
  decRenderConditions(decCurrentStats.labo);
}
function decParsePaliers(str) {
  var out = [];
  (str || '').split(',').forEach(function(part) {
    var m = part.match(/(\d+(?:[.,]\d+)?)\s*:\s*(\d+(?:[.,]\d+)?)/);
    if (m) out.push({ seuil: parseFloat(m[1].replace(',','.')), remise: parseFloat(m[2].replace(',','.')) });
  });
  return out;
}
function decAfficherOffresSpec(labo) {
  var el = document.getElementById('dec-offres-spec');
  if (!el || !decCondCurrent) return;
  var html = '';
  (decCondCurrent.offresSpec || []).forEach(function(o) {
    if (!o.mots || !o.titre) return;
    var paliers = decParsePaliersSR(o.seuils, o.remises);
    if (paliers.length === 0) return;
    var obligatoires = decParseObligatoires(o.obligatoires);
    html += decTheaAnalyseOffreSpecifique(o.titre, o.mots, paliers, labo, obligatoires);
  });
  el.innerHTML = html;
  el.style.display = html ? 'block' : 'none';
}
function decRefreshAffectation() {
  // Met a jour les CA captes par marche + le verdict, sans re-render (conserve le focus de saisie)
  if (!decCurrentStats || !decCondCurrent) return;
  var aff = decAffecterMarches(decCurrentStats.labo, decCondCurrent.marches);
  for (var i = 0; i < decCondCurrent.marches.length; i++) {
    var s = document.getElementById('dec-m-ca-' + i);
    if (s) s.textContent = Math.round(aff.stats[i].ca).toLocaleString('fr') + ' \u20ac \u00b7 ' + aff.stats[i].nb + ' r\u00e9f.';
  }
  decCalculerVerdict();
}
// ===== PRE-REMPLISSAGE CONDITIONS DEPUIS L'OFFRE THEA =====
function decTheaCondVierge(c) {
  if (!c) return true;
  var m = c.marches || [];
  var aRemise = false;
  for (var i = 0; i < m.length; i++) { if (String(m[i].mots || '').trim() || String(m[i].remise || '').trim() !== '') aRemise = true; }
  return !aRemise && !String(c.ug || '').trim() && !String(c.rfa || '').trim() && !String(c.franco || '').trim();
}
function decTheaPrefillConditions(labo, force) {
  if (String(labo || '').toUpperCase().indexOf('THEA') < 0) return false;
  if (force && !confirm('Remplacer les conditions saisies par celles de l\u2019offre UPP Th\u00e9a (taux du palier recommand\u00e9) ?')) return false;
  // Palier de r\u00e9f\u00e9rence : celui du plan d'action (palier sup. \u00e0 port\u00e9e sinon recommand\u00e9), d\u00e9faut March\u00e9 1
  var a = decTheaAnalyse(labo);
  var palier = (a && (a.nudge || a.reco)) ? (a.nudge || a.reco) : null;
  var niveau = DEC_THEA_NIVEAUX[0];
  if (palier) { for (var i = 0; i < DEC_THEA_NIVEAUX.length; i++) { if (DEC_THEA_NIVEAUX[i].nom === palier.nom) niveau = DEC_THEA_NIVEAUX[i]; } }
  var t = niveau.taux;
  var cond = {
    marches: [
      { nom: 'Th\u00e9alose 15ml',   mots: 'THEALOSE', remise: t.thealose },
      { nom: 'Autres RX 0%',        mots: 'OFTAMAC, BLEPHADEMODEX, NUTROF UNO', remise: 0 },
      { nom: 'Vitabact flacon',     mots: 'VITABACT', remise: t.vitabact_fl },
      { nom: 'Monoprost',           mots: 'MONOPROST', remise: t.monoprost },
      { nom: 'Nutrof Total',        mots: 'NUTROF', remise: t.nutrof180 },
      { nom: 'Cromadoses',          mots: 'CROMA', remise: t.cromadoses },
      { nom: 'Blepha',              mots: 'BLEPHA', remise: t.blepha },
      { nom: 'OTC offre',           mots: 'LARMECRAN, MULTILARM, NAABAK, NUTRILARM, OPHTAKIT, THEALOZ, THEAPHY, ZAGRAPA, ZASPRAY, VITAMINE B12', remise: t.otc },
      { nom: 'Hors offre',          mots: '', remise: 0 }
    ],
    ug: '', rfa: '', franco: 114,
    seuilCA: decGetSeuils().caOui, seuilRem: 30,
    prefillPalier: niveau.nom
  };
  if (!cond.offresSpec || cond.offresSpec.length === 0) {
    cond.offresSpec = [{ titre: 'Offre Vitabact volumes (permanente)', mots: 'VITABACT', seuils: '84, 156', remises: '50, 55' }];
  }
  if (!cond.marchesRetenus || cond.marchesRetenus.length === 0) {
    cond.marchesRetenus = [
      { nom: 'March\u00e9 2 OTC (156u, 50% OTC)', dateDebut: '2026-02-16', dateFin: '2026-12-31', notes: 'Vitabact 50%, Monoprost 4%, Cromadoses 7%, Nutrof 30%, Th\u00e9alose 16,5%' },
      { nom: 'Offre Vitabact volumes (84/156u)', dateDebut: '2026-02-16', dateFin: '2026-12-31', notes: '' }
    ];
  }
  var all = decGetCondData();
  all[labo] = cond;
  decSaveCondData(all);
  decCondCurrent = cond;
  if (force && decCurrentStats) { decRenderConditions(labo); decAfficherOffresSpec(labo); }
  return true;
}

function decAfficherConditions(labo) {
  var all = decGetCondData();
  if (String(labo || '').toUpperCase().indexOf('THEA') >= 0 && decTheaCondVierge(all[labo])) {
    decTheaPrefillConditions(labo, false);
  } else {
    decCondCurrent = decNormaliserCond(all[labo]);
  }
  decRenderConditions(labo);
  decRenderConditionsCommerciales(labo);
  // Charger en arriere-plan l'historique achats du labo correspondant (pour l'analyse de palier par marche)
  var laboObjPourAchats = decTrouverLaboObj(labo);
  if (laboObjPourAchats) {
    var idPourAchats = achGetLaboId(laboObjPourAchats);
    if (idPourAchats && !achatsLabos[idPourAchats]) {
      achChargerGitHub(idPourAchats).then(function(d){ if (d) decRenderPalierAnalyse(); });
    }
  }
}
async function decImporterStockLGPI(input) {
  var file = input.files[0];
  if (!file) return;
  var status = document.getElementById('dec-stock-status');
  var labo = decCurrentStats ? decCurrentStats.labo : null;
  if (!labo || !decOspharmProds || !decOspharmProds[labo]) {
    if (status) { status.textContent = 'Importez d\'abord l\'export Ospharm pour ce labo.'; status.style.color = 'var(--danger)'; }
    return;
  }
  if (status) { status.textContent = 'Lecture export stock LGPI (Excel)...'; status.style.color = 'var(--text-sec)'; }

  try {
    var data = await file.arrayBuffer();
    var wb = XLSX.read(data, { type: 'array' });
    var ws = wb.Sheets[wb.SheetNames[0]];
    var rows = XLSX.utils.sheet_to_json(ws, { defval: '' });

    if (rows.length === 0) { if (status) { status.textContent = 'Fichier vide ou format non reconnu.'; status.style.color = 'var(--danger)'; } return; }

    // Detecter les colonnes par leur libelle (insensible aux variations mineures)
    var cols = Object.keys(rows[0]);
    var colCip = cols.find(function(c){ return c.toLowerCase().indexOf('code cip') >= 0; });
    var colRef = cols.find(function(c){ return c.toLowerCase().indexOf('code r') >= 0 && c.toLowerCase().indexOf('rent') >= 0; });
    var colStockBoite = cols.find(function(c){ return c.toLowerCase().indexOf('stock') >= 0 && c.toLowerCase().indexOf('bo') >= 0; });

    if (!colStockBoite) { if (status) { status.textContent = 'Colonne stock introuvable dans ce fichier.'; status.style.color = 'var(--danger)'; } return; }

    var stockByEan = {};
    var stockByCip = {};
    rows.forEach(function(r) {
      var stock = parseInt(r[colStockBoite]) || 0;
      if (colRef) {
        var ref = String(r[colRef] || '').replace(/\D/g, '');
        if (ref.length >= 8) stockByEan[ref] = stock;
      }
      if (colCip) {
        var cip = String(r[colCip] || '').replace(/\D/g, '');
        if (cip) stockByCip[cip] = stock;
      }
    });

    var maj = 0, applique = {};
    decOspharmProds[labo].forEach(function(p) {
      if (!p.ean) return;
      var pean = String(p.ean).replace(/\D/g, '');
      if (stockByEan[pean] !== undefined) { p.stock = stockByEan[pean]; applique[pean] = p.stock; maj++; }
      else if (stockByCip[pean] !== undefined) { p.stock = stockByCip[pean]; applique[pean] = p.stock; maj++; }
    });

    if (status) { status.textContent = '✓ Stock LGPI (a l\'instant T) mis a jour pour ' + maj + '/' + decOspharmProds[labo].length + ' produit(s) — plus fiable que le stock Ospharm.'; status.style.color = 'var(--accent-text)'; }
    // v7.47 : mémoriser la date d'import du stock LGPI pour ce labo (affichée dans la ligne 📅)
    if (maj > 0) {
      // v7.79 : PERSISTANCE par poste — les valeurs survivent aux sessions et
      // sont ré-appliquées après chaque rechargement du cache GitHub.
      try {
        var all = JSON.parse(localStorage.getItem('_stock_lgpi_data') || '{}');
        all[String(labo).toUpperCase()] = applique;
        localStorage.setItem('_stock_lgpi_data', JSON.stringify(all));
      } catch (e) { console.warn('[Stock LGPI] persistance impossible', e); }
      var dEl = document.getElementById('dec-stock-date');
      var dFR = null;
      if (dEl && dEl.value) { var pp = dEl.value.split('-'); if (pp.length === 3) dFR = pp[2] + '/' + pp[1] + '/' + pp[0]; }
      decStockLgpiDateSet(labo, dFR);
    }
    decAfficherResume(labo);
  } catch(e) {
    if (status) { status.textContent = 'Erreur : ' + e.message; status.style.color = 'var(--danger)'; }
  }
}
function decTrouverLaboObj(labo) {
  var laboUp = String(labo || '').toUpperCase().replace(/\s+/g, ' ').trim();
  if (!laboUp) return null;
  return Object.values(condLabos).find(function(l) {
    if (!l || !l.nom) return false;
    var nomUp = l.nom.toUpperCase().replace(/\s+/g, ' ').trim();
    if (!nomUp) return false;
    return laboUp.indexOf(nomUp) >= 0 || nomUp.indexOf(laboUp) >= 0;
  }) || null;
}
function decRenderConditionsCommerciales(labo) {
  var el = document.getElementById('dec-cond-commerciales');
  if (!el) return;
  var laboObj = decTrouverLaboObj(labo);
  if (!laboObj) { el.innerHTML = ''; el.style.display = 'none'; return; }

  var marches = laboObj.marches_negocies || [];
  var paliers = laboObj.paliers_references || [];
  if (marches.length === 0 && paliers.length === 0) { el.innerHTML = ''; el.style.display = 'none'; return; }

  var html = '<div style="font-size:12px;font-weight:600;margin-bottom:8px">📋 Conditions commerciales — ' + laboObj.nom + ' <span style="font-size:10px;color:var(--text-ter);font-weight:400">(valable toute l\'année, saisi dans l\'onglet Conditions commerciales)</span></div>';

  if (marches.length > 0) {
    // Source de verite : marche officiel saisi produit par produit dans le Catalogue (laboObj.produits).
    // Couvre TOUT EAN present au catalogue, y compris marche vide (= delasse volontairement -> hors marche).
    var eanToMarche = {};
    if (laboObj.produits && laboObj.produits.length) {
      laboObj.produits.forEach(function(p) {
        if (p.ean) eanToMarche[String(p.ean).replace(/\D/g, '')] = p.marche || '';
      });
    }
    // Calculer le CA/refs realises par marche (badges synthetiques)
    var marchesAdapt = marches.map(function(m){ return { nom: m.label, mots: m.mots_cles || '', remise: m.rem || 0 }; });
    var affKenvue = decAffecterMarches(labo, marchesAdapt, undefined, eanToMarche);
    html += '<div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:10px">';
    marches.forEach(function(m, mi) {
      var st = affKenvue.stats[mi] || { ca: 0, nb: 0 };
      html += '<span style="font-size:11px;background:var(--surface3);padding:3px 9px;border-radius:12px;color:var(--text-sec)">' + (m.label||'?') + ' <strong style="color:var(--accent-text)">' + (m.rem||0) + '%</strong>';
      html += ' <span style="color:var(--text-ter)">· ' + Math.round(st.ca).toLocaleString('fr') + ' € · ' + st.nb + ' réf.</span></span>';
    });
    html += '</div>';

    // Tableau detaille produit par produit, regroupe par marche
    var prodsLabo = (typeof decOspharmProds !== 'undefined' && decOspharmProds && decOspharmProds[labo]) ? decOspharmProds[labo] : [];
    if (prodsLabo.length > 0) {
      var motsM = marches.map(function(m){ return String(m.mots_cles || '').split(',').map(function(x){ return x.trim().toUpperCase(); }).filter(function(x){ return x.length > 0; }); });
      var idxDefM = -1;
      for (var mj = 0; mj < marches.length; mj++) { if (motsM[mj].length === 0) { idxDefM = mj; break; } }
      var labelToIdxM = {};
      marches.forEach(function(m, mi){ labelToIdxM[String(m.label || '').toUpperCase()] = mi; });
      var groupes = marches.map(function(){ return []; });
      var horsMarche = [];
      prodsLabo.forEach(function(p) {
        var lib = String(p.lib || '').toUpperCase();
        var found = -1; // -1 = a trancher par mots-cles (EAN inconnu) ; -2 = hors marche explicite (catalogue)
        var cleanEan = p.ean ? String(p.ean).replace(/\D/g, '') : '';
        if (cleanEan && eanToMarche.hasOwnProperty(cleanEan)) {
          var mCat = String(eanToMarche[cleanEan] || '').toUpperCase();
          found = labelToIdxM.hasOwnProperty(mCat) ? labelToIdxM[mCat] : -2;
        }
        if (found === -1) {
          for (var mj = 0; mj < marches.length; mj++) {
            for (var k = 0; k < motsM[mj].length; k++) { if (motCleMatch(lib, motsM[mj][k])) { found = mj; break; } }
            if (found >= 0) break;
          }
        }
        if (found >= 0) groupes[found].push(p);
        else horsMarche.push(p); // -1 (EAN inconnu sans mot-cle) et -2 (declasse au catalogue) -> hors marche, jamais de fourre-tout par ordre de liste
      });

      var prodsLaboN1 = (typeof decOspharmProdsN1 !== 'undefined' && decOspharmProdsN1 && decOspharmProdsN1[labo]) ? decOspharmProdsN1[labo] : null;
      var hasN1Loc = !!prodsLaboN1;
      var thS2 = 'padding:5px 8px;font-size:9px;font-weight:600;text-transform:uppercase;color:var(--text-ter);text-align:right;border-bottom:1px solid var(--border)';
      var tdS2 = 'padding:4px 8px;font-size:11px;text-align:right;border-bottom:0.5px solid var(--border)';
      var ncols = hasN1Loc ? 7 : 4;
      // v7.46 : période de référence Ospharm visible au niveau des champs
      html += decOsphPeriodeLigne(hasN1Loc, labo);
      html += '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;margin-top:4px">';
      html += '<thead><tr><th style="' + thS2 + ';text-align:left">Produit</th>';
      if (hasN1Loc) { html += '<th style="' + thS2 + '" title="' + decOsphPeriodeTitle('N1') + '">Qté N-1</th><th style="' + thS2 + '" title="' + decOsphPeriodeTitle('N') + '">Qté N</th><th style="' + thS2 + '">Évol %</th>'; }
      html += '<th style="' + thS2 + '">CA HT</th><th style="' + thS2 + '">Marge</th><th style="' + thS2 + '">Taux</th></tr></thead><tbody>';
      marches.forEach(function(m, mi) {
        var grp = groupes[mi].slice().sort(function(a,b){ return b.caht - a.caht; });
        if (grp.length === 0) return;
        var sousCa = grp.reduce(function(s,p){ return s + p.caht; }, 0);
        var sousQteN = grp.reduce(function(s,p){ return s + (p.qte||0); }, 0);
        var sousQteN1 = 0, sousQteN1Found = false;
        if (hasN1Loc) { grp.forEach(function(p){ var q1 = decTrouverQteN1(p, prodsLaboN1); if (q1 !== null) { sousQteN1 += q1; sousQteN1Found = true; } }); }
        var sousEvol = (sousQteN1Found && sousQteN1 > 0) ? ((sousQteN - sousQteN1) / sousQteN1 * 100) : null;
        var sousEvolTxt = sousEvol === null ? '' : (' · ' + (sousEvol >= 0 ? '+' : '') + sousEvol.toFixed(1) + '%');
        html += '<tr><td colspan="' + ncols + '" style="padding:6px 8px;font-size:10px;font-weight:700;color:var(--accent-text);background:var(--surface2);text-align:left">' + m.label + ' (' + (m.rem||0) + '%) — ' + grp.length + ' réf. · ' + Math.round(sousCa).toLocaleString('fr') + ' €' + (hasN1Loc ? ' · Qté ' + (sousQteN1Found ? Math.round(sousQteN1).toLocaleString('fr') : '—') + ' → ' + Math.round(sousQteN).toLocaleString('fr') + sousEvolTxt : '') + '</td></tr>';
        grp.forEach(function(p) {
          var tx = p.caht > 0 ? (p.marge / p.caht * 100) : 0;
          html += '<tr><td style="' + tdS2 + ';text-align:left;white-space:nowrap;max-width:280px;overflow:hidden;text-overflow:ellipsis">' + (p.lib||'') + '</td>';
          if (hasN1Loc) {
            var qN1 = decTrouverQteN1(p, prodsLaboN1);
            html += '<td style="' + tdS2 + (qN1 === null ? ';color:var(--text-ter)' : '') + '">' + (qN1 === null ? '—' : Math.round(qN1).toLocaleString('fr')) + '</td>';
            html += '<td style="' + tdS2 + '">' + Math.round(p.qte||0).toLocaleString('fr') + '</td>';
            var evolP = (qN1 !== null && qN1 > 0) ? ((p.qte - qN1) / qN1 * 100) : null;
            html += '<td style="' + tdS2 + (evolP === null ? ';color:var(--text-ter)' : (';color:' + (evolP >= 0 ? 'var(--accent-text)' : '#c01c28'))) + '">' + (evolP === null ? '—' : (evolP >= 0 ? '+' : '') + evolP.toFixed(1) + '%') + '</td>';
          }
          html += '<td style="' + tdS2 + '">' + Math.round(p.caht).toLocaleString('fr') + ' €</td>';
          html += '<td style="' + tdS2 + '">' + Math.round(p.marge).toLocaleString('fr') + ' €</td>';
          html += '<td style="' + tdS2 + ';color:' + (tx >= decSeuilMarge() ? 'var(--accent-text)' : '#c01c28') + '">' + tx.toFixed(1) + '%</td></tr>';
        });
        // Ligne de sous-total en pied de groupe — mêmes colonnes que les lignes produit, plus
        // parlant qu'un simple texte d'en-tête pour comparer les marchés entre eux d'un coup d'œil.
        var sousMarge = grp.reduce(function(s,p){ return s + p.marge; }, 0);
        var sousTaux = sousCa > 0 ? (sousMarge / sousCa * 100) : 0;
        var tdTotM = 'padding:4px 8px;font-size:11px;text-align:right;font-weight:700;border-top:1px solid var(--border);border-bottom:1.5px solid var(--accent);background:var(--accent-bg)';
        html += '<tr><td style="' + tdTotM + ';text-align:left">Sous-total ' + m.label + '</td>';
        if (hasN1Loc) {
          html += '<td style="' + tdTotM + '">' + (sousQteN1Found ? Math.round(sousQteN1).toLocaleString('fr') : '—') + '</td>';
          html += '<td style="' + tdTotM + '">' + Math.round(sousQteN).toLocaleString('fr') + '</td>';
          html += '<td style="' + tdTotM + (sousEvol === null ? '' : (';color:' + (sousEvol >= 0 ? 'var(--accent-text)' : '#c01c28'))) + '">' + (sousEvol === null ? '—' : (sousEvol >= 0 ? '+' : '') + sousEvol.toFixed(1) + '%') + '</td>';
        }
        html += '<td style="' + tdTotM + '">' + Math.round(sousCa).toLocaleString('fr') + ' €</td>';
        html += '<td style="' + tdTotM + '">' + Math.round(sousMarge).toLocaleString('fr') + ' €</td>';
        html += '<td style="' + tdTotM + ';color:' + (sousTaux >= decSeuilMarge() ? 'var(--accent-text)' : '#c01c28') + '">' + sousTaux.toFixed(1) + '%</td></tr>';
      });
      if (horsMarche.length > 0) {
        var hCa = horsMarche.reduce(function(s,p){ return s + p.caht; }, 0);
        var hMarge = horsMarche.reduce(function(s,p){ return s + p.marge; }, 0);
        var hTaux = hCa > 0 ? (hMarge / hCa * 100) : 0;
        html += '<tr><td colspan="' + ncols + '" style="padding:6px 8px;font-size:10px;font-weight:700;color:var(--text-ter);background:var(--surface2);text-align:left">Hors marché négocié — ' + horsMarche.length + ' réf. · ' + Math.round(hCa).toLocaleString('fr') + ' €</td></tr>';
        var tdTotH = 'padding:4px 8px;font-size:11px;text-align:right;font-weight:700;border-top:1px solid var(--border);border-bottom:1.5px solid var(--text-ter);background:var(--surface2)';
        html += '<tr><td style="' + tdTotH + ';text-align:left">Sous-total Hors marché</td>';
        if (hasN1Loc) { html += '<td style="' + tdTotH + '">—</td><td style="' + tdTotH + '">' + Math.round(horsMarche.reduce(function(s,p){return s+(p.qte||0);},0)).toLocaleString('fr') + '</td><td style="' + tdTotH + '">—</td>'; }
        html += '<td style="' + tdTotH + '">' + Math.round(hCa).toLocaleString('fr') + ' €</td>';
        html += '<td style="' + tdTotH + '">' + Math.round(hMarge).toLocaleString('fr') + ' €</td>';
        html += '<td style="' + tdTotH + '">' + hTaux.toFixed(1) + '%</td></tr>';
      }
      html += '</tbody></table></div>';
    }
  }

  if (paliers.length > 0) {
    var sortedP = paliers.slice().sort(function(a,b){ return a.nb_refs - b.nb_refs; });
    html += '<div style="font-size:10px;color:var(--text-ter);margin-bottom:4px">Paliers par nombre de références :</div>';
    html += '<div style="display:flex;flex-wrap:wrap;gap:6px">';
    sortedP.forEach(function(p) {
      html += '<span style="font-size:11px;background:var(--surface3);padding:3px 9px;border-radius:12px;color:var(--text-sec)">' + p.nb_refs + ' réf. → <strong style="color:var(--accent-text)">' + p.remise + '%</strong></span>';
    });
    html += '</div>';
  }

  html += '<div style="margin-top:8px"><button type="button" onclick="showTab(\'cond\')" style="font-size:10px;padding:3px 9px;border:1px solid var(--border);border-radius:var(--radius-sm);background:transparent;color:var(--text-sec);cursor:pointer">→ Modifier dans Conditions commerciales</button></div>';

  el.innerHTML = html;
  el.style.display = 'block';
}
function decMoisInclusif(dDebut, dFin) {
  // Duree en mois pleins entre dDebut et dFin, dFin etant INCLUS dans la periode
  // (ex: 01/01/2026 -> 31/12/2026 = 12 mois, pas 11, car le 31/12 fait partie de l'engagement).
  var dFinExcl = new Date(dFin.getFullYear(), dFin.getMonth(), dFin.getDate() + 1);
  var m = (dFinExcl.getFullYear() - dDebut.getFullYear()) * 12 + (dFinExcl.getMonth() - dDebut.getMonth());
  if (dFinExcl.getDate() < dDebut.getDate()) m--;
  return m;
}
