var catLaboActif = null;
var catProduits  = [];   // [{ean, nom, moy, pa_net, pv_ttc, categorie, sous_categorie, marche, palier_id}]
// Limite d'affichage du tableau Catalogue — un grand catalogue (ex: THUASNE, 5000+ refs) en rendu
// complet (inputs + dropdown par ligne) peut geler le navigateur. On affiche un nombre raisonnable
// de lignes par defaut, avec un bouton pour tout afficher si besoin (recherche/filtre a privilegier
// pour les tres gros catalogues plutot que tout afficher d'un coup).
// Pagination du tableau Catalogue — un grand catalogue (ex: THUASNE, 5600+ refs) en rendu complet
// (inputs + dropdown par ligne) peut geler le navigateur si tout est affiché d'un coup. On affiche
// par pages de taille fixe avec navigation, plutot que tout charger en mémoire DOM.
var catPageSize = 300;
var catPage = 0;
// Filtre par Gamme labo — permet d'aller directement a une classe (ex: "Genou (genouillères)")
// sans avoir a feuilleter les pages. Vide = pas de filtre, tout le catalogue.
var catFiltreFamille = '';
function catChangerFiltreFamille(val) {
  catFiltreFamille = val || '';
  catPage = 0;
  catRenderTable();
}
function catChangerPage(delta) {
  catPage = Math.max(0, catPage + delta);
  catRenderTable();
  var tbl = document.getElementById('cat-tbody');
  if (tbl) tbl.scrollIntoView({ block: 'start' });
}
function catAllerPage(n) {
  catPage = Math.max(0, n);
  catRenderTable();
}

