function gibaudInitCatalogue(laboId) {
  if (!condLabos[laboId]) return;
  if (condLabos[laboId].produits && condLabos[laboId].produits.length > 0) return;
  var majEl = document.getElementById('cond-catalogue-maj');
  if (majEl) majEl.textContent = '⏳ Chargement GIBAUD...';
  gibaudLoadCatalogue(function(data) {
    if (!condLabos[laboId]) return;
    condLabos[laboId].produits = data.map(function(p) {
      return Object.assign({}, p, {moy:0,pa_net:0,pv_ttc:0,pv_ht:0,mbu:0,mb_pct:0,rem_cat:0,mois:new Array(12).fill(0)});
    });
    condLabos[laboId].catalogueMaj = new Date().toISOString();
    condLabos[laboId].tarifValidite = '2026-12-31';
    if (majEl) majEl.textContent = data.length + ' produits chargés';
    if (condLaboActif == laboId) { var cs = document.getElementById('cat-labo-sel'); if (cs && cs.value == laboId) catChargeLabo(); }
    condSauvegarder();
  });
}

// ===== THUASNE — Catalogue pré-chargé (Tarif Médical Détaillants Janvier 2026) =====
// Pages incluses : 1-2 (Venoflex), 4-12 (Ortho, Bandes, Mobiderm, Lymphatrex Essential)
// Pages exclues : 3 (sur-mesure Venoflex), 13-19 (sur-mesure, prothèses, lingerie)
// THUASNE_CATALOGUE_DEFAUT supprimé — catalogue chargé depuis produits/1781019340739.json (GitHub)
var THUASNE_CATALOGUE_DEFAUT = [];



function condAppliquerConfigCerave() {
  if (!condLaboActif || !condLabos[condLaboActif]) return;
  var labo = condLabos[condLaboActif];
  if (!labo.marches_negocies) labo.marches_negocies = [];
  function idPal() { return 'p' + Date.now() + Math.floor(Math.random()*100000); }
  function paliersDe(liste) { return liste.map(function(t){ return { id: idPal(), volume: t[0], refs: 0, remise: t[1] }; }); }

  var gammesDef = [
    { marche_id: 'cerave_base',     label: 'CeraVe - Base (18%)',  rem: 18, paliers: [] },
    { marche_id: 'cerave_corps',    label: 'CeraVe - Corps (Laits/Baumes/Intensif)', rem: 18, paliers: paliersDe([[36,3]]) },
    { marche_id: 'cerave_acne',     label: 'CeraVe - Acné',        rem: 18, paliers: paliersDe([[36,3]]) },
    { marche_id: 'cerave_solaires', label: 'CeraVe - Solaires',    rem: 18, paliers: paliersDe([[36,10]]) }
  ];

  gammesDef.forEach(function(def) {
    var m = labo.marches_negocies.find(function(x){ return x.marche_id === def.marche_id; });
    if (!m) {
      m = { label: def.label, marche_id: def.marche_id, rem: def.rem, paliers: [], palier_actif: null, eans: [] };
      labo.marches_negocies.push(m);
    }
    m.label = def.label;
    m.rem = def.rem;
    m.paliers = def.paliers;
    if (!m.eans) m.eans = [];
  });

  // Auto-affecter marche_id par nom produit
  var marchesMap = {};
  labo.marches_negocies.forEach(function(m) { marchesMap[m.marche_id] = m; });

  (labo.produits || []).forEach(function(p) {
    var n = (p.nom || '').toUpperCase();
    var cible = 'cerave_base';
    if (n.indexOf('LAIT') >= 0 || n.indexOf('BAUME') >= 0 || n.indexOf('INTENSIF') >= 0 || n.indexOf('SA LOTION') >= 0 || n.indexOf('SA CREAM') >= 0) cible = 'cerave_corps';
    else if (n.indexOf('ACNE') >= 0 || n.indexOf('BLEMISH') >= 0 || n.indexOf('SALICYLIC') >= 0) cible = 'cerave_acne';
    else if (n.indexOf('SOLAIRE') >= 0 || n.indexOf('SPF') >= 0 || n.indexOf('SUN') >= 0 || n.indexOf('UV') >= 0) cible = 'cerave_solaires';
    p.marche_id = cible;
    p.marche = marchesMap[cible].label;
    var m = marchesMap[cible];
    if (m && p.ean) { var ean = String(p.ean); if (m.eans.indexOf(ean) < 0) m.eans.push(ean); }
  });

  condRenderMarches();
  condSauvegarder();
  alert('Configuration CERAVE appliquée :\n- Base 18% (tous produits)\n- Corps (Laits/Baumes/Intensif) : 18% + 3% palier 36u (en 1 livraison)\n- Acné : 18% + 3% palier 36u (en 1 livraison)\n- Solaires : 18% + 10% palier 36u (en 1 livraison)\n\nProduits affectés automatiquement par nom. Vérifie le catalogue et corrige les cas limites à la main.');
}

function condAppliquerConfigLaRochePosay() {
  if (!condLaboActif || !condLabos[condLaboActif]) return;
  var labo = condLabos[condLaboActif];
  if (!labo.marches_negocies) labo.marches_negocies = [];
  function idPal() { return 'p' + Date.now() + Math.floor(Math.random()*100000); }
  function paliersDe(liste) { return liste.map(function(t){ return { id: idPal(), volume: t[0], refs: 0, remise: t[1] }; }); }

  var dateDebut = '2026-01-01';
  var dateFin   = '2026-12-31';

  var gammesDef = [
    { marche_id: 'lrp_base',      label: 'LRP - Base (16%)',                rem: 16, paliers: [] },
    { marche_id: 'lrp_solaires',  label: 'LRP - Solaires (16%+12% cascade)', rem: 16, cascade: 12, paliers: [] },
    { marche_id: 'lrp_cicaplast', label: 'LRP - Cicaplast Baume',           rem: 16, paliers: paliersDe([[72,6],[144,10]]) },
    { marche_id: 'lrp_effaclar',  label: 'LRP - Effaclar',                  rem: 16, paliers: paliersDe([[60,3],[120,5]]) },
    { marche_id: 'lrp_lipikar',   label: 'LRP - Lipikar',                   rem: 16, paliers: paliersDe([[72,3],[144,5]]) }
  ];

  gammesDef.forEach(function(def) {
    var m = labo.marches_negocies.find(function(x){ return x.marche_id === def.marche_id; });
    if (!m) {
      m = { label: def.label, marche_id: def.marche_id, rem: def.rem, paliers: [], palier_actif: null, eans: [] };
      labo.marches_negocies.push(m);
    }
    m.label = def.label;
    m.rem = def.rem;
    m.paliers = def.paliers;
    if (def.cascade) m.cascade_fixe = def.cascade; // remise cascade fixe (solaires)
    m.date_debut = dateDebut;
    m.date_fin = dateFin;
    if (!m.eans) m.eans = [];
  });

  // Auto-affecter marche_id par nom produit
  var marchesMap = {};
  labo.marches_negocies.forEach(function(m) { marchesMap[m.marche_id] = m; });

  (labo.produits || []).forEach(function(p) {
    var n = (p.nom || '').toUpperCase();
    var cible = 'lrp_base';
    if (n.indexOf('CICAPLAST') >= 0) cible = 'lrp_cicaplast';
    else if (n.indexOf('EFFACLAR') >= 0) cible = 'lrp_effaclar';
    else if (n.indexOf('LIPIKAR') >= 0) cible = 'lrp_lipikar';
    else if (n.indexOf('ANTHELIOS') >= 0 || n.indexOf('SOLAIRE') >= 0 || n.indexOf('UVMUNE') >= 0 || n.indexOf('SPF') >= 0) cible = 'lrp_solaires';
    p.marche_id = cible;
    p.marche = marchesMap[cible].label;
    var m = marchesMap[cible];
    if (m && p.ean) { var ean = String(p.ean); if (m.eans.indexOf(ean) < 0) m.eans.push(ean); }
  });

  condRenderMarches();
  condSauvegarder();
  alert('Configuration LA ROCHE POSAY appliquée :\n- Base 16% (tous produits)\n- Solaires : 16% + 12% cascade fixe\n- Cicaplast : palier 72u +6% / 144u +10% (en 1 livraison)\n- Effaclar : palier 60u +3% / 120u +5% (en 1 livraison)\n- Lipikar : palier 72u +3% / 144u +5% (en 1 livraison)\nValidité : 01/01/2026 → 31/12/2026\n\nProduits affectés automatiquement par nom. Vérifie le catalogue et corrige les cas limites à la main.');
}


