function condAppliquerConfigTopicremNouveauClient() {
  if (!condLaboActif || !condLabos[condLaboActif]) return;
  var labo = condLabos[condLaboActif];
  if (!labo.marches_negocies) labo.marches_negocies = [];
  function idPal() { return 'p' + Date.now() + Math.floor(Math.random()*100000); }

  var gammesDef = [
    { marche_id: 'topicrem_nc_corps_spec', label: 'Nouveau client - Corps Spécifiques (32%)',   rem: 32, paliers: [{ id: idPal(), volume: 8, refs: 0, remise: 32 }] },
    { marche_id: 'topicrem_nc_corps',      label: 'Nouveau client - Corps (40%)',               rem: 40, paliers: [{ id: idPal(), volume: 8, refs: 0, remise: 40 }] },
    { marche_id: 'topicrem_nc_hydrat',     label: 'Nouveau client - Hydratation (44%)',         rem: 44, paliers: [{ id: idPal(), volume: 8, refs: 0, remise: 44 }] },
    { marche_id: 'topicrem_nc_visage',     label: 'Nouveau client - Visage (30%)',              rem: 30, paliers: [{ id: idPal(), volume: 8, refs: 0, remise: 30 }] }
  ];

  gammesDef.forEach(function(def) {
    var m = labo.marches_negocies.find(function(x){ return x.marche_id === def.marche_id; });
    if (!m) {
      m = { label: def.label, marche_id: def.marche_id, rem: def.rem, paliers: [], palier_actif: null, eans: [] };
      labo.marches_negocies.push(m);
    }
    m.label   = def.label;
    m.paliers = def.paliers;
    m.rem     = def.rem;
    m.eans    = []; // reset pour recomposer
  });

  // Auto-composer depuis le catalogue TOPICREM par famille/nom
  var marchesMap = {};
  labo.marches_negocies.forEach(function(m) { marchesMap[m.marche_id] = m; });

  (labo.produits || []).forEach(function(p) {
    var nom = (p.nom || '').toUpperCase();
    var fam = (p.famille || '').toUpperCase();
    var mid = p.marche_id || ''; // marche_id original du catalogue
    var ean = String(p.ean || '');
    if (!ean) return;

    var cible = null;

    // HYDRA+ → Hydratation
    if (nom.indexOf('HYDRA+') >= 0) {
      cible = 'topicrem_nc_hydrat';
    }
    // Corps Spécifiques : MELA Lait unifiant, UR10, UR30, PV/DS, PH5, BABY, SUN PROTECT
    else if (mid === 'corps_spec' || mid === 'sun' || fam.indexOf('M1.') >= 0 || fam.indexOf('M5.') >= 0) {
      cible = 'topicrem_nc_corps_spec';
    }
    // Corps : CICA+, ULTRA-HYDRATANT corps, DA PROTECT Baume, Hygiène, Hiver Mains
    else if (mid === 'corps' || mid === 'hygiene' || mid === 'hiver' || fam.indexOf('M2.') >= 0 || fam.indexOf('M3.') >= 0 || fam.indexOf('HIVER') >= 0) {
      cible = 'topicrem_nc_corps';
    }
    // Visage : AH3, AC CONTROL, MELA Visage, DA PROTECT Visage, MELA Pain
    else if (mid === 'visage' || fam.indexOf('M4.') >= 0) {
      cible = 'topicrem_nc_visage';
    }

    if (cible && marchesMap[cible]) {
      if (marchesMap[cible].eans.indexOf(ean) < 0) {
        marchesMap[cible].eans.push(ean);
      }
      // Affecter marche_id sur le produit
      p.marche_id = cible;
    }
  });

  condRenderMarches();
  condSauvegarder();

  var counts = gammesDef.map(function(d) {
    return d.label.replace('Nouveau client - ','') + ' : ' + (marchesMap[d.marche_id] ? marchesMap[d.marche_id].eans.length : 0) + ' réf.';
  }).join('\n');
  alert('Offre nouveau client TOPICREM configurée et composée automatiquement :\n' + counts + '\n\nPalier : 8 références panachées.');
}

function topicremInitCatalogue(laboId) {
  if (!condLabos[laboId]) return;
  if (condLabos[laboId].produits && condLabos[laboId].produits.length > 0) return;
  condLabos[laboId].produits = TOPICREM_CATALOGUE_DEFAUT.map(function(p) {
    return Object.assign({}, p, {moy:0,pa_net:0,pv_ttc:0,pv_ht:0,mbu:0,mb_pct:0,rem_cat:0,mois:new Array(12).fill(0)});
  });
  condLabos[laboId].catalogueMaj = new Date().toISOString();
  condLabos[laboId].tarifValidite = '2026-12-31';
  condLabos[laboId].francoPort = 150;
}

