var cycleLaboActif = null;

function cycleInit() {
  if (Object.keys(condLabos).length === 0) {
    try {
      var saved = localStorage.getItem('cond_labos');
      if (saved) { condLabos = JSON.parse(saved); }
    } catch(e) {}
  }
  var sel = document.getElementById('cycle-labo-sel');
  if (!sel) return;
  while (sel.options.length > 1) sel.remove(1);
  Object.keys(condLabos)
    .filter(function(id){ return condLabos[id] && condLabos[id].nom; })
    .sort(function(a, b){ return condLabos[a].nom.localeCompare(condLabos[b].nom, 'fr', {sensitivity:'base'}); })
    .forEach(function(id) {
      var opt = document.createElement('option');
      opt.value = id;
      opt.textContent = condLabos[id].nom;
      sel.appendChild(opt);
    });
  if (cycleLaboActif && condLabos[cycleLaboActif]) {
    sel.value = cycleLaboActif;
    cycleRenderAll();
  }
}

function cycleGetData() {
  if (!cycleLaboActif || !condLabos[cycleLaboActif]) return null;
  var labo = condLabos[cycleLaboActif];
  if (!labo.cycleVie) labo.cycleVie = { mappings: [], arrets: [], nouveaux: [] };
  if (!labo.cycleVie.mappings) labo.cycleVie.mappings = [];
  if (!labo.cycleVie.arrets) labo.cycleVie.arrets = [];
  if (!labo.cycleVie.nouveaux) labo.cycleVie.nouveaux = [];
  return labo.cycleVie;
}

function cycleChargeLabo() {
  var sel = document.getElementById('cycle-labo-sel');
  cycleLaboActif = sel && sel.value ? String(sel.value) : null;
  var data = cycleGetData();
  if (data && data.mappings.length === 0) {
    var laboNom = (condLabos[cycleLaboActif] && condLabos[cycleLaboActif].nom || '').toUpperCase();
    if (laboNom.indexOf('AVENE') >= 0 || laboNom.indexOf('AVÈNE') >= 0) {
      data.mappings = AVENE_MAPPINGS_PREFILL.map(function(m){ return Object.assign({}, m); });
    }
  }
  cycleRenderAll();
}

function cycleRenderAll() {
  cycleRenderMappings();
  cycleRenderArrets();
  cycleRenderNouveaux();
}

function cycleSauvegarder() {
  condSauvegarder();
  var btn = document.querySelector('[onclick="cycleSauvegarder()"]');
  if (btn) { btn.textContent = 'Sauvegarde !'; setTimeout(function(){ btn.textContent = 'Sauvegarder'; }, 1500); }
}

// ----- Mappings ancien EAN -> nouvel EAN -----
function cycleAjouterMapping(nom, ancienEan, nouvelEan, statut, note) {
  var data = cycleGetData();
  if (!data) { alert('Choisissez d\'abord un labo.'); return; }
  data.mappings.push({
    nom: nom || '', ancien_ean: ancienEan || '', nouvel_ean: nouvelEan || '',
    statut: statut || 'a_valider', note: note || ''
  });
  cycleRenderMappings();
}

function cycleSupprimerMapping(idx) {
  var data = cycleGetData();
  if (!data) return;
  data.mappings.splice(idx, 1);
  cycleRenderMappings();
}

function cycleUpdateMapping(idx, key, val) {
  var data = cycleGetData();
  if (!data || !data.mappings[idx]) return;
  data.mappings[idx][key] = val;
}

// v7.28 — Application des mappings confirmés au catalogue (EAN et/ou libellé)
// Ligne EAN : ancien_ean + nouvel_ean remplis → l'EAN du produit change.
// Ligne libellé seul : ancien_ean rempli + nouvel_ean vide + nom rempli → seul le libellé change.
// Après application : statut 'applique' (jamais ré-appliqué), persistance + push produits/LABOID.json.
function cycleAppliquerMappings() {
  var data = cycleGetData();
  if (!data) { alert('Choisissez d\'abord un labo.'); return; }
  var labo = condLabos[cycleLaboActif];
  var prods = (labo && labo.produits) || [];
  if (!prods.length) { alert('Aucun produit chargé pour ce labo. Clique d\'abord sur le labo dans Conditions commerciales (chargement GitHub).'); return; }
  var appliques = 0, introuvables = [], conflits = [], renames = 0;
  data.mappings.forEach(function(m) {
    if (m.statut !== 'confirme') return;
    var ancien = String(m.ancien_ean || '').trim();
    var nouveau = String(m.nouvel_ean || '').trim();
    var nouveauNom = String(m.nom || '').trim();
    if (!ancien) return;
    var p = prods.find(function(x){ return String(x.ean || '') === ancien; });
    if (!p) { introuvables.push(ancien); return; }
    // Changement d'EAN
    if (nouveau && nouveau !== ancien) {
      var deja = prods.find(function(x){ return String(x.ean || '') === nouveau; });
      if (deja) { conflits.push(ancien + ' → ' + nouveau + ' (EAN déjà pris par « ' + (deja.nom||'') + ' »)'); return; }
      p.ean = nouveau;
      // Migration de la clé de classification catalogue
      if (labo.catalogue && labo.catalogue[ancien]) {
        labo.catalogue[nouveau] = labo.catalogue[ancien];
        delete labo.catalogue[ancien];
      }
    }
    // Changement de libellé (si le champ nom du mapping est rempli)
    if (nouveauNom && nouveauNom !== p.nom) { p.nom = nouveauNom; renames++; }
    m.statut = 'applique';
    m.note = ((m.note ? m.note + ' · ' : '') + 'appliqué le ' + new Date().toLocaleDateString('fr'));
    appliques++;
  });
  if (appliques > 0) {
    condPersistLight();
    condSyncGitHubAuto();
    condSauvegarderProduitsGitHub(cycleLaboActif);
  }
  cycleRenderMappings();
  var msg = appliques + ' mapping(s) appliqué(s)' + (renames ? ' (dont ' + renames + ' libellé(s))' : '') + '.';
  if (introuvables.length) msg += '\n\nEAN introuvables dans le catalogue : ' + introuvables.join(', ');
  if (conflits.length) msg += '\n\nConflits (non appliqués) : \n' + conflits.join('\n');
  if (appliques > 0) msg += '\n\nLe fichier produits/' + cycleLaboActif + '.json est poussé vers GitHub. Sur les autres machines : « Charger depuis GitHub ».';
  alert(msg);
}

function cycleRenderMappings() {
  var tbody = document.getElementById('cycle-mapping-tbody');
  if (!tbody) return;
  var data = cycleGetData();
  if (!data) { tbody.innerHTML = ''; return; }
  var inS = 'font-size:11px;padding:3px 5px;border:1px solid var(--border);border-radius:3px;background:var(--surface2);width:100%;box-sizing:border-box;';
  var td = 'padding:4px 6px;border-bottom:0.5px solid var(--border);font-size:11px;';
  var html = '';
  data.mappings.forEach(function(m, i) {
    var statutColor = m.statut === 'confirme' ? '#1a6b4a' : (m.statut === 'rejete' ? '#8b1c1c' : (m.statut === 'applique' ? '#1e5a8a' : '#92520a'));
    var statutBg = m.statut === 'confirme' ? '#e8f5ee' : (m.statut === 'rejete' ? '#fdeaea' : (m.statut === 'applique' ? '#e8f1f8' : '#fef3e2'));
    html += '<tr>';
    html += '<td style="' + td + '"><input type="text" value="' + (m.nom||'').replace(/"/g,'&quot;') + '" style="' + inS + '" oninput="cycleUpdateMapping(' + i + ',\'nom\',this.value)"></td>';
    html += '<td style="' + td + 'text-align:center"><input type="text" value="' + (m.ancien_ean||'') + '" style="' + inS + 'font-family:monospace;text-align:center" oninput="cycleUpdateMapping(' + i + ',\'ancien_ean\',this.value)"></td>';
    html += '<td style="' + td + 'text-align:center"><input type="text" value="' + (m.nouvel_ean||'') + '" style="' + inS + 'font-family:monospace;text-align:center" oninput="cycleUpdateMapping(' + i + ',\'nouvel_ean\',this.value)"></td>';
    html += '<td style="' + td + 'text-align:center;background:' + statutBg + '"><select style="' + inS + 'color:' + statutColor + ';font-weight:600" onchange="cycleUpdateMapping(' + i + ',\'statut\',this.value)">' +
      ['a_valider','confirme','rejete','applique'].map(function(s){
        var lbl = s === 'a_valider' ? 'À valider' : (s === 'confirme' ? 'Confirmé' : (s === 'applique' ? 'Appliqué ✓' : 'Rejeté'));
        return '<option value="' + s + '"' + (m.statut===s?' selected':'') + '>' + lbl + '</option>';
      }).join('') + '</select></td>';
    html += '<td style="' + td + '"><input type="text" value="' + (m.note||'').replace(/"/g,'&quot;') + '" style="' + inS + '" oninput="cycleUpdateMapping(' + i + ',\'note\',this.value)"></td>';
    html += '<td style="' + td + 'text-align:center"><button type="button" onclick="cycleSupprimerMapping(' + i + ')" style="font-size:11px;color:var(--danger);background:none;border:none;cursor:pointer">✕</button></td>';
    html += '</tr>';
  });
  tbody.innerHTML = html;
}

