// API future : etant donne un EAN, retourne l'EAN "actuel" en suivant la chaine de mappings confirmes.
// Permettra plus tard de cumuler l'historique de ventes ancien+nouveau EAN. Pas encore branche ailleurs.
function cycleResoudreEAN(ean, laboId) {
  var labo = condLabos[laboId];
  if (!labo || !labo.cycleVie || !labo.cycleVie.mappings) return ean;
  var current = ean;
  var seen = {};
  while (true) {
    if (seen[current]) break; // securite anti-boucle
    seen[current] = true;
    var m = labo.cycleVie.mappings.find(function(x){ return x.ancien_ean === current && x.statut === 'confirme'; });
    if (!m) break;
    current = m.nouvel_ean;
  }
  return current;
}



// ===== SIMULATION =====
var simProduitsSource = [];
var simTop100Data = {};   // EAN -> {lib, qte_ph, pdm_ph, ordre_panel, pdm_panel, dn_pct}
var simProxData   = {};   // EAN -> {prix_zone, ton_prix, ton_vol, prix_pan, prix_qrt, dn_zone_n, dn_zone_d}

function simParseXLSX(file, callback) {
  var reader = new FileReader();
  reader.onload = function(e) {
    try {
      var wb = XLSX.read(e.target.result, {type:'array'});
      var ws = wb.Sheets[wb.SheetNames[0]];
      var rows = XLSX.utils.sheet_to_json(ws, {header:1, defval:null});
      callback(null, rows);
    } catch(err) { callback(err); }
  };
  reader.readAsArrayBuffer(file);
}

function simCleanEAN(v) {
  if (!v) return '';
  return String(v).replace(/\s/g,'').replace(/\xa0/g,'');
}

function simParseFloat(v) {
  if (v === null || v === undefined) return 0;
  var s = String(v).replace(',','.').replace(/[^\d.-]/g,'');
  var f = parseFloat(s);
  return isNaN(f) ? 0 : f;
}

function simImportTop100(input) {
  var file = input.files[0]; if (!file) return;
  var badge = document.getElementById('sim-top100-badge');
  if (badge) badge.textContent = 'Chargement...';
  simParseXLSX(file, function(err, rows) {
    if (err) { if(badge) badge.textContent = 'Erreur'; return; }
    // Row 0 = group headers, Row 1 = sub-headers, Row 2+ = data
    // Cols: Ordre(0), EAN(1), Libelle(2), QtePharm(3), EvolPh(4), PDMph(5), dn(6), OrdrePanel(7), EvolPanel(8), PDMpanel(9), DN(10)
    simTop100Data = {};
    var count = 0;
    rows.slice(2).forEach(function(r) {
      if (!r[1]) return;
      var ean = simCleanEAN(r[1]);
      if (ean.length < 8) return;
      var qte_ph = simParseFloat(r[3]);
      var pdm_ph = simParseFloat(r[5]);
      var ordre_panel = r[7] ? parseInt(r[7]) : 999;
      var pdm_panel = simParseFloat(r[9]);
      var dn_pct = simParseFloat(r[10]);
      simTop100Data[ean] = { lib: String(r[2]||'').substring(0,45), qte_ph:qte_ph,
        pdm_ph:pdm_ph, ordre_panel:ordre_panel, pdm_panel:pdm_panel, dn_pct:dn_pct };
      count++;
    });
    if (badge) badge.textContent = '\u2713 ' + count + ' produits';
    document.getElementById('sim-import-status').textContent = 'Top 100 : ' + count + ' produits charges.';
    input.value = '';
  });
}

function simImportProx(input) {
  var file = input.files[0]; if (!file) return;
  var badge = document.getElementById('sim-prox-badge');
  if (badge) badge.textContent = 'Chargement...';
  simParseXLSX(file, function(err, rows) {
    if (err) { if(badge) badge.textContent = 'Erreur'; return; }
    // Row 0 = group headers, Row 1 = col headers, Row 2+ = data
    // Cols: EAN(0), Lib(1), TVA(2),
    // Panel prox(3,4,5), Panel ayant vendu(6,7,8), Votre ville(9,10),
    // Votre pharmacie: Volume(11), DernPrix(12)
    // Panel: PrixMoy(13), MinMax(14)
    // Types: Banlieue(15), Centre ville(16), Centre commercial(17), Quartier(18), Rural(19)
    simProxData = {};
    var count = 0;
    rows.slice(2).forEach(function(r) {
      if (!r[0]) return;
      var ean = simCleanEAN(r[0]);
      if (ean.length < 8) return;
      // Parse prix_zone from col 6 (ex: "19.9 €DN: 2/20")
      var col6 = String(r[6]||'');
      var prix_zone_m = col6.match(/[\d]+[.,]?[\d]*/);
      var prix_zone = prix_zone_m ? parseFloat(prix_zone_m[0].replace(',','.')) : null;
      var dn_zone_m = col6.match(/DN:\s*(\d+)\/(\d+)/);
      var dn_zone_n = dn_zone_m ? parseInt(dn_zone_m[1]) : 0;
      var dn_zone_d = dn_zone_m ? parseInt(dn_zone_m[2]) : 20;
      // Parse ton prix col 12
      var col12 = String(r[12]||'');
      var ton_prix_m = col12.match(/[\d]+[.,]?[\d]*/);
      var ton_prix = ton_prix_m ? parseFloat(ton_prix_m[0].replace(',','.')) : null;
      var ton_vol = r[11] ? parseFloat(r[11]) : 0;
      // Parse prix panel col 13
      var col13 = String(r[13]||'');
      var prix_pan_m = col13.match(/[\d]+[.,]?[\d]*/);
      var prix_pan = prix_pan_m ? parseFloat(prix_pan_m[0].replace(',','.')) : null;
      // Prix quartier col 18
      var col18 = String(r[18]||'');
      var prix_qrt_m = col18.match(/[\d]+[.,]?[\d]*/);
      var prix_qrt = prix_qrt_m ? parseFloat(prix_qrt_m[0].replace(',','.')) : null;
      simProxData[ean] = { prix_zone:prix_zone, ton_prix:ton_prix, ton_vol:ton_vol,
        prix_pan:prix_pan, prix_qrt:prix_qrt, dn_zone_n:dn_zone_n, dn_zone_d:dn_zone_d };
      count++;
    });
    if (badge) badge.textContent = '\u2713 ' + count + ' produits';
    document.getElementById('sim-import-status').textContent += ' | Prix prox. : ' + count + ' produits charges.';
    input.value = '';
  });
}

function simInit() {
  if (Object.keys(condLabos).length === 0) {
    try { var s=localStorage.getItem('cond_labos'); if(s){condLabos=JSON.parse(s);} } catch(e) {}
  }
  var sel = document.getElementById('sim-labo');
  if (!sel) return;
  while (sel.options.length > 1) sel.remove(1);
  Object.keys(condLabos)
    .filter(function(id){ return condLabos[id] && condLabos[id].nom; })
    .sort(function(a, b){ return condLabos[a].nom.localeCompare(condLabos[b].nom, 'fr', {sensitivity:'base'}); })
    .forEach(function(id) {
      var l = condLabos[id];
      var o = document.createElement('option');
      o.value = id; o.textContent = l.nom + (l.produits ? ' (' + l.produits.length + ' prod.)' : '');
      sel.appendChild(o);
    });
  if (sel.options.length > 1) { sel.selectedIndex = 1; simChargeLabo(); }
}

function simChargeLabo() {
  var idStr = document.getElementById('sim-labo').value;
  var id = idStr ? (parseInt(idStr) || idStr) : null;
  simProduitsSource = (id && condLabos[id] && condLabos[id].produits) ? condLabos[id].produits : [];
  console.log('simChargeLabo: id=', id, 'prods=', simProduitsSource.length, 'keys=', Object.keys(condLabos));
  document.getElementById('sim-result').style.display = 'none';
}

function simAjouterPalier() {
  var div = document.getElementById('sim-paliers-inputs');
  var inp = document.createElement('input');
  inp.type = 'number'; inp.className = 'sim-palier-inp';
  inp.value = ''; inp.min = 0; inp.max = 60; inp.step = 0.5;
  inp.style.cssText = 'width:52px;font-size:12px;padding:5px 6px;border:1px solid var(--border);border-radius:var(--radius-sm);background:var(--surface2);font-family:"DM Mono",monospace;text-align:center';
  div.insertBefore(inp, div.lastElementChild);
}

function simGetPaliers() {
  var inps = document.querySelectorAll('.sim-palier-inp');
  var vals = [];
  inps.forEach(function(inp) {
    var v = parseFloat(inp.value);
    if (!isNaN(v) && v > 0) vals.push(v);
  });
  return vals.length > 0 ? vals : [25, 30, 35];
}

function simCalcUG(qte, ugMode) {
  if (ugMode === 'none' || !ugMode) return 0;
  var parts = ugMode.split('+');
  var ach = parseInt(parts[0])||0, off = parseInt(parts[1])||0;
  return (ach > 0 && qte >= ach) ? Math.floor(qte / ach) * off : 0;
}

function simLancer() {
  // Need at least Top100 data
  if (Object.keys(simTop100Data).length === 0 && simProduitsSource.length === 0) {
    alert('Importez au moins le Top 100 Panel France.');
    return;
  }

  var tvaR      = parseFloat(document.getElementById('sim-tva').value) / 100;
  var moisCible = parseFloat(document.getElementById('sim-mois-cible').value) || 2;
  var nbPharmas = parseFloat(document.getElementById('sim-nb-pharmas').value) || 20;
  var laboIdStr = document.getElementById('sim-labo').value;
  var laboId    = laboIdStr ? (parseInt(laboIdStr) || laboIdStr) : null;

  // Build unified product list
  // Priority: Top100 as base, enrich with Prox data and LGPI rotations
  var allEANs = Object.keys(simTop100Data);
  if (allEANs.length === 0 && simProduitsSource.length > 0) {
    // Fallback: use LGPI data only
    simProduitsSource.forEach(function(p){ if(p.ean) allEANs.push(p.ean); });
  }

  var produits = allEANs.map(function(ean) {
    var t = simTop100Data[ean] || {};
    var p = simProxData[ean]   || {};
    // Get marche conditions from catalogue
    var cat = (laboId && condLabos[laboId] && condLabos[laboId].catalogue) ? condLabos[laboId].catalogue[ean] : null;
    var marcheId = cat ? (cat.marche_id || '') : '';
    var marcheDef = marcheId ? MARCHES_NUTRICO.find(function(m){ return m.id === marcheId; }) : null;
    // LGPI product if available
    var lgpi = null;
    if (laboId && condLabos[laboId] && condLabos[laboId].produits) {
      lgpi = condLabos[laboId].produits.find(function(x){ return x.ean === ean; }) || null;
    }

    // Rotation estimates
    var rot_reel = lgpi ? (lgpi.moy||0) : (t.qte_ph||0) / 12;
    var rot_pdm  = (t.pdm_ph > 0 && t.qte_ph > 0) ? (t.qte_ph / t.pdm_ph * t.pdm_panel / 12) : 0;
    var rot_dn   = (t.dn_pct > 0) ? (t.qte_ph||0) / 12 / (t.dn_pct/100 * nbPharmas) : 0;

    // PV: priority = Quartier > ton prix > panel France > LGPI
    var pv_ttc = p.prix_qrt || p.ton_prix || p.prix_pan || (lgpi ? lgpi.pv_ttc : 0) || 0;
    // PA Cat Net from LGPI or estimate from PA_net column
    var pa_net = lgpi ? (lgpi.pa_net||0) : 0;
    var rem_cat = lgpi ? (lgpi.rem_cat||30) : 30;
    var pa_cat_brut = rem_cat > 0 ? pa_net / (1 - rem_cat/100) : pa_net;

    return { ean:ean, lib:t.lib || (lgpi?lgpi.nom:''), ordre:t.ordre_panel||999,
             marcheId: marcheDef ? marcheDef.id : 'general',
             rot_reel:rot_reel, rot_pdm:rot_pdm, rot_dn:rot_dn,
             pdm_ph:t.pdm_ph||0, dn_zone_n:p.dn_zone_n||0, dn_zone_d:p.dn_zone_d||nbPharmas,
             pv_ttc:pv_ttc, pa_cat_brut:pa_cat_brut, pa_net:pa_net,
             prix_zone:p.prix_zone||0, ton_vol:p.ton_vol||0 };
  });

  // Sort by panel order
  produits.sort(function(a,b){ return a.ordre - b.ordre; });

  // Filter: only products with some data
  produits = produits.filter(function(p){ return p.pv_ttc > 0 || p.pa_cat_brut > 0; });

  function fE(v){ return Math.round(v).toString().replace(/\B(?=(\d{3})+(?!\d))/g,' ') + '\u00a0\u20ac'; }
  function f1(v){ return (+v).toFixed(1).replace('.',','); }
  function f2(v){ return (+v).toFixed(2).replace('.',','); }

  // Count refs in general market to determine 30% or 25%
  var nGeneral = produits.filter(function(p){ return p.marcheId === 'general'; }).length;
  var remGeneral = nGeneral >= 30 ? 30 : 25;

  function calcScenario(prods, rem) {
    var lignes = [];
    var totCA=0, totMarge=0, totUG=0, totQte=0;
    prods.forEach(function(p) {
      var rot      = p.rot_reel > 0 ? p.rot_reel : (p.rot_dn > 0 ? p.rot_dn : p.rot_pdm);
      var qteCmd   = Math.ceil(rot * moisCible);
      if (qteCmd <= 0) qteCmd = 1;
      // Use marche-specific remise
      var mDef = p.marcheId ? MARCHES_NUTRICO.find(function(m){ return m.id === p.marcheId; }) : null;
      var remEff = mDef ? (mDef.id === 'general' ? remGeneral : (mDef.rem_30||rem)) : rem;
      var paNet    = p.pa_cat_brut > 0 ? p.pa_cat_brut * (1 - remEff/100) : 0;
      var pvHT     = p.pv_ttc / (1 + tvaR);
      var mbu      = paNet > 0 ? pvHT - paNet : 0;
      var mb       = (pvHT > 0 && paNet > 0) ? mbu/pvHT*100 : null;
      // UG: from marche definition or default tiers
      var ug = 0, ugLbl = '-';
      if (mDef && !mDef.ug_tiers && mDef.ug_ach > 0) {
        // Fixed UG: e.g. 12+2 or 6+1
        ug = Math.floor(qteCmd / mDef.ug_ach) * mDef.ug_off;
        ugLbl = mDef.ug_ach + '+' + mDef.ug_off;
      } else {
        // General market: tiered UG
        if (qteCmd >= 24) { ug = Math.floor(qteCmd/24)*8; ugLbl='24+8'; }
        else if (qteCmd >= 12) { ug = Math.floor(qteCmd/12)*3; ugLbl='12+3'; }
        else if (qteCmd >= 6)  { ug = Math.floor(qteCmd/6)*1;  ugLbl='6+1'; }
      }
      var caCmd  = qteCmd * p.pv_ttc;
      var margeCmd = qteCmd * mbu;
      totCA += caCmd; totMarge += margeCmd; totUG += ug; totQte += qteCmd;
      lignes.push({ ean:p.ean, lib:p.lib, ordre:p.ordre,
        rot_reel:p.rot_reel, rot_dn:p.rot_dn, rot_pdm:p.rot_pdm,
        dn_zone_n:p.dn_zone_n, dn_zone_d:p.dn_zone_d,
        qteCmd:qteCmd, paNet:paNet, pvTTC:p.pv_ttc, pv_qrt:p.prix_qrt||0,
        ug:ug, ugLbl:ugLbl, mb:mb, margeCmd:margeCmd, caCmd:caCmd,
        isNew: p.rot_reel <= 0 });
    });
    var caHT = totCA/(1+tvaR);
    var mbG  = caHT > 0 ? totMarge/caHT*100 : 0;
    return { lignes:lignes, totCA:totCA, totMarge:totMarge, totUG:totUG, totQte:totQte, mbG:mbG };
  }

  var top30  = produits.slice(0, 30);
  var top25  = produits.slice(0, Math.min(29, produits.length));
  var sc30   = calcScenario(top30,  30);
  var sc25   = calcScenario(top25,  25);

  // Global KPIs
  var gainMarge = sc30.totMarge - sc25.totMarge;
  var gainUG    = sc30.totUG - sc25.totUG;
  var verdict   = gainMarge >= 0
    ? 'Marche 30 refs g\u00e9n\u00e8re <b>+' + fE(gainMarge) + '</b> et <b>+' + gainUG + ' UG</b> suppl\u00e9mentaires.'
    : 'Marche 25 refs g\u00e9n\u00e8re <b>+' + fE(-gainMarge) + '</b> de marge suppl\u00e9mentaire.';

  var kpiHtml = '';
  [{sc:sc30,rem:30,cl:'hi'},{sc:sc25,rem:25,cl:'warn'}].forEach(function(x) {
    kpiHtml += '<div class="met ' + x.cl + '" style="text-align:center">' +
      '<p class="lbl">March\u00e9 ' + (x.rem===30?'30':'25') + ' refs \u2014 Remise ' + x.rem + '%</p>' +
      '<p class="val" style="font-size:22px">' + f1(x.sc.mbG) + '%</p>' +
      '<p class="sub">MB% moyen sur ' + moisCible + ' mois de commande</p>' +
      '<p style="font-size:14px;font-weight:600;margin:4px 0">' + fE(x.sc.totMarge) + '</p>' +
      '<p class="sub">Marge sur commande</p>' +
      '<p style="font-size:12px;color:var(--accent-text);font-weight:600">+' + x.sc.totUG + ' UG gratuites</p>' +
      '<p class="sub">CA commande : ' + fE(x.sc.totCA) + ' | ' + x.sc.totQte + ' u. payantes</p>' +
      '</div>';
  });
  kpiHtml += '<div class="nego" style="grid-column:1/-1">' +
    '<p class="nego-title">Verdict</p><p class="nego-body">' + verdict + '</p></div>';
  document.getElementById('sim-global-kpis').innerHTML = kpiHtml;

  // Comparison table
  var thS = 'padding:6px 8px;font-size:9px;font-weight:600;letter-spacing:.04em;text-transform:uppercase;border-bottom:1px solid var(--border);white-space:nowrap;';
  var html = '<thead><tr style="background:var(--text);color:#fff">';
  html += '<th style="' + thS + 'text-align:center;width:40px">Rang</th>';
  html += '<th style="' + thS + 'text-align:left;min-width:160px">Produit</th>';
  html += '<th style="' + thS + 'text-align:center">Rot. r\u00e9elle<br>/mois</th>';
  html += '<th style="' + thS + 'text-align:center">Estim. DN<br>/mois</th>';
  html += '<th style="' + thS + 'text-align:center">DN zone</th>';
  html += '<th style="' + thS + 'text-align:center">PV Quartier</th>';
  html += '<th style="' + thS + 'text-align:center;background:#1a3a20">PA net 30%</th>';
  html += '<th style="' + thS + 'text-align:center;background:#1a3a20">MB% 30%</th>';
  html += '<th style="' + thS + 'text-align:center;background:#1a3a20">UG 30%</th>';
  html += '<th style="' + thS + 'text-align:center;background:#3a3a10">MB% 25%</th>';
  html += '<th style="' + thS + 'text-align:center;background:#3a3a10">UG 25%</th>';
  html += '</tr></thead><tbody>';

  sc30.lignes.forEach(function(l, ri) {
    var l25 = sc25.lignes[ri];
    var bg  = ri % 2 === 0 ? '#fff' : 'var(--surface2)';
    var tdS = 'padding:5px 8px;border-bottom:0.5px solid var(--border);font-size:11px;background:' + bg;
    var mb30c = l.mb===null?'':(l.mb>=35?'var(--accent-text)':l.mb>=28?'var(--warn)':'var(--danger)');
    var mb25c = (l25&&l25.mb!==null)?(l25.mb>=35?'var(--accent-text)':l25.mb>=28?'var(--warn)':'var(--danger)'):'';
    var isNew = l.rot_reel <= 0;
    html += '<tr>';
    html += '<td style="' + tdS + ';text-align:center;font-family:monospace;color:var(--text-ter)">' + l.ordre + '</td>';
    html += '<td style="' + tdS + ';max-width:180px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="' + l.lib + '">' +
      l.lib + (isNew ? ' <span style="font-size:9px;background:#fff3e0;color:#b36000;padding:1px 4px;border-radius:2px">NEW</span>' : '') + '</td>';
    html += '<td style="' + tdS + ';text-align:center;font-family:monospace">' + (l.rot_reel>0 ? f1(l.rot_reel) : '<span style="color:var(--text-ter)">-</span>') + '</td>';
    html += '<td style="' + tdS + ';text-align:center;font-family:monospace;color:var(--text-sec)">' + (l.rot_dn>0 ? f1(l.rot_dn) : '-') + '</td>';
    html += '<td style="' + tdS + ';text-align:center;font-size:10px">' + (l.dn_zone_n>0 ? l.dn_zone_n+'/'+l.dn_zone_d : '-') + '</td>';
    html += '<td style="' + tdS + ';text-align:center;font-family:monospace">' + (l.pv_qrt>0 ? f2(l.pv_qrt)+'\u20ac' : f2(l.pvTTC)+'\u20ac') + '</td>';
    html += '<td style="' + tdS + ';text-align:center;font-family:monospace;background:#e8f5ee">' + (l.paNet>0?f2(l.paNet)+'\u20ac':'-') + '</td>';
    html += '<td style="' + tdS + ';text-align:center;font-weight:700;background:#e8f5ee;color:' + mb30c + '">' + (l.mb!==null?f1(l.mb)+'%':'-') + '</td>';
    html += '<td style="' + tdS + ';text-align:center;background:#e8f5ee">' + (l.ug>0?'<b style="color:var(--accent-text)">+'+l.ug+'</b><br><span style="font-size:9px">'+l.ugLbl+'</span>':'-') + '</td>';
    html += '<td style="' + tdS + ';text-align:center;font-weight:700;background:#fffbea;color:' + mb25c + '">' + (l25&&l25.mb!==null?f1(l25.mb)+'%':'exclu') + '</td>';
    html += '<td style="' + tdS + ';text-align:center;background:#fffbea">' + (l25&&l25.ug>0?'<b style="color:var(--warn)">+'+l25.ug+'</b>':'-') + '</td>';
    html += '</tr>';
  });
  html += '</tbody>';
  document.getElementById('sim-table').innerHTML = html;

  // ===== RECOMMANDATION FINALE =====
  var bestSc = gainMarge >= 0 ? sc30 : sc25;
  var bestRem = gainMarge >= 0 ? 30 : 25;
  var bestNRefs = gainMarge >= 0 ? 30 : 25;

  // Products to prioritize: sort by score = mb * rot (value x volume)
  var lignes = bestSc.lignes.slice();

  // Category 1: Already selling + good MB
  var actifs_bons = lignes.filter(function(l){ return !l.isNew && l.mb !== null && l.mb >= 28; });
  // Category 2: Already selling + bad MB -> need negotiation
  var actifs_faibles = lignes.filter(function(l){ return !l.isNew && l.mb !== null && l.mb < 28; });
  // Category 3: New + good DN in zone
  var nouveaux_dn = lignes.filter(function(l){ return l.isNew && l.dn_zone_n >= 2; });
  // Category 4: New + no presence in zone -> opportunity
  var nouveaux_zero = lignes.filter(function(l){ return l.isNew && l.dn_zone_n <= 1; });

  // Top UG products (most units = most UG)
  var topUG = lignes.slice().sort(function(a,b){ return b.ug - a.ug; }).filter(function(l){ return l.ug > 0; }).slice(0,5);

  function fE(v){ return Math.round(v).toString().replace(/\B(?=(\d{3})+(?!\d))/g,' ') + '\u00a0\u20ac'; }
  function f1(v){ return (+v).toFixed(1).replace('.',','); }
  function f2(v){ return (+v).toFixed(2).replace('.',','); }

  var recHtml = '';

  // ===== BLOC 1: Quel marche prendre =====
  var marcheColor = gainMarge >= 0 ? 'var(--accent-text)' : 'var(--warn)';
  recHtml += '<div class="card" style="border-top:4px solid ' + marcheColor + '">';
  recHtml += '<p class="card-title">\u2460 Quel march\u00e9 prendre ?</p>';
  recHtml += '<div class="rgrid">';
  recHtml += '<div class="met ' + (gainMarge>=0?'hi':'warn') + '" style="text-align:center">';
  recHtml += '<p class="lbl">Recommandation</p>';
  recHtml += '<p class="val" style="font-size:20px">March\u00e9 ' + bestNRefs + ' r\u00e9f\u00e9rences</p>';
  recHtml += '<p class="sub">Remise ' + bestRem + '% + UG (6+1, 12+3 ou 24+8)</p>';
  recHtml += '</div>';
  recHtml += '<div class="met hi"><p class="lbl">Marge g\u00e9n\u00e9r\u00e9e</p><p class="val">' + fE(bestSc.totMarge) + '</p><p class="sub">sur ' + moisCible + ' mois de commande</p></div>';
  recHtml += '<div class="met hi"><p class="lbl">MB% moyen</p><p class="val">' + f1(bestSc.mbG) + '%</p></div>';
  recHtml += '<div class="met hi"><p class="lbl">UG gratuites</p><p class="val">+' + bestSc.totUG + '</p><p class="sub">unit\u00e9s offertes</p></div>';
  recHtml += '</div>';

  // Justification text
  recHtml += '<div style="margin-top:12px;padding:12px;background:var(--surface2);border-radius:var(--radius-sm);font-size:12px;line-height:1.6">';
  if (gainMarge >= 0) {
    recHtml += 'Le march\u00e9 <b>30 r\u00e9f\u00e9rences \u00e0 30%</b> est plus avantageux car la remise suppl\u00e9mentaire (+5 pts vs 25%) compense largement le co\u00fbt du r\u00e9f\u00e9rencement des 5 r\u00e9f\u00e9rences suppl\u00e9mentaires. ';
    recHtml += 'Gain : <b>+' + fE(gainMarge) + '</b> de marge et <b>+' + gainUG + ' UG</b> vs le march\u00e9 25 r\u00e9f\u00e9rences.';
  } else {
    recHtml += 'Le march\u00e9 <b>25 r\u00e9f\u00e9rences \u00e0 25%</b> est suffisant. Les 5 r\u00e9f\u00e9rences suppl\u00e9mentaires du march\u00e9 30 ne compensent pas la complexit\u00e9 de gestion. ';
    recHtml += 'Gain : <b>+' + fE(-gainMarge) + '</b> de marge en restant sur 25 r\u00e9f\u00e9rences.';
  }
  recHtml += '</div></div>';

  // ===== BLOC 2: Produits prioritaires =====
  recHtml += '<div class="card">';
  recHtml += '<p class="card-title">\u2461 Produits prioritaires \u00e0 r\u00e9f\u00e9rencer</p>';

  if (nouveaux_dn.length > 0) {
    recHtml += '<p style="font-size:11px;font-weight:600;color:var(--accent-text);margin:8px 0 4px">';
    recHtml += '\u2605 D\u00e9j\u00e0 vendus dans ta zone (' + nouveaux_dn.length + ' produits) \u2014 r\u00e9f\u00e9rencement imm\u00e9diat recommand\u00e9</p>';
    recHtml += '<div style="display:flex;flex-direction:column;gap:4px">';
    nouveaux_dn.forEach(function(l) {
      var mbClr = l.mb>=35?'var(--accent-text)':l.mb>=28?'var(--warn)':'var(--danger)';
      recHtml += '<div style="display:flex;justify-content:space-between;align-items:center;padding:6px 10px;background:var(--accent-bg);border-radius:var(--radius-sm)">';
      recHtml += '<span style="font-size:12px;font-weight:500">' + l.lib + '</span>';
      recHtml += '<div style="display:flex;gap:12px;font-size:11px">';
      recHtml += '<span>DN zone: <b>' + l.dn_zone_n + '/' + l.dn_zone_d + '</b></span>';
      recHtml += '<span>PV: <b>' + f2(l.pvTTC) + '\u20ac</b></span>';
      recHtml += '<span style="color:' + mbClr + ';font-weight:700">MB% ' + (l.mb!==null?f1(l.mb)+'%':'?') + '</span>';
      recHtml += (l.ug>0 ? '<span style="color:var(--accent-text)">+' + l.ug + ' UG</span>' : '');
      recHtml += '</div></div>';
    });
    recHtml += '</div>';
  }

  if (actifs_faibles.length > 0) {
    recHtml += '<p style="font-size:11px;font-weight:600;color:var(--danger);margin:12px 0 4px">';
    recHtml += '\u26a0 Produits en vente avec MB% insuffisant (' + actifs_faibles.length + ') \u2014 v\u00e9rifier prix ou n\u00e9gocier</p>';
    recHtml += '<div style="display:flex;flex-direction:column;gap:4px">';
    actifs_faibles.forEach(function(l) {
      recHtml += '<div style="display:flex;justify-content:space-between;align-items:center;padding:6px 10px;background:#fff3f0;border-radius:var(--radius-sm)">';
      recHtml += '<span style="font-size:12px">' + l.lib + '</span>';
      recHtml += '<div style="display:flex;gap:12px;font-size:11px">';
      recHtml += '<span>Rot: <b>' + f1(l.rot_reel) + '/m</b></span>';
      recHtml += '<span>PV actuel: <b>' + f2(l.pvTTC) + '\u20ac</b></span>';
      recHtml += '<span style="color:var(--danger);font-weight:700">MB% ' + (l.mb!==null?f1(l.mb)+'%':'?') + '</span>';
      recHtml += '</div></div>';
    });
    recHtml += '</div>';
  }

  recHtml += '</div>';

  // ===== BLOC 3: Commande optimale =====
  recHtml += '<div class="card">';
  recHtml += '<p class="card-title">\u2462 Commande optimale — ' + moisCible + ' mois de couverture</p>';
  recHtml += '<p style="font-size:11px;color:var(--text-ter);margin-bottom:12px">Produits tri\u00e9s par valeur d\u2019UG d\u00e9clench\u00e9es, puis par marge.</p>';

  // Sort by UG desc then mb desc
  var cmdLignes = bestSc.lignes.filter(function(l){ return l.qteCmd > 0 && l.mb !== null; })
    .sort(function(a,b){ return (b.ug - a.ug) || (b.mb - a.mb); });

  var thS2 = 'padding:6px 8px;font-size:9px;font-weight:600;text-transform:uppercase;letter-spacing:.04em;border-bottom:1px solid var(--border);white-space:nowrap;';
  var cmdHtml = '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:11px">';
  cmdHtml += '<thead><tr style="background:var(--text);color:#fff">';
  cmdHtml += '<th style="' + thS2 + 'text-align:left">Produit</th>';
  cmdHtml += '<th style="' + thS2 + 'text-align:center">Qte \u00e0 cde</th>';
  cmdHtml += '<th style="' + thS2 + 'text-align:center;background:#1a3a20">PA net ' + bestRem + '%</th>';
  cmdHtml += '<th style="' + thS2 + 'text-align:center;background:#1a3a20">MB%</th>';
  cmdHtml += '<th style="' + thS2 + 'text-align:center;background:#1a3a20">UG</th>';
  cmdHtml += '<th style="' + thS2 + 'text-align:center">PV cible</th>';
  cmdHtml += '<th style="' + thS2 + 'text-align:center">Marge</th>';
  cmdHtml += '<th style="' + thS2 + 'text-align:center">Statut</th>';
  cmdHtml += '</tr></thead><tbody>';

  cmdLignes.forEach(function(l, ri) {
    var bg = ri % 2 === 0 ? '#fff' : 'var(--surface2)';
    var tdC = 'padding:5px 8px;border-bottom:0.5px solid var(--border);background:' + bg;
    var mbClr = l.mb>=35?'var(--accent-text)':l.mb>=28?'var(--warn)':'var(--danger)';
    var statut = l.isNew
      ? '<span style="font-size:9px;background:#fff3e0;color:#b36000;padding:1px 5px;border-radius:3px;font-weight:600">NOUVEAU</span>'
      : '<span style="font-size:9px;background:var(--accent-bg);color:var(--accent-text);padding:1px 5px;border-radius:3px">EN STOCK</span>';
    cmdHtml += '<tr>';
    cmdHtml += '<td style="' + tdC + ';max-width:180px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-weight:' + (l.isNew?'600':'400') + '" title="' + l.lib + '">' + l.lib + '</td>';
    cmdHtml += '<td style="' + tdC + ';text-align:center;font-weight:700">' + l.qteCmd + '</td>';
    cmdHtml += '<td style="' + tdC + ';text-align:center;font-family:monospace;background:#e8f5ee">' + (l.paNet>0?f2(l.paNet)+'\u20ac':'-') + '</td>';
    cmdHtml += '<td style="' + tdC + ';text-align:center;font-weight:700;background:#e8f5ee;color:' + mbClr + '">' + (l.mb!==null?f1(l.mb)+'%':'-') + '</td>';
    cmdHtml += '<td style="' + tdC + ';text-align:center;background:#e8f5ee">' + (l.ug>0?'<b style="color:var(--accent-text)">+'+l.ug+'</b> <span style="font-size:9px;color:var(--text-ter)">'+l.ugLbl+'</span>':'-') + '</td>';
    cmdHtml += '<td style="' + tdC + ';text-align:center;font-family:monospace">' + f2(l.pv_qrt>0?l.pv_qrt:l.pvTTC) + '\u20ac</td>';
    cmdHtml += '<td style="' + tdC + ';text-align:center;font-family:monospace;font-weight:600">' + (l.margeCmd>0?fE(l.margeCmd):'-') + '</td>';
    cmdHtml += '<td style="' + tdC + ';text-align:center">' + statut + '</td>';
    cmdHtml += '</tr>';
  });

  // Total row
  cmdHtml += '<tr style="background:var(--text);color:#fff;font-weight:600">';
  cmdHtml += '<td style="padding:7px 8px">TOTAL ' + cmdLignes.length + ' r\u00e9f\u00e9rences</td>';
  cmdHtml += '<td style="padding:7px 8px;text-align:center">' + bestSc.totQte + ' u.</td>';
  cmdHtml += '<td colspan="2" style="padding:7px 8px;text-align:center;background:#1a3a20">' + f1(bestSc.mbG) + '% MB moyen</td>';
  cmdHtml += '<td style="padding:7px 8px;text-align:center;background:#1a3a20">+' + bestSc.totUG + ' UG</td>';
  cmdHtml += '<td style="padding:7px 8px"></td>';
  cmdHtml += '<td style="padding:7px 8px;text-align:center">' + fE(bestSc.totMarge) + '</td>';
  cmdHtml += '<td style="padding:7px 8px"></td>';
  cmdHtml += '</tr></tbody></table></div>';

  recHtml += cmdHtml + '</div>';

  document.getElementById('sim-recommandation').innerHTML = recHtml;
  document.getElementById('sim-result').style.display = 'block';
}

var simInited = false;

window.addEventListener('DOMContentLoaded', function() {
  // showTab('workflow') géré par le premier DOMContentLoaded — ne pas répéter ici
  try { renderTsrfBadges(); } catch(e) {}
  try { decRenderStockTarget(); } catch(e) {}
  // Charger les donnees ANALYSE ZONE depuis l'URL (?az=BASE64) si presentes
  try {
    var params = new URLSearchParams(window.location.search);
    var azB64 = params.get('az');
    if (azB64) {
      var parsed = JSON.parse(decodeURIComponent(escape(atob(azB64))));
      // Gérer les deux formats :
      // 1. Format actuel exporterCommandeJSON() : {labo, date, produits:[{ean, libelle, qte_min, alerte, stock, dn, role}]}
      // 2. Format plat (nouveau) : [{ean, libelle, qte_az, alerte, ...}]
      if (parsed && parsed.produits && Array.isArray(parsed.produits)) {
        var laboNom = parsed.labo || '';
        window._cmdRapportSource = 'Analyse Zone'; // v7.96
        cmdAzData = parsed.produits.map(function(p) {
          return {
            ean: p.ean || '', libelle: p.libelle || '',
            qte_az: p.qte_min || p.qte_az || 0,
            alerte: p.alerte || '', dn: p.dn || '',
            role: p.role || '', stock: p.stock || 0,
            labo: laboNom
          };
        });
      } else if (Array.isArray(parsed)) {
        window._cmdRapportSource = 'Analyse Zone'; // v7.96
        cmdAzData = parsed.map(function(p) {
          return {
            ean: p.ean || '', libelle: p.libelle || '',
            qte_az: p.qte_az || p.qte_min || 0,
            alerte: p.alerte || '', dn: p.dn || '',
            role: p.role || '', stock: p.stock || 0,
            labo: p.labo || ''
          };
        });
      }
      // Nettoyer l'URL sans recharger la page
      window.history.replaceState({}, '', window.location.pathname);
      // Aller sur l'onglet Commande et afficher la banniere
      if (cmdAzData && cmdAzData.length) {
        setTimeout(function(){
          showTab('cmd');
          cmdRenderAzBanner();
        }, 200);
      }
    }
  } catch(e) { console.warn('AZ param error', e); }
});


// ===== ANALYSE ZONE → CALCULATEUR (transfert ?az=BASE64) =====
// cmdAzData : tableau de {ean, libelle, qte_az, alerte, dn, role} issu de l'Analyse Zone
var cmdAzData = null;

// Affiche/maj la banniere AZ dans l'onglet Commande
// v7.83 — guide workflow de l'onglet Commande (bouton ❓)
function cmdWorkflowToggle() {
  var el = document.getElementById('cmd-workflow');
  if (!el) return;
  if (el.style.display !== 'none') { el.style.display = 'none'; return; }
  var li = 'font-size:11.5px;margin:0 0 7px 0';
  el.innerHTML =
    '<div style="background:var(--surface2);padding:12px 14px;border-radius:var(--radius-sm);margin-bottom:12px">' +
    '<p style="' + li + '"><b>1. V\u00e9rifier le chargement.</b> Il est AUTOMATIQUE \u00e0 l\u2019ouverture (v7.99) : attendre le bandeau \u00ab \u2713 Catalogues et conditions charg\u00e9s \u00bb en haut de l\u2019onglet. Le bouton \u00ab \u2191 Charger depuis GitHub \u00bb (Conditions) ne sert plus qu\u2019\u00e0 forcer un rechargement.</p>' +
    '<p style="' + li + '"><b>2. R\u00e9gler le simulateur.</b> Choisir le labo \u00b7 Stock actuel : \u00ab D\u00e9duire du besoin \u00bb \u00b7 couverture 2 mois \u00b7 seuil colisage 50 %. Le DERNIER stock LGPI import\u00e9 (March\u00e9s \u00e9quivalents, dat\u00e9) est conserv\u00e9 et utilis\u00e9 automatiquement jusqu\u2019au prochain import \u2014 sur les 3 machines.</p>' +
    '<p style="' + li + '"><b>3. Coller la commande Moteur (recommand\u00e9).</b> Dans le Sheet Moteur : s\u00e9lectionner le tableau du labo avec sa ligne de titres \u2192 Cmd+C \u2192 bouton \u00ab \ud83d\udccb Coller commande Moteur \u00bb \u2192 Cmd+V \u2192 Charger.</p>' +
    '<p style="' + li + '"><b>4. G\u00e9n\u00e9rer.</b> \u00ab G\u00e9n\u00e9rer le rapport Moteur vs Calculateur \u00bb (ou \u00ab Calculer la commande \u00bb sans le Moteur). Qt\u00e9 finale = max(Moteur, Calculateur). Tout est PR\u00c9-COCH\u00c9 sauf les \ud83d\udd35 Calc seul.</p>' +
    '<p style="' + li + '"><b>5. Filtrer et arbitrer.</b> Cliquer un badge de statut = filtrer le tableau (re-clic ou \u00ab Tous \u00bb = tout revoir). Commencer par \ud83d\udd35 Calc seul : cocher uniquement ce qui se vendra avant l\u2019\u00e9ch\u00e9ance 45 j fin de mois (saisonnalit\u00e9, stock). \ud83d\udfe0 Moteur seul, \u2705 OK, \ud83d\udcc9 Moteur > Calc : \u00e0 laisser coch\u00e9s.</p>' +
    '<p style="' + li + '"><b>6. Finaliser.</b> Le bandeau \ud83d\uded2 \u00ab Ma commande \u00bb totalise les lignes coch\u00e9es (produits \u00b7 unit\u00e9s \u00b7 \u20ac HT) \u2192 \u00ab \ud83d\udccb Copier la s\u00e9lection \u00bb (EAN + qt\u00e9) pour la saisie LGPI / Sheets / mail, ou \u00ab \ud83d\udda8 Imprimer la commande \u00bb pour le bon de commande papier tri\u00e9 par segment.</p>' +
    '</div>';
  el.style.display = 'block';
}

// v7.83 — coller la commande g\u00e9n\u00e9r\u00e9e par le Sheet Moteur (copier-coller TSV brut)
function cmdMoteurToggle() {
  var el = document.getElementById('cmd-moteur-zone');
  if (!el) return;
  el.style.display = (el.style.display === 'none' || !el.style.display) ? 'block' : 'none';
}
function cmdMoteurCharger() {
  var ta = document.getElementById('cmd-moteur-texte');
  if (!ta || !ta.value.trim()) { alert('Collez d\'abord le tableau copi\u00e9 depuis le Sheet Moteur.'); return; }
  var lignes = ta.value.split(/\r?\n/);
  var idx = { ean: 0, lib: 1, labo: 2, qte: 3, colis: 4, seg: 5, stock: 6, besoin: 7 };
  var out = [];
  for (var i = 0; i < lignes.length; i++) {
    var cells = lignes[i].split('\t');
    if (cells.length < 4) continue;
    var c0 = String(cells[0] || '').trim().toUpperCase();
    if (c0 === 'EAN') {
      cells.forEach(function(h, j) {
        var H = String(h || '').trim().toUpperCase();
        if (H === 'EAN') idx.ean = j;
        if (H.indexOf('LIBEL') === 0) idx.lib = j;
        if (H === 'LABO') idx.labo = j;
        if (H.indexOf('QT') === 0) idx.qte = j;
        if (H === 'COLISAGE') idx.colis = j;
        if (H === 'SEGMENT') idx.seg = j;
        if (H.indexOf('STOCK') === 0) idx.stock = j;
        if (H.indexOf('BESOIN') === 0) idx.besoin = j; // v7.91 : Besoin Théo
      });
      continue;
    }
    var ean = String(cells[idx.ean] || '').replace(/\D/g, '');
    if (ean.length < 10) continue;
    var qte = parseInt(String(cells[idx.qte] || '').replace(/\s/g, ''), 10) || 0;
    if (qte <= 0) continue;
    out.push({
      ean: ean,
      libelle: String(cells[idx.lib] || '').trim(),
      qte_az: qte,
      alerte: '', dn: '',
      role: String(cells[idx.seg] || '').trim().toUpperCase(),
      stock: parseInt(cells[idx.stock], 10) || 0,
      besoin: parseInt(cells[idx.besoin], 10) || 0,
      colisage: parseInt(cells[idx.colis], 10) || 0,
      labo: String(cells[idx.labo] || '').trim()
    });
  }
  if (!out.length) { alert('Aucune ligne reconnue. Copiez le tableau AVEC sa ligne de titres (EAN, Libell\u00e9, Labo, Qt\u00e9 \u00e0 commander, Colisage, Segment, Stock RT).'); return; }
  cmdAzData = out;
  window._cmdRapportSource = 'Moteur'; // v7.96
  ta.value = '';
  var z = document.getElementById('cmd-moteur-zone');
  if (z) z.style.display = 'none';
  cmdRenderAzBanner();
  // v8.06 — confirmation explicite + amener la bannière sous les yeux
  var b = document.getElementById('cmd-az-banner');
  if (b && b.scrollIntoView) { try { b.scrollIntoView({ behavior: 'smooth', block: 'center' }); } catch (e) { b.scrollIntoView(); } }
  var totU = 0; out.forEach(function(r){ totU += r.qte_az || 0; });
  alert('\u2713 Collage r\u00e9ussi : ' + out.length + ' produits \u00b7 ' + totU + ' unit\u00e9s' + (out[0].labo ? ' \u2014 ' + out[0].labo : '') + '.\n\nLa banni\u00e8re \u26a1 est affich\u00e9e en haut : cliquez \u00ab \ud83d\udcca G\u00e9n\u00e9rer le rapport \u00bb.');
}

function cmdRenderAzBanner() {
  var el = document.getElementById('cmd-az-banner');
  if (!el) return;
  if (!cmdAzData || !cmdAzData.length) { el.style.display = 'none'; return; }
  var labo = cmdAzData[0] && cmdAzData[0].labo ? cmdAzData[0].labo : '';
  var nbRupture = cmdAzData.filter(function(r){ return r.alerte && r.alerte.indexOf('RUPTURE') >= 0; }).length;
  var nbDanger = cmdAzData.filter(function(r){ return r.alerte && r.alerte.indexOf('DANGER') >= 0; }).length;
  el.style.display = 'block';
  el.innerHTML =
    '<div style="display:flex;align-items:center;gap:12px;flex-wrap:wrap">' +
    '<span style="font-size:13px;font-weight:700">⚡ ' + cmdAzData.length + ' produits chargés — ' + (window._cmdRapportSource || 'Moteur / Analyse Zone') + (labo ? ' — ' + labo : '') + '</span>' +
    (nbRupture ? '<span style="background:var(--danger);color:#fff;border-radius:4px;padding:2px 8px;font-size:11px;font-weight:600">🔴 ' + nbRupture + ' RUPTURE</span>' : '') +
    (nbDanger  ? '<span style="background:var(--warn);color:#fff;border-radius:4px;padding:2px 8px;font-size:11px;font-weight:600">🟠 ' + nbDanger + ' DANGER</span>' : '') +
    '<button onclick="cmdGenererAvecAz()" style="padding:5px 14px;background:var(--accent);color:#fff;border:none;border-radius:var(--radius-sm);cursor:pointer;font-size:12px;font-weight:600">📊 Générer le rapport ' + (window._cmdRapportSource || 'Moteur') + ' vs Calculateur</button>' +
    '<button onclick="cmdAzData=null;cmdRenderAzBanner()" style="padding:5px 10px;background:transparent;color:var(--text-ter);border:1px solid var(--border);border-radius:var(--radius-sm);cursor:pointer;font-size:11px">✕ Effacer</button>' +
    '</div>';
}

// v7.87 — segmentation ABC par contribution au CA annuel (ventes Ospharm,
// tous labos confondus, périmètre = produits du labo sélectionné).
// Seuils = règle officielle du Moteur (v7.88, vérifiée 41/44 sur commande réelle) :
// SOCLE <= 80 % du CA cumulé · COEUR 80-95 % · COMPLEMENT les 5 % restants (ou CA nul).
// Le suffixe * distingue un segment CALCULÉ d'un segment fourni par le Moteur.
function cmdSegmentsABC() {
  var caht = {};
  try {
    if (typeof decOspharmProds !== 'undefined' && decOspharmProds) {
      Object.keys(decOspharmProds).forEach(function(l) {
        (decOspharmProds[l] || []).forEach(function(p) {
          if (p.ean) caht[p.ean] = (caht[p.ean] || 0) + (p.caht || 0);
        });
      });
    }
  } catch (e) {}
  var peri = (cmdProduitsSource || []).map(function(p) {
    var e = String(p.ean || '');
    return { ean: e, ca: caht[e] || 0 };
  }).filter(function(x) { return x.ean; });
  peri.sort(function(a, b) { return b.ca - a.ca; });
  var total = peri.reduce(function(s, x) { return s + x.ca; }, 0);
  var segByEan = {}, cumul = 0;
  peri.forEach(function(x) {
    cumul += x.ca;
    var part = total > 0 ? cumul / total : 1;
    segByEan[x.ean] = (x.ca <= 0) ? 'COMPLEMENT*' : (part <= 0.80 ? 'SOCLE*' : (part <= 0.95 ? 'COEUR*' : 'COMPLEMENT*'));
  });
  return segByEan;
}

// Génère la commande calculateur PUIS affiche le rapport de rapprochement AZ vs Calc
function cmdGenererAvecAz() {
  // Si aucun labo n'est sélectionné dans le dropdown Commande, essayer de le charger
  // automatiquement depuis le nom du labo dans les données AZ
  if (cmdProduitsSource.length === 0 && cmdAzData && cmdAzData.length) {
    var laboNomAz = (cmdAzData[0].labo || '').toUpperCase().trim();
    if (laboNomAz) {
      // Chercher l'ID du labo dans condLabos par correspondance de nom
      var laboIdTrouve = null;
      Object.keys(condLabos).forEach(function(k) {
        var nom = ((condLabos[k] || {}).nom || '').toUpperCase().trim();
        if (nom === laboNomAz || nom.indexOf(laboNomAz) >= 0 || laboNomAz.indexOf(nom) >= 0) {
          laboIdTrouve = k;
        }
      });
      if (laboIdTrouve && condLabos[laboIdTrouve] && condLabos[laboIdTrouve].produits && condLabos[laboIdTrouve].produits.length) {
        // Sélectionner ce labo dans le dropdown et charger les produits
        var sel = document.getElementById('cmd-labo-sel');
        if (sel) sel.value = laboIdTrouve;
        cmdChargeLabo();
      }
    }
  }

  if (cmdProduitsSource.length === 0) {
    alert('Chargez d\'abord un labo dans l\'onglet Commande (sélectionner le labo dans la liste) pour avoir les rotations produits.');
    return;
  }
  // Lancer la génération normale
  cmdGenerer();

  // Construire l'index AZ par EAN
  // v7.96 — remplacements d'EAN (module Cycle de vie du labo) : l'ancien EAN
  // est replié sur le nouveau partout (rotations, stock, prix, quantités
  // sources) pour que le rapport ne montre QUE l'EAN à commander.
  var eanRemap = {};
  try {
    var _selCv = document.getElementById('cmd-labo-sel');
    var _cv = _selCv && _selCv.value && condLabos[_selCv.value] && condLabos[_selCv.value].cycleVie;
    ((_cv && _cv.mappings) || []).forEach(function(m) {
      var a = String(m.ancien_ean || '').replace(/\D/g, '');
      var n = String(m.nouvel_ean || '').replace(/\D/g, '');
      if (a && n && a !== n) eanRemap[a] = n;
    });
  } catch (e) {}
  var eanRemplaces = {}; // nouvel EAN -> ancien (pour le marqueur ↻)
  function cmdRemapEan(e) {
    e = String(e);
    if (eanRemap[e]) { eanRemplaces[eanRemap[e]] = e; return eanRemap[e]; }
    return e;
  }
  var azByEan = {};
  (cmdAzData || []).forEach(function(r){
    if (!r.ean) return;
    var k = cmdRemapEan(r.ean);
    if (azByEan[k]) { // ancien + nouveau présents : cumuler la demande
      azByEan[k].qte_az = (azByEan[k].qte_az || azByEan[k].qte_min || 0) + (r.qte_az || r.qte_min || 0);
      azByEan[k].besoin = (azByEan[k].besoin || 0) + (r.besoin || 0);
      azByEan[k].stock = (azByEan[k].stock || 0) + (r.stock || 0);
    } else { azByEan[k] = r; }
  });
  // v7.95 — rapport universel : sans collage Moteur, le rapport fonctionne
  // en mode « Calculateur seul » (statut 🧮, tout pré-coché).
  var sansMoteur = !(cmdAzData && cmdAzData.length);
  window._cmdRapportSansMoteur = sansMoteur;
  var srcNom = window._cmdRapportSource || 'Moteur'; // v7.96 : « Moteur » ou « Analyse Zone »
  window._cmdRapportSourceNom = srcNom;

  // Récupérer les lignes générées par cmdGenerer (stockées dans cmdDerniereSimulation.lignesArray)
  var lignesCalc = (cmdDerniereSimulation && cmdDerniereSimulation.lignesArray) || [];
  var calcByEan = {};
  lignesCalc.forEach(function(l){
    if (!l.ean) return;
    var k = cmdRemapEan(l.ean);
    if (calcByEan[k]) { calcByEan[k].qte = (calcByEan[k].qte || 0) + (l.qte || 0); }
    else { calcByEan[k] = l; }
  });

  // Union des deux ensembles
  var allEans = {};
  Object.keys(azByEan).forEach(function(e){ allEans[e] = true; });
  Object.keys(calcByEan).forEach(function(e){ allEans[e] = true; });

  var segABC = cmdSegmentsABC(); // v7.87
  // v7.83 — prix unitaire net pour valoriser le rapport (ligne calc prioritaire, sinon catalogue)
  var prixByEan = {}, stockByEan = {}, moyByEan = {}, colisByEan = {};
  (cmdProduitsSource || []).forEach(function(p){
    if (p.ean) {
      prixByEan[String(p.ean)] = p.pa_net || p.prix_net_rendu || 0;
      stockByEan[String(p.ean)] = (p.stock !== undefined && p.stock !== null) ? p.stock : null; // v7.89
      moyByEan[String(p.ean)] = p.moy || 0; // v7.91
      colisByEan[String(p.ean)] = p.colisage || 0; // v7.94
    }
  });
  // v7.96 — replier les index de l'ancien EAN vers le nouveau
  Object.keys(eanRemap).forEach(function(a) {
    var n = eanRemap[a];
    if (!prixByEan[n] && prixByEan[a]) prixByEan[n] = prixByEan[a];
    if ((stockByEan[n] === undefined || stockByEan[n] === null) && stockByEan[a] !== undefined) stockByEan[n] = stockByEan[a];
    else if (stockByEan[n] !== undefined && stockByEan[n] !== null && stockByEan[a]) stockByEan[n] += stockByEan[a];
    moyByEan[n] = (moyByEan[n] || 0) + (moyByEan[a] || 0); // les rotations s'additionnent
    if (!colisByEan[n] && colisByEan[a]) colisByEan[n] = colisByEan[a];
  });
  // v7.91 — paramètres pour le besoin réel (non arrondi au colisage) et la couverture
  var moisCible91 = parseFloat((document.getElementById('cmd-mois') || {}).value) || 2;
  var stockMode91 = ((document.getElementById('cmd-stock-mode') || {}).value) || 'deduct';
  // v7.92 — rotation de secours par EAN depuis le cache Ospharm (12 mois).
  // MAX et non somme : un même EAN peut figurer sous son fabricant ET sous la
  // clé COALIA du cache — la somme compterait ses ventes deux fois.
  var moyOsph = {};
  try {
    if (typeof decOspharmProds !== 'undefined' && decOspharmProds) {
      Object.keys(decOspharmProds).forEach(function(l) {
        (decOspharmProds[l] || []).forEach(function(p) {
          if (p.ean) {
            var e = String(p.ean);
            var m = (p.qte || 0) / 12;
            if (!moyOsph[e] || m > moyOsph[e]) moyOsph[e] = m;
          }
        });
      });
    }
  } catch (e) {}
  Object.keys(eanRemap).forEach(function(a) { // v7.96 : rotation de l'ancien EAN -> nouveau
    if (moyOsph[a]) { moyOsph[eanRemap[a]] = (moyOsph[eanRemap[a]] || 0) + moyOsph[a]; delete moyOsph[a]; }
  });
  var rapport = [];
  Object.keys(allEans).forEach(function(ean) {
    var az   = azByEan[ean];
    var calc = calcByEan[ean];
    var qteAz   = az   ? (az.qte_az || 0)   : 0;
    var qteCalc = calc ? (calc.qte || 0) : 0;
    var libelle = (az ? az.libelle : calc ? calc.nom : ean).slice(0, 45);
    var alerte  = az ? (az.alerte || '') : '';
    var dn      = az ? (az.dn || '') : '';
    var ecart   = qteCalc - qteAz;
    var statut;
    if (sansMoteur) { statut = '\ud83e\uddee Calc'; }
    else if (qteAz > 0 && qteCalc > 0) {
      statut = Math.abs(ecart) <= 1 ? '✅ OK' : (qteCalc > qteAz ? '📈 Calc > ' + srcNom : '📉 ' + srcNom + ' > Calc');
    } else if (qteCalc > 0) { statut = '🔵 Calc seul'; }
    else { statut = '🟠 ' + srcNom + ' seul'; }
    var role = az ? String(az.role || '').toUpperCase() : '';
    if (!role) role = segABC[ean] || ''; // v7.87 : segment calculé (suffixe *)
    var qteF = Math.max(qteAz, qteCalc);
    var prixU = (calc && calc.paNet) ? calc.paNet : (prixByEan[ean] || 0);
    var stockV = az ? (az.stock || 0) : ((stockByEan[ean] !== undefined && stockByEan[ean] !== null) ? stockByEan[ean] : null); // v7.89
    // v7.97 — le stock LGPI (import MEQ pharmacie entière, daté) PRIME sur le
    // Stock RT de la source pour les lignes à EAN remplacé (la source regardait
    // l'ancien code mort), et sert de repli quand aucun stock n'est connu.
    var stockLgpi = (typeof condStockLGPI !== 'undefined' && condStockLGPI && condStockLGPI[ean] !== undefined) ? condStockLGPI[ean] : null;
    if (eanRemplaces[ean] && stockLgpi !== null) stockV = stockLgpi;
    else if (stockV === null && stockLgpi !== null) stockV = stockLgpi;
    // v7.91 — besoin réel NON arrondi au colisage (pour acheter ailleurs à l'unité)
    // = max(Besoin Théo du Moteur, besoin brut calculateur), et couverture en mois
    // si on commande la qté finale au colisage : (stock + qté) / rotation mensuelle.
    var moy91 = moyByEan[ean] || (calc && calc.moy) || moyOsph[ean] || 0; // v7.92 : repli cache Ospharm
    var stockPourBesoin = stockMode91 === 'deduct' ? (stockV || 0) : 0;
    var besoinCalcBrut = moy91 > 0 ? Math.max(0, Math.ceil(moy91 * moisCible91 - stockPourBesoin)) : 0;
    var besoinReel = Math.max(az ? (az.besoin || 0) : 0, besoinCalcBrut);
    if (eanRemplaces[ean]) besoinReel = besoinCalcBrut; // v7.97 : le besoin de la source est périmé sur un EAN remplacé
    var couv = moy91 > 0 ? ((stockV || 0) + qteF) / moy91 : null;
    var ancienEan = eanRemplaces[ean] || null; // v7.96
    if (ancienEan) libelle = libelle + ' \u21bb';
    rapport.push({ ean: ean, libelle: libelle, ancienEan: ancienEan, dn: dn, alerte: alerte, role: role,
      qteAz: qteAz, qteCalc: qteCalc, ecart: ecart, statut: statut,
      prixU: prixU, ca: qteF * prixU, stock: stockV,
      besoinReel: besoinReel, couv: couv, moy: moy91,
      colis: colisByEan[ean] || (az ? (az.colisage || 0) : 0),
      qteFinale: qteF });
  });

  // v7.84 — rendu délégué à cmdRapportRender : filtres par statut,
  // cases à cocher, sélection valorisée. Pré-cochage : tout SAUF « Calc seul »
  // (les lignes à arbitrer soi-même).
  window._cmdRapport = rapport;
  window._cmdRapportFiltre = null;
  window._cmdRapportFiltreSeg = null;
  window._cmdRapportSel = {};
  rapport.forEach(function(r){ window._cmdRapportSel[r.ean] = (r.statut !== '\ud83d\udd35 Calc seul'); });
  cmdRapportRender();
}

// ═══════════ v7.84 — rendu du rapport Moteur vs Calculateur ═══════════
function cmdRapportRender() {
  var rapport = window._cmdRapport || [];
  var rapportEl = document.getElementById('cmd-az-rapport');
  if (!rapportEl) return;
  if (!rapport.length) { rapportEl.style.display = 'none'; return; }
  var sel = window._cmdRapportSel || {};
  var filtre = window._cmdRapportFiltre || null;
  var filtreSeg = window._cmdRapportFiltreSeg || null; // v7.90

  // Tri : ruptures d'abord, puis par qte desc
  rapport.sort(function(a, b) {
    var pa = a.alerte.indexOf('RUPTURE') >= 0 ? 0 : a.alerte.indexOf('DANGER') >= 0 ? 1 : 2;
    var pb = b.alerte.indexOf('RUPTURE') >= 0 ? 0 : b.alerte.indexOf('DANGER') >= 0 ? 1 : 2;
    return pa !== pb ? pa - pb : Math.max(b.qteAz, b.qteCalc) - Math.max(a.qteAz, a.qteCalc);
  });

  var totalAz   = rapport.reduce(function(s,r){ return s + r.qteAz; }, 0);
  var totalCalc = rapport.reduce(function(s,r){ return s + r.qteCalc; }, 0);
  var totalFin  = rapport.reduce(function(s,r){ return s + r.qteFinale; }, 0);
  var totalCA   = rapport.reduce(function(s,r){ return s + r.ca; }, 0);

  // Sous-totaux par segment (sur TOUTES les lignes, indépendant du filtre)
  var segCouleurs = { 'SOCLE':'#dbeafe', 'COEUR':'#fef9c3', 'CŒUR':'#fef9c3', 'COMPLEMENT':'#fce7f3', 'COMPLÉMENT':'#fce7f3' };
  var segOrdre = ['SOCLE','COEUR','CŒUR','COMPLEMENT','COMPLÉMENT'];
  var segTot = {};
  rapport.forEach(function(r){
    var k = (r.role || 'Hors ' + srcN).replace('*', '');
    if (!segTot[k]) segTot[k] = { u: 0, ca: 0 };
    segTot[k].u += r.qteFinale; segTot[k].ca += r.ca;
  });
  var segBadges = Object.keys(segTot).sort(function(a,b){
    var ia = segOrdre.indexOf(a), ib = segOrdre.indexOf(b);
    return (ia < 0 ? 99 : ia) - (ib < 0 ? 99 : ib);
  }).map(function(k){
    var actifSeg = (filtreSeg === k);
    return '<button type="button" onclick="cmdRapportFiltrerSeg(this.getAttribute(\'data-seg\'))" data-seg="' + k + '" style="background:' + (segCouleurs[k] || '#f1f5f9') + ';padding:4px 12px;border-radius:12px;font-size:11px;font-weight:600;margin-right:6px;cursor:pointer;border:2px solid ' + (actifSeg ? '#1e293b' : 'transparent') + '">' + k + ' : ' + segTot[k].u + ' u · ' + Math.round(segTot[k].ca) + '\u20ac</button>';
  }).join('');

  // Badges de statut = FILTRES cliquables (re-clic = enlever le filtre)
  var statCounts = {};
  rapport.forEach(function(r){ statCounts[r.statut] = (statCounts[r.statut]||0)+1; });
  var srcN = window._cmdRapportSourceNom || 'Moteur';
  var badgeColor = { '\u2705 OK':'#dcfce7', '\ud83d\udd35 Calc seul':'#dbeafe', '\ud83e\uddee Calc':'#f0fdf4' };
  badgeColor['\ud83d\udcc8 Calc > ' + srcN] = '#eff6ff';
  badgeColor['\ud83d\udcc9 ' + srcN + ' > Calc'] = '#fef2f2';
  badgeColor['\ud83d\udfe0 ' + srcN + ' seul'] = '#fff8ee';
  var summaryBadges = Object.keys(statCounts).map(function(st){
    var actif = (filtre === st);
    return '<button type="button" onclick="cmdRapportFiltrer(this.getAttribute(\'data-st\'))" data-st="' + st + '" style="background:' + (badgeColor[st]||'#f1f5f9') + ';padding:4px 12px;border-radius:12px;font-size:11px;font-weight:600;margin-right:6px;cursor:pointer;border:2px solid ' + (actif ? '#1e293b' : 'transparent') + '">' + st + ' : ' + statCounts[st] + '</button>';
  }).join('');
  summaryBadges += '<button type="button" onclick="cmdRapportFiltrer(null)" style="background:' + ((filtre || filtreSeg) ? '#fff' : '#1e293b') + ';color:' + ((filtre || filtreSeg) ? '#334155' : '#fff') + ';padding:4px 12px;border-radius:12px;font-size:11px;font-weight:600;cursor:pointer;border:2px solid #1e293b">Tous</button>';

  // Lignes visibles selon le filtre
  var visibles = rapport.filter(function(r){
    if (filtre && r.statut !== filtre) return false;
    if (filtreSeg && (r.role || 'Hors Moteur').replace('*', '') !== filtreSeg) return false;
    return true;
  });

  var thS = 'padding:6px 8px;background:#1e293b;color:#fff;font-size:10px;font-weight:600;text-transform:uppercase;letter-spacing:.05em;white-space:nowrap;text-align:center;position:sticky;top:0;z-index:2'; // v7.93 : en-tête figé
  var rows = visibles.map(function(r, i) {
    var coche = !!sel[r.ean];
    var bg = i%2===0?'#fff':'#f8fafc';
    if (r.alerte.indexOf('RUPTURE') >= 0) bg = '#fff1f2';
    else if (r.alerte.indexOf('DANGER') >= 0) bg = '#fff8ee';
    var alerteTxt = r.alerte.indexOf('RUPTURE') >= 0 ? '\ud83d\udd34 RUPTURE' : r.alerte.indexOf('DANGER') >= 0 ? '\ud83d\udfe0 DANGER' : '';
    var ecartTxt = r.qteAz > 0 && r.qteCalc > 0 ? (r.ecart > 0 ? '+' : '') + r.ecart : '';
    var ecartClr = r.ecart < -2 ? 'color:#dc2626' : r.ecart > 2 ? 'color:#16a34a' : 'color:#64748b';
    return '<tr style="background:' + bg + (coche ? '' : ';opacity:.55') + '">' +
      '<td style="padding:6px 8px;text-align:center"><input type="checkbox" ' + (coche ? 'checked ' : '') + 'onchange="cmdRapportCocher(\'' + r.ean + '\', this.checked)" style="width:16px;height:16px;cursor:pointer"></td>' +
      '<td style="padding:6px 8px;font-size:10px;color:#94a3b8;font-family:monospace">' + r.ean + '</td>' +
      '<td style="padding:6px 8px;font-size:12px;font-weight:500;max-width:180px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis" title="' + r.libelle + '">' + r.libelle + '</td>' +
      '<td style="padding:6px 8px;font-size:10.5px;font-weight:600">' + (r.role || '') + '</td>' +
      '<td style="padding:6px 8px;font-size:11px">' + r.dn + '</td>' +
      '<td style="padding:6px 8px;font-size:11px;font-weight:600;color:#dc2626">' + alerteTxt + '</td>' +
      '<td style="padding:6px 8px;text-align:center;font-weight:600;color:' + (r.stock === 0 ? '#dc2626' : '#92660a') + '">' + (r.stock === null ? '\u2014' : r.stock) + '</td>' +
      '<td style="padding:6px 8px;text-align:center;font-weight:700;color:#003B7A">' + (r.qteAz || '\u2014') + '</td>' +
      '<td style="padding:6px 8px;text-align:center;font-weight:700;color:#065f46">' + (r.qteCalc || '\u2014') + '</td>' +
      '<td style="padding:6px 8px;text-align:center;font-weight:600;' + ecartClr + '">' + ecartTxt + '</td>' +
      '<td style="padding:6px 8px;text-align:center;font-weight:700;color:#b91c1c">' + (r.besoinReel > 0 ? r.besoinReel : '\u2014') + '</td>' +
      '<td style="padding:6px 8px;text-align:center;font-size:11px;color:#64748b">' + (r.colis > 0 ? '\u00d7' + r.colis : '\u2014') + '</td>' +
      '<td style="padding:6px 8px;text-align:center"><input type="number" min="0" value="' + r.qteFinale + '" oninput="cmdRapportQteLive(this.getAttribute(\'data-ean\'), this.value)" onchange="cmdRapportQteChange(this.getAttribute(\'data-ean\'), this.value)" data-ean="' + r.ean + '" style="width:58px;text-align:center;font-weight:700;font-size:13px;color:#7c3aed;border:1px solid var(--border);border-radius:4px;padding:2px;background:transparent"></td>' +
      '<td id="cmd-couv-' + r.ean + '" style="padding:6px 8px;text-align:center;font-size:11px;' + ((r.couv !== null && r.couv !== undefined) ? (r.couv > 3 ? 'color:#dc2626;font-weight:700' : (r.couv > 2.5 ? 'color:#b45309;font-weight:600' : 'color:#475569')) : 'color:#475569') + '">' + ((r.couv !== null && r.couv !== undefined) ? (Math.round(r.couv * 10) / 10).toFixed(1).replace('.', ',') + ' m' : '\u2014') + '</td>' +
      '<td id="cmd-ca-' + r.ean + '" style="padding:6px 8px;text-align:right;font-size:11px;color:#0f766e;font-weight:600">' + (r.ca > 0 ? Math.round(r.ca) + '\u20ac' : '\u2014') + '</td>' +
      '<td style="padding:6px 8px;font-size:11px">' + r.statut + '</td>' +
      '</tr>';
  }).join('');

  rapportEl.style.display = 'block';
  rapportEl.innerHTML =
    '<p class="card-title" style="margin-bottom:12px">\u26a1 ' + (window._cmdRapportSansMoteur ? 'Rapport de commande \u2014 Calculateur' : 'Rapport de rapprochement \u2014 ' + srcN + ' vs Calculateur') + '</p>' +
    '<div style="display:flex;gap:16px;flex-wrap:wrap;margin-bottom:12px">' +
    '<div style="background:#eff6ff;border-radius:8px;padding:10px 16px;text-align:center"><div style="font-size:22px;font-weight:700;color:#003B7A">' + totalAz + '</div><div style="font-size:11px;color:#64748b">Unit\u00e9s ' + srcN + '</div></div>' +
    '<div style="background:#f0fdf4;border-radius:8px;padding:10px 16px;text-align:center"><div style="font-size:22px;font-weight:700;color:#065f46">' + totalCalc + '</div><div style="font-size:11px;color:#64748b">Total unit\u00e9s Calc.</div></div>' +
    '<div style="background:#faf5ff;border-radius:8px;padding:10px 16px;text-align:center"><div style="font-size:22px;font-weight:700;color:#7c3aed">' + totalFin + '</div><div style="font-size:11px;color:#64748b">Total \u00e0 commander</div></div>' +
    '<div style="background:#f0fdfa;border-radius:8px;padding:10px 16px;text-align:center"><div style="font-size:22px;font-weight:700;color:#0f766e">' + Math.round(totalCA) + '\u20ac</div><div style="font-size:11px;color:#64748b">CA cde HT (qt\u00e9 finale)</div></div>' +
    '<div style="flex:1;display:flex;align-items:center;flex-wrap:wrap;gap:4px">' + summaryBadges + '</div>' +
    '</div>' +
    '<div style="margin-bottom:12px">' + segBadges + '</div>' +
    '<div id="cmd-rapport-sel" style="display:flex;align-items:center;gap:12px;flex-wrap:wrap;background:#f8fafc;border:1px solid var(--border);border-radius:var(--radius-sm);padding:8px 12px;margin-bottom:10px"></div>' +
    '<div id="cmd-rapport-aide" style="display:none"></div>' +
    '<div style="display:flex;gap:8px;margin-bottom:8px">' +
    '<button type="button" onclick="cmdRapportToutCocher(true)" style="font-size:11px;padding:4px 12px;border:1px solid var(--border);background:#fff;border-radius:var(--radius-sm);cursor:pointer">\u2611 Tout cocher (lignes affich\u00e9es)</button>' +
    '<button type="button" onclick="cmdRapportToutCocher(false)" style="font-size:11px;padding:4px 12px;border:1px solid var(--border);background:#fff;border-radius:var(--radius-sm);cursor:pointer">\u2610 Tout d\u00e9cocher (lignes affich\u00e9es)</button>' +
    '<button type="button" onclick="cmdRapportCouv3()" style="font-size:11px;padding:4px 12px;border:1px solid #b45309;background:#fffbeb;color:#92400e;border-radius:var(--radius-sm);cursor:pointer;font-weight:600">\u26a1 Couv. &gt; 3 mois \u2192 1 colis</button>' +
    ((filtre || filtreSeg) ? '<span style="font-size:11px;color:var(--text-sec);align-self:center">Filtre actif : ' + [filtre, filtreSeg].filter(Boolean).join(' + ') + ' \u2014 ' + visibles.length + ' ligne(s)</span>' : '') +
    '</div>' +
    '<div style="overflow:auto;max-height:72vh;border:1px solid var(--border);border-radius:6px"><table style="width:100%;border-collapse:collapse;font-size:12px">' +
    '<thead><tr>' +
    '<th style="' + thS + '">\u2611</th>' +
    '<th style="' + thS + '">EAN</th>' +
    '<th style="' + thS + ';text-align:left">Libell\u00e9</th>' +
    '<th style="' + thS + '">Segment</th>' +
    '<th style="' + thS + '">DN%</th>' +
    '<th style="' + thS + '">Alerte</th>' +
    '<th style="' + thS + ';color:#fbbf24">Stock</th>' +
    '<th style="' + thS + ';color:#93c5fd">Qt\u00e9 ' + srcN + '</th>' +
    '<th style="' + thS + ';color:#6ee7b7">Qt\u00e9 Calc</th>' +
    '<th style="' + thS + '">\u00c9cart</th>' +
    '<th style="' + thS + ';color:#fca5a5">Besoin r\u00e9el</th>' +
    '<th style="' + thS + '">Colis.</th>' +
    '<th style="' + thS + ';color:#c4b5fd">Qt\u00e9 finale</th>' +
    '<th style="' + thS + '">Couv.</th>' +
    '<th style="' + thS + '">CA cde</th>' +
    '<th style="' + thS + '">Statut</th>' +
    '</tr></thead><tbody>' + rows + '</tbody></table></div>' +
    '<p style="font-size:11px;color:#94a3b8;margin-top:8px">\ud83d\udfe0 ' + srcN + ' seul = pas de rotation c\u00f4t\u00e9 calculateur, la qt\u00e9 ' + srcN + ' fait foi \u00b7 \u2705 OK = les deux logiques convergent \u00b7 \ud83d\udcc9 ' + srcN + ' > Calc = urgence stock \u00b7 \ud83d\udd35 Calc seul = non demand\u00e9 par ' + (srcN === 'Moteur' ? 'le Moteur' : 'l\u2019Analyse Zone') + ', v\u00e9rifier saisonnalit\u00e9 et stock avant de garder \u00b7 \ud83e\uddee Calc = rapport sans source Sheets \u00b7 Qt\u00e9 finale = max(' + srcN + ', Calculateur) au colisage, valoris\u00e9e au prix net \u00b7 Besoin r\u00e9el = besoin NON arrondi au colisage (pour comparer/acheter ailleurs \u00e0 l\u2019unit\u00e9) \u00b7 Couv. = mois de stock si on commande la qt\u00e9 finale : (stock + qt\u00e9) \u00f7 rotation \u00b7 \u21bb = EAN remplac\u00e9 (Cycle de vie) \u00b7 Segment* = calcul\u00e9 par contribution au CA annuel Ospharm du labo (SOCLE \u2264 80 %, C\u0152UR 80-95 % \u2014 r\u00e8gle du Moteur), sans * = fourni par la source</p>';
  cmdRapportSelMaj();
}

function cmdRapportFiltrer(st) {
  window._cmdRapportFiltre = (st && window._cmdRapportFiltre !== st) ? st : null;
  if (!st) window._cmdRapportFiltreSeg = null; // « Tous » réinitialise les deux filtres
  cmdRapportRender();
}

// v7.90 — filtre par segment (SOCLE / COEUR / COMPLEMENT), cumulable avec le statut
function cmdRapportFiltrerSeg(sg) {
  window._cmdRapportFiltreSeg = (sg && window._cmdRapportFiltreSeg !== sg) ? sg : null;
  cmdRapportRender();
}

function cmdRapportCocher(ean, on) {
  if (!window._cmdRapportSel) window._cmdRapportSel = {};
  window._cmdRapportSel[ean] = !!on;
  cmdRapportSelMaj();
}

function cmdRapportToutCocher(on) {
  var rapport = window._cmdRapport || [];
  var filtre = window._cmdRapportFiltre || null;
  var filtreSeg = window._cmdRapportFiltreSeg || null;
  if (!window._cmdRapportSel) window._cmdRapportSel = {};
  rapport.forEach(function(r){
    if (filtre && r.statut !== filtre) return;
    if (filtreSeg && (r.role || 'Hors Moteur').replace('*', '') !== filtreSeg) return;
    window._cmdRapportSel[r.ean] = !!on;
  });
  cmdRapportRender();
}

// v8.10 — recalcul EN DIRECT pendant la frappe : couverture, CA de ligne et
// bandeau 🛒 se mettent à jour sans re-rendu (le champ garde le focus).
function cmdRapportQteLive(ean, val) {
  var rapport = window._cmdRapport || [];
  var v = Math.max(0, parseInt(val, 10) || 0);
  rapport.forEach(function(r) {
    if (r.ean !== ean) return;
    r.qteFinale = v;
    r.ca = v * (r.prixU || 0);
    if (r.moy > 0) r.couv = ((r.stock || 0) + v) / r.moy;
    var tdC = document.getElementById('cmd-couv-' + ean);
    if (tdC) {
      if (r.couv !== null && r.couv !== undefined) {
        tdC.textContent = (Math.round(r.couv * 10) / 10).toFixed(1).replace('.', ',') + ' m';
        tdC.style.color = r.couv > 3 ? '#dc2626' : (r.couv > 2.5 ? '#b45309' : '#475569');
        tdC.style.fontWeight = r.couv > 3 ? '700' : (r.couv > 2.5 ? '600' : '400');
      } else { tdC.textContent = '\u2014'; }
    }
    var tdA = document.getElementById('cmd-ca-' + ean);
    if (tdA) { tdA.textContent = r.ca > 0 ? Math.round(r.ca) + '\u20ac' : '\u2014'; }
  });
  cmdRapportSelMaj();
}

// v8.03 — quantité finale ÉDITABLE : l'ajustement se répercute sur le CA,
// la couverture, le bandeau, la copie et le bon de commande imprimé.
function cmdRapportQteChange(ean, val) {
  var rapport = window._cmdRapport || [];
  var v = Math.max(0, parseInt(val, 10) || 0);
  rapport.forEach(function(r) {
    if (r.ean !== ean) return;
    r.qteFinale = v;
    r.ca = v * (r.prixU || 0);
    if (r.moy > 0) r.couv = ((r.stock || 0) + v) / r.moy;
  });
  cmdRapportRender();
}

// v8.03/v8.07 — règle du cash en un clic : sur TOUTES les lignes (cochées ou
// non) dont la couverture dépasse 3 mois, ramener la quantité au minimum du
// colisage (1 colis) — ainsi une ligne cochée plus tard est déjà assainie.
function cmdRapportCouv3() {
  var rapport = window._cmdRapport || [];
  var n = 0, dejaMin = 0;
  rapport.forEach(function(r) {
    if (r.couv === null || r.couv === undefined || r.couv <= 3) return;
    if (r.colis > 0 && r.qteFinale > r.colis) {
      r.qteFinale = r.colis;
      r.ca = r.colis * (r.prixU || 0);
      if (r.moy > 0) r.couv = ((r.stock || 0) + r.colis) / r.moy;
      n++;
    } else {
      dejaMin++; // déjà au colisage minimum (ou colisage inconnu) — la couverture restera > 3 mois
    }
  });
  cmdRapportRender();
  var msg = [];
  if (n) msg.push('\u2713 ' + n + ' ligne(s) ramen\u00e9e(s) \u00e0 1 colis.');
  if (dejaMin) msg.push('\u26a0 ' + dejaMin + ' ligne(s) d\u00e9j\u00e0 au colisage minimum avec une couverture > 3 mois (Couv. en rouge) : le colisage impos\u00e9 d\u00e9passe le besoin \u2014 garder 1 colis, d\u00e9cocher, ou acheter \u00e0 l\u2019unit\u00e9 ailleurs.');
  if (!msg.length) msg.push('Aucune ligne avec une couverture > 3 mois \u2014 la commande respecte la r\u00e8gle du cash.');
  alert(msg.join('\n'));
}

// Bandeau récapitulatif de la sélection (lignes cochées, TOUTES, filtre ou pas)
function cmdRapportSelMaj() {
  var el = document.getElementById('cmd-rapport-sel');
  if (!el) return;
  var rapport = window._cmdRapport || [];
  var sel = window._cmdRapportSel || {};
  var n = 0, u = 0, ca = 0;
  rapport.forEach(function(r){ if (sel[r.ean]) { n++; u += r.qteFinale; ca += r.ca; } });
  el.innerHTML =
    '<span style="font-size:13px;font-weight:700">\ud83d\uded2 Ma commande : ' + n + ' produit(s) \u00b7 ' + u + ' unit\u00e9s \u00b7 ' + Math.round(ca) + '\u20ac HT</span>' +
    '<button type="button" onclick="cmdRapportCopier()" style="font-size:11px;padding:5px 14px;background:var(--accent);color:#fff;border:none;border-radius:var(--radius-sm);cursor:pointer;font-weight:600">\ud83d\udccb Copier la s\u00e9lection (EAN + Qt\u00e9)</button>' +
    '<button type="button" onclick="cmdRapportImprimer()" style="font-size:11px;padding:5px 14px;background:#1e293b;color:#fff;border:none;border-radius:var(--radius-sm);cursor:pointer;font-weight:600">\ud83d\udda8 Imprimer la commande</button>' +
    '<button type="button" onclick="cmdRapportImprimerBesoins()" style="font-size:11px;padding:5px 14px;background:#fff;color:#92400e;border:1px solid #b45309;border-radius:var(--radius-sm);cursor:pointer;font-weight:600">\ud83d\udda8 Non retenus (besoin r\u00e9el)</button>' +
    '<button type="button" onclick="cmdRapportAideToggle()" style="font-size:11px;padding:5px 14px;background:#fff;color:#334155;border:1px solid var(--border);border-radius:var(--radius-sm);cursor:pointer;font-weight:600">\u2753 Workflow de validation</button>';
}

// v7.86 — bon de commande imprimable de la sélection cochée
// v7.98 — guide de validation de la sélection (bouton ❓ du bandeau Ma commande)
function cmdRapportAideToggle() {
  var el = document.getElementById('cmd-rapport-aide');
  if (!el) return;
  if (el.style.display !== 'none') { el.style.display = 'none'; return; }
  var srcN = window._cmdRapportSourceNom || 'Moteur';
  var li = 'font-size:11.5px;margin:0 0 7px 0';
  el.innerHTML =
    '<div style="background:var(--surface2);padding:12px 14px;border-radius:var(--radius-sm);margin-bottom:10px;border:1px solid var(--border)">' +
    '<p style="' + li + ';font-weight:700">Comment valider la commande \u2014 2 passes de 30 secondes</p>' +
    '<p style="' + li + '"><b>Pr\u00e9-cochage.</b> Tout est coch\u00e9 d\u2019office SAUF les \ud83d\udd35 Calc seul. Coch\u00e9 ne veut PAS dire \u00e0 valider les yeux ferm\u00e9s.</p>' +
    '<p style="' + li + '"><b>Passe 1 \u2014 les coch\u00e9s.</b> Balayer la colonne Couv. de haut en bas : au-del\u00e0 de \u2248 2,5-3 mois, se poser la question avant de garder \u2014 rupture fant\u00f4me (EAN remplac\u00e9 \u21bb, stock r\u00e9el \u00e9lev\u00e9), saisonnalit\u00e9 \u00e0 contre-temps, colisage disproportionn\u00e9 (comparer Besoin r\u00e9el vs Colis.). D\u00e9cocher, \u00e9diter la Qt\u00e9 finale (champ modifiable, le bon imprim\u00e9 suit), cliquer \u00ab \u26a1 Couv. &gt; 3 mois \u2192 1 colis \u00bb pour appliquer la r\u00e8gle d\u2019un coup, ou pr\u00e9voir d\u2019acheter \u00e0 l\u2019unit\u00e9 ailleurs.</p>' +
    '<p style="' + li + '"><b>Passe 2 \u2014 les d\u00e9coch\u00e9s.</b> Filtre \ud83d\udd35 Calc seul (+ filtre segment : commencer par SOCLE) : cocher UNIQUEMENT ce qui se vendra avant l\u2019\u00e9ch\u00e9ance 45 j fin de mois (r\u00e8gle du cash). Un COMPL\u00c9MENT* en Calc seul se d\u00e9coche presque toujours.</p>' +
    '<p style="' + li + '"><b>Finaliser.</b> \u00ab Tous \u00bb pour tout revoir \u2192 v\u00e9rifier le bandeau \ud83d\uded2 (produits \u00b7 unit\u00e9s \u00b7 \u20ac HT) \u2192 \ud83d\udccb Copier la s\u00e9lection (EAN \u00b7 Qt\u00e9 \u00b7 Colis. \u00b7 Besoin r\u00e9el) ou \ud83d\udda8 Imprimer le bon de commande (avec colisage) \u2014 ajuster les quantit\u00e9s au colisage \u00e0 la saisie \u00b7 \ud83d\udda8 \u00ab Non retenus (besoin r\u00e9el) \u00bb = les besoins D\u00c9COCH\u00c9S dont le stock couvre MOINS de 3 mois (ruptures en t\u00eate), sans colisage, \u00e0 passer chez un autre fournisseur.</p>' +
    '<p style="' + li + ';color:var(--text-sec)">Rep\u00e8res : Qt\u00e9 finale = max(' + srcN + ', Calculateur) au colisage \u00b7 Couv. = (stock + qt\u00e9) \u00f7 rotation \u00b7 plafond cash \u2248 2,5 mois \u00b7 \u21bb = EAN remplac\u00e9, stock LGPI prioritaire.</p>' +
    '</div>';
  el.style.display = 'block';
}

function cmdRapportImprimer() {
  var rapport = window._cmdRapport || [];
  var sel = window._cmdRapportSel || {};
  var lignes = rapport.filter(function(r){ return sel[r.ean]; });
  if (!lignes.length) { alert('Aucun produit coch\u00e9.'); return; }
  // Tri : segment (SOCLE, COEUR, COMPLEMENT, Hors Moteur) puis CA d\u00e9croissant
  var ordre = { 'SOCLE': 0, 'COEUR': 1, 'C\u0152UR': 1, 'COMPLEMENT': 2, 'COMPL\u00c9MENT': 2 };
  lignes.sort(function(a, b) {
    var ra = String(a.role || '').replace('*', ''), rb = String(b.role || '').replace('*', '');
    var oa = (ra in ordre) ? ordre[ra] : 3;
    var ob = (rb in ordre) ? ordre[rb] : 3;
    return oa !== ob ? oa - ob : b.ca - a.ca;
  });
  var laboNom = (function(){
    var s = document.getElementById('cmd-labo-sel');
    return (s && s.selectedOptions[0]) ? s.selectedOptions[0].text : 'Commande';
  })();
  var date = new Date().toLocaleDateString('fr-FR');
  var totU = 0, totCA = 0;
  var rows = lignes.map(function(r) {
    totU += r.qteFinale; totCA += r.ca;
    return '<tr>' +
      '<td style="font-family:monospace">' + r.ean + '</td>' +
      '<td>' + r.libelle + '</td>' +
      '<td>' + (r.role || 'Hors ' + (window._cmdRapportSourceNom || 'Moteur')) + '</td>' +
      '<td>' + (r.colis > 0 ? '\u00d7' + r.colis : '\u2014') + '</td>' +
      '<td>' + r.qteFinale + '</td>' +
      '<td>' + (r.prixU > 0 ? (Math.round(r.prixU * 100) / 100).toFixed(2).replace('.', ',') + '\u20ac' : '\u2014') + '</td>' +
      '<td>' + (r.ca > 0 ? (Math.round(r.ca * 100) / 100).toFixed(2).replace('.', ',') + '\u20ac' : '\u2014') + '</td>' +
      '</tr>';
  }).join('');
  var w = window.open('', '_blank');
  if (!w) { alert('Fen\u00eatre bloqu\u00e9e par le navigateur \u2014 autorisez les popups pour ce site.'); return; }
  w.document.write('<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Bon de commande ' + laboNom + ' \u2014 ' + date + '</title><style>' +
    'body{font-family:DM Sans,Arial,sans-serif;font-size:12px;color:#1a1a18;padding:24px;max-width:900px;margin:0 auto}' +
    'h1{font-size:16px;font-weight:700;margin-bottom:4px}' +
    '.sub{font-size:11px;color:#6b6a64;margin-bottom:20px}' +
    'table{width:100%;border-collapse:collapse;font-size:11px;margin-bottom:16px}' +
    'th{padding:6px 8px;background:#1a1a18 !important;color:#fff !important;text-align:left;font-size:9px;font-weight:600;letter-spacing:.05em;text-transform:uppercase;-webkit-print-color-adjust:exact;print-color-adjust:exact}' +
    'th:nth-child(n+4){text-align:right}' +
    'td{padding:5px 8px;border-bottom:0.5px solid #e0e0e0}' +
    'td:nth-child(n+4){text-align:right;font-family:monospace}' +
    'tr:nth-child(even){background:#f9f9f7}' +
    'tfoot td{font-weight:700;border-top:2px solid #1a1a18;background:#f5f4f0}' +
    '.footer{margin-top:24px;font-size:10px;color:#9e9d96;border-top:1px solid #e0e0e0;padding-top:8px}' +
    '@media print{body{padding:12px}}' +
    '</style></head><body>' +
    '<h1>Bon de commande \u2014 ' + laboNom + '</h1>' +
    '<div class="sub">S\u00e9lection valid\u00e9e le ' + date + ' \u00b7 Pharmacie Michelet \u00b7 ' + lignes.length + ' produits \u00b7 Qt\u00e9 finale = max(Moteur, Calculateur) \u00b7 prix nets rendus TSRF</div>' +
    '<table><thead><tr><th>EAN</th><th>Libell\u00e9</th><th>Segment</th><th>Colis.</th><th>Qt\u00e9</th><th>PU net HT</th><th>Total HT</th></tr></thead>' +
    '<tbody>' + rows + '</tbody>' +
    '<tfoot><tr><td colspan="4">TOTAL</td><td>' + totU + '</td><td></td><td>' + (Math.round(totCA * 100) / 100).toFixed(2).replace('.', ',') + '\u20ac</td></tr></tfoot>' +
    '</table>' +
    '<div class="footer">Calculateur Pharmacie Michelet \u00b7 calculateur-pharmacie.vercel.app</div>' +
    '</body></html>');
  w.document.close();
  setTimeout(function(){ w.print(); }, 400);
}

// v8.08 — liste des besoins NON retenus dans la commande (lignes décochées,
// besoin réel > 0) : à passer chez un autre fournisseur, sans colisage imposé.
// PU net COALIA affiché comme prix de référence pour comparer les offres.
function cmdRapportImprimerBesoins() {
  var rapport = window._cmdRapport || [];
  var sel = window._cmdRapportSel || {};
  var lignes = rapport.filter(function(r) { return !sel[r.ean] && (r.besoinReel || 0) > 0; })
    .map(function(r) {
      // v8.09 — couverture du stock ACTUEL (sans commander) : stock ÷ rotation
      var cs = (r.moy > 0) ? ((r.stock || 0) / r.moy) : null;
      return Object.assign({}, r, { couvStock: cs });
    })
    .filter(function(r) { return r.couvStock === null || r.couvStock < 3; });
  if (!lignes.length) { alert('Aucun besoin urgent parmi les lignes d\u00e9coch\u00e9es : tous les stocks couvrent d\u00e9j\u00e0 plus de 3 mois.'); return; }
  var ordre = { 'SOCLE': 0, 'COEUR': 1, 'C\u0152UR': 1, 'COMPLEMENT': 2, 'COMPL\u00c9MENT': 2 };
  lignes.sort(function(a, b) {
    var za = (a.stock === 0) ? 0 : 1, zb = (b.stock === 0) ? 0 : 1; // v8.09 : ruptures en tête
    if (za !== zb) return za - zb;
    var ra = String(a.role || '').replace('*', ''), rb = String(b.role || '').replace('*', '');
    var oa = (ra in ordre) ? ordre[ra] : 3, ob = (rb in ordre) ? ordre[rb] : 3;
    return oa !== ob ? oa - ob : (b.besoinReel * (b.prixU || 0)) - (a.besoinReel * (a.prixU || 0));
  });
  var laboNom = (function() {
    var s = document.getElementById('cmd-labo-sel');
    return (s && s.selectedOptions && s.selectedOptions[0]) ? s.selectedOptions[0].text : '';
  })();
  var date = new Date().toLocaleDateString('fr-FR');
  var totU = 0, totBudget = 0;
  var rows = lignes.map(function(r) {
    var budget = r.besoinReel * (r.prixU || 0);
    totU += r.besoinReel; totBudget += budget;
    return '<tr>' +
      '<td style="font-family:monospace">' + r.ean + '</td>' +
      '<td>' + r.libelle + '</td>' +
      '<td>' + (r.role || '') + '</td>' +
      '<td>' + (r.stock === 0 ? '<b style="color:#dc2626">0 \ud83d\udd34</b>' : (r.stock === null || r.stock === undefined ? '\u2014' : r.stock)) + '</td>' +
      '<td>' + (r.couvStock !== null ? (Math.round(r.couvStock * 10) / 10).toFixed(1).replace('.', ',') + ' m' : '\u2014') + '</td>' +
      '<td><b>' + r.besoinReel + '</b></td>' +
      '<td>' + (r.colis > 0 ? '\u00d7' + r.colis : '\u2014') + '</td>' +
      '<td>' + (r.prixU > 0 ? (Math.round(r.prixU * 100) / 100).toFixed(2).replace('.', ',') + '\u20ac' : '\u2014') + '</td>' +
      '<td>' + (budget > 0 ? (Math.round(budget * 100) / 100).toFixed(2).replace('.', ',') + '\u20ac' : '\u2014') + '</td>' +
      '</tr>';
  }).join('');
  var w = window.open('', '_blank');
  if (!w) { alert('Fen\u00eatre bloqu\u00e9e par le navigateur \u2014 autorisez les popups pour ce site.'); return; }
  w.document.write('<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Besoins non retenus ' + laboNom + ' \u2014 ' + date + '</title><style>' +
    'body{font-family:DM Sans,Arial,sans-serif;font-size:12px;color:#1a1a18;padding:24px;max-width:900px;margin:0 auto}' +
    'h1{font-size:16px;font-weight:700;margin-bottom:4px}' +
    '.sub{font-size:11px;color:#6b6a64;margin-bottom:20px}' +
    'table{width:100%;border-collapse:collapse;font-size:11px;margin-bottom:16px}' +
    'th{padding:6px 8px;background:#92400e !important;color:#fff !important;text-align:left;font-size:9px;font-weight:600;letter-spacing:.05em;text-transform:uppercase;-webkit-print-color-adjust:exact;print-color-adjust:exact}' +
    'th:nth-child(n+4){text-align:right}' +
    'td{padding:5px 8px;border-bottom:0.5px solid #e0e0e0}' +
    'td:nth-child(n+4){text-align:right;font-family:monospace}' +
    'tr:nth-child(even){background:#fffbf5}' +
    'tfoot td{font-weight:700;border-top:2px solid #92400e;background:#fef3e2}' +
    '.footer{margin-top:24px;font-size:10px;color:#9e9d96;border-top:1px solid #e0e0e0;padding-top:8px}' +
    '@media print{body{padding:12px}}' +
    '</style></head><body>' +
    '<h1>Besoins non retenus \u2014 \u00e0 commander hors ' + (laboNom || 'plateforme') + '</h1>' +
    '<div class="sub">\u00c9tabli le ' + date + ' \u00b7 Pharmacie Michelet \u00b7 ' + lignes.length + ' produits \u00b7 stock couvrant MOINS de 3 mois \u00b7 ruptures (stock 0 \ud83d\udd34) en t\u00eate \u00b7 besoin r\u00e9el NON arrondi au colisage \u2014 le colisage ' + (laboNom || '') + ' et son PU net figurent \u00e0 titre de comparaison pour n\u00e9gocier ailleurs (achat \u00e0 l\u2019unit\u00e9)</div>' +
    '<table><thead><tr><th>EAN</th><th>Libell\u00e9</th><th>Segment</th><th>Stock</th><th>Couv. stock</th><th>Besoin r\u00e9el</th><th>Colis. ' + (laboNom || '') + '</th><th>PU net r\u00e9f.</th><th>Budget HT</th></tr></thead>' +
    '<tbody>' + rows + '</tbody>' +
    '<tfoot><tr><td colspan="5">TOTAL</td><td>' + totU + '</td><td></td><td></td><td>' + (Math.round(totBudget * 100) / 100).toFixed(2).replace('.', ',') + '\u20ac</td></tr></tfoot>' +
    '</table>' +
    '<div class="footer">Calculateur Pharmacie Michelet \u00b7 calculateur-pharmacie.vercel.app</div>' +
    '</body></html>');
  w.document.close();
  setTimeout(function() { w.print(); }, 400);
}

function cmdRapportCopier() {
  var rapport = window._cmdRapport || [];
  var sel = window._cmdRapportSel || {};
  var lignes = ['EAN\tLibell\u00e9\tQt\u00e9\tColis.\tBesoin r\u00e9el\tCA HT'];
  var u = 0, ca = 0;
  rapport.forEach(function(r){
    if (sel[r.ean]) {
      lignes.push(r.ean + '\t' + r.libelle + '\t' + r.qteFinale + '\t' + (r.colis || '') + '\t' + (r.besoinReel || 0) + '\t' + (Math.round(r.ca*100)/100));
      u += r.qteFinale; ca += r.ca;
    }
  });
  if (lignes.length <= 1) { alert('Aucun produit coch\u00e9.'); return; }
  var txt = lignes.join('\n');
  function ok() { alert((lignes.length-1) + ' produits copi\u00e9s (' + u + ' u \u00b7 ' + Math.round(ca) + '\u20ac HT) \u2014 collez o\u00f9 vous voulez (Sheets, LGPI, mail\u2026).'); }
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(txt).then(ok, function(){ window.prompt ? null : null; alert('Copie bloqu\u00e9e par le navigateur \u2014 r\u00e9essayez.'); });
  } else {
    var ta = document.createElement('textarea');
    ta.value = txt; document.body.appendChild(ta); ta.select();
    try { document.execCommand('copy'); ok(); } catch(e) { alert('Copie impossible sur ce navigateur.'); }
    document.body.removeChild(ta);
  }
}

