// Extrait les dates du nom de fichier. Formats acceptés :
//   "Toutes_les_ventes_2025-07-01_2026-06-30.xlsx"
//   "Toutes les ventes 2025-07-01 2026-06-30 année N en cours.xlsx"
//   "... 2025-07-01 au 2026-06-30 ..."
// Retourne { debut, fin, nb_jours, coeff } ou null
function meqDetecterPeriode(filename) {
  var m = filename.match(/(\d{4}-\d{2}-\d{2})[\s_]+(?:au[\s_]+)?(\d{4}-\d{2}-\d{2})/i);
  if (!m) return null;
  var d1 = new Date(m[1]);
  var d2 = new Date(m[2]);
  if (isNaN(d1) || isNaN(d2) || d2 <= d1) return null;
  var nb_jours = Math.round((d2 - d1) / 86400000) + 1;
  var coeff = Math.round((365 / nb_jours) * 100) / 100;
  return { debut: m[1], fin: m[2], nb_jours: nb_jours, coeff: coeff };
}

// Marchés virtuels calculés (cache recalculé après chaque import)
