async function facturesTraiter(files) {
  if (!files || !files.length) return;
  var apiKey = localStorage.getItem('anthropic_api_key') || '';
  if (!apiKey) {
    apiKey = prompt('Clé API Anthropic (sk-ant-...) :');
    if (!apiKey || !apiKey.startsWith('sk-')) { alert('Clé invalide.'); return; }
    localStorage.setItem('anthropic_api_key', apiKey);
  }

  var progressEl = document.getElementById('factures-progress');
  var barEl = document.getElementById('factures-progress-bar');
  var txtEl = document.getElementById('factures-progress-txt');
  var resEl = document.getElementById('factures-resultats');
  var actEl = document.getElementById('factures-actions');

  progressEl.style.display = 'block';
  resEl.innerHTML = '';
  actEl.style.display = 'none';
  _facturesImportees = [];

  var filesArr = Array.from(files);
  var resultats = [];

  for (var i = 0; i < filesArr.length; i++) {
    var file = filesArr[i];
    var pct = Math.round((i / filesArr.length) * 100);
    barEl.style.width = pct + '%';
    txtEl.textContent = 'Analyse ' + (i+1) + '/' + filesArr.length + ' : ' + file.name + '...';

    try {
      var lignes = await facturesExtrairePDF(file, apiKey);
      resultats.push({ fichier: file.name, lignes: lignes, ok: true });
    } catch(e) {
      resultats.push({ fichier: file.name, lignes: [], ok: false, erreur: e.message });
    }
  }

  barEl.style.width = '100%';
  txtEl.textContent = filesArr.length + ' facture(s) analysée(s)';

  // Afficher les résultats
  var html = '';
  var totalLignes = 0;
  resultats.forEach(function(r) {
    totalLignes += r.lignes.length;
    html += '<div style="margin-bottom:12px;border:1px solid var(--border);border-radius:8px;overflow:hidden">';
    html += '<div style="padding:8px 12px;background:var(--surface2);display:flex;align-items:center;gap:8px">';
    html += '<span>' + (r.ok ? '✅' : '❌') + '</span>';
    html += '<span style="font-size:12px;font-weight:600;flex:1">' + r.fichier + '</span>';
    html += '<span style="font-size:11px;color:var(--text-ter)">' + r.lignes.length + ' ligne(s)</span>';
    html += '</div>';
    if (r.ok && r.lignes.length > 0) {
      html += '<div style="padding:8px 12px;overflow-x:auto">';
      html += '<table style="width:100%;font-size:11px;border-collapse:collapse">';
      html += '<tr style="color:var(--text-ter);border-bottom:1px solid var(--border)">';
      html += '<th style="text-align:left;padding:3px 6px">EAN</th><th style="text-align:left;padding:3px 6px">Libellé</th>';
      html += '<th style="text-align:right;padding:3px 6px">Qté</th><th style="text-align:right;padding:3px 6px">PA net</th>';
      html += '<th style="text-align:right;padding:3px 6px">HT</th><th style="text-align:left;padding:3px 6px">Fournisseur</th></tr>';
      r.lignes.forEach(function(l) {
        html += '<tr style="border-bottom:1px solid var(--border)">';
        html += '<td style="padding:3px 6px;font-family:monospace;font-size:10px">' + (l.ean || '—') + '</td>';
        html += '<td style="padding:3px 6px">' + l.libelle + '</td>';
        html += '<td style="padding:3px 6px;text-align:right">' + l.quantite + '</td>';
        html += '<td style="padding:3px 6px;text-align:right">' + (l.pa_net ? l.pa_net.toFixed(2) + ' €' : '—') + '</td>';
        html += '<td style="padding:3px 6px;text-align:right">' + (l.montant_ht ? l.montant_ht.toFixed(2) + ' €' : '—') + '</td>';
        html += '<td style="padding:3px 6px">' + (l.fournisseur || '—') + '</td>';
        html += '</tr>';
      });
      html += '</table></div>';
      _facturesImportees = _facturesImportees.concat(r.lignes);
    } else if (!r.ok) {
      html += '<div style="padding:8px 12px;font-size:11px;color:var(--danger)">' + r.erreur + '</div>';
    }
    html += '</div>';
  });

  resEl.innerHTML = html;
  if (_facturesImportees.length > 0) {
    actEl.style.display = 'block';
  }
}

async function facturesExtrairePDF(file, apiKey) {
  // Lire le PDF en base64
  var base64 = await new Promise(function(resolve, reject) {
    var reader = new FileReader();
    reader.onload = function(e) { resolve(e.target.result.split(',')[1]); };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });

  var prompt = 'Tu es un expert comptable. Extrais toutes les lignes de produits de cette facture pharmaceutique.\n\n' +
    'Pour chaque ligne de produit, retourne un objet JSON avec exactement ces champs :\n' +
    '- ean : code EAN/CIP/ACL à 13 chiffres (string, null si absent)\n' +
    '- libelle : nom du produit (string)\n' +
    '- quantite : quantité livrée (number)\n' +
    '- prix_brut : prix unitaire brut avant remise (number, null si absent)\n' +
    '- remise_pct : remise en % (number, 0 si pas de remise, null si "Echanges" ou UG)\n' +
    '- pa_net : prix unitaire net après remise (number, null si Echanges/UG)\n' +
    '- montant_ht : montant HT de la ligne (number, null si Echanges/UG)\n' +
    '- tva : taux TVA % (number)\n' +
    '- fournisseur : nom du fournisseur/laboratoire (string)\n' +
    '- date_facture : date de la facture au format YYYY-MM-DD (string)\n' +
    '- numero_facture : numéro de la facture (string)\n\n' +
    'IMPORTANT :\n' +
    '- Les lignes "Echanges" ou UG (unités gratuites) ont remise_pct=null et pa_net=null\n' +
    '- Retourne UNIQUEMENT un tableau JSON valide, sans texte avant ou après\n' +
    '- Exemple : [{"ean":"3578835503630","libelle":"FORCAPIL SPRAY","quantite":6,"prix_brut":38.15,"remise_pct":50,"pa_net":19.08,"montant_ht":114.48,"tva":20,"fournisseur":"Arkopharma","date_facture":"2026-06-24","numero_facture":"204094096"}]';

  var resp = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': apiKey,
      'anthropic-version': '2023-06-01',
      'anthropic-dangerous-direct-browser-access': 'true'
    },
    body: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 4000,
      messages: [{
        role: 'user',
        content: [{
          type: 'document',
          source: { type: 'base64', media_type: 'application/pdf', data: base64 }
        }, {
          type: 'text',
          text: prompt
        }]
      }]
    })
  });

  if (!resp.ok) {
    var err = await resp.json().catch(function(){ return {}; });
    throw new Error('API Anthropic : ' + (err.error && err.error.message ? err.error.message : resp.status));
  }

  var data = await resp.json();
  var text = (data.content || []).map(function(c){ return c.text || ''; }).join('');
  // Nettoyer le JSON
  var clean = text.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
  var lignes = JSON.parse(clean);
  if (!Array.isArray(lignes)) throw new Error('Format inattendu');
  return lignes;
}

function facturesAppliquer() {
  if (!_facturesImportees.length) return;
  var statusEl = document.getElementById('factures-apply-status');

  // Regrouper par fournisseur
  var parFourn = {};
  _facturesImportees.forEach(function(l) {
    var fourn = (l.fournisseur || 'Inconnu').toUpperCase();
    if (!parFourn[fourn]) parFourn[fourn] = { lignes: [], caHT: 0, qtes: {} };
    parFourn[fourn].lignes.push(l);
    if (l.montant_ht) parFourn[fourn].caHT += l.montant_ht;
    // Compter les paires/unités par EAN
    var ean = l.ean || l.libelle;
    parFourn[fourn].qtes[ean] = (parFourn[fourn].qtes[ean] || 0) + (l.quantite || 0);
  });

  // Stocker dans condLabos pour chaque labo correspondant
  var majCount = 0;
  Object.keys(condLabos).forEach(function(id) {
    var labo = condLabos[id];
    if (!labo || !labo.nom) return;
    var nomUp = labo.nom.toUpperCase();
    // Chercher le fournisseur correspondant
    Object.keys(parFourn).forEach(function(fourn) {
      var fournMots = fourn.split(/\s+/);
      var match = fournMots.some(function(m){ return m.length > 3 && nomUp.indexOf(m) >= 0; }) ||
                  nomUp.split(/\s+/).some(function(m){ return m.length > 3 && fourn.indexOf(m) >= 0; });
      if (match) {
        if (!labo.achats_factures) labo.achats_factures = [];
        // Ajouter les lignes non déjà présentes (par n° facture)
        _facturesImportees.filter(function(l){ return (l.fournisseur||'').toUpperCase() === fourn; })
          .forEach(function(l) {
            var existe = labo.achats_factures.some(function(a){
              return a.numero_facture === l.numero_facture && a.ean === l.ean;
            });
            if (!existe) { labo.achats_factures.push(l); majCount++; }
          });
      }
    });
  });

  condSauvegarder();
  if (statusEl) statusEl.textContent = majCount + ' ligne(s) ajoutée(s) aux labos correspondants ✓';

  // Afficher un résumé par labo
  setTimeout(function(){
    facturesAfficherSuiviPaliers();
    document.getElementById('factures-modal').remove();
  }, 1500);
}

function facturesAfficherSuiviPaliers() {
  // Chercher ou créer le panneau de suivi dans l'onglet Conditions commerciales
  var existing = document.getElementById('factures-suivi-panel');
  if (existing) existing.remove();

  if (!condLaboActif || !condLabos[condLaboActif]) return;
  var labo = condLabos[condLaboActif];
  var achats = labo.achats_factures || [];
  if (!achats.length) return;

  var panel = document.createElement('div');
  panel.id = 'factures-suivi-panel';
  panel.style.cssText = 'margin-top:16px;padding:14px;background:var(--surface2);border-radius:8px;border:1px solid var(--border)';

  // Calculer les totaux
  var caTotal = 0, qtesParEan = {};
  achats.forEach(function(a) {
    if (a.montant_ht) caTotal += a.montant_ht;
    var k = a.ean || a.libelle;
    qtesParEan[k] = (qtesParEan[k] || 0) + (a.quantite || 0);
  });
  var nbRefs = Object.keys(qtesParEan).length;
  var nbPaires = Object.values(qtesParEan).reduce(function(s,v){ return s+v; }, 0);
  var periodes = achats.map(function(a){ return a.date_facture; }).filter(Boolean).sort();
  var periodeStr = periodes.length ? periodes[0] + ' → ' + periodes[periodes.length-1] : 'période inconnue';

  var html = '<div style="font-size:13px;font-weight:700;margin-bottom:10px">📊 Suivi achats — ' + (labo.nom || '') + '</div>';
  html += '<div style="font-size:11px;color:var(--text-ter);margin-bottom:10px">Période : ' + periodeStr + ' · ' + achats.length + ' ligne(s) de facture</div>';

  // KPIs
  html += '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin-bottom:12px">';
  html += '<div style="background:#fff;border-radius:6px;padding:8px;text-align:center"><div style="font-size:18px;font-weight:700;color:var(--accent-text)">' + Math.round(caTotal).toLocaleString('fr') + ' €</div><div style="font-size:10px;color:var(--text-ter)">CA HT total</div></div>';
  html += '<div style="background:#fff;border-radius:6px;padding:8px;text-align:center"><div style="font-size:18px;font-weight:700;color:var(--accent-text)">' + nbPaires + '</div><div style="font-size:10px;color:var(--text-ter)">Unités achetées</div></div>';
  html += '<div style="background:#fff;border-radius:6px;padding:8px;text-align:center"><div style="font-size:18px;font-weight:700;color:var(--accent-text)">' + nbRefs + '</div><div style="font-size:10px;color:var(--text-ter)">Références</div></div>';
  html += '</div>';

  // Progression par marché
  var marches = labo.marches_negocies || [];
  if (marches.length) {
    html += '<div style="font-size:12px;font-weight:600;margin-bottom:8px">Progression par marché :</div>';
    marches.forEach(function(m) {
      var paliers = m.paliers || [];
      if (!paliers.length) return;
      var palierMax = paliers[paliers.length-1];
      var seuil = palierMax.volume;
      // Utiliser CA ou unités selon le type de palier
      var valeur = seuil > 500 ? caTotal : nbPaires; // heuristique : > 500 = € sinon unités
      var unite = seuil > 500 ? '€' : 'u';
      var pct = Math.min(100, Math.round(valeur / seuil * 100));
      var couleur = pct >= 100 ? '#16a34a' : pct >= 70 ? '#d97706' : '#6366f1';
      html += '<div style="margin-bottom:8px">';
      html += '<div style="display:flex;justify-content:space-between;margin-bottom:3px">';
      html += '<span style="font-size:11px;font-weight:500">' + m.label + '</span>';
      html += '<span style="font-size:11px;color:' + couleur + ';font-weight:600">' + Math.round(valeur).toLocaleString('fr') + ' / ' + Math.round(seuil).toLocaleString('fr') + ' ' + unite + ' (' + pct + '%)</span>';
      html += '</div>';
      html += '<div style="height:6px;background:var(--border);border-radius:3px"><div style="height:100%;width:' + pct + '%;background:' + couleur + ';border-radius:3px;transition:width .4s"></div></div>';
      html += '</div>';
    });
  }

  html += '<div style="margin-top:10px;display:flex;gap:8px">';
  html += '<button onclick="facturesOuvrirModal()" style="font-size:11px;padding:5px 10px;background:var(--accent,#6366f1);color:#fff;border:none;border-radius:6px;cursor:pointer">+ Ajouter des factures</button>';
  html += '<button onclick="facturesEffacer()" style="font-size:11px;padding:5px 10px;background:transparent;border:1px solid var(--danger);color:var(--danger);border-radius:6px;cursor:pointer">🗑 Effacer les données</button>';
  html += '</div>';

  panel.innerHTML = html;

  // Insérer dans le panel conditions commerciales
  var condPanel = document.getElementById('cond-labo-form');
  if (condPanel) condPanel.appendChild(panel);
}

function facturesEffacer() {
  if (!confirm('Effacer toutes les données de factures pour ce labo ?')) return;
  if (condLaboActif && condLabos[condLaboActif]) {
    condLabos[condLaboActif].achats_factures = [];
    condSauvegarder();
    var p = document.getElementById('factures-suivi-panel');
    if (p) p.remove();
  }
}

