function dashboardRenderGuide() {
  var el = document.getElementById('dashboard-guide');
  if (!el) return;

  // Détecter l'état de l'app
  var nbLabos = Object.keys(condLabos).filter(function(k){ return condLabos[k] && condLabos[k].nom; }).length;
  var hasGithubToken = !!localStorage.getItem('gh_token');
  var hasOspharm = typeof decOspharmProds !== 'undefined' && decOspharmProds && Object.keys(decOspharmProds).length > 0;
  var hasVentes = Object.values(condLabos).some(function(l){ return l && l.produits && l.produits.some(function(p){ return (p.moy||0) > 0; }); });
  var lastGhLoad = localStorage.getItem('_last_gh_load');
  var maintenantH = new Date().getHours();

  var etapes = [];

  // Étape 1 : Charger depuis GitHub
  if (!hasGithubToken || nbLabos === 0) {
    etapes.push({ urgence: 'critique', emoji: '🔴', titre: 'Charger depuis GitHub', 
      texte: 'Cliquez sur le bouton <b>GitHub</b> (onglet Conditions commerciales) pour charger vos labos et conditions.',
      action: null });
  } else {
    var dernier = lastGhLoad ? new Date(parseInt(lastGhLoad)) : null;
    var hEcoules = dernier ? (Date.now() - dernier.getTime()) / 3600000 : 999;
    if (hEcoules > 8) {
      etapes.push({ urgence: 'info', emoji: '🔵', titre: 'Début de session — Charger GitHub', 
        texte: 'Rechargez vos données depuis GitHub pour être sûr d\'avoir la version la plus récente.',
        action: 'condChargerGitHub()' });
    }
  }

  // Étape 2 : Ventes Ospharm
  if (!hasOspharm) {
    etapes.push({ urgence: 'attention', emoji: '🟡', titre: 'Importer les ventes Ospharm', 
      texte: 'Allez dans <b>Décision RDV</b> → importez votre export Ospharm mensuel pour activer les alertes rupture et le score RDV.',
      action: "showTab('dec')" });
  }

  // Étape 3 : Rotations LGPI
  if (!hasVentes) {
    etapes.push({ urgence: 'attention', emoji: '🟡', titre: 'Importer les rotations LGPI', 
      texte: 'Allez dans <b>Catalogue</b> → sélectionnez un labo → importez son état des ventes LGPI pour calculer les quantités à commander.',
      action: "showTab('cat')" });
  }

  if (!etapes.length) {
    el.innerHTML = '<div style="font-size:12px;color:#16a34a;padding:8px 0">✅ Tout est à jour — vous pouvez piloter vos RDVs.</div>';
    return;
  }

  var html = '<div style="margin-bottom:12px">';
  html += '<div style="font-size:11px;font-weight:700;color:var(--text-ter);text-transform:uppercase;letter-spacing:.05em;margin-bottom:8px">⚡ Actions recommandées</div>';
  etapes.forEach(function(e) {
    html += '<div style="display:flex;align-items:flex-start;gap:8px;padding:8px 10px;border-radius:6px;margin-bottom:6px;background:var(--surface2);border-left:3px solid '
      + (e.urgence==='critique' ? '#dc2626' : e.urgence==='attention' ? '#d97706' : '#3b82f6') + '">';
    html += '<span style="font-size:16px;flex-shrink:0">' + e.emoji + '</span>';
    html += '<div style="flex:1"><div style="font-size:12px;font-weight:600;margin-bottom:2px">' + e.titre + '</div>';
    html += '<div style="font-size:11px;color:var(--text-sec)">' + e.texte + '</div></div>';
    if (e.action) {
      html += '<button onclick="' + e.action + '" style="flex-shrink:0;font-size:10px;padding:3px 8px;background:var(--accent,#6366f1);color:#fff;border:none;border-radius:4px;cursor:pointer">→</button>';
    }
    html += '</div>';
  });

  // Rappel fréquences
  html += '<details style="margin-top:8px"><summary style="font-size:11px;color:var(--text-ter);cursor:pointer">📋 Fréquences recommandées</summary>';
  html += '<div style="font-size:11px;color:var(--text-sec);padding:8px;line-height:1.8">';
  html += '🔵 <b>Chaque session</b> — Charger depuis GitHub<br>';
  html += '🟢 <b>Avant chaque RDV</b> — Importer PDF LGPI du labo concerné<br>';
  html += '🟡 <b>Mensuel</b> — Importer Ospharm + ZIP Digipharmacie (factures)<br>';
  html += '🟠 <b>Annuel</b> — Mettre à jour les conditions commerciales + catalogues tarifs';
  html += '</div></details>';
  html += '</div>';

  el.innerHTML = html;
}

function dashboardRender() {
  var el = document.getElementById('dashboard-panel');
  if (!el) return;

  var labosAll = Object.values(condLabos).filter(function(l){ return l && l.nom; })
    .sort(function(a,b){ return (b.caAnnuel||0) - (a.caAnnuel||0); });
  var labos = labosAll.filter(function(l){ return !l.type || l.type === 'direct'; });
  var labosIndirect = labosAll.filter(function(l){ return l.type && l.type !== 'direct'; });

  if (!labos.length) {
    el.innerHTML = '<div style="font-size:12px;color:var(--text-ter);padding:12px">Aucun labo configuré — allez dans Conditions commerciales pour en ajouter.</div>';
    return;
  }

  // KPIs globaux
  var caTot = 0, margeTot = 0, nbLabos = 0, nbAlertes = 0;
  labos.forEach(function(l) {
    caTot += l.caAnnuel || 0;
    if (l.caAnnuel > 0) { margeTot += (l.mbActuel || 0) * (l.caAnnuel || 0); nbLabos++; }
  });
  var margeMoy = caTot > 0 ? margeTot / caTot : 0;

  // Alertes Ospharm globales
  if (typeof decOspharmProds !== 'undefined' && decOspharmProds) {
    Object.values(decOspharmProds).forEach(function(prods) {
      (prods || []).forEach(function(p) {
        if (p.alerte === 'RUPTURE' || p.alerte === 'DANGER') nbAlertes++;
      });
    });
  }

  var html = '';

  // Barre KPIs globaux
  html += '<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:16px">';
  html += kpiCard('CA total', Math.round(caTot).toLocaleString('fr') + ' €', 'annualisé · ' + nbLabos + ' labo(s)', '#6366f1');
  html += kpiCard('Marge moyenne', margeMoy.toFixed(1) + ' %', 'pondérée par CA', margeMoy >= 35 ? '#16a34a' : margeMoy >= 28 ? '#d97706' : '#dc2626');
  html += kpiCard('Alertes stock', nbAlertes, 'ruptures + dangers Ospharm', nbAlertes === 0 ? '#16a34a' : nbAlertes < 5 ? '#d97706' : '#dc2626');
  html += kpiCard('Labos actifs', nbLabos, 'avec CA > 0', '#6366f1');
  html += '</div>';

  // Section labos directs — dépliable
  html += '<div style="margin-bottom:12px;border:1px solid var(--border);border-radius:8px;overflow:hidden">';
  html += '<div onclick="dashToggle(\'direct\')" style="display:flex;align-items:center;justify-content:space-between;padding:10px 14px;background:var(--surface2);cursor:pointer;user-select:none">';
  html += '<span style="font-size:12px;font-weight:700">🏭 Labos directs (' + labos.length + ')</span>';
  html += '<span id="dash-toggle-direct" style="font-size:16px;color:var(--text-ter)">▾</span>';
  html += '</div>';
  html += '<div id="dash-section-direct">';
  html += '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px">';
  html += '<thead><tr style="background:var(--surface2);color:var(--text-ter);font-size:10px;text-transform:uppercase">';
  ['Labo','CA annuel','Marge %','Score RDV','Alertes','Paliers','Dernier RDV','Action'].forEach(function(h) {
    html += '<th style="padding:7px 10px;text-align:left;font-weight:600;white-space:nowrap">' + h + '</th>';
  });
  html += '</tr></thead><tbody>';

  labos.forEach(function(labo, i) {
    var ca = labo.caAnnuel || 0;
    var mb = labo.mbActuel || 0;
    var bgRow = i % 2 === 0 ? 'var(--surface)' : 'var(--surface2)';

    // Alertes Ospharm pour ce labo
    var nbR = 0, nbD = 0;
    if (typeof decOspharmProds !== 'undefined' && decOspharmProds) {
      var osphKey = Object.keys(decOspharmProds).find(function(k) {
        var kUp = k.toUpperCase(), nUp = (labo.nom||'').toUpperCase();
        return kUp === nUp || kUp.split(' ').some(function(m){ return m.length > 2 && nUp.indexOf(m) >= 0; });
      });
      if (osphKey && decOspharmProds[osphKey]) {
        decOspharmProds[osphKey].forEach(function(p) {
          if (p.alerte === 'RUPTURE') nbR++;
          else if (p.alerte === 'DANGER') nbD++;
        });
      }
    }

    // Score RDV simplifié (sans Ospharm complet)
    var score = 0;
    var seuilCA = 5000, seuilRem = 35;
    if (ca >= seuilCA) score += 30; else score += Math.round(ca / seuilCA * 30);
    var remTot = 0;
    (labo.marches_negocies || []).forEach(function(m){ remTot = Math.max(remTot, m.rem || 0); });
    if (remTot >= seuilRem) score += 25; else score += Math.round(remTot / seuilRem * 25);
    score += Math.min(25, (nbR * 3 + nbD * 1.5) * 2.5);
    if (!labo.lastOrder) score += 15;
    else {
      var moisEcoules = (Date.now() - new Date(labo.lastOrder).getTime()) / (1000*60*60*24*30);
      if (moisEcoules >= 6) score += 20; else if (moisEcoules >= 3) score += 10;
    }
    var scoreColor = score >= 70 ? '#16a34a' : score >= 40 ? '#d97706' : '#dc2626';
    var scoreEmoji = score >= 70 ? '🟢' : score >= 40 ? '🟡' : '🔴';

    // Progression paliers
    var palierHtml = '<span style="color:var(--text-ter)">—</span>';
    var marches = labo.marches_negocies || [];
    if (marches.length > 0) {
      var achats = labo.achats_factures || [];
      var caAchats = achats.reduce(function(s,a){ return s + (a.montant_ht||0); }, 0);
      if (caAchats > 0) {
        var palierMax = 0;
        marches.forEach(function(m) {
          (m.paliers||[]).forEach(function(p){ if (p.volume > palierMax) palierMax = p.volume; });
        });
        if (palierMax > 0) {
          var val = palierMax > 500 ? caAchats : achats.reduce(function(s,a){ return s+(a.quantite||0);},0);
          var pct = Math.min(100, Math.round(val / palierMax * 100));
          var pc = pct >= 100 ? '#16a34a' : pct >= 70 ? '#d97706' : '#6366f1';
          palierHtml = '<div style="display:flex;align-items:center;gap:4px">'
            + '<div style="width:60px;height:5px;background:var(--border);border-radius:3px">'
            + '<div style="width:'+pct+'%;height:100%;background:'+pc+';border-radius:3px"></div></div>'
            + '<span style="font-size:10px;color:'+pc+'">'+pct+'%</span></div>';
        }
      } else {
        palierHtml = '<span style="font-size:10px;color:var(--text-ter)">' + marches.length + ' marché(s)</span>';
      }
    }

    // Dernier RDV
    var lastRdv = labo.lastOrder ? new Date(labo.lastOrder).toLocaleDateString('fr-FR') : '—';

    html += '<tr style="background:' + bgRow + ';border-bottom:1px solid var(--border)">';
    html += '<td style="padding:8px 10px;font-weight:600">' + (labo.nom||'') + '</td>';
    html += '<td style="padding:8px 10px">' + (ca > 0 ? Math.round(ca).toLocaleString('fr') + ' €' : '<span style="color:var(--text-ter)">—</span>') + '</td>';
    html += '<td style="padding:8px 10px;color:' + (mb >= 35 ? '#16a34a' : mb >= 28 ? '#d97706' : mb > 0 ? '#dc2626' : 'var(--text-ter)') + ';font-weight:600">' + (mb > 0 ? mb.toFixed(1) + ' %' : '—') + '</td>';
    html += '<td style="padding:8px 10px"><span style="font-size:13px">' + scoreEmoji + '</span> <span style="font-size:11px;color:' + scoreColor + ';font-weight:600">' + score + '/100</span></td>';
    html += '<td style="padding:8px 10px">' + (nbR > 0 ? '<span style="color:#dc2626;font-weight:600">⚠ ' + nbR + ' R</span>' : '') + (nbD > 0 ? ' <span style="color:#d97706">' + nbD + ' D</span>' : '') + (nbR === 0 && nbD === 0 ? '<span style="color:var(--text-ter)">—</span>' : '') + '</td>';
    html += '<td style="padding:8px 10px">' + palierHtml + '</td>';
    html += '<td style="padding:8px 10px;font-size:11px;color:var(--text-ter)">' + lastRdv + '</td>';
    html += '<td style="padding:8px 10px"><button onclick="showTab(\'cond\')" style="font-size:10px;padding:3px 8px;background:var(--accent,#6366f1);color:#fff;border:none;border-radius:4px;cursor:pointer">→ RDV</button></td>';
    html += '</tr>';
  });

  html += '</tbody></table></div>';
  html += '</div></div>'; // fermer dash-section-direct + container

  // Section centrales / groupements — dépliable
  if (labosIndirect.length > 0) {
    var caTotInd = labosIndirect.reduce(function(s,l){ return s+(l.caAnnuel||0); }, 0);
    html += '<div style="margin-bottom:12px;border:1px solid var(--border);border-radius:8px;overflow:hidden">';
    html += '<div onclick="dashToggle(\'indirect\')" style="display:flex;align-items:center;justify-content:space-between;padding:10px 14px;background:var(--surface2);cursor:pointer;user-select:none">';
    html += '<span style="font-size:12px;font-weight:700">🏪 Centrales & Groupements (' + labosIndirect.length + ') — CA total : ' + Math.round(caTotInd).toLocaleString('fr') + ' €</span>';
    html += '<span id="dash-toggle-indirect" style="font-size:16px;color:var(--text-ter)">▸</span>';
    html += '</div>';
    html += '<div id="dash-section-indirect" style="display:none;padding:12px 14px">';
    html += '<div style="display:flex;flex-wrap:wrap;gap:8px">';
    labosIndirect.forEach(function(l) {
      var ca = l.caAnnuel || 0;
      var mb = l.mbActuel || 0;
      var typeLabel = l.type === 'centrale' ? '🏪' : l.type === 'groupement' ? '🤝' : '📦';
      var mbColor = mb >= 35 ? '#16a34a' : mb >= 28 ? '#d97706' : mb > 0 ? '#dc2626' : 'var(--text-ter)';
      html += '<div style="background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:8px 12px;min-width:150px">';
      html += '<div style="font-size:10px;color:var(--text-ter)">' + typeLabel + ' ' + (l.type||'autre') + '</div>';
      html += '<div style="font-size:12px;font-weight:600;margin:2px 0">' + l.nom + '</div>';
      html += '<div style="font-size:13px;color:var(--accent-text);font-weight:700">' + (ca > 0 ? Math.round(ca).toLocaleString('fr') + ' €' : '—') + '</div>';
      if (mb > 0) html += '<div style="font-size:11px;color:' + mbColor + '">' + mb.toFixed(1) + '% MB</div>';
      html += '</div>';
    });
    html += '</div></div></div>';
  }

  el.innerHTML = html;
}
  try { dashboardRenderGuide(); } catch(e) {}


function dashToggle(section) {
  var panel = document.getElementById('dash-section-' + section);
  var icon  = document.getElementById('dash-toggle-' + section);
  if (!panel) return;
  var open = panel.style.display !== 'none';
  panel.style.display = open ? 'none' : '';
  if (icon) icon.textContent = open ? '▸' : '▾';
}

function kpiCard(label, value, sub, color) {
  return '<div style="background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:12px;text-align:center">'
    + '<div style="font-size:20px;font-weight:700;color:' + color + '">' + value + '</div>'
    + '<div style="font-size:11px;font-weight:600;color:var(--text-sec);margin-top:2px">' + label + '</div>'
    + '<div style="font-size:10px;color:var(--text-ter);margin-top:2px">' + sub + '</div>'
    + '</div>';
}

// ===== IMPORT ZIP FACTURES DIGIPHARMACIE =====

// Fournisseurs non-pharmaceutiques à ignorer automatiquement
var FACTURES_IGNORE = [
  'adobe','pharmagest','free','cegedim','mutualease','cabinet','arditti',
  'lamier','atelier','sra pharmacie','pharmacie-michelet','1healthmedia',
  'health initiative','integral pharma'
];

// Centrales de distribution (pas des labos directs — on cumule par fournisseur réel)
var FACTURES_CENTRALES = ['alloga','cerp','sagitta','la centrale','pharmupp','csp','eurodep','mesoigner'];

async function facturesImporterZip(input) {
  var file = input.files[0];
  if (!file) return;
  var apiKey = localStorage.getItem('anthropic_api_key') || '';
  if (!apiKey) {
    apiKey = prompt('Clé API Anthropic (sk-ant-...) :');
    if (!apiKey || !apiKey.startsWith('sk-')) { alert('Clé invalide.'); return; }
    localStorage.setItem('anthropic_api_key', apiKey);
  }

  var modal = document.getElementById('factures-modal');
  var resEl = document.getElementById('factures-resultats');
  var actEl = document.getElementById('factures-actions');
  var progressEl = document.getElementById('factures-progress');
  var barEl = document.getElementById('factures-progress-bar');
  var txtEl = document.getElementById('factures-progress-txt');

  progressEl.style.display = 'block';
  resEl.innerHTML = '';
  actEl.style.display = 'none';
  _facturesImportees = [];

  txtEl.textContent = 'Lecture du ZIP...';
  barEl.style.width = '5%';

  // Lire le ZIP avec JSZip (chargé dynamiquement)
  var JSZip = await facturesChargerJSZip();
  var zip = await JSZip.loadAsync(await file.arrayBuffer());

  // Lister les PDFs
  var pdfs = [];
  zip.forEach(function(path, entry) {
    if (!entry.dir && path.toLowerCase().endsWith('.pdf')) {
      pdfs.push({ path: path, entry: entry });
    }
  });

  txtEl.textContent = pdfs.length + ' PDFs trouvés — identification...';

  // Identifier et filtrer
  var aTraiter = [];
  var ignores = [];
  pdfs.forEach(function(pdf) {
    var nom = pdf.path.split('/').pop().toLowerCase();
    // Extraire fournisseur depuis le nom de fichier
    var m = nom.match(/(?:facture|avoir|releve)_\d+_(.+?)_[a-z0-9]/i);
    var fourn = m ? m[1].replace(/_/g, ' ').toLowerCase() : nom;

    // Ignorer les non-pharmaceutiques
    var isIgnore = FACTURES_IGNORE.some(function(ig){ return fourn.indexOf(ig) >= 0; });
    // Ignorer les avoirs (on ne compte que les achats)
    var isAvoir = nom.startsWith('avoir');
    // Ignorer les relevés
    var isReleve = nom.startsWith('releve');

    if (isIgnore || isAvoir || isReleve) {
      ignores.push({ nom: pdf.path.split('/').pop(), raison: isAvoir ? 'avoir' : isReleve ? 'relevé' : 'non-pharma' });
    } else {
      aTraiter.push({ path: pdf.path, entry: pdf.entry, fourn: fourn, nomFichier: pdf.path.split('/').pop() });
    }
  });

  txtEl.textContent = aTraiter.length + ' factures pharmaceutiques à analyser (' + ignores.length + ' ignorées)';
  barEl.style.width = '10%';

  // Traitement en parallèle par lots de 5 (limite API Anthropic)
  var resultats = [];
  var BATCH = 5;
  var done = 0;
  for (var b = 0; b < aTraiter.length; b += BATCH) {
    var lot = aTraiter.slice(b, b + BATCH);
    var pct = Math.round(10 + (done / aTraiter.length) * 85);
    barEl.style.width = pct + '%';
    txtEl.textContent = 'Analyse ' + (done+1) + '-' + Math.min(done+BATCH, aTraiter.length) + '/' + aTraiter.length + ' (lot en parallèle)...';

    var lotResultats = await Promise.all(lot.map(async function(item) {
      try {
        var pdfData = await item.entry.async('base64');
        var lignes = await facturesExtrairePDFBase64(pdfData, apiKey);
        return { fichier: item.nomFichier, fourn: item.fourn, lignes: lignes, ok: true };
      } catch(e) {
        return { fichier: item.nomFichier, fourn: item.fourn, lignes: [], ok: false, erreur: e.message };
      }
    }));

    lotResultats.forEach(function(r) {
      resultats.push(r);
      if (r.ok) _facturesImportees = _facturesImportees.concat(r.lignes);
    });
    done += lot.length;
  }

  barEl.style.width = '100%';
  txtEl.textContent = aTraiter.length + ' factures analysées — ' + _facturesImportees.length + ' lignes extraites';

  // Résumé par fournisseur
  var parFourn = {};
  _facturesImportees.forEach(function(l) {
    var f = (l.fournisseur || 'Inconnu');
    if (!parFourn[f]) parFourn[f] = { nb: 0, caHT: 0 };
    parFourn[f].nb++;
    parFourn[f].caHT += l.montant_ht || 0;
  });

  var html = '';
  // Résumé compact
  html += '<div style="margin-bottom:12px;padding:10px;background:var(--surface2);border-radius:8px">';
  html += '<div style="font-size:12px;font-weight:700;margin-bottom:8px">Résumé par fournisseur</div>';
  html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:6px">';
  Object.keys(parFourn).sort().forEach(function(f) {
    var d = parFourn[f];
    html += '<div style="background:#fff;border:1px solid var(--border);border-radius:6px;padding:6px 10px">';
    html += '<div style="font-size:11px;font-weight:600">' + f + '</div>';
    html += '<div style="font-size:12px;color:var(--accent-text);font-weight:700">' + Math.round(d.caHT).toLocaleString('fr') + ' € HT</div>';
    html += '<div style="font-size:10px;color:var(--text-ter)">' + d.nb + ' ligne(s)</div>';
    html += '</div>';
  });
  html += '</div></div>';

  // Erreurs
  var erreurs = resultats.filter(function(r){ return !r.ok; });
  if (erreurs.length) {
    html += '<div style="margin-bottom:10px;padding:8px;background:var(--danger-bg);border-radius:6px">';
    html += '<div style="font-size:11px;font-weight:600;color:var(--danger);margin-bottom:4px">' + erreurs.length + ' facture(s) en erreur :</div>';
    erreurs.forEach(function(e) {
      html += '<div style="font-size:11px;color:var(--danger)">• ' + e.fichier + ' : ' + e.erreur + '</div>';
    });
    html += '</div>';
  }

  // Ignorées
  if (ignores.length) {
    html += '<div style="font-size:10px;color:var(--text-ter);margin-bottom:8px">';
    html += ignores.length + ' fichier(s) ignoré(s) : ';
    html += ignores.slice(0,5).map(function(i){ return i.nom + ' (' + i.raison + ')'; }).join(', ');
    if (ignores.length > 5) html += '... et ' + (ignores.length-5) + ' autres';
    html += '</div>';
  }

  resEl.innerHTML = html;
  if (_facturesImportees.length > 0) actEl.style.display = 'block';
}

async function facturesExtrairePDFBase64(base64, apiKey) {
  var prompt = 'Tu es un expert comptable. Extrais toutes les lignes de produits de cette facture pharmaceutique.\n\n'
    + 'Pour chaque ligne de produit, retourne un objet JSON avec exactement ces champs :\n'
    + '- ean : code EAN/CIP/ACL à 13 chiffres (string, null si absent)\n'
    + '- libelle : nom du produit (string)\n'
    + '- quantite : quantité livrée (number)\n'
    + '- pa_net : prix unitaire net après remise (number, null si Echanges/UG)\n'
    + '- montant_ht : montant HT de la ligne (number, null si Echanges/UG)\n'
    + '- tva : taux TVA % (number)\n'
    + '- fournisseur : nom du fournisseur/laboratoire (string)\n'
    + '- date_facture : date au format YYYY-MM-DD (string)\n'
    + '- numero_facture : numéro de la facture (string)\n\n'
    + 'IMPORTANT : Retourne UNIQUEMENT un tableau JSON valide, sans texte avant ou après.\n'
    + 'Les lignes "Echanges" ou UG ont montant_ht=null.';

  var resp = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': apiKey,
      'anthropic-version': '2023-06-01',
      'anthropic-dangerous-direct-browser-access': 'true'
    },
    body: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 4000,
      messages: [{
        role: 'user',
        content: [
          { type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: base64 } },
          { type: 'text', text: prompt }
        ]
      }]
    })
  });

  if (!resp.ok) throw new Error('API ' + resp.status);
  var data = await resp.json();
  var text = (data.content || []).map(function(c){ return c.text || ''; }).join('');
  var clean = text.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
  var lignes = JSON.parse(clean);
  if (!Array.isArray(lignes)) throw new Error('Format inattendu');
  return lignes.filter(function(l){ return l.montant_ht && l.montant_ht > 0; });
}

async function facturesChargerJSZip() {
  if (window.JSZip) return window.JSZip;
  return new Promise(function(resolve, reject) {
    var script = document.createElement('script');
    script.src = 'https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js';
    script.onload = function(){ resolve(window.JSZip); };
    script.onerror = reject;
    document.head.appendChild(script);
  });
}

// ═══════════════════════════════════════════════════════════════════════════
// v7.21 — WIDGET PRIX PUBLIC (zéro saisie — tout vient des Conditions commerciales)
// Barre fixe en bas à gauche : recherche par nom, EAN complet (douchette =
// frappe + Entrée) ou ≥4 derniers chiffres, sur tous les labos de condLabos.
// Sélection → prix public TTC immédiat :
//   remise  = simLPPRRemiseActive(labo, p)  (marché négocié, sinon implicite
//             tarif/PA net), repli p.rem_cat
//   tx marque = labo.mbActuel (Conditions commerciales), repli 35 %
//   PA net = tarif × (1 − remise) ; PV HT = PA net / (1 − tx marque) ;
//   PV TTC = PV HT × (1 + TVA). Pure lecture, aucune donnée modifiée.
// ═══════════════════════════════════════════════════════════════════════════

function pxNormTva(t, laboId) {
  var tva = (t !== undefined && t !== null) ? t : (condLabos[laboId] ? (condLabos[laboId].tva || 5.5) : 5.5);
  if (tva > 0 && tva < 1) tva = Math.round(tva * 1000) / 10;
  return tva || 0;
}

function pxChercher(q) {
  q = (q || '').trim();
  if (q.length < 2) return [];
  var isNum = /^\d+$/.test(q);
  if (isNum && q.length < 4) return []; // au moins 4 chiffres pour l'EAN
  var qUp = q.toUpperCase();
  var res = [];
  var ids = Object.keys(condLabos || {});
  for (var k = 0; k < ids.length && res.length < 8; k++) {
    var l = condLabos[ids[k]];
    var prods = (l && l.produits) || [];
    for (var i = 0; i < prods.length && res.length < 8; i++) {
      var p = prods[i];
      if (isNum) {
        var ean = String(p.ean || '');
        if (ean === q || ean.slice(-q.length) === q) res.push({ laboId: ids[k], laboNom: l.nom || '', p: p });
      } else {
        if ((p.nom || '').toUpperCase().indexOf(qUp) >= 0) res.push({ laboId: ids[k], laboNom: l.nom || '', p: p });
      }
    }
  }
  return res;
}

function pxRenderResultats(items) {
  var box = document.getElementById('px-res');
  if (!box) return;
  if (!items.length) { box.style.display = 'none'; box.innerHTML = ''; return; }
  var html = '';
  items.forEach(function(it, idx) {
    var tarif = it.p.pu_catalogue || it.p.pa_net || 0;
    // v7.31 : ANATONIC → tarif × 1.6 = PV TTC direct, arrondi € supérieur (pas de TVA en plus)
    // v7.32 : prix manuel prioritaire sur toute formule, marqué ✏️
    var prixAff = tarif ? tarif.toFixed(2) + ' € HT' : '—';
    if (tarif && (it.laboNom || '').toUpperCase().indexOf('ANATONIC') >= 0) {
      prixAff = Math.ceil(tarif * 1.6).toFixed(2) + ' € TTC';
    }
    if (it.p.pv_ttc_manuel > 0) {
      prixAff = it.p.pv_ttc_manuel.toFixed(2) + ' € TTC ✏️';
    }
    html += '<div class="px-item" data-idx="' + idx + '" style="padding:6px 10px;font-size:11px;cursor:pointer;border-bottom:0.5px solid var(--border);display:flex;justify-content:space-between;gap:8px">' +
      '<span style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap"><strong>' + (it.p.nom || '') + '</strong>' +
      ' <span style="color:var(--text-ter)">· ' + it.laboNom + ' · …' + String(it.p.ean || '').slice(-4) + '</span></span>' +
      '<span style="color:var(--accent-text);white-space:nowrap">' + prixAff + '</span></div>';
  });
  box.innerHTML = html;
  box.style.display = 'block';
  box._items = items;
  Array.prototype.forEach.call(box.querySelectorAll('.px-item'), function(el) {
    el.onclick = function() { pxSelectionner(box._items[parseInt(el.getAttribute('data-idx'))]); };
    el.onmouseenter = function(){ el.style.background = 'var(--surface2)'; };
    el.onmouseleave = function(){ el.style.background = ''; };
  });
}

var pxCourant = null; // v7.32 — sélection courante du widget (pour le prix manuel)

function pxSelectionner(it) {
  pxCourant = it;
  var labo = condLabos[it.laboId];
  var p = it.p;
  var tarif = p.pu_catalogue || 0;
  var paNetConnu = p.pa_net || 0;
  if (!tarif && paNetConnu) tarif = paNetConnu;

  var tva = pxNormTva(p.tva, it.laboId);
  var pvTTC, pvHT, paNet, calcDetail;

  // ANATONIC : pas de remise négociée — tarif × 1.6 = PV TTC direct, arrondi € supérieur (v7.31)
  var isAnatonic = (labo && (labo.nom || '').toUpperCase().indexOf('ANATONIC') >= 0);
  if (isAnatonic && tarif > 0) {
    pvTTC = Math.ceil(tarif * 1.6);
    pvHT  = pvTTC / (1 + tva / 100);
    paNet = tarif;
    calcDetail =
      'Tarif catalogue <strong>' + tarif.toFixed(2) + ' €</strong>' +
      ' × coeff <strong>1.6</strong>' +
      ' = <strong>' + (tarif * 1.6).toFixed(2) + ' € TTC</strong>' +
      ' → arrondi € supérieur = <strong>' + pvTTC.toFixed(2) + ' € TTC</strong>';
  } else {
    // Remise : marché négocié, rem_cat, ou 0
    var rem = 0, remSrc = 'aucune';
    try { rem = simLPPRRemiseActive(labo, p) || 0; } catch(e) { rem = 0; }
    if (rem > 0) {
      remSrc = p.marche_id ? 'marché ' + p.marche_id : 'implicite tarif/PA net';
    } else if (p.rem_cat > 0) {
      rem = p.rem_cat; remSrc = 'rem. catalogue';
    }
    var tm = (labo && labo.mbActuel > 0) ? labo.mbActuel : 35;
    var tmSrc = (labo && labo.mbActuel > 0) ? 'conditions labo' : 'défaut 35 %';
    paNet = tarif * (1 - rem / 100);
    if (rem === 0 && paNetConnu > 0) { paNet = paNetConnu; }
    pvHT  = (tm > 0 && tm < 100) ? paNet / (1 - tm / 100) : paNet;
    pvTTC = pvHT * (1 + tva / 100);
    calcDetail =
      'Tarif <strong>' + (tarif ? tarif.toFixed(2) + ' €' : '—') + '</strong>' +
      ' − remise <strong>' + rem.toFixed(1) + ' %</strong> <span style="color:var(--text-ter)">(' + remSrc + ')</span>' +
      ' → PA net <strong>' + paNet.toFixed(2) + ' €</strong>' +
      ' · tx marque <strong>' + tm.toFixed(1) + ' %</strong> <span style="color:var(--text-ter)">(' + tmSrc + ')</span>' +
      ' · TVA ' + tva + ' %';
  }

  // v7.32 — prix manuel prioritaire sur la formule, jusqu'à modification ou effacement
  if (p.pv_ttc_manuel > 0) {
    pvTTC = p.pv_ttc_manuel;
    pvHT  = pvTTC / (1 + tva / 100);
    calcDetail = '✏️ <strong>PRIX MANUEL</strong> — remplace la formule. ' + calcDetail;
  }

  document.getElementById('px-res').style.display = 'none';
  document.getElementById('px-q').value = '';
  var d = document.getElementById('px-detail');
  d.style.display = 'block';
  document.getElementById('px-nom').textContent = p.nom || '';
  document.getElementById('px-meta').textContent = it.laboNom + ' · EAN ' + (p.ean || '—');
  document.getElementById('px-calc').innerHTML = calcDetail;
  document.getElementById('px-pvttc').textContent = pvTTC.toFixed(2) + ' €';
  document.getElementById('px-pvht').textContent = 'PV HT ' + pvHT.toFixed(2) + ' € · marge ' + (pvHT - paNet).toFixed(2) + ' €';
  var refEl = document.getElementById('px-ref');
  refEl.textContent = (p.pv_ttc > 0) ? 'PV TTC actuel en base : ' + p.pv_ttc.toFixed(2) + ' €' : '';
  var manEl = document.getElementById('px-manuel');
  if (manEl) manEl.value = (p.pv_ttc_manuel > 0) ? p.pv_ttc_manuel.toFixed(2) : '';
}

// v7.32 — Prix manuel : enregistré sur le produit (pv_ttc_manuel) et poussé
// dans produits/LABOID.json sur GitHub → durable, partagé entre machines
// (« Charger depuis GitHub » sur les autres). Effacer = retour à la formule.
function pxSauverPrixManuel() {
  if (!pxCourant) return;
  var brut = String(document.getElementById('px-manuel').value || '').replace(',', '.').trim();
  var v = parseFloat(brut);
  if (isNaN(v) || v <= 0) { alert('Prix invalide. Exemple : 89 ou 89,50'); return; }
  pxCourant.p.pv_ttc_manuel = Math.round(v * 100) / 100;
  pxPersisterPrixManuel();
  pxSelectionner(pxCourant);
}

function pxEffacerPrixManuel() {
  if (!pxCourant || !(pxCourant.p.pv_ttc_manuel > 0)) return;
  delete pxCourant.p.pv_ttc_manuel;
  pxPersisterPrixManuel();
  pxSelectionner(pxCourant);
}

function pxPersisterPrixManuel() {
  try { condPersistLight(); } catch(e) {}
  try { condSyncGitHubAuto(); } catch(e) {}
  try { condSauvegarderProduitsGitHub(pxCourant.laboId); } catch(e) { console.warn('[PrixPublic] push GitHub échoué', e); }
}

function pxInit() {
  if (document.getElementById('px-widget')) return;
  var w = document.createElement('div');
  w.id = 'px-widget';
  // v7.40 : ancré au-dessus du tableau Catalogue (div #px-anchor, aligné à droite,
  // au niveau de l'en-tête TVA/PA) — les résultats et le détail se déploient vers
  // le bas en surimpression (position:absolute) sans pousser le tableau.
  // Repli : si l'ancre est absente (ancien index), comportement flottant v7.23.
  var ancre = document.getElementById('px-anchor');
  if (ancre) {
    w.style.cssText = 'position:relative;max-width:560px;font-size:13px;display:none;';
  } else {
    w.style.cssText = 'position:fixed;bottom:30px;right:10px;z-index:9998;max-width:560px;font-size:13px;display:none;';
  }
  w.innerHTML =
    '<div id="px-res" style="display:none;background:var(--surface,#fff);border:1px solid var(--border,#ccc);border-radius:8px;margin-bottom:4px;max-height:320px;overflow:auto;box-shadow:0 4px 14px rgba(0,0,0,.18)"></div>' +
    '<div id="px-detail" style="display:none;background:var(--surface,#fff);border:1px solid var(--border,#ccc);border-radius:8px;margin-bottom:4px;padding:8px 10px;box-shadow:0 4px 14px rgba(0,0,0,.18)">' +
      '<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px">' +
        '<div style="min-width:0"><div id="px-nom" style="font-weight:700;font-size:12px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap"></div>' +
        '<div id="px-meta" style="font-size:10px;color:var(--text-ter,#888)"></div></div>' +
        '<button type="button" onclick="document.getElementById(\'px-detail\').style.display=\'none\'" style="border:none;background:transparent;cursor:pointer;font-size:14px;color:var(--text-ter,#888);line-height:1">✕</button>' +
      '</div>' +
      '<div id="px-calc" style="font-size:10px;color:var(--text-sec,#555);margin-top:6px;line-height:1.6"></div>' +
      '<div style="display:flex;align-items:baseline;gap:12px;margin-top:6px">' +
        '<span style="font-size:11px;color:var(--text-sec,#555)">Prix public TTC</span>' +
        '<strong id="px-pvttc" style="font-size:22px;color:var(--accent-text,#0a7)"></strong>' +
        '<span id="px-pvht" style="font-size:10px;color:var(--text-ter,#888)"></span>' +
      '</div>' +
      '<div id="px-ref" style="font-size:10px;color:var(--text-ter,#888);margin-top:4px"></div>' +
      '<div style="display:flex;align-items:center;gap:6px;margin-top:8px;padding-top:8px;border-top:0.5px solid var(--border,#ccc)">' +
        '<span style="font-size:10px;color:var(--text-sec,#555);white-space:nowrap">✏️ Prix manuel TTC</span>' +
        '<input id="px-manuel" placeholder="ex : 89,50" autocomplete="off" style="border:1px solid var(--border,#ccc);border-radius:4px;outline:none;font-size:11px;width:64px;padding:3px 6px;text-align:right">' +
        '<button type="button" onclick="pxSauverPrixManuel()" style="font-size:10px;padding:3px 8px;background:#1e5a8a;color:#fff;border:none;border-radius:4px;cursor:pointer;font-weight:500">Enregistrer</button>' +
        '<button type="button" onclick="pxEffacerPrixManuel()" title="Effacer le prix manuel — retour à la formule" style="font-size:10px;padding:3px 8px;background:transparent;color:var(--text-sec,#555);border:1px solid var(--border,#ccc);border-radius:4px;cursor:pointer">✕ formule</button>' +
      '</div>' +
    '</div>' +
    '<div style="background:var(--surface,#fff);border:1px solid var(--border,#ccc);border-radius:22px;padding:8px 14px;display:flex;align-items:center;gap:6px;box-shadow:0 2px 8px rgba(0,0,0,.15)">' +
      '<span style="font-size:15px">💶</span>' +
      '<input id="px-q" placeholder="Prix public — nom, EAN ou 4 derniers chiffres" autocomplete="off" style="border:none;outline:none;background:transparent;font-size:14px;width:440px">' +
    '</div>';
  if (ancre) {
    ancre.appendChild(w);
    // Résultats + détail en surimpression sous la barre (au lieu d'au-dessus en mode flottant)
    ['px-res', 'px-detail'].forEach(function (id) {
      var el = document.getElementById(id);
      if (!el) return;
      el.style.position = 'absolute';
      el.style.top = '100%';
      el.style.right = '0';
      el.style.width = '520px';
      el.style.maxWidth = '90vw';
      // La liste de résultats doit passer AU-DESSUS du panneau de détail si les
      // deux sont ouverts (nouvelle recherche pendant qu'un détail est affiché).
      el.style.zIndex = (id === 'px-res') ? '9999' : '9998';
      el.style.marginTop = '4px';
      el.style.marginBottom = '0';
    });
  } else {
    document.body.appendChild(w);
  }
  var q = document.getElementById('px-q');
  q.addEventListener('input', function() { pxRenderResultats(pxChercher(q.value)); });
  q.addEventListener('keydown', function(e) {
    if (e.key === 'Enter') { // douchette : EAN complet + Entrée → sélection directe
      var items = pxChercher(q.value);
      if (items.length >= 1) pxSelectionner(items[0]);
    }
    if (e.key === 'Escape') {
      document.getElementById('px-res').style.display = 'none';
      document.getElementById('px-detail').style.display = 'none';
      q.value = '';
    }
  });
  document.addEventListener('click', function(e) {
    if (!w.contains(e.target)) document.getElementById('px-res').style.display = 'none';
  });
}
// v7.24 : visibilité conditionnelle — le widget n'apparaît que dans l'onglet
// Catalogue (panel-cat visible) avec un labo étiquettes sélectionné (catLaboActif) :
// ANATONIC, THUASNE, GIBAUD, PODOWELL, ORLIMAN (v8.65 : ORLIMAN + barre agrandie).
// Le gestionnaire ci-dessous (800 ms) crée le widget au besoin et pilote son
// affichage ; il remplace le simple watchdog v7.22.
function pxBoot() {
  try {
    pxInit();
    if (document.getElementById('px-widget')) console.log('[PrixPublic] widget initialisé ✓');
  } catch(e) { console.error('[PrixPublic] échec init :', e); }
}
function pxDoitAfficher() {
  try {
    var panel = document.getElementById('panel-cat');
    if (!panel || panel.style.display === 'none') return false;
    if (typeof catLaboActif === 'undefined' || !catLaboActif || !condLabos[catLaboActif]) return false;
    var nom = (condLabos[catLaboActif].nom || '').toUpperCase();
    return nom.indexOf('ANATONIC') >= 0 || nom.indexOf('THUASNE') >= 0
        || nom.indexOf('GIBAUD') >= 0  || nom.indexOf('PODOWELL') >= 0
        || nom.indexOf('ORLIMAN') >= 0;
  } catch(e) { return false; }
}
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', function() { setTimeout(pxBoot, 400); });
} else {
  setTimeout(pxBoot, 200);
}
setInterval(function() {
  if (!document.body) return;
  if (!document.getElementById('px-widget')) pxBoot();
  var w = document.getElementById('px-widget');
  if (w) w.style.display = pxDoitAfficher() ? '' : 'none';
}, 800);

// ============================================================
// v7.37 — Authentification par mot de passe partagé
// Session : jeton "expiration.signature" délivré par /api/login
// (signature HMAC vérifiée côté serveur — le client ne lit que
// l'expiration pour savoir s'il doit réafficher l'écran).
// En v7.37 le verrou est côté interface ; le verrouillage serveur
// des écritures GitHub arrive en v7.38 (proxy /api/github).
// ============================================================
function authGetSession() {
  try { return localStorage.getItem('app_session') || ''; } catch (e) { return ''; }
}
function authSessionValide() {
  var t = authGetSession();
  if (!t) return false;
  var exp = parseInt(t.split('.')[0], 10);
  return !isNaN(exp) && Date.now() < exp;
}
function authMasquerOverlay() {
  var ov = document.getElementById('auth-overlay');
  if (ov) ov.remove();
}
async function authLogin() {
  var champ = document.getElementById('auth-pass');
  var errEl = document.getElementById('auth-err');
  var btn = document.getElementById('auth-btn');
  var pass = champ ? champ.value : '';
  if (!pass) { if (errEl) errEl.textContent = 'Saisir le mot de passe.'; return; }
  if (btn) { btn.disabled = true; btn.textContent = 'Vérification…'; }
  if (errEl) errEl.textContent = '';
  try {
    var r = await fetch('/api/login', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ password: pass })
    });
    var data = await r.json().catch(function () { return {}; });
    if (r.ok && data.token) {
      try { localStorage.setItem('app_session', data.token); } catch (e) {}
      authMasquerOverlay();
    } else if (r.status === 401) {
      if (errEl) errEl.textContent = 'Mot de passe incorrect.';
    } else {
      if (errEl) errEl.textContent = data.error || ('Erreur serveur (' + r.status + '). Variables APP_PASSWORD / SESSION_SECRET configurées sur Vercel ?');
    }
  } catch (e) {
    if (errEl) errEl.textContent = 'Connexion impossible : ' + e.message;
  }
  if (btn) { btn.disabled = false; btn.textContent = 'Se connecter'; }
}
function authDeconnexion() {
  try { localStorage.removeItem('app_session'); } catch (e) {}
  location.reload();
}
(function authInit() {
  var ov = document.getElementById('auth-overlay');
  if (!ov) return; // overlay absent (ancien index) — ne rien bloquer
  if (authSessionValide()) { authMasquerOverlay(); return; }
  var champ = document.getElementById('auth-pass');
  if (champ) {
    champ.addEventListener('keydown', function (ev) { if (ev.key === 'Enter') authLogin(); });
    try { champ.focus(); } catch (e) {}
  }
})();

// ============================================================
// v7.38/v7.39 — Proxy GitHub côté serveur (/api/github)
// Le token GitHub n'existe plus côté navigateur : il vit dans la
// variable d'environnement Vercel GH_TOKEN. Tous les appels
// existants vers api.github.com/repos/OWNER/REPO/* sont
// interceptés ici et reroutés vers /api/github avec le jeton de
// session (X-Session). Aucune des 15 fonctions existantes n'est
// modifiée : l'intercepteur est le point de passage unique.
// v7.39 : les corps de requête > 800 Ko sont compressés en gzip
// (CompressionStream natif) et décompressés par le proxy — la
// limite Vercel de 4,5 Mo par requête provoquait une erreur 413
// sur la sauvegarde manuelle de data-labos.json (produits inclus).
// ============================================================
async function ghGzip(texte) {
  var flux = new Blob([texte]).stream().pipeThrough(new CompressionStream('gzip'));
  return await new Response(flux).arrayBuffer();
}
(function ghProxyInit() {
  var GH_API_PREFIX = 'https://api.github.com/repos/' + GH_OWNER + '/' + GH_REPO + '/';
  var SEUIL_GZIP = 800000; // octets — en dessous, envoi tel quel
  var fetchOrigine = window.fetch.bind(window);
  window.fetch = function (input, init) {
    try {
      var url = (typeof input === 'string') ? input : ((input && input.url) || '');
      if (url.indexOf(GH_API_PREFIX) === 0) {
        var reste = url.substring(GH_API_PREFIX.length);
        var qIdx = reste.indexOf('?');
        var chemin = qIdx >= 0 ? reste.substring(0, qIdx) : reste;
        var query = qIdx >= 0 ? '&' + reste.substring(qIdx + 1) : '';
        var proxyUrl = '/api/github?path=' + encodeURIComponent(chemin) + query;
        var options = {};
        for (var k in (init || {})) options[k] = init[k];
        var h = {};
        var hs = (init && init.headers) || {};
        for (var hk in hs) {
          if (hk.toLowerCase() === 'authorization') continue; // jamais le faux token vers le proxy
          h[hk] = hs[hk];
        }
        h['X-Session'] = authGetSession();
        options.headers = h;
        // v7.39 — compression des gros corps (sauvegarde data-labos, blobs Ospharm…)
        if (typeof options.body === 'string' && options.body.length > SEUIL_GZIP && typeof CompressionStream !== 'undefined') {
          return ghGzip(options.body).then(function (buf) {
            h['X-Gzip'] = '1';
            h['Content-Type'] = 'application/octet-stream';
            options.body = buf;
            return fetchOrigine(proxyUrl, options);
          });
        }
        return fetchOrigine(proxyUrl, options);
      }
    } catch (e) { /* en cas de doute, laisser passer l'appel original */ }
    return fetchOrigine(input, init);
  };
  // Sentinelle : les gardes existantes ("if (!token) return") exigent un
  // gh_token non vide. On écrase toute valeur par 'proxy' — ce qui purge
  // au passage les vrais PAT encore stockés sur les 3 machines.
  try { localStorage.setItem('gh_token', 'proxy'); } catch (e) {}
})();

// ============================================================
// v7.42 — Proxy OneDrive côté serveur (/api/onedrive)
// Plus aucun token Microsoft dans le navigateur : connexion UNIQUE via
// /api/onedrive-auth (refresh token chiffré stocké côté serveur), puis
// renouvellement silencieux. Intercepteur identique au principe GitHub :
// les appels graph.microsoft.com/v1.0/me/drive* sont reroutés vers le
// proxy avec la session. Particularités gérées ici :
//  - téléchargements : le proxy renvoie l'URL directe Microsoft
//    (X-Proxy-Redirect) que l'intercepteur suit lui-même — pas de limite
//    de taille Vercel ;
//  - uploads > 3,5 Mo : session d'upload Graph créée via le proxy, puis
//    envoi par morceaux directement chez Microsoft.
// ============================================================
var ODP_SEUIL_UPLOAD = 3500000;      // octets — au-delà : session d'upload
var ODP_CHUNK = 13107200;            // 12,5 Mo — multiple requis de 320 Kio

async function odpUploadParSession(cheminGraph, blob, fetchOrigine, sessionHeaders) {
  // cheminGraph se termine par ":/content" — la session d'upload se crée sur ":/createUploadSession"
  var cheminSession = cheminGraph.replace(/:\/content(\?.*)?$/, ':/createUploadSession');
  var r = await fetchOrigine('/api/onedrive?path=' + encodeURIComponent(cheminSession), {
    method: 'POST',
    headers: Object.assign({ 'Content-Type': 'application/json' }, sessionHeaders),
    body: JSON.stringify({ item: { '@microsoft.graph.conflictBehavior': 'replace' } })
  });
  if (!r.ok) return r; // laisser l'appelant voir l'erreur telle quelle
  var s = await r.json();
  if (!s.uploadUrl) return new Response(JSON.stringify({ error: { message: 'Session d\u2019upload sans uploadUrl' } }), { status: 502 });
  var total = blob.size;
  var derniere = null;
  for (var debut = 0; debut < total; debut += ODP_CHUNK) {
    var fin = Math.min(debut + ODP_CHUNK, total);
    derniere = await fetchOrigine(s.uploadUrl, {
      method: 'PUT',
      headers: {
        'Content-Range': 'bytes ' + debut + '-' + (fin - 1) + '/' + total
      },
      body: blob.slice(debut, fin)
    });
    if (!derniere.ok && derniere.status !== 202) return derniere;
  }
  return derniere;
}

(function odProxyInit() {
  var GRAPH_PREFIX = 'https://graph.microsoft.com/v1.0/';
  var fetchPrecedent = window.fetch.bind(window); // inclut déjà l'intercepteur GitHub
  window.fetch = function (input, init) {
    var url = '';
    try { url = (typeof input === 'string') ? input : ((input && input.url) || ''); } catch (e) {}
    if (url.indexOf(GRAPH_PREFIX) !== 0) return fetchPrecedent(input, init);
    try {
      var chemin = url.substring(GRAPH_PREFIX.length); // conserve sa query ($select…) et son encodage
      var options = {};
      for (var k in (init || {})) options[k] = init[k];
      var h = {};
      var hs = (init && init.headers) || {};
      for (var hk in hs) {
        var lc = hk.toLowerCase();
        if (lc === 'authorization') continue; // le Bearer périmé ne sert plus
        h[hk] = hs[hk];
      }
      h['X-Session'] = authGetSession();
      options.headers = h;

      // Gros upload (PUT …:/content avec un Blob/File volumineux) → session d'upload
      var estContenu = /:\/content(\?|$)/.test(chemin);
      var corps = options.body;
      if (options.method === 'PUT' && estContenu && corps && typeof Blob !== 'undefined' && corps instanceof Blob && corps.size > ODP_SEUIL_UPLOAD) {
        return odpUploadParSession(chemin, corps, fetchPrecedent, { 'X-Session': h['X-Session'] });
      }

      return fetchPrecedent('/api/onedrive?path=' + encodeURIComponent(chemin), options).then(function (rep) {
        // Téléchargement : le proxy a converti le 302 Graph en URL directe
        if (rep.headers.get('X-Proxy-Redirect') === '1') {
          return rep.json().then(function (j) {
            if (j && j.downloadUrl) return fetchPrecedent(j.downloadUrl);
            return rep;
          });
        }
        return rep;
      });
    } catch (e) {
      return fetchPrecedent(input, init);
    }
  };
  // Sentinelle : les gardes existantes exigent un ms_graph_token non vide.
  try { localStorage.setItem('ms_graph_token', 'proxy'); } catch (e) {}
})();

// Remplace l'ancien flux implicite (redéclaration : la dernière définition gagne).
// Un clic → page de connexion Microsoft UNE FOIS pour toute la pharmacie —
// ensuite tous les postes sont servis par le serveur, sans identifiant.
async function rdvConnectOneDrive() {
  if (!authSessionValide()) { alert('Session expirée — rechargez la page et reconnectez-vous d\u2019abord au calculateur.'); return; }
  window.location.href = '/api/onedrive-auth?session=' + encodeURIComponent(authGetSession());
}

// Retour de la connexion OneDrive (…/?onedrive=ok)
(function odRetourConnexion() {
  try {
    if (new URLSearchParams(window.location.search).get('onedrive') === 'ok') {
      history.replaceState(null, '', window.location.pathname);
      setTimeout(function () { alert('OneDrive connecté ✓ — valable pour tous les postes, plus aucune connexion à refaire.'); }, 300);
    }
  } catch (e) {}
})();

// v7.43 — Répare le bouton mort du panneau Documents : rdvConnecterOneDrive
// (avec « er ») était référencé par un onclick mais jamais défini.
async function rdvConnecterOneDrive() { return rdvConnectOneDrive(); }

// ============================================================
// v7.44 — Statut OneDrive réel (interrogation du proxy, cache 5 min)
// ============================================================
var odStatutCache = null; // { ok, t }
async function rdvOdVerifier(force) {
  if (!force && odStatutCache && (Date.now() - odStatutCache.t) < 300000) return odStatutCache.ok;
  var ok = false;
  try {
    // Passe par l'intercepteur v7.42 → /api/onedrive avec la session.
    var r = await fetch('https://graph.microsoft.com/v1.0/me/drive');
    ok = r.ok;
  } catch (e) { ok = false; }
  odStatutCache = { ok: ok, t: Date.now() };
  return ok;
}
async function rdvOdMajStatut() {
  var ok = await rdvOdVerifier();
  document.querySelectorAll('.rdv-od-badge').forEach(function (el) {
    el.textContent = ok ? '● OneDrive connecté' : '○ OneDrive non connecté';
    el.style.color = ok ? '#0078d4' : '#c0392b';
  });
  document.querySelectorAll('.rdv-od-btn').forEach(function (el) {
    el.style.display = ok ? 'none' : '';
  });
}

// ============================================================
// v7.45 — Migration one-shot : purge des doublons DUCRAY/PODOWELL
// Les IDs 1780849801715 (DUCRAY) et 1781526783718 (PODOWELL) ont été
// supprimés de data-labos.json le 13/07/2026 (dédoublonnage). Comme le
// chargement GitHub FUSIONNE dans condLabos sans supprimer les entrées
// locales, chaque machine doit purger son localStorage — ce bloc le fait
// automatiquement au démarrage, avant toute sauvegarde possible.
// Idempotent et inoffensif une fois la purge faite partout ;
// pourra être retiré dans quelques versions.
// ============================================================
(function migrationDedup745() {
  var A_SUPPRIMER = ['1780849801715', '1781526783718'];
  var purge = 0;
  A_SUPPRIMER.forEach(function (id) {
    if (condLabos && condLabos[id]) { delete condLabos[id]; purge++; }
  });
  if (purge > 0) {
    try { if (typeof condPersistLight === 'function') condPersistLight(); } catch (e) {}
    try { if (typeof condInit === 'function') condInit(); } catch (e) {}
    console.warn('[Migration v7.45] ' + purge + ' doublon(s) DUCRAY/PODOWELL purgé(s) du cache local de cette machine.');
  }
})();

// ============================================================
// v8.65 — Purge du doublon AVENE (id « 1 », fiche VIDE : CA 0, 0 produit,
// 0 condition). La vraie fiche AVENE est 1781536914046 (238 produits,
// 18 marchés négociés). Comme le chargement GitHub FUSIONNE dans condLabos
// sans supprimer, la purge est rappelée APRÈS chaque fusion
// (condChargerGitHub + repli public) en plus du démarrage — le premier
// auto-save nettoiera data-labos.json sur GitHub pour les 3 machines.
// Garde-fou : ne supprime QUE si nom AVENE et CA annuel nul.
// ============================================================
function condPurgerDoublonAvene() {
  try {
    var l = condLabos && condLabos['1'];
    if (l && String(l.nom || '').toUpperCase().indexOf('AVENE') >= 0 && !(l.caAnnuel > 0)) {
      delete condLabos['1'];
      console.warn('[Migration v8.65] Doublon AVENE (id 1, fiche vide) purgé.');
      return 1;
    }
  } catch (e) {}
  return 0;
}
(function migrationDedupAvene865() {
  if (condPurgerDoublonAvene() > 0) {
    try { if (typeof condPersistLight === 'function') condPersistLight(); } catch (e) {}
    try { if (typeof condInit === 'function') condInit(); } catch (e) {}
  }
})();

// ============================================================
// v7.46 — Période de référence Ospharm visible au niveau des champs
// Les données Ospharm sont déjà chargées AUTOMATIQUEMENT à chaque
// démarrage (filet v7.16, fetch public du cache GitHub). Ce module rend
// la période explicite là où les chiffres s'affichent : ligne 📅 au-dessus
// des tableaux (analyse labo + Vue COALIA) et infobulles sur Qté N / N-1.
// La période N-1 est dérivée de la période N (mêmes dates, année − 1).
// ============================================================
function decOsphMeta() {
  try { return JSON.parse(localStorage.getItem('_osph_meta') || 'null'); } catch (e) { return null; }
}
function decOsphAnMoins1(d) {
  // '01/06/2025' → '01/06/2024' (robuste : ne touche que l'année finale)
  return String(d || '').replace(/(\d{4})\s*$/, function (m) { return String(parseInt(m, 10) - 1); });
}
function decOsphPeriodeTitle(quelle) {
  var m = decOsphMeta();
  if (!m || !m.periodeDebut || !m.periodeFin) return 'Période Ospharm inconnue — réimporter un export daté';
  if (quelle === 'N1') {
    return 'Quantités vendues du ' + decOsphAnMoins1(m.periodeDebut) + ' au ' + decOsphAnMoins1(m.periodeFin) + ' (Ospharm, N-1)';
  }
  return 'Quantités vendues du ' + m.periodeDebut + ' au ' + m.periodeFin + ' (export Ospharm ' + (m.fichier || '') + ')';
}
function decOsphPeriodeLigne(avecN1) {
  var m = decOsphMeta();
  if (!m || !m.periodeDebut || !m.periodeFin) return '';
  var t = '📅 Réf. Ospharm — Qté N : <b>' + m.periodeDebut + ' → ' + m.periodeFin + '</b>';
  if (avecN1) t += ' · Qté N-1 : <b>' + decOsphAnMoins1(m.periodeDebut) + ' → ' + decOsphAnMoins1(m.periodeFin) + '</b>';
  t += ' <span style="color:var(--text-ter)">(importé le ' + (m.importeeLe || '?') + ')</span>';
  return '<div style="font-size:10.5px;color:var(--text-sec);margin:2px 0 4px">' + t + '</div>';
}

// ============================================================
// v7.47 — Référence du stock affichée et datée
// Le stock affiché vient soit de l'export Ospharm (daté par son import),
// soit de l'import « Stock réel LGPI » (à l'instant T, par labo, par
// machine). La ligne 📅 et l'infobulle de la colonne Stock indiquent
// laquelle des deux sources fait foi et à quelle date elle remonte.
// Un nouvel import Ospharm réinitialise les dates LGPI (nouveau stock de
// référence). Dates LGPI stockées par machine (_stock_lgpi_dates).
// ============================================================
function decStockLgpiDateSet(labo, dateFR) {
  try {
    var d = JSON.parse(localStorage.getItem('_stock_lgpi_dates') || '{}');
    var auj = new Date();
    d[String(labo).toUpperCase()] = dateFR || (('0' + auj.getDate()).slice(-2) + '/' + ('0' + (auj.getMonth() + 1)).slice(-2) + '/' + auj.getFullYear());
    localStorage.setItem('_stock_lgpi_dates', JSON.stringify(d));
  } catch (e) {}
}
// v7.79 : ré-appliquer les stocks LGPI persistés (par poste) sur les données
// fraîchement rechargées depuis ospharm-cache.json.
function decStockLgpiAppliquer() {
  try {
    // v8.01 — le DERNIER stock LGPI (Marchés équivalents, pharmacie entière,
    // daté, permanent sur GitHub) s'applique d'abord à TOUS les labos.
    // L'import LGPI par labo (ci-dessous, ce poste), plus frais, reste prioritaire.
    if (typeof condStockLGPI !== 'undefined' && condStockLGPI && typeof condStockLGPIMeta !== 'undefined' && condStockLGPIMeta) {
      Object.keys(decOspharmProds || {}).forEach(function (labo) {
        (decOspharmProds[labo] || []).forEach(function (p) {
          if (!p.ean) return;
          var pean = String(p.ean).replace(/\D/g, '');
          if (condStockLGPI[pean] !== undefined) p.stock = condStockLGPI[pean];
        });
      });
    }
    var all = JSON.parse(localStorage.getItem('_stock_lgpi_data') || '{}');
    Object.keys(all).forEach(function (laboUp) {
      Object.keys(decOspharmProds || {}).forEach(function (labo) {
        if (String(labo).toUpperCase() !== laboUp) return;
        decOspharmProds[labo].forEach(function (p) {
          if (!p.ean) return;
          var pean = String(p.ean).replace(/\D/g, '');
          if (all[laboUp][pean] !== undefined) p.stock = all[laboUp][pean];
        });
      });
    });
  } catch (e) {}
}
// v8.01 — affiche le dernier stock conservé dans le bloc d'import de Décision RDV
function decStockPersistMaj() {
  var el = document.getElementById('dec-stock-persist');
  if (!el) return;
  if (typeof condStockLGPIMeta !== 'undefined' && condStockLGPIMeta) {
    el.innerHTML = '\u2713 Dernier stock conserv\u00e9 : <b>LGPI au ' + condStockLGPIMeta.date + '</b> \u00b7 ' + condStockLGPIMeta.nb + ' r\u00e9f. (pharmacie enti\u00e8re \u2014 import March\u00e9s \u00e9quivalents), appliqu\u00e9 par d\u00e9faut \u00e0 tous les labos. Un import ici (par labo) reste prioritaire car plus frais.';
    el.style.color = 'var(--accent-text)';
  } else { el.textContent = ''; }
}

function decStockLgpiDate(labo) {
  try {
    var d = JSON.parse(localStorage.getItem('_stock_lgpi_dates') || '{}');
    return d[String(labo).toUpperCase()] || null;
  } catch (e) { return null; }
}
function decStockRefCourt(labo) {
  var lgpi = labo ? decStockLgpiDate(labo) : null;
  if (lgpi) return 'LGPI au <b>' + lgpi + '</b> (instant T)';
  if (typeof condStockLGPIMeta !== 'undefined' && condStockLGPIMeta) return 'LGPI au <b>' + condStockLGPIMeta.date + '</b> (pharmacie enti\u00e8re)'; // v8.01
  var m = decOsphMeta();
  return 'Ospharm au <b>' + ((m && m.importeeLe) || '?') + '</b> (date d\u2019import de l\u2019export)';
}
function decStockRefTitle(labo) {
  var lgpi = labo ? decStockLgpiDate(labo) : null;
  if (lgpi) return 'Stock réel LGPI importé le ' + lgpi + ' (à l\u2019instant T — prioritaire sur le stock Ospharm)';
  if (typeof condStockLGPIMeta !== 'undefined' && condStockLGPIMeta) return 'Dernier stock LGPI conservé (import Marchés équivalents du ' + condStockLGPIMeta.date + ', pharmacie entière) — importez un export plus frais pour l\u2019actualiser'; // v8.01
  var m = decOsphMeta();
  return 'Stock issu de l\u2019export Ospharm importé le ' + ((m && m.importeeLe) || '?') + ' — pour un stock à l\u2019instant T, importer l\u2019export LGPI « Stock »';
}
// v7.47 : la ligne 📅 accepte désormais le labo et ajoute la référence stock
// v7.48 : reformulation — chaque date accolée à sa donnée. « Importé le 02/07 »
// qualifiait les VENTES Ospharm mais, placé en fin de ligne après le stock
// LGPI du 13/07, semblait le contredire. Nouveau format :
// 📅 Ventes Ospharm (export importé le 02/07/2026) : Qté N … · Qté N-1 … — Stock : LGPI au 13/07/2026
function decOsphPeriodeLigne(avecN1, labo) {
  var m = decOsphMeta();
  if (!m || !m.periodeDebut || !m.periodeFin) return '';
  var t = '📅 Ventes Ospharm <span style="color:var(--text-ter)">(export importé le ' + (m.importeeLe || '?') + ')</span> : ';
  t += 'Qté N <b>' + m.periodeDebut + ' → ' + m.periodeFin + '</b>';
  if (avecN1) t += ' · Qté N-1 <b>' + decOsphAnMoins1(m.periodeDebut) + ' → ' + decOsphAnMoins1(m.periodeFin) + '</b>';
  t += ' &nbsp;—&nbsp; Stock : ' + decStockRefCourt(labo);
  return '<div style="font-size:10.5px;color:var(--text-sec);margin:2px 0 4px">' + t + '</div>';
}


// ═════════════════════════════════════════════════════════════════════════════
// v8.25 — ONGLET 📥 ACHATS & IMPORTS : base de données d'achats multi-labos
// Sources mensuelles : export Digipharmacie (index factures), factures CERP
// (PDF détaillé, ligne à ligne), Récapitulatif achats sous contrats CERP,
// Suivi Achats Génériques Alliance. Persistance : achats-data.json sur GitHub
// (commit data-only via le proxy serveur). Toute requête labo (TEVA, SANDOZ…)
// s'appuie ensuite sur cette base.
// ═════════════════════════════════════════════════════════════════════════════

var achatsBase = null;       // { v:1, maj:'', mois:{ 'AAAA-MM': { digi:[], cerpL:[], cerpR:{}, alliance:{} } } }
var achatsInited = false;
var ACHATS_GH_FILE = 'achats-data.json';

function achatsMoisObj(m) {
  if (!achatsBase.mois[m]) achatsBase.mois[m] = {};
  return achatsBase.mois[m];
}

function achatsNum(v) { return parseFloat(String(v == null ? '' : v).replace(/\s/g, '').replace(',', '.')) || 0; }

// ── Init : charger la base depuis GitHub puis rendre ─────────────────────────
var _achatsChargement = null;
function achatsChargerBase() {
  if (achatsBase) return Promise.resolve(achatsBase);
  if (_achatsChargement) return _achatsChargement;
  _achatsChargement = fetch('https://raw.githubusercontent.com/' + GH_OWNER + '/' + GH_REPO + '/' + GH_BRANCH + '/' + ACHATS_GH_FILE + '?t=' + Date.now())
    .then(function(r) { return r.ok ? r.json() : null; })
    .then(function(d) {
      achatsBase = (d && d.mois) ? d : { v: 1, maj: '', mois: {} };
      // v8.56 : _doublonsRetires est un \u00e9tat d'AFFICHAGE de session \u2014 s'il arrive
      // du JSON (s\u00e9rialis\u00e9 par erreur \u2264 v8.55), on le purge : seul un nettoyage
      // fra\u00eechement ex\u00e9cut\u00e9 ci-dessous a le droit de le (re)poser.
      delete achatsBase._doublonsRetires;
      // v8.31 \u2014 nettoyage : d\u00e9doublonner les lignes Digipharmacie h\u00e9rit\u00e9es des
      // versions pr\u00e9c\u00e9dentes (m\u00eame fichier import\u00e9 avec et sans R\u00e9f\u00e9rence).
      var retires = 0;
      Object.keys(achatsBase.mois).forEach(function(m) {
        var o = achatsBase.mois[m];
        if (!o.digi || !o.digi.length) return;
        var vu = {}, propre = [];
        o.digi.forEach(function(dd) {
          var k = dd.fi || dd.r || JSON.stringify(dd);
          if (vu[k] !== undefined) { propre[vu[k]] = dd; retires++; } // garder la plus riche (derni\u00e8re)
          else { vu[k] = propre.length; propre.push(dd); }
        });
        o.digi = propre;
      });
      if (retires > 0) {
        achatsBase._doublonsRetires = retires;
        console.warn('[Achats] ' + retires + ' doublon(s) Digipharmacie retir\u00e9(s) \u2014 \ud83d\udcbe re-sauvegarder sur GitHub pour p\u00e9renniser.');
      }
      return achatsBase;
    })
    .catch(function() { achatsBase = { v: 1, maj: '', mois: {} }; return achatsBase; });
  return _achatsChargement;
}

function achatsInit() {
  if (achatsInited) { achatsRender(); return; }
  achatsInited = true;
  achatsRender();
  achatsChargerBase().then(function() { achatsRender(); });
}

// ── Sauvegarde GitHub (via proxy serveur, comme data-labos.json) ─────────────
async function achatsSauverGitHub() {
  var st = document.getElementById('achats-save-status');
  if (!achatsBase) return;
  if (st) { st.textContent = 'Sauvegarde\u2026'; st.style.color = 'var(--text-sec)'; }
  try {
    achatsBase.maj = new Date().toISOString();
    var token = condGetToken();
    // v8.56 : jamais de champ d'affichage dans le fichier de donn\u00e9es
    var copie = Object.assign({}, achatsBase);
    delete copie._doublonsRetires;
    var body = JSON.stringify(copie);
    var b64 = btoa(unescape(encodeURIComponent(body)));
    var sha = null;
    var g = await fetch('https://api.github.com/repos/' + GH_OWNER + '/' + GH_REPO + '/contents/' + ACHATS_GH_FILE + '?t=' + Date.now(), {
      headers: { 'Authorization': 'token ' + token, 'Accept': 'application/vnd.github.v3+json' }
    });
    if (g.ok) { var ex = await g.json(); sha = ex.sha; }
    var payload = { message: 'data: achats-data.json (base imports achats)', content: b64, branch: GH_BRANCH };
    if (sha) payload.sha = sha;
    var p = await fetch('https://api.github.com/repos/' + GH_OWNER + '/' + GH_REPO + '/contents/' + ACHATS_GH_FILE, {
      method: 'PUT',
      headers: { 'Authorization': 'token ' + token, 'Accept': 'application/vnd.github.v3+json', 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    if (!p.ok) {
      var e1 = await p.json();
      // SHA obsolète : re-lire et réessayer une fois
      if (String(e1.message || '').toLowerCase().indexOf('sha') >= 0) {
        var g2 = await fetch('https://api.github.com/repos/' + GH_OWNER + '/' + GH_REPO + '/contents/' + ACHATS_GH_FILE + '?t=' + Date.now(), {
          headers: { 'Authorization': 'token ' + token, 'Accept': 'application/vnd.github.v3+json' }
        });
        if (g2.ok) { payload.sha = (await g2.json()).sha; }
        p = await fetch('https://api.github.com/repos/' + GH_OWNER + '/' + GH_REPO + '/contents/' + ACHATS_GH_FILE, {
          method: 'PUT',
          headers: { 'Authorization': 'token ' + token, 'Accept': 'application/vnd.github.v3+json', 'Content-Type': 'application/json' },
          body: JSON.stringify(payload)
        });
        if (!p.ok) throw new Error((await p.json()).message || p.status);
      } else throw new Error(e1.message || p.status);
    }
    if (st) { st.textContent = '\u2713 Base sauvegard\u00e9e sur GitHub (' + Math.round(body.length / 1024) + ' Ko)'; st.style.color = 'var(--accent-text)'; }
    // v8.56 : le nettoyage est p\u00e9rennis\u00e9 \u2014 le bandeau doublons dispara\u00eet sans rechargement
    if (achatsBase._doublonsRetires) { delete achatsBase._doublonsRetires; try { achatsRender(); } catch (eR) {} }
    setTimeout(function() { if (st) st.textContent = ''; }, 5000);
  } catch (err) {
    if (st) { st.textContent = 'Erreur sauvegarde : ' + err.message; st.style.color = 'var(--danger)'; }
  }
}

// ── Reconstruction texte PDF (lignes tri\u00e9es y desc, x asc) ────────────────────
async function achatsPdfLignes(doc) {
  var pages = [];
  for (var pn = 1; pn <= doc.numPages; pn++) {
    var page = await doc.getPage(pn);
    var tc = await page.getTextContent();
    var parY = {};
    tc.items.forEach(function(it) {
      var y = Math.round(it.transform[5]);
      (parY[y] = parY[y] || []).push({ x: it.transform[4], s: it.str });
    });
    pages.push(Object.keys(parY).map(Number).sort(function(a, b) { return b - a; }).map(function(y) {
      return parY[y].sort(function(a, b) { return a.x - b.x; }).map(function(o) { return o.s; }).join(' ').replace(/\s+/g, ' ').trim();
    }));
  }
  return pages;
}

var ACHATS_MOIS_FR = { janvier: '01', 'f\u00e9vrier': '02', fevrier: '02', mars: '03', avril: '04', mai: '05', juin: '06', juillet: '07', 'ao\u00fbt': '08', aout: '08', septembre: '09', octobre: '10', novembre: '11', 'd\u00e9cembre': '12', decembre: '12' };

// ── IMPORT 1 : export Digipharmacie (ZIP/CSV/XLSX) — TOUTES les lignes ───────
function achatsImportDigi(input) {
  var file = input.files && input.files[0];
  if (!file) return;
  var finir = function() { input.value = ''; };
  var traiter = function(grid) {
    var hi = -1, col = {};
    for (var i = 0; i < Math.min(grid.length, 10) && hi < 0; i++) {
      var l = grid[i].map(function(c) { return String(c || '').toLowerCase(); });
      var iF = l.findIndex(function(c) { return c.indexOf('nom du fichier') >= 0; });
      if (iF >= 0) {
        hi = i; col.fichier = iF;
        col.type = l.findIndex(function(c) { return c === 'type'; });
        col.ref = l.findIndex(function(c) { return c.indexOf('reference') >= 0 || c.indexOf('r\u00e9f\u00e9rence') >= 0; });
        col.fourn = l.findIndex(function(c) { return c.indexOf('fournisseur') >= 0; });
        col.date = l.findIndex(function(c) { return c === 'date'; });
        if (col.date < 0) col.date = l.findIndex(function(c) { return c.indexOf('date') === 0 && c.indexOf('\u00e9ch\u00e9ance') < 0 && c.indexOf('echeance') < 0; }); // v8.38 : anciens exports
        col.b21 = l.findIndex(function(c) { return c.indexOf('2.10') >= 0 || c.indexOf('2,10') >= 0; });
        col.b55 = l.findIndex(function(c) { return c.indexOf('5.50') >= 0 || c.indexOf('5,50') >= 0; });
        col.b10 = l.findIndex(function(c) { return c.indexOf('10%') >= 0; });
        col.b20 = l.findIndex(function(c) { return c.indexOf('20%') >= 0; });
        col.ht = l.findIndex(function(c) { return c.indexOf('montant ht') >= 0; });
        col.ttc = l.findIndex(function(c) { return c.indexOf('ttc') >= 0; });
      }
    }
    if (hi < 0) { alert('Format Digipharmacie non reconnu (colonne \u00ab Nom du fichier \u00bb absente).'); finir(); return; }
    // v8.38 : accepter les deux formats de date (2025-03-15 ET 15/03/2025 \u2014
    // les exports Digipharmacie plus anciens sont en format fran\u00e7ais).
    var lireMoisDate = function(v) {
      var s2 = String(v || '');
      var mIso = s2.match(/(\d{4})-(\d{2})/);
      if (mIso) return { mois: mIso[1] + '-' + mIso[2], date: s2.slice(0, 10) };
      var mFr = s2.match(/(\d{2})\/(\d{2})\/(\d{4})/);
      if (mFr) return { mois: mFr[3] + '-' + mFr[2], date: mFr[3] + '-' + mFr[2] + '-' + mFr[1] };
      return null;
    };
    var nb = 0, parMois = {}, nbSansDate = 0;
    for (var r = hi + 1; r < grid.length; r++) {
      var l2 = grid[r];
      if (!l2 || !l2[col.date]) continue;
      var dm2 = lireMoisDate(l2[col.date]);
      if (!dm2) { nbSansDate++; continue; }
      var mois = dm2.mois;
      var ligne = {
        r: String(col.ref >= 0 ? l2[col.ref] : '').trim(),
        f: String(col.fourn >= 0 ? l2[col.fourn] : '').trim(),
        t: (/avoir/i.test(String(col.type >= 0 ? l2[col.type] : '')) || achatsNum(col.ht >= 0 ? l2[col.ht] : 0) < 0) ? 'A' : 'F', // v8.32 : HT n\u00e9gatif = avoir
        d: dm2.date,
        fi: String(l2[col.fichier] || '').trim(),
        b21: achatsNum(col.b21 >= 0 ? l2[col.b21] : 0),
        b55: achatsNum(col.b55 >= 0 ? l2[col.b55] : 0),
        b10: achatsNum(col.b10 >= 0 ? l2[col.b10] : 0),
        b20: achatsNum(col.b20 >= 0 ? l2[col.b20] : 0),
        ht: achatsNum(col.ht >= 0 ? l2[col.ht] : 0) || achatsNum(col.ttc >= 0 ? l2[col.ttc] : 0)
      };
      if (!parMois[mois]) parMois[mois] = [];
      parMois[mois].push(ligne);
      nb++;
    }
    if (!nb) { alert('Aucune ligne exploitable dans cet export' + (nbSansDate ? ' (' + nbSansDate + ' ligne(s) \u00e0 date illisible \u2014 envoyez-moi le fichier pour calibrer)' : '') + '.'); finir(); return; }
    // v8.30 \u2014 FUSION d\u00e9dupliqu\u00e9e : un export Digipharmacie contient les documents
    // TRAIT\u00c9S sur la p\u00e9riode, dont des factures dat\u00e9es des mois pr\u00e9c\u00e9dents (retardataires).
    // On fusionne donc par mois SANS \u00e9craser l'existant, cl\u00e9 = R\u00e9f\u00e9rence du document
    // (repli : nom du fichier) \u2014 imports cumulatifs, insensibles \u00e0 l'ordre et aux chevauchements.
    var moisT = Object.keys(parMois).sort();
    var nbNouv = 0, nbMaj = 0;
    moisT.forEach(function(m) {
      var o = achatsMoisObj(m);
      var exist = o.digi || [];
      var map = {};
      // v8.31 : cl\u00e9 = nom de fichier (stable entre versions ; les lignes pr\u00e9-v8.30
      // n'ont pas de R\u00e9f\u00e9rence \u2192 la cl\u00e9 R\u00e9f\u00e9rence cr\u00e9ait des doublons d'avoirs)
      exist.forEach(function(d, i2) { map[d.fi || d.r] = i2; });
      parMois[m].forEach(function(d) {
        var k = d.fi || d.r;
        if (k && map[k] !== undefined) { exist[map[k]] = d; nbMaj++; }
        else { exist.push(d); if (k) map[k] = exist.length - 1; nbNouv++; }
      });
      o.digi = exist;
    });
    achatsRender();
    alert('\u2713 Digipharmacie fusionn\u00e9 : ' + nbNouv + ' nouveau(x) document(s), ' + nbMaj + ' d\u00e9j\u00e0 connu(s) mis \u00e0 jour\nMois touch\u00e9s : ' + moisT.map(function(m) { return m + ' (' + (parMois[m] || []).length + ')'; }).join(', ') + '\n\ud83d\udcbe Pensez \u00e0 \u00ab Sauvegarder sur GitHub \u00bb.');
    finir();
  };
  var lireTableur = function(buf, nomInterne) {
    if (/\.csv$/i.test(nomInterne)) {
      var txt = new TextDecoder('utf-8').decode(buf).replace(/^\ufeff/, '');
      traiter(txt.split(/\r?\n/).map(function(l) { return l.split(';'); }));
    } else {
      var wbk = XLSX.read(new Uint8Array(buf), { type: 'array' });
      traiter(XLSX.utils.sheet_to_json(wbk.Sheets[wbk.SheetNames[0]], { header: 1, raw: false, defval: '' }));
    }
  };
  var reader = new FileReader();
  reader.onload = function(e) {
    var buf = e.target.result;
    if (/\.zip$/i.test(file.name)) {
      var suite = function() {
        JSZip.loadAsync(buf).then(function(zip) {
          var cible = null;
          zip.forEach(function(chemin, entry) { if (!cible && !entry.dir && /\.(csv|xlsx)$/i.test(chemin)) cible = entry; });
          if (!cible) { alert('Aucun CSV/XLSX dans ce ZIP.'); finir(); return; }
          cible.async('arraybuffer').then(function(b2) { lireTableur(b2, cible.name); });
        }).catch(function(err) { alert('ZIP illisible : ' + err.message); finir(); });
      };
      if (typeof JSZip === 'undefined') {
        var s = document.createElement('script');
        s.src = 'https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js';
        s.onload = suite;
        s.onerror = function() { alert('Module ZIP indisponible \u2014 d\u00e9posez le CSV/XLSX directement.'); finir(); };
        document.head.appendChild(s);
      } else suite();
    } else lireTableur(buf, file.name);
  };
  reader.readAsArrayBuffer(file);
}

// ── IMPORT 2 : factures CERP d\u00e9taill\u00e9es (PDF) — TOUTES les lignes produit ────
function achatsImportCerpFactures(input) {
  var file = input.files && input.files[0];
  if (!file) return;
  var reader = new FileReader();
  reader.onload = function(e) {
    pdfjsLib.getDocument({ data: new Uint8Array(e.target.result) }).promise.then(async function(doc) {
      var pages = await achatsPdfLignes(doc);
      var estPrix = function(t) { return /^\d{1,6},\d\d$/.test(t); };
      var lireLigne = function(ln) {
        var toks = ln.split(' ').filter(function(t) { return t !== ''; });
        if (!toks.length || !/^\d{13}$/.test(toks[0])) return null;
        while (toks.length && /^[A-Z]{1,2}$/.test(toks[toks.length - 1])) toks.pop();
        if (!toks.length || !/^\d$/.test(toks[toks.length - 1])) return null;
        var tva = toks.pop();
        if (toks.length < 4 || !estPrix(toks[toks.length - 1])) return null;
        var mht = achatsNum(toks.pop());
        if (!estPrix(toks[toks.length - 1])) return null;
        var punet = achatsNum(toks.pop());
        var puht;
        if (toks.length >= 2 && estPrix(toks[toks.length - 1]) && estPrix(toks[toks.length - 2])) { toks.pop(); puht = achatsNum(toks.pop()); }
        else if (estPrix(toks[toks.length - 1])) puht = achatsNum(toks.pop());
        else return null;
        if (!toks.length || !/^\d{1,4}$/.test(toks[toks.length - 1])) return null;
        var qte = parseInt(toks.pop(), 10);
        if (!qte || toks.length < 2) return null;
        if (Math.abs(qte * punet - mht) > Math.max(0.05, qte * 0.006)) return null;
        return [toks[0], toks.slice(1).join(' '), qte, puht, mht, parseInt(tva, 10)];
      };
      var parMois = {}, nb = 0, nbRejet = 0;
      pages.forEach(function(lignes) {
        var texte = lignes.join('\n');
        var dm = texte.match(/(\d{2})\/(\d{2})\/(\d{4})/);
        if (!dm) return;
        var mois = dm[3] + '-' + dm[2];
        lignes.forEach(function(ln) {
          if (!/^\d{13}\s/.test(ln)) return;
          var l = lireLigne(ln);
          if (!l) { nbRejet++; return; }
          if (!parMois[mois]) parMois[mois] = [];
          parMois[mois].push(l);
          nb++;
        });
      });
      if (!nb) { alert('Aucune ligne produit lisible dans ce PDF CERP.'); input.value = ''; return; }
      var moisT = Object.keys(parMois).sort();
      moisT.forEach(function(m) {
        var o = achatsMoisObj(m);
        o.cerpL = (o.cerpL || []).concat(parMois[m]); // cumulables (plusieurs lots de factures)
      });
      achatsRender();
      alert('\u2713 Factures CERP : ' + nb + ' ligne(s) produit import\u00e9e(s) (' + doc.numPages + ' pages' + (nbRejet ? ', ' + nbRejet + ' illisibles ignor\u00e9es' : '') + ')\nMois : ' + moisT.join(', ') + '\n\ud83d\udcbe Pensez \u00e0 \u00ab Sauvegarder sur GitHub \u00bb.');
      input.value = '';
    }).catch(function(err) { alert('PDF illisible : ' + err.message); input.value = ''; });
  };
  reader.readAsArrayBuffer(file);
}

// ── IMPORT 3 : R\u00e9capitulatif achats sous contrats CERP (PDF mensuel) ─────────
function achatsImportCerpRecap(input) {
  var file = input.files && input.files[0];
  if (!file) return;
  var reader = new FileReader();
  reader.onload = function(e) {
    pdfjsLib.getDocument({ data: new Uint8Array(e.target.result) }).promise.then(async function(doc) {
      var pages = await achatsPdfLignes(doc);
      var lignes = [].concat.apply([], pages);
      var texte = lignes.join('\n');
      if (!/achats sous contrats/i.test(texte)) { alert('Ce PDF ne ressemble pas au R\u00e9capitulatif achats sous contrats CERP.'); input.value = ''; return; }
      var mp = texte.match(/P\u00e9riode\s*:\s*([A-Za-z\u00e0-\u00fc\u00c0-\u00dc]+)\s+(\d{4})/);
      if (!mp || !ACHATS_MOIS_FR[mp[1].toLowerCase()]) { alert('P\u00e9riode introuvable dans le r\u00e9capitulatif.'); input.value = ''; return; }
      var mois = mp[2] + '-' + ACHATS_MOIS_FR[mp[1].toLowerCase()];
      var labos = {};
      var labosT = {};          // v8.39 : d\u00e9tail par taux de remise { labo: { '2.5': [6 nums], ... } }
      var dernierLabo = null;
      lignes.forEach(function(ln) {
        var mR = ln.match(/^Remise\s+([\d.,]+)\s?%\s+(.*)$/i);
        if (mR && dernierLabo) {
          var numsR2 = (mR[2].match(/-?\d[\d\s]*[.,]\d{1,2}|\b\d+\b/g) || []).map(achatsNum);
          if (numsR2.length >= 6) {
            var tauxK = String(parseFloat(mR[1].replace(',', '.')));
            if (!labosT[dernierLabo]) labosT[dernierLabo] = {};
            labosT[dernierLabo][tauxK] = numsR2.slice(0, 6);
          }
          return;
        }
        var mT = ln.match(/^(.{2,40}?)\s+Total Laboratoire\s+(.*)$/i);
        var mC = null;
        if (!mT) mC = ln.match(/^TOTAL\s+(March\u00e9[^\d]*?)\s+([\d\s.,-]+)$/i);
        var nom = null, reste = null;
        if (mT) { nom = mT[1].trim(); reste = mT[2]; }
        else if (mC) { nom = mC[1].trim(); reste = mC[2]; }
        if (!nom) return;
        var nums = (reste.match(/-?\d[\d\s]*[.,]\d{1,2}/g) || []).map(achatsNum);
        if (nums.length >= 6) { labos[nom] = nums.slice(0, 6); dernierLabo = nom; } // [brutM, remM, netM, brutA, remA, netA]
      });
      if (!Object.keys(labos).length) { alert('Aucune ligne \u00ab Total Laboratoire \u00bb lisible.'); input.value = ''; return; }
      achatsMoisObj(mois).cerpR = labos;
      achatsMoisObj(mois).cerpRT = labosT; // v8.39 : d\u00e9tail par taux
      achatsRender();
      alert('\u2713 R\u00e9cap CERP ' + mois + ' : ' + Object.keys(labos).length + ' laboratoire(s)/contrat(s)\n\ud83d\udcbe Pensez \u00e0 \u00ab Sauvegarder sur GitHub \u00bb.');
      input.value = '';
    }).catch(function(err) { alert('PDF illisible : ' + err.message); input.value = ''; });
  };
  reader.readAsArrayBuffer(file);
}

// v8.25 \u2014 lecture des totaux Alliance : tokens SANS espace interne, puis fusion
// des milliers (\u00ab 1 471,37 \u00bb) UNIQUEMENT si n\u00e9cessaire pour retomber sur 8 ou 4 champs
// [brutM remM netM qteM brutA remA netA qteA] \u2014 \u00e9vite d'avaler \u00ab qte 2 \u00bb + \u00ab 160,69 \u00bb en 2160,69.
function achatsParseTotaux(reste) {
  var toks = String(reste).split(/\s+/).filter(function(t) { return /^-?\d+(?:[.,]\d{1,2})?$/.test(t); });
  var fusionner = function(arr) {
    for (var i = 0; i < arr.length - 1; i++) {
      if (/^\d{1,3}$/.test(arr[i]) && /^\d{3}[.,]\d{1,2}$/.test(arr[i + 1])) {
        var f = arr.slice();
        f.splice(i, 2, arr[i] + arr[i + 1]);
        return f;
      }
    }
    return null;
  };
  var essai = toks.slice();
  for (var g = 0; g < 6; g++) {
    if (essai.length === 8 || essai.length === 4) break;
    var f2 = essai.length > 8 ? fusionner(essai) : null;
    if (!f2) break;
    essai = f2;
  }
  if (essai.length !== 8 && essai.length !== 4) return null;
  return essai.map(function(t) { return parseFloat(t.replace(',', '.')) || 0; });
}

// ── IMPORT 4 : Suivi Achats G\u00e9n\u00e9riques Alliance (PDF mensuel) ────────────────
function achatsImportAlliance(input) {
  var file = input.files && input.files[0];
  if (!file) return;
  var reader = new FileReader();
  reader.onload = function(e) {
    pdfjsLib.getDocument({ data: new Uint8Array(e.target.result) }).promise.then(async function(doc) {
      var pages = await achatsPdfLignes(doc);
      var lignes = [].concat.apply([], pages);
      var mois = null;
      lignes.forEach(function(ln) {
        if (mois || /\u00e9dition|edition/i.test(ln)) return;
        var mm = ln.match(/\b(janvier|f\u00e9vrier|fevrier|mars|avril|mai|juin|juillet|ao\u00fbt|aout|septembre|octobre|novembre|d\u00e9cembre|decembre)\s+(\d{4})\b/i);
        if (mm) mois = mm[2] + '-' + ACHATS_MOIS_FR[mm[1].toLowerCase()];
      });
      if (!mois) { alert('Mois introuvable dans ce Suivi Alliance.'); input.value = ''; return; }
      var labos = {};
      var labosT = {};          // v8.39 : d\u00e9tail par taux { labo: { '10': {bm, rm}, ... } }
      var laboCourant = null;
      lignes.forEach(function(lnT) {
        var mX = lnT.match(/^(?:([A-Z][A-Za-z \.\-&']{1,35}?)\s+)?(-?\d+(?:[.,]\d+)?)\s?%\s+(.*)$/);
        if (mX && !/Total|Remise/i.test(lnT.slice(0, 12))) {
          if (mX[1]) laboCourant = mX[1].trim();
          if (laboCourant && !/MICHELET/i.test(laboCourant)) {
            var vX = achatsParseTotaux(mX[3]);
            if (vX) {
              var tK = String(Math.abs(parseFloat(mX[2].replace(',', '.'))));
              if (!labosT[laboCourant]) labosT[laboCourant] = {};
              labosT[laboCourant][tK] = (vX.length === 8) ? { bm: vX[0], rm: Math.abs(vX[1]) } : { bm: 0, rm: 0 };
            }
          }
        }
      });
      lignes.forEach(function(ln) {
        var mT = ln.match(/^(.{2,40}?)\s*-\s*Total\s+(.*)$/);
        if (!mT || /MICHELET/i.test(mT[1])) return;
        var vals = achatsParseTotaux(mT[2]);
        if (!vals) return;
        // 8 valeurs = Mois(4)+Cumul(4) ; 4 = Cumul seul (pas d'achat ce mois)
        if (vals.length >= 8) labos[mT[1].trim()] = { bm: vals[0], rm: Math.abs(vals[1]), nm: vals[2], qm: vals[3], ba: vals[4], ra: Math.abs(vals[5]), na: vals[6], qa: vals[7] };
        else if (vals.length >= 4) labos[mT[1].trim()] = { bm: 0, rm: 0, nm: 0, qm: 0, ba: vals[0], ra: Math.abs(vals[1]), na: vals[2], qa: vals[3] };
      });
      if (!Object.keys(labos).length) { alert('Aucune ligne \u00ab Labo - Total \u00bb lisible.'); input.value = ''; return; }
      achatsMoisObj(mois).alliance = labos;
      achatsMoisObj(mois).allianceT = labosT; // v8.39 : d\u00e9tail par taux
      achatsRender();
      alert('\u2713 Suivi Alliance ' + mois + ' : ' + Object.keys(labos).length + ' laboratoire(s)\n\ud83d\udcbe Pensez \u00e0 \u00ab Sauvegarder sur GitHub \u00bb.');
      input.value = '';
    }).catch(function(err) { alert('PDF illisible : ' + err.message); input.value = ''; });
  };
  reader.readAsArrayBuffer(file);
}

// ── Suppression d'une source pour un mois ────────────────────────────────────
function achatsSupprSource(mois, source) {
  if (!achatsBase || !achatsBase.mois[mois]) return;
  if (!confirm('Supprimer ' + source + ' de ' + mois + ' ?')) return;
  delete achatsBase.mois[mois][source];
  if (source === 'cerpR') delete achatsBase.mois[mois].cerpRT; // v8.55 : le d\u00e9tail par taux suit son r\u00e9cap
  if (!Object.keys(achatsBase.mois[mois]).length) delete achatsBase.mois[mois];
  achatsRender();
}

// ── REQU\u00caTE LABO : agr\u00e9gation multi-sources par mois ─────────────────────────
function achatsRequete() {
  var q = (document.getElementById('achats-req') || {}).value || '';
  q = q.trim().toUpperCase();
  var out = document.getElementById('achats-req-res');
  if (!out) return;
  if (q.length < 2) { out.innerHTML = '<p style="font-size:12px;color:var(--text-ter)">Tapez un nom de labo (ex. TEVA, SANDOZ, EG, BIOGARAN, ARROW\u2026).</p>'; return; }
  if (!achatsBase || !Object.keys(achatsBase.mois).length) { out.innerHTML = '<p style="font-size:12px;color:var(--text-ter)">Base vide \u2014 importez d\u2019abord vos fichiers mensuels.</p>'; return; }
  var tokens = [q];
  if (q === 'SANDOZ') tokens.push('SAND');
  if (q === 'BIOGARAN') tokens.push('BGR', 'BIOGAR');
  if (q === 'VIATRIS') tokens.push('VIAT', 'MYLAN');
  if (q === 'CRISTERS') tokens.push('CRIST');
  var match = function(txt) {
    var T = String(txt).toUpperCase();
    return tokens.some(function(tk) { return T.indexOf(tk) >= 0; });
  };
  var moisT = Object.keys(achatsBase.mois).sort();
  var html = '<table style="width:100%;border-collapse:collapse;font-size:11.5px"><thead><tr>' +
    '<th style="text-align:left;padding:4px 6px;border-bottom:1px solid var(--border)">Mois</th>' +
    '<th style="text-align:right;padding:4px 6px;border-bottom:1px solid var(--border)" title="Suivi Alliance : CA brut / remise">Alliance brut / rem</th>' +
    '<th style="text-align:right;padding:4px 6px;border-bottom:1px solid var(--border)" title="R\u00e9cap sous contrats CERP : CA mois / remise mois">CERP r\u00e9cap brut / rem</th>' +
    '<th style="text-align:right;padding:4px 6px;border-bottom:1px solid var(--border)" title="Lignes factures CERP dont la d\u00e9signation contient le terme : \u03a3 brut / \u03a3 remise (nb lignes)">CERP lignes brut / rem</th>' +
    '<th style="text-align:right;padding:4px 6px;border-bottom:1px solid var(--border)" title="Digipharmacie : \u03a3 HT factures (F) et avoirs (A) des fournisseurs correspondants">Direct F / A</th>' +
    '</tr></thead><tbody>';
  var tA = 0, tAr = 0, tR = 0, tRr = 0, tL = 0, tLr = 0, tF = 0, tAv = 0, trouve = false;
  moisT.forEach(function(m) {
    var o = achatsBase.mois[m];
    var al = null;
    Object.keys(o.alliance || {}).forEach(function(k) { if (!al && match(k)) al = o.alliance[k]; });
    var cr = null;
    Object.keys(o.cerpR || {}).forEach(function(k) { if (!cr && match(k)) cr = o.cerpR[k]; });
    var lb = 0, lr = 0, ln = 0;
    (o.cerpL || []).forEach(function(l) {
      if (!match(l[1])) return;
      var brut = l[2] * l[3];
      lb += brut; lr += Math.max(0, brut - l[4]); ln++;
    });
    var fH = 0, aH = 0;
    (o.digi || []).forEach(function(d) {
      if (!match(d.f) && !match(d.fi)) return;
      if (d.t === 'A') aH += Math.abs(d.ht); else fH += d.ht;
    });
    if (!al && !cr && !ln && !fH && !aH) return;
    trouve = true;
    tA += al ? al.bm : 0; tAr += al ? al.rm : 0;
    tR += cr ? cr[0] : 0; tRr += cr ? cr[1] : 0;
    tL += lb; tLr += lr; tF += fH; tAv += aH;
    var td = 'padding:3px 6px;border-bottom:1px solid var(--border);text-align:right;font-family:monospace';
    html += '<tr><td style="padding:3px 6px;border-bottom:1px solid var(--border)">' + m + '</td>' +
      '<td style="' + td + '">' + (al ? al.bm.toFixed(2) + ' / ' + al.rm.toFixed(2) : '\u2014') + '</td>' +
      '<td style="' + td + '">' + (cr ? cr[0].toFixed(2) + ' / ' + cr[1].toFixed(2) : '\u2014') + '</td>' +
      '<td style="' + td + '">' + (ln ? lb.toFixed(2) + ' / ' + lr.toFixed(2) + ' (' + ln + ')' : '\u2014') + '</td>' +
      '<td style="' + td + '">' + ((fH || aH) ? fH.toFixed(2) + ' / ' + aH.toFixed(2) : '\u2014') + '</td></tr>';
  });
  html += '<tr style="font-weight:700;background:var(--surface2)"><td style="padding:4px 6px">TOTAL</td>' +
    '<td style="padding:4px 6px;text-align:right;font-family:monospace">' + tA.toFixed(2) + ' / ' + tAr.toFixed(2) + '</td>' +
    '<td style="padding:4px 6px;text-align:right;font-family:monospace">' + tR.toFixed(2) + ' / ' + tRr.toFixed(2) + '</td>' +
    '<td style="padding:4px 6px;text-align:right;font-family:monospace">' + tL.toFixed(2) + ' / ' + tLr.toFixed(2) + '</td>' +
    '<td style="padding:4px 6px;text-align:right;font-family:monospace">' + tF.toFixed(2) + ' / ' + tAv.toFixed(2) + '</td></tr>' +
    '</tbody></table>' +
    '<p style="font-size:10.5px;color:var(--text-ter);margin-top:6px">Montants en \u20ac HT. Taux de remise moyen obtenu chez le grossiste : ' +
    ((tA + tR) > 0 ? (100 * (tAr + tRr) / (tA + tR)).toFixed(1) + ' %' : '\u2014') +
    '. Le r\u00e9cap CERP et les lignes factures CERP se recoupent \u2014 ne pas additionner les deux.</p>';
  out.innerHTML = trouve ? html : '<p style="font-size:12px;color:var(--text-ter)">Aucune donn\u00e9e pour \u00ab ' + q + ' \u00bb dans la base.</p>';
}

// ── AIDE \u2753 ──────────────────────────────────────────────────────────────────
function achatsAideToggle() {
  var el = document.getElementById('achats-aide');
  if (!el) return;
  if (el.style.display !== 'none') { el.style.display = 'none'; return; }
  var li = 'font-size:11.5px;margin:0 0 7px 0';
  el.innerHTML = '<div style="background:var(--surface2);padding:12px 14px;border-radius:var(--radius-sm);margin-bottom:12px">' +
    '<p style="' + li + '"><b>1. Chaque mois, importer les 4 fichiers.</b> \ud83d\udce6 Export Digipharmacie (ZIP/CSV/XLSX : toutes vos factures et avoirs fournisseurs) \u00b7 \ud83e\uddfe Factures CERP d\u00e9taill\u00e9es (PDF : chaque ligne produit, cumulables) \u00b7 \ud83d\udcca R\u00e9cap achats sous contrats CERP (PDF : tous les labos g\u00e9n\u00e9riques + march\u00e9s) \u00b7 \ud83d\ude9a Suivi Achats G\u00e9n\u00e9riques Alliance (PDF : tous les g\u00e9n\u00e9riqueurs).</p>' +
    '<p style="' + li + '"><b>2. \ud83d\udcbe Sauvegarder sur GitHub</b> apr\u00e8s chaque s\u00e9rie d\u2019imports \u2014 la base (achats-data.json) est alors partag\u00e9e entre vos 3 machines et recharg\u00e9e \u00e0 l\u2019ouverture de l\u2019onglet.</p>' +
    '<p style="' + li + '"><b>3. Interroger la base.</b> Tapez un labo (TEVA, SANDOZ, EG, BIOGARAN\u2026) : le tableau croise par mois le Suivi Alliance, le R\u00e9cap CERP, les lignes de factures CERP (recherche dans les d\u00e9signations) et vos achats directs/avoirs Digipharmacie \u2014 avec le taux de remise grossiste moyen obtenu. Base de toute n\u00e9gociation de remise compl\u00e9mentaire.</p>' +
    '<p style="' + li + '"><b>Bon \u00e0 savoir.</b> Les exports Digipharmacie listent les documents TRAIT\u00c9S sur la p\u00e9riode (donc aussi des factures dat\u00e9es des mois pr\u00e9c\u00e9dents) : l\u2019import FUSIONNE par r\u00e9f\u00e9rence de document, sans doublon ni \u00e9crasement \u2014 importez vos exports dans n\u2019importe quel ordre, m\u00eame chevauchants. Les PDF CERP r\u00e9cap et Alliance REMPLACENT leur mois ; un r\u00e9cap marqu\u00e9 <b>\u26a0 totaux seuls</b> a \u00e9t\u00e9 import\u00e9 avant la v8.39 (sans d\u00e9tail par taux de remise) : r\u00e9importez le m\u00eame PDF pour alimenter la ventilation Indirect des contr\u00f4les trimestriels et pr\u00e9visionnels \u2014 <b>\u2705 par taux</b> confirme que le mois est complet ; les factures CERP d\u00e9taill\u00e9es se cumulent (supprimez la source \ud83d\uddd1 avant de tout r\u00e9importer). Le suivi EG de l\u2019onglet Conditions reste ind\u00e9pendant.</p>' +
    '</div>';
  el.style.display = 'block';
}

// ── RENDU DE L'ONGLET ────────────────────────────────────────────────────────
function achatsRender() {
  var el = document.getElementById('achats-racine');
  if (!el) return;
  var btn = 'font-size:11px;padding:6px 12px;border-radius:var(--radius-sm);cursor:pointer;font-weight:600;color:#fff;border:none';
  var html =
    '<p class="card-title" style="font-size:14px">\ud83d\udce5 Achats & Imports \u2014 base de donn\u00e9es mensuelle multi-labos</p>' +
    '<div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center;margin-bottom:10px">' +
    '<label style="' + btn + ';background:#7c3aed">\ud83d\udce6 Export Digipharmacie<input type="file" accept=".zip,.csv,.xlsx" style="display:none" onchange="achatsImportDigi(this)"></label>' +
    '<label style="' + btn + ';background:#0369a1">\ud83e\uddfe Factures CERP (d\u00e9tail)<input type="file" accept=".pdf" style="display:none" onchange="achatsImportCerpFactures(this)"></label>' +
    '<label style="' + btn + ';background:#0f6e56">\ud83d\udcca R\u00e9cap sous contrats CERP<input type="file" accept=".pdf" style="display:none" onchange="achatsImportCerpRecap(this)"></label>' +
    '<label style="' + btn + ';background:#b45309">\ud83d\ude9a Suivi Alliance<input type="file" accept=".pdf" style="display:none" onchange="achatsImportAlliance(this)"></label>' +
    '<button type="button" onclick="achatsSauverGitHub()" style="' + btn + ';background:#111">\ud83d\udcbe Sauvegarder sur GitHub</button>' +
    '<button type="button" onclick="achatsAideToggle()" style="font-size:11px;padding:6px 10px;border-radius:var(--radius-sm);cursor:pointer;font-weight:600;background:#fff;border:1px solid var(--border)">\u2753 Workflow</button>' +
    '<span id="achats-save-status" style="font-size:11px"></span>' +
    '</div>' +
    '<div id="achats-aide" style="display:none"></div>';

  // Archive des mois
  var moisT = achatsBase ? Object.keys(achatsBase.mois).sort().reverse() : [];
  html += '<div class="card" style="padding:12px 14px;margin-bottom:14px">' +
    '<p style="font-size:12px;font-weight:700;margin:0 0 8px 0">\ud83d\uddc4 Base : ' + (achatsBase ? moisT.length : '\u2026') + ' mois' + (achatsBase && achatsBase.maj ? ' \u00b7 derni\u00e8re sauvegarde ' + achatsBase.maj.slice(0, 10) : '') + '</p>' +
    (achatsBase && achatsBase._doublonsRetires ? '<p style="font-size:11.5px;color:#b45309;font-weight:600;margin:0 0 8px 0">\ud83e\uddf9 ' + achatsBase._doublonsRetires + ' doublon(s) d\u2019avoirs/factures retir\u00e9(s) automatiquement (h\u00e9ritage des premiers imports) \u2014 cliquez \ud83d\udcbe Sauvegarder sur GitHub pour p\u00e9renniser le nettoyage.</p>' : '');
  if (!achatsBase) {
    html += '<p style="font-size:12px;color:var(--text-ter)">Chargement de la base depuis GitHub\u2026</p>';
  } else if (!moisT.length) {
    html += '<p style="font-size:12px;color:var(--text-ter)">Base vide \u2014 commencez par importer un mois complet (4 fichiers).</p>';
  } else {
    html += '<table style="width:100%;border-collapse:collapse;font-size:11.5px"><thead><tr>' +
      '<th style="text-align:left;padding:4px 6px;border-bottom:1px solid var(--border)">Mois</th>' +
      '<th style="text-align:left;padding:4px 6px;border-bottom:1px solid var(--border)">\ud83d\udce6 Digipharmacie</th>' +
      '<th style="text-align:left;padding:4px 6px;border-bottom:1px solid var(--border)">\ud83e\uddfe CERP d\u00e9tail</th>' +
      '<th style="text-align:left;padding:4px 6px;border-bottom:1px solid var(--border)">\ud83d\udcca CERP r\u00e9cap</th>' +
      '<th style="text-align:left;padding:4px 6px;border-bottom:1px solid var(--border)">\ud83d\ude9a Alliance</th>' +
      '</tr></thead><tbody>';
    moisT.forEach(function(m) {
      var o = achatsBase.mois[m];
      var cell = function(present, txt, source) {
        return '<td style="padding:3px 6px;border-bottom:1px solid var(--border)">' +
          (present ? '\u2705 ' + txt + ' <button type="button" onclick="achatsSupprSource(\'' + m + '\',\'' + source + '\')" style="font-size:10px;background:none;border:none;color:var(--danger);cursor:pointer" title="Supprimer cette source">\ud83d\uddd1</button>' : '<span style="color:var(--text-ter)">\u2014</span>') + '</td>';
      };
      html += '<tr><td style="padding:3px 6px;border-bottom:1px solid var(--border);font-weight:600">' + m + '</td>' +
        cell(o.digi, (o.digi || []).length + ' lignes', 'digi') +
        cell(o.cerpL, (o.cerpL || []).length + ' lignes produit', 'cerpL') +
        // v8.55 : bandeau honn\u00eate \u2014 un r\u00e9cap import\u00e9 AVANT la v8.39 n'a que les totaux
        // par labo (cerpR), pas le d\u00e9tail par taux (cerpRT) dont vivent la ventilation
        // Indirect du contr\u00f4le trimestriel TEVA et le pr\u00e9visionnel. On le dit.
        (function() {
          if (!o.cerpR) return '<td style="padding:3px 6px;border-bottom:1px solid var(--border)"><span style="color:var(--text-ter)">\u2014</span></td>';
          var nbR = Object.keys(o.cerpR).length, nbT = Object.keys(o.cerpRT || {}).length;
          var sup = ' <button type="button" onclick="achatsSupprSource(\'' + m + '\',\'cerpR\')" style="font-size:10px;background:none;border:none;color:var(--danger);cursor:pointer" title="Supprimer cette source">\ud83d\uddd1</button>';
          if (nbT) return '<td style="padding:3px 6px;border-bottom:1px solid var(--border)" title="D\u00e9tail par taux de remise pr\u00e9sent (' + nbT + ' labo(s)) \u2014 ventilation Indirect des contr\u00f4les trimestriels et pr\u00e9visionnels aliment\u00e9e.">\u2705 ' + nbR + ' labos \u00b7 par taux' + sup + '</td>';
          return '<td style="padding:3px 6px;border-bottom:1px solid var(--border)" title="Import ant\u00e9rieur \u00e0 la v8.39 : totaux par labo uniquement, SANS d\u00e9tail par taux de remise \u2014 la ventilation Indirect (contr\u00f4le trimestriel TEVA, pr\u00e9visionnel) ne peut pas se construire sur ce mois. R\u00e9importez le m\u00eame PDF \u00ab R\u00e9cap sous contrats CERP \u00bb : le mois est remplac\u00e9 proprement, avec le d\u00e9tail."><span style="color:#b45309;font-weight:600">\u26a0 ' + nbR + ' labos \u00b7 totaux seuls</span>' + sup + '</td>';
        })() +
        cell(o.alliance, Object.keys(o.alliance || {}).length + ' labos', 'alliance') +
        '</tr>';
    });
    html += '</tbody></table>';
  }
  html += '</div>';

  // Requête labo
  html += '<div class="card" style="padding:12px 14px">' +
    '<p style="font-size:12px;font-weight:700;margin:0 0 8px 0">\ud83d\udd0e Requ\u00eate labo (toutes sources crois\u00e9es)</p>' +
    '<div style="display:flex;gap:8px;margin-bottom:10px">' +
    '<input type="text" id="achats-req" placeholder="TEVA, SANDOZ, EG, BIOGARAN, ARROW\u2026" style="flex:1;max-width:320px;font-size:13px;padding:6px 10px;border:1px solid var(--border);border-radius:var(--radius-sm);background:var(--surface2)" onkeydown="if(event.key===\'Enter\')achatsRequete()">' +
    '<button type="button" onclick="achatsRequete()" style="' + btn + ';background:#0f6e56">Analyser</button>' +
    '</div>' +
    '<div id="achats-req-res"></div>' +
    '</div>';

  el.innerHTML = html;
}


// ═════════════════════════════════════════════════════════════════════════════
// v8.34 — ONGLET 🧾 VENTES : base de données mensuelle des ventes.
// Deux sources par mois : export Ospharm « Toutes les ventes » (période d'UN mois)
// et export LGPI. Persistance : ventes-data.json sur GitHub (comme achats-data.json).
// LE PONT : ventesReconstituerOspharm() agrège les 12 derniers mois de la base et
// remplace decOspharmProds / decOspharmProdsN1 / decOspharmData en mémoire —
// tous les modules existants (Décision RDV, MEQ, Commande, ratio EG…) consomment
// alors la base Ventes sans modification. Auto au démarrage dès que 12 mois couverts.
// ═════════════════════════════════════════════════════════════════════════════

var ventesBase = null;   // { v:1, maj:'', mois:{ 'AAAA-MM': { osph:{labo:[[ean,lib,qte,caht,paht,marge,stock]]}, osphMeta:{}, lgpi:[[ean,lib,qte,caht]], lgpiMeta:{} } } }
var ventesInited = false;
var VENTES_GH_FILE = 'ventes-data.json';
var _ventesChargement = null;

function ventesMoisObj(m) {
  if (!ventesBase.mois[m]) ventesBase.mois[m] = {};
  return ventesBase.mois[m];
}

function ventesChargerBase() {
  if (ventesBase) return Promise.resolve(ventesBase);
  if (_ventesChargement) return _ventesChargement;
  _ventesChargement = fetch('https://raw.githubusercontent.com/' + GH_OWNER + '/' + GH_REPO + '/' + GH_BRANCH + '/' + VENTES_GH_FILE + '?t=' + Date.now())
    .then(function(r) { return r.ok ? r.json() : null; })
    .then(function(d) { ventesBase = (d && d.mois) ? d : { v: 1, maj: '', mois: {} }; return ventesBase; })
    .catch(function() { ventesBase = { v: 1, maj: '', mois: {} }; return ventesBase; });
  return _ventesChargement;
}

function ventesInit() {
  if (ventesInited) { ventesRender(); return; }
  ventesInited = true;
  ventesRender();
  ventesChargerBase().then(function() { ventesRender(); });
}

async function ventesSauverGitHub() {
  var st = document.getElementById('ventes-save-status');
  if (!ventesBase) return;
  if (st) { st.textContent = 'Sauvegarde\u2026'; st.style.color = 'var(--text-sec)'; }
  try {
    ventesBase.maj = new Date().toISOString();
    var token = condGetToken();
    var body = JSON.stringify(ventesBase);
    var b64 = btoa(unescape(encodeURIComponent(body)));
    var sha = null;
    var g = await fetch('https://api.github.com/repos/' + GH_OWNER + '/' + GH_REPO + '/contents/' + VENTES_GH_FILE + '?t=' + Date.now(), {
      headers: { 'Authorization': 'token ' + token, 'Accept': 'application/vnd.github.v3+json' }
    });
    if (g.ok) { sha = (await g.json()).sha; }
    var payload = { message: 'data: ventes-data.json (base ventes mensuelles)', content: b64, branch: GH_BRANCH };
    if (sha) payload.sha = sha;
    var doPut = function() {
      return fetch('https://api.github.com/repos/' + GH_OWNER + '/' + GH_REPO + '/contents/' + VENTES_GH_FILE, {
        method: 'PUT',
        headers: { 'Authorization': 'token ' + token, 'Accept': 'application/vnd.github.v3+json', 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });
    };
    var p = await doPut();
    if (!p.ok) {
      var e1 = await p.json();
      if (String(e1.message || '').toLowerCase().indexOf('sha') >= 0) {
        var g2 = await fetch('https://api.github.com/repos/' + GH_OWNER + '/' + GH_REPO + '/contents/' + VENTES_GH_FILE + '?t=' + Date.now(), {
          headers: { 'Authorization': 'token ' + token, 'Accept': 'application/vnd.github.v3+json' }
        });
        if (g2.ok) payload.sha = (await g2.json()).sha;
        p = await doPut();
        if (!p.ok) throw new Error((await p.json()).message || p.status);
      } else throw new Error(e1.message || p.status);
    }
    var ko = Math.round(body.length / 1024);
    if (st) {
      st.textContent = '\u2713 Base sauvegard\u00e9e (' + (ko > 1024 ? (ko / 1024).toFixed(1) + ' Mo' : ko + ' Ko') + ')' + (ko > 3800 ? ' \u26a0 proche de la limite 4,5 Mo' : '');
      st.style.color = ko > 3800 ? '#b45309' : 'var(--accent-text)';
    }
    setTimeout(function() { if (st && st.textContent.indexOf('\u2713') === 0) st.textContent = ''; }, 6000);
  } catch (err) {
    if (st) { st.textContent = 'Erreur sauvegarde : ' + err.message; st.style.color = 'var(--danger)'; }
  }
}

// ── Mois d'un fichier : dates ISO du nom, ou mois fran\u00e7ais, sinon prompt ──────
function ventesMoisDuFichier(nomFichier) {
  var m = String(nomFichier).match(/(\d{4}-\d{2})-\d{2}[\s_]+(?:au[\s_]+)?(\d{4}-\d{2})-\d{2}/);
  if (m) return (m[1] === m[2]) ? m[1] : 'MULTI';
  var MF = { janvier: '01', 'f\u00e9vrier': '02', fevrier: '02', mars: '03', avril: '04', mai: '05', juin: '06', juillet: '07', 'ao\u00fbt': '08', aout: '08', septembre: '09', octobre: '10', novembre: '11', 'd\u00e9cembre': '12', decembre: '12' };
  var f = String(nomFichier).toLowerCase();
  var mm2 = f.match(/\b(janvier|f\u00e9vrier|fevrier|mars|avril|mai|juin|juillet|ao\u00fbt|aout|septembre|octobre|novembre|d\u00e9cembre|decembre)[\s_-]*(\d{2,4})\b/);
  if (mm2) {
    var an = mm2[2].length === 2 ? '20' + mm2[2] : mm2[2];
    return an + '-' + MF[mm2[1]];
  }
  return null;
}

// ── IMPORT 1 : export Ospharm mensuel (m\u00eames colonnes que l'import global) ────
// v8.35 \u2014 s\u00e9lection MULTIPLE : chaque fichier mensuel s'importe dans son mois,
// \u00e0 la cha\u00eene, avec un bilan unique. Un fichier multi-mois reste refus\u00e9
// (l'export Ospharm agr\u00e8ge la p\u00e9riode sans d\u00e9tail mensuel \u2014 inventilable).
function ventesImportOspharm(input) {
  var fichiers = Array.prototype.slice.call(input.files || []);
  if (!fichiers.length) return;
  var bilan = [];
  var suivant = function(idx) {
    if (idx >= fichiers.length) {
      ventesRender();
      alert('Import Ospharm termin\u00e9 (' + fichiers.length + ' fichier(s)) :\n' + bilan.join('\n') + '\n\ud83d\udcbe Pensez \u00e0 \u00ab Sauvegarder sur GitHub \u00bb.');
      input.value = '';
      return;
    }
    ventesImportOspharmUn(fichiers[idx], function(msg) { bilan.push(msg); suivant(idx + 1); });
  };
  suivant(0);
}

function ventesImportOspharmUn(file, fini) {
  var mois = ventesMoisDuFichier(file.name);
  if (mois === 'MULTI') { fini('\u2717 ' + file.name + ' : couvre plusieurs mois \u2014 refus\u00e9 (exporter mois par mois)'); return; }
  if (!mois) {
    mois = prompt('Mois de \u00ab ' + file.name + ' \u00bb (AAAA-MM) :', new Date().toISOString().slice(0, 7));
    if (!mois || !/^\d{4}-\d{2}$/.test(mois.trim())) { fini('\u2717 ' + file.name + ' : mois non fourni \u2014 ignor\u00e9'); return; }
    mois = mois.trim();
  }
  var reader = new FileReader();
  reader.onload = function(ev) {
    try {
      var wb = XLSX.read(new Uint8Array(ev.target.result), { type: 'array' });
      var rows = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]], { header: 1, raw: false, defval: '' });
      if (!rows.length) throw new Error('Fichier vide');
      var header = rows[0];
      var cols = {};
      for (var i = 0; i < header.length; i++) {
        var h = String(header[i] || '').trim();
        if (h) cols[h] = i;
      }
      if (cols['Libell\u00e9 laboratoire'] === undefined || cols['Quantit\u00e9'] === undefined) {
        fini('\u2717 ' + file.name + ' : format non reconnu (colonnes Ospharm absentes)');
        return;
      }
      var eanKey = Object.keys(cols).find(function(k) { return /EAN|CIP|ACL/i.test(k); });
      var num = function(v) { return parseFloat(String(v == null ? '' : v).replace(/[^\d.-]/g, '')) || 0; };
      var parLabo = {}, nb = 0;
      for (var r = 1; r < rows.length; r++) {
        var row = rows[r];
        var labo = String(row[cols['Libell\u00e9 laboratoire']] || '').trim();
        if (!labo) continue;
        var ean = eanKey ? String(row[cols[eanKey]] || '').replace(/\D/g, '') : '';
        var lib = String(row[cols['Libell\u00e9 produit']] || '').trim().slice(0, 40);
        if (!parLabo[labo]) parLabo[labo] = [];
        parLabo[labo].push([
          ean, lib,
          num(row[cols['Quantit\u00e9']]),
          Math.round(num(row[cols['CA HT']]) * 100) / 100,
          Math.round(num(row[cols['Prix achat HT']]) * 100) / 100,
          Math.round(num(row[cols['Marge']]) * 100) / 100,
          num(row[cols['Stocks quantit\u00e9']])
        ]);
        nb++;
      }
      if (!nb) { fini('\u2717 ' + file.name + ' : aucune ligne exploitable'); return; }
      var o = ventesMoisObj(mois);
      var remplace = !!o.osph;
      o.osph = parLabo;
      o.osphMeta = { fichier: file.name, importeLe: new Date().toISOString().slice(0, 10), nb: nb };
      fini('\u2713 ' + mois + ' : ' + nb + ' lignes \u00b7 ' + Object.keys(parLabo).length + ' labos' + (remplace ? ' (mois remplac\u00e9)' : ''));
    } catch (err) { fini('\u2717 ' + file.name + ' : ' + err.message); }
  };
  reader.readAsArrayBuffer(file);
}

// ── IMPORT 2 : export LGPI mensuel (d\u00e9tection tol\u00e9rante) ─────────────────────
function ventesImportLgpi(input) {
  var fichiers = Array.prototype.slice.call(input.files || []);
  if (!fichiers.length) return;
  var bilan = [];
  var suivant = function(idx) {
    if (idx >= fichiers.length) {
      ventesRender();
      alert('Import LGPI termin\u00e9 (' + fichiers.length + ' fichier(s)) :\n' + bilan.join('\n') + '\n\ud83d\udcbe Pensez \u00e0 \u00ab Sauvegarder sur GitHub \u00bb.');
      input.value = '';
      return;
    }
    ventesImportLgpiUn(fichiers[idx], function(msg) { bilan.push(msg); suivant(idx + 1); });
  };
  suivant(0);
}

function ventesImportLgpiUn(file, fini) {
  var mois = ventesMoisDuFichier(file.name);
  if (mois === 'MULTI' || !mois) {
    mois = prompt('Mois de \u00ab ' + file.name + ' \u00bb (AAAA-MM) :', new Date().toISOString().slice(0, 7));
    if (!mois || !/^\d{4}-\d{2}$/.test(mois.trim())) { fini('\u2717 ' + file.name + ' : mois non fourni \u2014 ignor\u00e9'); return; }
    mois = mois.trim();
  }
  var reader = new FileReader();
  reader.onload = function(ev) {
    try {
      var wb = XLSX.read(new Uint8Array(ev.target.result), { type: 'array' });
      var grid = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]], { header: 1, raw: false, defval: '' });
      // en-t\u00eate : ligne contenant une colonne quantit\u00e9
      var hi = -1, colQ = -1, colCA = -1;
      for (var i = 0; i < Math.min(grid.length, 12) && hi < 0; i++) {
        for (var j = 0; j < grid[i].length; j++) {
          var h = String(grid[i][j]).toLowerCase();
          if (/quantit|\bqt\u00e9\b|\bqte\b/.test(h)) { hi = i; colQ = j; }
          if (hi === i && /ca\b|chiffre/.test(h) && colCA < 0) colCA = j;
        }
      }
      if (hi < 0) { fini('\u2717 ' + file.name + ' : colonne Quantit\u00e9 introuvable'); return; }
      // colonne EAN par le contenu (codes 13 chiffres)
      var colE = -1;
      for (var j2 = 0; j2 < (grid[hi].length || 25) && colE < 0; j2++) {
        var hits = 0, seen = 0;
        for (var i2 = hi + 1; i2 < Math.min(grid.length, hi + 50); i2++) {
          var cv = String((grid[i2] || [])[j2] || '').replace(/\s/g, '');
          if (!cv) continue;
          seen++;
          if (/^\d{13}$/.test(cv)) hits++;
        }
        if (seen >= 3 && hits / seen > 0.7) colE = j2;
      }
      if (colE < 0) { fini('\u2717 ' + file.name + ' : colonne EAN/CIP13 introuvable'); return; }
      // libell\u00e9 : colonne texte la plus longue \u00e0 gauche de la quantit\u00e9
      var colL = -1, best = 0;
      for (var j3 = 0; j3 < grid[hi].length; j3++) {
        if (j3 === colE || j3 === colQ) continue;
        var lg = 0;
        for (var i3 = hi + 1; i3 < Math.min(grid.length, hi + 30); i3++) {
          var v3 = String((grid[i3] || [])[j3] || '');
          if (/[A-Za-z]{3}/.test(v3)) lg += v3.length;
        }
        if (lg > best) { best = lg; colL = j3; }
      }
      var num = function(v) { return parseFloat(String(v == null ? '' : v).replace(/\s/g, '').replace(',', '.')) || 0; };
      var lignes = [], nb = 0;
      for (var r = hi + 1; r < grid.length; r++) {
        var row = grid[r] || [];
        var ean = String(row[colE] || '').replace(/\s/g, '');
        if (!/^\d{13}$/.test(ean)) continue;
        lignes.push([ean, String(colL >= 0 ? row[colL] : '').trim().slice(0, 40), num(row[colQ]), colCA >= 0 ? Math.round(num(row[colCA]) * 100) / 100 : 0]);
        nb++;
      }
      if (!nb) { fini('\u2717 ' + file.name + ' : aucune ligne EAN exploitable'); return; }
      var o = ventesMoisObj(mois);
      var remplace = !!o.lgpi;
      o.lgpi = lignes;
      o.lgpiMeta = { fichier: file.name, importeLe: new Date().toISOString().slice(0, 10), nb: nb };
      fini('\u2713 ' + mois + ' : ' + nb + ' lignes' + (remplace ? ' (mois remplac\u00e9)' : ''));
    } catch (err) { fini('\u2717 ' + file.name + ' : ' + err.message); }
  };
  reader.readAsArrayBuffer(file);
}

function ventesSupprSource(mois, source) {
  if (!ventesBase || !ventesBase.mois[mois]) return;
  if (!confirm('Supprimer ' + source + ' de ' + mois + ' ?')) return;
  delete ventesBase.mois[mois][source];
  delete ventesBase.mois[mois][source + 'Meta'];
  if (!Object.keys(ventesBase.mois[mois]).length) delete ventesBase.mois[mois];
  ventesRender();
}

// ── LE PONT : reconstituer le cache Ospharm 12 mois depuis la base ────────────
function ventesReconstituerOspharm(silencieux) {
  if (!ventesBase) return false;
  var moisOsph = Object.keys(ventesBase.mois).filter(function(m) { return ventesBase.mois[m].osph; }).sort();
  if (!moisOsph.length) { if (!silencieux) alert('Aucun mois Ospharm dans la base Ventes.'); return false; }
  var fenetre = moisOsph.slice(-12);
  if (!silencieux && fenetre.length < 12) {
    if (!confirm('La base ne couvre que ' + fenetre.length + ' mois Ospharm (' + fenetre[0] + ' \u2192 ' + fenetre[fenetre.length - 1] + ').\nRemplacer quand m\u00eame le cache 12 mois de l\u2019application ?\n(Tous les modules verront une p\u00e9riode partielle.)')) return false;
  }
  // N\u22121 : les 12 mois pr\u00e9c\u00e9dant la fen\u00eatre, s'ils existent
  var idx0 = moisOsph.indexOf(fenetre[0]);
  var fenetreN1 = moisOsph.slice(Math.max(0, idx0 - 12), idx0);
  var agg = function(listeMois) {
    var prods = {}, data = {};
    listeMois.forEach(function(m) {
      var parLabo = ventesBase.mois[m].osph || {};
      Object.keys(parLabo).forEach(function(labo) {
        if (!prods[labo]) { prods[labo] = {}; data[labo] = 0; }
        parLabo[labo].forEach(function(l) {
          var k = l[0] || l[1];
          var p = prods[labo][k];
          if (!p) p = prods[labo][k] = { ean: l[0], lib: l[1], qte: 0, caht: 0, paht: 0, marge: 0, stock: 0 };
          p.qte += l[2] || 0;
          p.caht += l[3] || 0;
          p.paht += l[4] || 0;
          p.marge += l[5] || 0;
          p.stock = l[6] || p.stock; // instantan\u00e9 : dernier mois qui le fournit
          p.lib = l[1] || p.lib;
          data[labo] += l[3] || 0;
        });
      });
    });
    var out = {};
    Object.keys(prods).forEach(function(labo) {
      out[labo] = Object.keys(prods[labo]).map(function(k) {
        var p = prods[labo][k];
        p.caht = Math.round(p.caht * 100) / 100;
        p.paht = Math.round(p.paht * 100) / 100;
        p.marge = Math.round(p.marge * 100) / 100;
        return p;
      });
    });
    return { prods: out, data: data };
  };
  var N = agg(fenetre);
  decOspharmProds = N.prods;
  decOspharmData = {};
  Object.keys(N.data).forEach(function(l2) { decOspharmData[l2] = Math.round(N.data[l2] * 100) / 100; });
  decOspharmProdsN1 = {};
  if (fenetreN1.length) {
    var N1 = agg(fenetreN1);
    Object.keys(N1.prods).forEach(function(labo) {
      decOspharmProdsN1[labo] = N1.prods[labo].map(function(p) { return { ean: p.ean, lib: p.lib, qte: p.qte }; });
    });
  } else {
    Object.keys(decOspharmProds).forEach(function(labo) {
      decOspharmProdsN1[labo] = decOspharmProds[labo].map(function(p) { return { ean: p.ean, lib: p.lib, qte: 0 }; });
    });
  }
  var debut = fenetre[0] + '-01';
  var finM = fenetre[fenetre.length - 1];
  var finJ = new Date(parseInt(finM.slice(0, 4), 10), parseInt(finM.slice(5, 7), 10), 0).getDate();
  var fin = finM + '-' + ('0' + finJ).slice(-2);
  var meta = {
    importeeLe: new Date().toLocaleDateString('fr-FR'),
    importeeTs: Date.now(),
    fichier: 'Base Ventes ' + debut + ' ' + fin + ' (' + fenetre.length + ' mois' + (fenetreN1.length ? ', N-1 ' + fenetreN1.length + ' mois' : '') + ')',
    periodeDebut: debut,
    periodeFin: fin,
    nbLabos: Object.keys(decOspharmProds).length
  };
  try { localStorage.setItem('_osph_meta', JSON.stringify(meta)); } catch (e) {}
  try { localStorage.setItem('_osph_data', JSON.stringify(decOspharmData)); } catch (e) {}
  window._ventesPontActif = fenetre[0] + ' \u2192 ' + finM;
  console.info('[Ventes] Cache Ospharm reconstitu\u00e9 depuis la base : ' + meta.fichier);
  if (!silencieux) {
    alert('\u2713 Cache Ospharm de l\u2019application remplac\u00e9 par la base Ventes\n' + meta.fichier + '\n' + meta.nbLabos + ' laboratoires \u2014 tous les onglets (D\u00e9cision RDV, MEQ, Commande\u2026) utilisent maintenant ces donn\u00e9es.');
    ventesRender();
  }
  return true;
}

// ── Auto au d\u00e9marrage : si la base couvre \u2265 12 mois, elle prend le relais ───
function ventesAutoAlimenter() {
  ventesChargerBase().then(function() {
    var moisOsph = Object.keys(ventesBase.mois).filter(function(m) { return ventesBase.mois[m].osph; });
    if (moisOsph.length >= 12) ventesReconstituerOspharm(true);
  });
}

function ventesAideToggle() {
  var el = document.getElementById('ventes-aide');
  if (!el) return;
  if (el.style.display !== 'none') { el.style.display = 'none'; return; }
  var li = 'font-size:11.5px;margin:0 0 7px 0';
  el.innerHTML = '<div style="background:var(--surface2);padding:12px 14px;border-radius:var(--radius-sm);margin-bottom:12px">' +
    '<p style="' + li + '"><b>1. Chaque mois, deux imports.</b> \ud83d\udcc8 Export Ospharm \u00ab Toutes les ventes \u00bb du 1er au dernier jour du mois (le mois est lu dans le nom du fichier \u2014 un export multi-mois est refus\u00e9) \u00b7 \ud83c\udfea Export LGPI \u00ab Toutes les ventes \u00bb du mois (mois lu dans le nom, sinon demand\u00e9).</p>' +
    '<p style="' + li + '"><b>2. \ud83d\udcbe Sauvegarder sur GitHub</b> \u2014 la base (ventes-data.json) est partag\u00e9e entre vos 3 machines.</p>' +
    '<p style="' + li + '"><b>3. Le pont Ospharm.</b> D\u00e8s que la base couvre 12 mois, elle alimente AUTOMATIQUEMENT toute l\u2019application au d\u00e9marrage (D\u00e9cision RDV, MEQ, Commande, suivi EG\u2026) \u00e0 la place du fichier ospharm-cache.json \u2014 plus besoin d\u2019exporter les 12 mois glissants : le mois le plus ancien sort, le nouveau entre. Le bouton \u26a1 force le remplacement imm\u00e9diat (avec avertissement si moins de 12 mois). Si des mois N\u22121 sont en base, la comparaison N/N\u22121 est reconstitu\u00e9e aussi.</p>' +
    '<p style="' + li + '"><b>Re-import d\u2019un mois</b> : remplace la source de ce mois. \ud83d\uddd1 supprime une source. Les ventes LGPI serviront aux prochains branchements (MEQ, saisonnalit\u00e9) \u2014 une \u00e9tape \u00e0 la fois.</p>' +
    '</div>';
  el.style.display = 'block';
}

function ventesRender() {
  var el = document.getElementById('ventes-racine');
  if (!el) return;
  var btn = 'font-size:11px;padding:6px 12px;border-radius:var(--radius-sm);cursor:pointer;font-weight:600;color:#fff;border:none';
  var html =
    '<p class="card-title" style="font-size:14px">\ud83e\uddfe Ventes \u2014 base de donn\u00e9es mensuelle (Ospharm + LGPI)</p>' +
    '<div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center;margin-bottom:10px">' +
    '<label style="' + btn + ';background:#0f6e56">\ud83d\udcc8 Import Ospharm (mois)<input type="file" accept=".xlsx,.xls" multiple style="display:none" onchange="ventesImportOspharm(this)"></label>' +
    '<label style="' + btn + ';background:#1d4ed8">\ud83c\udfea Import LGPI (mois)<input type="file" accept=".xlsx,.xls,.csv" multiple style="display:none" onchange="ventesImportLgpi(this)"></label>' +
    '<button type="button" onclick="ventesReconstituerOspharm(false)" style="' + btn + ';background:#7c3aed">\u26a1 Alimenter l\u2019app (12 derniers mois)</button>' +
    '<button type="button" onclick="ventesSauverGitHub()" style="' + btn + ';background:#111">\ud83d\udcbe Sauvegarder sur GitHub</button>' +
    '<button type="button" onclick="ventesAideToggle()" style="font-size:11px;padding:6px 10px;border-radius:var(--radius-sm);cursor:pointer;font-weight:600;background:#fff;border:1px solid var(--border)">\u2753 Workflow</button>' +
    '<span id="ventes-save-status" style="font-size:11px"></span>' +
    '</div>' +
    '<div id="ventes-aide" style="display:none"></div>';

  var moisT = ventesBase ? Object.keys(ventesBase.mois).sort().reverse() : [];
  var nbOsph = ventesBase ? moisT.filter(function(m) { return ventesBase.mois[m].osph; }).length : 0;
  html += '<div class="card" style="padding:12px 14px;margin-bottom:14px">' +
    '<p style="font-size:12px;font-weight:700;margin:0 0 4px 0">\ud83d\uddc4 Base : ' + (ventesBase ? moisT.length : '\u2026') + ' mois' + (ventesBase && ventesBase.maj ? ' \u00b7 derni\u00e8re sauvegarde ' + ventesBase.maj.slice(0, 10) : '') + '</p>' +
    '<p style="font-size:11px;margin:0 0 8px 0;color:' + (window._ventesPontActif ? 'var(--accent-text)' : 'var(--text-ter)') + '">' +
    (window._ventesPontActif
      ? '\u26a1 Pont ACTIF : l\u2019application est aliment\u00e9e par la base Ventes (' + window._ventesPontActif + ')'
      : (nbOsph >= 12 ? '\u26a1 12 mois couverts \u2014 le pont s\u2019activera au prochain d\u00e9marrage (ou bouton \u26a1)' : nbOsph + '/12 mois Ospharm en base \u2014 l\u2019application reste sur ospharm-cache.json jusqu\u2019\u00e0 12 mois (bouton \u26a1 pour forcer)')) +
    '</p>';
  if (!ventesBase) {
    html += '<p style="font-size:12px;color:var(--text-ter)">Chargement de la base depuis GitHub\u2026</p>';
  } else if (!moisT.length) {
    html += '<p style="font-size:12px;color:var(--text-ter)">Base vide \u2014 importez votre premier mois (Ospharm + LGPI).</p>';
  } else {
    html += '<table style="width:100%;border-collapse:collapse;font-size:11.5px"><thead><tr>' +
      '<th style="text-align:left;padding:4px 6px;border-bottom:1px solid var(--border)">Mois</th>' +
      '<th style="text-align:left;padding:4px 6px;border-bottom:1px solid var(--border)">\ud83d\udcc8 Ospharm</th>' +
      '<th style="text-align:left;padding:4px 6px;border-bottom:1px solid var(--border)">\ud83c\udfea LGPI</th>' +
      '</tr></thead><tbody>';
    moisT.forEach(function(m) {
      var o = ventesBase.mois[m];
      var cell = function(present, txt, source) {
        return '<td style="padding:3px 6px;border-bottom:1px solid var(--border)">' +
          (present ? '\u2705 ' + txt + ' <button type="button" onclick="ventesSupprSource(\'' + m + '\',\'' + source + '\')" style="font-size:10px;background:none;border:none;color:var(--danger);cursor:pointer" title="Supprimer">\ud83d\uddd1</button>' : '<span style="color:var(--text-ter)">\u2014</span>') + '</td>';
      };
      var nO = 0;
      if (o.osph) Object.keys(o.osph).forEach(function(l) { nO += o.osph[l].length; });
      html += '<tr><td style="padding:3px 6px;border-bottom:1px solid var(--border);font-weight:600">' + m + '</td>' +
        cell(o.osph, nO + ' lignes \u00b7 ' + Object.keys(o.osph || {}).length + ' labos', 'osph') +
        cell(o.lgpi, (o.lgpi || []).length + ' lignes', 'lgpi') +
        '</tr>';
    });
    html += '</tbody></table>';
  }
  html += '</div>';
  el.innerHTML = html;
}
